--
-- Name: capture_change(); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE OR REPLACE FUNCTION "audit"."capture_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public', 'pg_temp'
    AS $$
DECLARE
    v_old_data JSONB;
    v_new_data JSONB;
    v_record_id UUID;
    v_user_role TEXT;
    v_ip_address INET;
    v_user_agent TEXT;
    v_changed_fields TEXT[];
BEGIN
    SELECT role INTO v_user_role
    FROM public.user_roles
    WHERE user_id = auth.uid()
    ORDER BY 
        CASE role 
            WHEN 'admin' THEN 1 
            WHEN 'restaurant' THEN 2
            WHEN 'partner' THEN 3
            ELSE 4 
        END
    LIMIT 1;
    
    BEGIN
        v_ip_address := current_setting('app.current_ip', true)::inet;
    EXCEPTION WHEN OTHERS THEN
        v_ip_address := NULL;
    END;
    
    BEGIN
        v_user_agent := current_setting('app.current_user_agent', true);
    EXCEPTION WHEN OTHERS THEN
        v_user_agent := NULL;
    END;
    
    IF TG_OP = 'INSERT' THEN
        v_new_data := to_jsonb(NEW);
        v_record_id := NEW.id;
        v_old_data := NULL;
    ELSIF TG_OP = 'UPDATE' THEN
        v_old_data := to_jsonb(OLD);
        v_new_data := to_jsonb(NEW);
        v_record_id := NEW.id;
    ELSIF TG_OP = 'DELETE' THEN
        v_old_data := to_jsonb(OLD);
        v_new_data := NULL;
        v_record_id := OLD.id;
    END IF;
    
    -- Calculate changed fields
    v_changed_fields := audit.get_changed_fields(v_old_data, v_new_data, TG_OP);
    
    INSERT INTO audit.log (
        table_schema,
        table_name,
        record_id,
        action,
        old_data,
        new_data,
        changed_fields,
        changed_by,
        user_role,
        ip_address,
        user_agent,
        application
    ) VALUES (
        TG_TABLE_SCHEMA,
        TG_TABLE_NAME,
        v_record_id,
        TG_OP,
        v_old_data,
        v_new_data,
        v_changed_fields,
        auth.uid(),
        v_user_role,
        v_ip_address,
        v_user_agent,
        COALESCE(current_setting('app.application_name', true), 'unknown')
    );
    
    IF TG_OP = 'DELETE' THEN
        RETURN OLD;
    ELSE
        RETURN NEW;
    END IF;
END;
$$;


ALTER FUNCTION "audit"."capture_change"() OWNER TO "postgres";

--
-- Name: FUNCTION "capture_change"(); Type: COMMENT; Schema: audit; Owner: postgres
--

COMMENT ON FUNCTION "audit"."capture_change"() IS 'Trigger function that captures all changes to audited tables';


--
-- Name: enable_auditing("text", "text"); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE OR REPLACE FUNCTION "audit"."enable_auditing"("p_table_name" "text", "p_schema" "text" DEFAULT 'public'::"text") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'audit', 'public', 'pg_temp'
    AS $$
BEGIN
    EXECUTE format('
        DROP TRIGGER IF EXISTS audit_trigger ON %I.%I;
        CREATE TRIGGER audit_trigger
            AFTER INSERT OR UPDATE OR DELETE ON %I.%I
            FOR EACH ROW EXECUTE FUNCTION audit.capture_change();
    ', p_schema, p_table_name, p_schema, p_table_name);
    
    RAISE NOTICE 'Auditing enabled for %.%', p_schema, p_table_name;
END;
$$;


ALTER FUNCTION "audit"."enable_auditing"("p_table_name" "text", "p_schema" "text") OWNER TO "postgres";

--
-- Name: get_changed_fields("jsonb", "jsonb", "text"); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE OR REPLACE FUNCTION "audit"."get_changed_fields"("old_data" "jsonb", "new_data" "jsonb", "action" "text") RETURNS "text"[]
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'audit', 'public', 'pg_temp'
    AS $$
BEGIN
    IF action = 'UPDATE' THEN
        RETURN (
            SELECT array_agg(key)
            FROM jsonb_each(old_data) old_vals
            JOIN jsonb_each(new_data) new_vals USING (key)
            WHERE old_vals.value IS DISTINCT FROM new_vals.value
        );
    ELSIF action = 'INSERT' THEN
        RETURN (SELECT array_agg(key) FROM jsonb_each(new_data));
    ELSIF action = 'DELETE' THEN
        RETURN (SELECT array_agg(key) FROM jsonb_each(old_data));
    ELSE
        RETURN NULL;
    END IF;
END;
$$;


ALTER FUNCTION "audit"."get_changed_fields"("old_data" "jsonb", "new_data" "jsonb", "action" "text") OWNER TO "postgres";

--
-- Name: get_recent_changes(timestamp with time zone, integer); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE OR REPLACE FUNCTION "audit"."get_recent_changes"("p_since" timestamp with time zone DEFAULT ("now"() - '24:00:00'::interval), "p_limit" integer DEFAULT 100) RETURNS TABLE("action_timestamp" timestamp with time zone, "table_name" "text", "action" "text", "record_id" "uuid", "changed_by" "uuid")
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'audit', 'public', 'pg_temp'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        al.action_timestamp,
        al.table_name,
        al.action,
        al.record_id,
        al.changed_by
    FROM audit.log al
    WHERE al.action_timestamp >= p_since
    ORDER BY al.action_timestamp DESC
    LIMIT p_limit;
END;
$$;


ALTER FUNCTION "audit"."get_recent_changes"("p_since" timestamp with time zone, "p_limit" integer) OWNER TO "postgres";

--
-- Name: get_record_history("text", "uuid", integer); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE OR REPLACE FUNCTION "audit"."get_record_history"("p_table_name" "text", "p_record_id" "uuid", "p_limit" integer DEFAULT 100) RETURNS TABLE("action_timestamp" timestamp with time zone, "action" "text", "changed_by" "uuid", "user_role" "text", "changed_fields" "text"[], "old_values" "jsonb", "new_values" "jsonb")
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'audit', 'public', 'pg_temp'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        al.action_timestamp,
        al.action,
        al.changed_by,
        al.user_role,
        al.changed_fields,
        al.old_data,
        al.new_data
    FROM audit.log al
    WHERE al.table_name = p_table_name
    AND al.record_id = p_record_id
    ORDER BY al.action_timestamp DESC
    LIMIT p_limit;
END;
$$;


ALTER FUNCTION "audit"."get_record_history"("p_table_name" "text", "p_record_id" "uuid", "p_limit" integer) OWNER TO "postgres";

