CREATE OR REPLACE FUNCTION "audit"."get_user_activity"("p_user_id" "uuid", "p_limit" integer DEFAULT 100) RETURNS TABLE("action_timestamp" timestamp with time zone, "table_name" "text", "action" "text", "record_id" "uuid")
