--
-- Name: purge_old_logs(integer); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE OR REPLACE FUNCTION "audit"."purge_old_logs"("p_retention_days" integer DEFAULT 90) RETURNS integer
    LANGUAGE "plpgsql"
    SET "search_path" TO 'audit', 'public', 'pg_temp'
    AS $$
DECLARE
    v_count INTEGER;
BEGIN
    DELETE FROM audit.log
    WHERE action_timestamp < now() - (p_retention_days || ' days')::interval;
    
    GET DIAGNOSTICS v_count = ROW_COUNT;
    RETURN v_count;
END;
$$;


ALTER FUNCTION "audit"."purge_old_logs"("p_retention_days" integer) OWNER TO "postgres";

