--
-- Name: verify_audit_coverage(); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE OR REPLACE FUNCTION "audit"."verify_audit_coverage"() RETURNS TABLE("schema_name" "text", "table_name" "text", "has_audit_trigger" boolean, "status" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'audit', 'public', 'pg_temp'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        n.nspname::TEXT as schema_name,
        c.relname::TEXT as table_name,
        EXISTS (
            SELECT 1 
            FROM pg_trigger t 
            WHERE t.tgrelid = c.oid 
            AND t.tgname = 'audit_trigger'
        ) as has_audit_trigger,
        CASE 
            WHEN EXISTS (
                SELECT 1 
                FROM pg_trigger t 
                WHERE t.tgrelid = c.oid 
                AND t.tgname = 'audit_trigger'
            ) THEN 'OK'
            ELSE 'MISSING'
        END as status
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE c.relkind = 'r'  -- ordinary tables
    AND n.nspname = 'public'
    AND c.relname IN (
        'profiles', 'restaurants', 'meals', 'orders', 
        'meal_schedules', 'subscriptions', 'customer_wallets',
        'wallet_transactions', 'user_addresses', 'meal_history',
        'meal_reviews', 'notifications', 'drivers', 'delivery_jobs',
        'partner_payouts', 'partner_earnings', 'affiliate_applications',
        'affiliate_commissions', 'support_tickets', 'user_roles',
        'gdpr_export_logs'
    )
    ORDER BY n.nspname, c.relname;
END;
$$;


ALTER FUNCTION "audit"."verify_audit_coverage"() OWNER TO "postgres";

--
-- Name: FUNCTION "verify_audit_coverage"(); Type: COMMENT; Schema: audit; Owner: postgres
--

COMMENT ON FUNCTION "audit"."verify_audit_coverage"() IS 'Verifies that all critical tables have audit triggers enabled';


--
-- Name: accept_friend_request("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."accept_friend_request"("p_friendship_id" "uuid", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_user_id);
  RETURN public.accept_friend_request_trusted(p_friendship_id, p_user_id);
END;
$$;


ALTER FUNCTION "public"."accept_friend_request"("p_friendship_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: accept_friend_request_trusted("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."accept_friend_request_trusted"("p_friendship_id" "uuid", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_friendship public.friendships%ROWTYPE;
  v_name TEXT;
BEGIN
  IF auth.uid() IS NULL OR auth.uid() <> p_user_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authorized');
  END IF;

  SELECT * INTO v_friendship
  FROM public.friendships
  WHERE id = p_friendship_id
    AND target_id = p_user_id
    AND status = 'pending'
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'No pending request found');
  END IF;

  UPDATE public.friendships SET status = 'accepted', updated_at = now()
  WHERE id = p_friendship_id;

  SELECT COALESCE(full_name, 'Someone') INTO v_name
  FROM public.profiles WHERE user_id = p_user_id;

  INSERT INTO public.notifications (user_id, type, title, message, status, data)
  VALUES (
    v_friendship.requester_id, 'general', 'Friend Request Accepted',
    v_name || ' accepted your friend request!', 'unread',
    jsonb_build_object('friendship_id', p_friendship_id, 'friend_id', p_user_id)
  );

  RETURN jsonb_build_object('success', true, 'message', 'Friend request accepted');
END;
$$;


ALTER FUNCTION "public"."accept_friend_request_trusted"("p_friendship_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

