--
-- Name: add_meal_to_top_meals(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."add_meal_to_top_meals"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
    -- Insert or update the meal in user's top meals
    INSERT INTO public.user_top_meals (user_id, meal_id, is_auto_added, order_count, last_ordered_at)
    VALUES (NEW.user_id, NEW.meal_id, TRUE, 1, NEW.created_at)
    ON CONFLICT (user_id, meal_id) 
    DO UPDATE SET
        order_count = public.user_top_meals.order_count + 1,
        last_ordered_at = NEW.created_at,
        is_auto_added = TRUE
    WHERE public.user_top_meals.user_id = NEW.user_id 
      AND public.user_top_meals.meal_id = NEW.meal_id;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."add_meal_to_top_meals"() OWNER TO "postgres";

--
-- Name: add_to_delivery_queue("uuid", integer, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."add_to_delivery_queue"("p_order_id" "uuid", "p_priority_score" integer DEFAULT 50, "p_priority_reason" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_queue_id UUID;
  v_order_record RECORD;
BEGIN
  -- Get order details
  SELECT 
    o.id,
    o.restaurant_id,
    o.delivery_address,
    o.delivery_lat,
    o.delivery_lng,
    o.estimated_delivery_time,
    o.delivery_fee,
    o.tip_amount
  INTO v_order_record
  FROM public.orders o
  WHERE o.id = p_order_id;
  
  IF v_order_record IS NULL THEN
    RAISE EXCEPTION 'Order not found: %', p_order_id;
  END IF;
  
  -- Insert into queue
  INSERT INTO public.delivery_queue (
    order_id,
    restaurant_id,
    status,
    priority_score,
    priority_reason,
    delivery_address,
    delivery_lat,
    delivery_lng,
    estimated_delivery_time,
    delivery_fee,
    tip_amount,
    expires_at
  ) VALUES (
    p_order_id,
    v_order_record.restaurant_id,
    'waiting',
    p_priority_score,
    p_priority_reason,
    v_order_record.delivery_address,
    v_order_record.delivery_lat,
    v_order_record.delivery_lng,
    v_order_record.estimated_delivery_time,
    COALESCE(v_order_record.delivery_fee, 3.00),
    COALESCE(v_order_record.tip_amount, 0),
    now() + interval '30 minutes'
  )
  RETURNING id INTO v_queue_id;
  
  RETURN v_queue_id;
END;
$$;


ALTER FUNCTION "public"."add_to_delivery_queue"("p_order_id" "uuid", "p_priority_score" integer, "p_priority_reason" "text") OWNER TO "postgres";

--
-- Name: adherence_daily_value("uuid", "text", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."adherence_daily_value"("p_user_id" "uuid", "p_metric" "text", "p_day" "date") RETURNS numeric
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  SELECT CASE p_metric
    WHEN 'meal_logging' THEN (
      SELECT count(DISTINCT mh.id)::NUMERIC
      FROM public.meal_history mh
      WHERE mh.user_id = p_user_id
        AND mh.logged_at >= (p_day::TIMESTAMP AT TIME ZONE 'Asia/Qatar')
        AND mh.logged_at < ((p_day + 1)::TIMESTAMP AT TIME ZONE 'Asia/Qatar')
    )
    WHEN 'activity' THEN (
      SELECT coalesce(sum(greatest(coalesce(ws.duration_minutes, 0), 0)), 0)::NUMERIC
      FROM public.workout_sessions ws
      WHERE ws.user_id = p_user_id AND ws.session_date = p_day
    )
    WHEN 'water' THEN (
      SELECT coalesce(sum(greatest(coalesce(we.amount_ml, 0), 0)), 0)::NUMERIC
      FROM public.water_entries we
      WHERE we.user_id = p_user_id AND we.log_date = p_day
    )
    ELSE 0::NUMERIC
  END;
$$;


ALTER FUNCTION "public"."adherence_daily_value"("p_user_id" "uuid", "p_metric" "text", "p_day" "date") OWNER TO "postgres";

--
-- Name: admin_cancel_meal_schedule("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."admin_cancel_meal_schedule"("p_schedule_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id UUID; v_schedule RECORD; v_restaurant RECORD; v_active_job_count INTEGER;
  v_wallet_id UUID; v_wallet_balance NUMERIC;
  v_cancelled_earnings_count INTEGER; v_cancelled_jobs_count INTEGER;
  v_updated_notifications_count INTEGER;
BEGIN
  v_admin_id := (select auth.uid());
  IF NOT public.has_role(v_admin_id, 'admin') THEN RAISE EXCEPTION 'Unauthorized: only admins can perform this action.'; END IF;
  SELECT ms.id, ms.user_id, ms.order_status, ms.meal_id, ms.addons_total,
         m.name AS meal_name, m.restaurant_id
  INTO v_schedule FROM meal_schedules ms LEFT JOIN meals m ON m.id = ms.meal_id WHERE ms.id = p_schedule_id
  FOR UPDATE OF ms;
  IF NOT FOUND THEN RAISE EXCEPTION 'Order not found.'; END IF;
  IF v_schedule.order_status NOT IN ('pending','confirmed') THEN RAISE EXCEPTION 'Orders in "%" status cannot be cancelled.', v_schedule.order_status; END IF;
  SELECT COUNT(*) INTO v_active_job_count FROM delivery_jobs WHERE schedule_id = p_schedule_id AND status IN ('preparing','ready','out_for_delivery','picked_up');
  IF v_active_job_count > 0 THEN RAISE EXCEPTION 'Cannot cancel: a driver is already preparing or delivering this order.'; END IF;
  UPDATE delivery_jobs SET status = 'cancelled', updated_at = NOW() WHERE schedule_id = p_schedule_id AND status IN ('pending','scheduled','assigned');
  GET DIAGNOSTICS v_cancelled_jobs_count = ROW_COUNT;
  DELETE FROM delivery_queue WHERE metadata->>'schedule_id' = p_schedule_id::TEXT AND status IN ('queued','assigned','accepted');
  UPDATE meal_schedules SET order_status = 'cancelled', cancellation_reason = p_reason, updated_at = NOW() WHERE id = p_schedule_id;
  UPDATE subscriptions SET meals_used_this_month = GREATEST(0, COALESCE(meals_used_this_month,0) - 1), meals_used_this_week = GREATEST(0, COALESCE(meals_used_this_week,0) - 1)
  WHERE user_id = v_schedule.user_id AND status = 'active' AND id = (SELECT id FROM subscriptions WHERE user_id = v_schedule.user_id AND status = 'active' ORDER BY created_at DESC LIMIT 1);
  IF EXISTS (SELECT 1 FROM wallet_transactions wt WHERE wt.user_id = v_schedule.user_id AND wt.type = 'debit' AND wt.description = 'Extra meal credit purchase'
    AND wt.created_at >= (SELECT created_at FROM meal_schedules WHERE id = p_schedule_id) - INTERVAL '1 hour'
    AND wt.created_at <= (SELECT created_at FROM meal_schedules WHERE id = p_schedule_id) + INTERVAL '1 hour') THEN
    UPDATE subscriptions SET meals_per_month = GREATEST(1, COALESCE(meals_per_month,0) - 1)
    WHERE user_id = v_schedule.user_id AND status = 'active' AND id = (SELECT id FROM subscriptions WHERE user_id = v_schedule.user_id AND status = 'active' ORDER BY created_at DESC LIMIT 1);
  END IF;
  IF v_schedule.addons_total IS NOT NULL AND v_schedule.addons_total > 0 THEN
    SELECT id, COALESCE(balance, 0) INTO v_wallet_id, v_wallet_balance FROM customer_wallets WHERE user_id = v_schedule.user_id;
    UPDATE customer_wallets SET balance = COALESCE(balance, 0) + v_schedule.addons_total, total_credits = COALESCE(total_credits, 0) + v_schedule.addons_total, updated_at = NOW() WHERE user_id = v_schedule.user_id;
    INSERT INTO wallet_transactions (wallet_id, user_id, amount, type, reference_type, reference_id, description, balance_after, created_at)
    VALUES (v_wallet_id, v_schedule.user_id, v_schedule.addons_total, 'refund', 'order', p_schedule_id, 'Admin cancellation refund - addons for ' || COALESCE(v_schedule.meal_name, 'meal'), COALESCE(v_wallet_balance, 0) + v_schedule.addons_total, NOW());
  END IF;
  UPDATE partner_earnings SET status = 'cancelled' WHERE meal_schedule_id = p_schedule_id AND status IN ('pending','paid');
  GET DIAGNOSTICS v_cancelled_earnings_count = ROW_COUNT;
  UPDATE notifications SET status = 'read' WHERE user_id = v_schedule.user_id AND type = 'meal_scheduled' AND (data->>'schedule_id')::TEXT = p_schedule_id::TEXT AND status = 'unread';
  GET DIAGNOSTICS v_updated_notifications_count = ROW_COUNT;
  BEGIN
    IF v_schedule.restaurant_id IS NOT NULL THEN
      SELECT id, name, owner_id INTO v_restaurant FROM restaurants WHERE id = v_schedule.restaurant_id;
      IF v_restaurant.owner_id IS NOT NULL THEN
        INSERT INTO notifications (user_id, type, title, message, status, data)
        VALUES (v_restaurant.owner_id, 'order_update', 'Order Cancelled by Admin', 'An admin has cancelled the order for ' || COALESCE(v_schedule.meal_name, 'a meal') || '.', 'unread', jsonb_build_object('schedule_id', p_schedule_id, 'meal_name', COALESCE(v_schedule.meal_name, ''), 'cancelled_by', 'admin'));
      END IF;
    END IF;
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'Failed to notify partner for schedule %: %', p_schedule_id, SQLERRM; END;
  BEGIN
    INSERT INTO notifications (user_id, type, title, message, status, data)
    VALUES (v_schedule.user_id, 'order_update', 'Meal Cancelled by Admin', 'Your scheduled meal for ' || COALESCE(v_schedule.meal_name, 'a meal') || ' has been cancelled by admin. Your meal credit has been refunded.', 'unread', jsonb_build_object('schedule_id', p_schedule_id, 'meal_name', COALESCE(v_schedule.meal_name, ''), 'action', 'cancelled', 'credit_refunded', true, 'cancelled_by', 'admin'));
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'Failed to notify customer for schedule %: %', p_schedule_id, SQLERRM; END;
  RETURN jsonb_build_object('success', true, 'schedule_id', p_schedule_id, 'refunded_addons', COALESCE(v_schedule.addons_total, 0), 'cancelled_earnings', v_cancelled_earnings_count, 'cancelled_jobs', v_cancelled_jobs_count, 'marked_notifications_read', v_updated_notifications_count, 'cancelled_by', 'admin');
END;
$$;


ALTER FUNCTION "public"."admin_cancel_meal_schedule"("p_schedule_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: admin_delete_delivery_surge_rule("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."admin_delete_delivery_surge_rule"("p_rule_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF auth.uid() IS NULL OR NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;

  DELETE FROM public.delivery_surge_rules WHERE id = p_rule_id;
  RETURN FOUND;
END;
