--
-- Name: admin_list_delivery_surge_rules(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."admin_list_delivery_surge_rules"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF auth.uid() IS NULL OR NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;

  RETURN COALESCE((
    SELECT jsonb_agg(to_jsonb(rule) ORDER BY rule.priority DESC, rule.created_at ASC)
    FROM public.delivery_surge_rules rule
  ), '[]'::JSONB);
END;
$$;


