--
-- Name: admin_list_user_ip_logs(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."admin_list_user_ip_logs"() RETURNS TABLE("user_id" "uuid", "ip_address" "text", "country_code" "text", "country_name" "text", "city" "text", "action" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'admin_required' USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  SELECT
    logs.user_id,
    logs.ip_address::TEXT AS ip_address,
    logs.country_code,
    logs.country_name,
    logs.city,
    logs.action,
    logs.created_at
  FROM public.user_ip_logs AS logs
  ORDER BY logs.created_at DESC;
END;
$$;


