--
-- Name: admin_update_order_status("text", "uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."admin_update_order_status"("p_source" "text", "p_order_id" "uuid", "p_new_status" "text", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_order public.orders%ROWTYPE;
  v_target public.order_status;
BEGIN
  IF v_actor IS NULL OR NOT public.has_role(v_actor, 'admin') THEN
    RAISE EXCEPTION 'ADMIN_ACCESS_REQUIRED';
  END IF;

  IF p_source = 'meal_schedule' THEN
    IF p_new_status = 'cancelled' THEN
      RETURN public.admin_cancel_meal_schedule(p_order_id, p_reason);
    END IF;

    PERFORM public.update_order_status(p_order_id, p_new_status, 'admin');
    RETURN jsonb_build_object(
      'success', TRUE,
      'source', 'meal_schedule',
      'order_id', p_order_id,
      'status', p_new_status
    );
  END IF;

  IF p_source <> 'order' THEN
    RAISE EXCEPTION 'INVALID_ORDER_SOURCE';
  END IF;

  v_target := p_new_status::public.order_status;
  IF v_target NOT IN ('cancelled', 'completed') THEN
    RAISE EXCEPTION 'ADMIN_STATUS_NOT_SUPPORTED';
  END IF;

  SELECT o.* INTO v_order
  FROM public.orders o
  WHERE o.id = p_order_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'ORDER_NOT_FOUND';
  END IF;

  IF v_target = 'completed' AND v_order.status <> 'delivered' THEN
    RAISE EXCEPTION 'ORDER_MUST_BE_DELIVERED_FIRST';
  END IF;

  IF v_target = 'cancelled'
    AND v_order.status IN ('delivered', 'completed', 'cancelled') THEN
    RAISE EXCEPTION 'ORDER_CANNOT_BE_CANCELLED';
  END IF;

  IF v_target = 'cancelled' THEN
    RETURN public.process_direct_order_cancellation(
      v_order.id,
      v_actor,
      'admin',
      COALESCE(NULLIF(TRIM(p_reason), ''), 'Admin cancellation')
    );
  END IF;

  PERFORM set_config('request.jwt.claim.role', 'service_role', TRUE);

  UPDATE public.delivery_jobs
  SET status = 'cancelled',
      failure_reason = LEFT(COALESCE(NULLIF(TRIM(p_reason), ''), 'Admin cancellation'), 500),
      updated_at = NOW()
  WHERE order_id = v_order.id
    AND v_target = 'cancelled'
    AND status IN ('pending', 'assigned', 'accepted');

  UPDATE public.orders
  SET status = v_target,
      updated_at = NOW()
  WHERE id = v_order.id;

  RETURN jsonb_build_object(
    'success', TRUE,
    'source', 'order',
    'order_id', v_order.id,
    'status', v_target
  );
END;
$$;


ALTER FUNCTION "public"."admin_update_order_status"("p_source" "text", "p_order_id" "uuid", "p_new_status" "text", "p_reason" "text") OWNER TO "postgres";

--
-- Name: admin_update_user_subscription_wallet("uuid", "uuid", "text", "public"."subscription_status", "text", integer, integer, integer, integer, numeric, "date", boolean, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."admin_update_user_subscription_wallet"("p_user_id" "uuid", "p_subscription_id" "uuid" DEFAULT NULL::"uuid", "p_plan" "text" DEFAULT 'monthly'::"text", "p_status" "public"."subscription_status" DEFAULT 'active'::"public"."subscription_status", "p_tier" "text" DEFAULT 'basic'::"text", "p_meals_per_week" integer DEFAULT 0, "p_meals_per_month" integer DEFAULT 0, "p_meals_used_this_week" integer DEFAULT 0, "p_meals_used_this_month" integer DEFAULT 0, "p_price" numeric DEFAULT 0, "p_end_date" "date" DEFAULT NULL::"date", "p_includes_gym" boolean DEFAULT false, "p_wallet_balance" numeric DEFAULT NULL::numeric) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor_id UUID := auth.uid();
  v_subscription_id UUID;
  v_wallet public.customer_wallets%ROWTYPE;
  v_current_balance NUMERIC(10, 2) := 0;
  v_next_balance NUMERIC(10, 2);
  v_delta NUMERIC(10, 2);
  v_transaction_id UUID;
  v_today DATE := CURRENT_DATE;
BEGIN
  IF auth.role() <> 'service_role' AND (
    v_actor_id IS NULL OR NOT EXISTS (
      SELECT 1
      FROM public.user_roles ur
      WHERE ur.user_id = v_actor_id
        AND ur.role IN ('admin', 'staff')
    )
  ) THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;

  IF p_user_id IS NULL THEN
    RAISE EXCEPTION 'USER_REQUIRED';
  END IF;

  IF p_subscription_id IS NULL THEN
    INSERT INTO public.subscriptions (
      user_id,
      plan,
      plan_type,
      status,
      tier,
      meals_per_week,
      meals_per_month,
      meals_used_this_week,
      meals_used_this_month,
      price,
      start_date,
      end_date,
      includes_gym,
      active,
      week_start_date,
      month_start_date,
      updated_at
    ) VALUES (
      p_user_id,
      p_plan,
      p_plan,
      p_status,
      p_tier,
      GREATEST(COALESCE(p_meals_per_week, 0), 0),
      GREATEST(COALESCE(p_meals_per_month, 0), 0),
      GREATEST(COALESCE(p_meals_used_this_week, 0), 0),
      GREATEST(COALESCE(p_meals_used_this_month, 0), 0),
      GREATEST(COALESCE(p_price, 0), 0),
      v_today,
      p_end_date,
      COALESCE(p_includes_gym, FALSE),
      p_status = 'active',
      v_today,
      v_today,
      NOW()
    )
    RETURNING id INTO v_subscription_id;
  ELSE
    UPDATE public.subscriptions
    SET plan = p_plan,
        plan_type = p_plan,
        status = p_status,
        tier = p_tier,
        meals_per_week = GREATEST(COALESCE(p_meals_per_week, 0), 0),
        meals_per_month = GREATEST(COALESCE(p_meals_per_month, 0), 0),
        meals_used_this_week = GREATEST(COALESCE(p_meals_used_this_week, 0), 0),
        meals_used_this_month = GREATEST(COALESCE(p_meals_used_this_month, 0), 0),
        price = GREATEST(COALESCE(p_price, 0), 0),
        end_date = p_end_date,
        includes_gym = COALESCE(p_includes_gym, FALSE),
        active = p_status = 'active',
        week_start_date = COALESCE(week_start_date, v_today),
        month_start_date = COALESCE(month_start_date, v_today),
        updated_at = NOW()
    WHERE id = p_subscription_id
      AND user_id = p_user_id
    RETURNING id INTO v_subscription_id;

    IF v_subscription_id IS NULL THEN
      RAISE EXCEPTION 'SUBSCRIPTION_NOT_FOUND';
    END IF;
  END IF;

  IF p_status = 'active' THEN
    UPDATE public.subscriptions
    SET active = FALSE,
        status = 'expired',
        updated_at = NOW()
    WHERE user_id = p_user_id
      AND id <> v_subscription_id
      AND status = 'active';
  END IF;

  IF p_wallet_balance IS NOT NULL THEN
    v_next_balance := ROUND(GREATEST(COALESCE(p_wallet_balance, 0), 0), 2);

    INSERT INTO public.customer_wallets (user_id, balance, total_credits, total_debits, is_active)
    VALUES (p_user_id, 0, 0, 0, TRUE)
    ON CONFLICT (user_id) DO NOTHING;

    SELECT *
      INTO v_wallet
    FROM public.customer_wallets
    WHERE user_id = p_user_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'WALLET_NOT_FOUND';
    END IF;

    v_current_balance := COALESCE(v_wallet.balance, 0);
    v_delta := ROUND(v_next_balance - v_current_balance, 2);

    UPDATE public.customer_wallets
    SET balance = v_next_balance,
        total_credits = COALESCE(total_credits, 0) + CASE WHEN v_delta > 0 THEN v_delta ELSE 0 END,
        total_debits = COALESCE(total_debits, 0) + CASE WHEN v_delta < 0 THEN ABS(v_delta) ELSE 0 END,
        is_active = TRUE,
        updated_at = NOW()
    WHERE id = v_wallet.id;

    IF ABS(v_delta) >= 0.01 THEN
      INSERT INTO public.wallet_transactions (
        wallet_id,
        user_id,
        type,
        amount,
        balance_after,
        reference_type,
        reference_id,
        description,
        metadata
      ) VALUES (
        v_wallet.id,
        p_user_id,
        'admin_adjustment',
        ABS(v_delta),
        v_next_balance,
        'admin_adjustment',
        v_subscription_id,
        'Admin adjusted wallet balance',
        jsonb_build_object(
          'actor_id', v_actor_id,
          'previous_balance', v_current_balance,
          'new_balance', v_next_balance,
          'delta', v_delta
        )
      )
      RETURNING id INTO v_transaction_id;
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'success', TRUE,
    'subscription_id', v_subscription_id,
    'wallet_balance', COALESCE(v_next_balance, v_current_balance),
    'wallet_transaction_id', v_transaction_id
  );
END;
$$;


ALTER FUNCTION "public"."admin_update_user_subscription_wallet"("p_user_id" "uuid", "p_subscription_id" "uuid", "p_plan" "text", "p_status" "public"."subscription_status", "p_tier" "text", "p_meals_per_week" integer, "p_meals_per_month" integer, "p_meals_used_this_week" integer, "p_meals_used_this_month" integer, "p_price" numeric, "p_end_date" "date", "p_includes_gym" boolean, "p_wallet_balance" numeric) OWNER TO "postgres";

--
-- Name: admin_upsert_delivery_surge_rule("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."admin_upsert_delivery_surge_rule"("p_rule" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_id UUID := NULLIF(p_rule ->> 'id', '')::UUID;
  v_rule public.delivery_surge_rules%ROWTYPE;
  v_days SMALLINT[] := ARRAY(
    SELECT value::SMALLINT
    FROM jsonb_array_elements_text(COALESCE(p_rule -> 'days_of_week', '[]'::JSONB)) value
  );
  v_cities TEXT[] := ARRAY(
    SELECT TRIM(value)
    FROM jsonb_array_elements_text(COALESCE(p_rule -> 'cities', '[]'::JSONB)) value
    WHERE NULLIF(TRIM(value), '') IS NOT NULL
  );
BEGIN
  IF auth.uid() IS NULL OR NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;

  IF v_id IS NULL THEN
    INSERT INTO public.delivery_surge_rules (
      name, description, enabled, priority, days_of_week, start_time, end_time,
      cities, demand_threshold, multiplier, flat_surcharge, max_surcharge,
      customer_message, effective_from, effective_until, created_by
    ) VALUES (
      TRIM(COALESCE(p_rule ->> 'name', 'New pricing rule')),
      NULLIF(TRIM(p_rule ->> 'description'), ''),
      COALESCE((p_rule ->> 'enabled')::BOOLEAN, FALSE),
      COALESCE((p_rule ->> 'priority')::INTEGER, 100),
      v_days,
      NULLIF(p_rule ->> 'start_time', '')::TIME,
      NULLIF(p_rule ->> 'end_time', '')::TIME,
      v_cities,
      COALESCE((p_rule ->> 'demand_threshold')::INTEGER, 0),
      COALESCE((p_rule ->> 'multiplier')::NUMERIC, 1),
      COALESCE((p_rule ->> 'flat_surcharge')::NUMERIC, 0),
      COALESCE((p_rule ->> 'max_surcharge')::NUMERIC, 25),
      TRIM(COALESCE(p_rule ->> 'customer_message', 'Higher demand applies for this delivery window.')),
      NULLIF(p_rule ->> 'effective_from', '')::TIMESTAMPTZ,
      NULLIF(p_rule ->> 'effective_until', '')::TIMESTAMPTZ,
      auth.uid()
    ) RETURNING * INTO v_rule;
  ELSE
    UPDATE public.delivery_surge_rules SET
      name = TRIM(COALESCE(p_rule ->> 'name', name)),
      description = NULLIF(TRIM(p_rule ->> 'description'), ''),
      enabled = COALESCE((p_rule ->> 'enabled')::BOOLEAN, enabled),
      priority = COALESCE((p_rule ->> 'priority')::INTEGER, priority),
      days_of_week = v_days,
      start_time = NULLIF(p_rule ->> 'start_time', '')::TIME,
      end_time = NULLIF(p_rule ->> 'end_time', '')::TIME,
      cities = v_cities,
      demand_threshold = COALESCE((p_rule ->> 'demand_threshold')::INTEGER, demand_threshold),
      multiplier = COALESCE((p_rule ->> 'multiplier')::NUMERIC, multiplier),
      flat_surcharge = COALESCE((p_rule ->> 'flat_surcharge')::NUMERIC, flat_surcharge),
      max_surcharge = COALESCE((p_rule ->> 'max_surcharge')::NUMERIC, max_surcharge),
      customer_message = TRIM(COALESCE(p_rule ->> 'customer_message', customer_message)),
      effective_from = NULLIF(p_rule ->> 'effective_from', '')::TIMESTAMPTZ,
      effective_until = NULLIF(p_rule ->> 'effective_until', '')::TIMESTAMPTZ,
      updated_at = now()
    WHERE id = v_id
    RETURNING * INTO v_rule;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'SURGE_RULE_NOT_FOUND';
    END IF;
  END IF;

  RETURN to_jsonb(v_rule);
END;
$$;


ALTER FUNCTION "public"."admin_upsert_delivery_surge_rule"("p_rule" "jsonb") OWNER TO "postgres";

--
-- Name: apply_community_challenge_progress("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."apply_community_challenge_progress"("p_user_id" "uuid", "p_challenge_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_participant public.challenge_participants%ROWTYPE;
  v_challenge public.community_challenges%ROWTYPE;
  v_progress INTEGER;
  v_new_progress INTEGER;
  v_reward_version INTEGER;
  v_reward_source TEXT;
  v_reward_amount INTEGER;
  v_xp_result JSONB := NULL;
  v_wallet_result JSONB := NULL;
  v_qatar_today DATE := (now() AT TIME ZONE 'Asia/Qatar')::DATE;
  v_can_award BOOLEAN := false;
  v_has_wallet_settlement BOOLEAN := false;
BEGIN
  SELECT * INTO v_participant
  FROM public.challenge_participants
  WHERE challenge_id = p_challenge_id AND user_id = p_user_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not participating in this challenge');
  END IF;

  SELECT * INTO v_challenge
  FROM public.community_challenges
  WHERE id = p_challenge_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Challenge not found');
  END IF;

  v_progress := public.calculate_community_challenge_progress(p_user_id, p_challenge_id);
  v_new_progress := least(greatest(v_progress, 0), greatest(coalesce(v_challenge.target_value, 0), 0));
  v_can_award := v_challenge.target_value > 0
    AND v_challenge.start_date <= v_qatar_today
    AND (coalesce(v_challenge.is_active, false) OR v_challenge.end_date < v_qatar_today);

  IF v_can_award
     AND v_new_progress >= v_challenge.target_value
     AND v_participant.completed_at IS NULL THEN
    v_reward_version := greatest(v_participant.completion_version, 0) + 1;
    v_reward_source := p_challenge_id::TEXT || ':v' || v_reward_version;
    v_reward_amount := greatest(coalesce(v_challenge.xp_reward, v_challenge.reward_points, 100), 0);

    IF v_reward_amount > 0 THEN
      v_xp_result := public.award_xp(
        p_user_id,
        v_reward_amount,
        'Community challenge completed: ' || coalesce(v_challenge.title, 'Challenge'),
        'community_challenge_complete',
        v_reward_source,
        jsonb_build_object('challenge_id', p_challenge_id, 'completion_version', v_reward_version)
      );
    END IF;

    v_wallet_result := public.grant_community_challenge_wallet_reward(
      p_user_id,
      p_challenge_id,
      v_participant.id,
      v_reward_version,
      v_reward_source,
      coalesce(v_challenge.wallet_reward_amount, 0),
      v_challenge.title
    );

    UPDATE public.challenge_participants
    SET current_progress = v_new_progress,
        completed_at = now(),
        completion_version = v_reward_version,
        reward_source_id = v_reward_source,
        reward_xp_amount = v_reward_amount,
        reward_reversed_at = NULL,
        reward_settlement_finalized_at = CASE
          WHEN v_challenge.end_date < v_qatar_today THEN now()
          ELSE reward_settlement_finalized_at
        END,
        updated_at = now()
    WHERE id = v_participant.id;

  ELSIF v_new_progress >= v_challenge.target_value
     AND v_participant.completed_at IS NOT NULL THEN
    SELECT EXISTS (
      SELECT 1
      FROM public.community_challenge_reward_settlements settlement
      WHERE settlement.participant_id = v_participant.id
        AND settlement.completion_version = greatest(v_participant.completion_version, 1)
    ) INTO v_has_wallet_settlement;

    IF NOT v_has_wallet_settlement THEN
      v_wallet_result := public.grant_community_challenge_wallet_reward(
        p_user_id,
        p_challenge_id,
        v_participant.id,
        greatest(v_participant.completion_version, 1),
        coalesce(v_participant.reward_source_id, p_challenge_id::TEXT || ':v1'),
        coalesce(v_challenge.wallet_reward_amount, 0),
        v_challenge.title
      );
    END IF;

    UPDATE public.challenge_participants
    SET current_progress = v_new_progress,
        reward_settlement_finalized_at = CASE
          WHEN v_challenge.end_date < v_qatar_today THEN now()
          ELSE reward_settlement_finalized_at
        END,
        updated_at = now()
    WHERE id = v_participant.id;

  ELSIF (v_challenge.target_value <= 0 OR v_new_progress < v_challenge.target_value)
     AND v_participant.completed_at IS NOT NULL THEN
    IF v_participant.reward_xp_amount > 0 AND v_participant.reward_source_id IS NOT NULL THEN
      v_xp_result := public.award_xp(
        p_user_id,
        -v_participant.reward_xp_amount,
        'Community challenge evidence reversed: ' || coalesce(v_challenge.title, 'Challenge'),
        'community_challenge_reversed',
        v_participant.reward_source_id,
        jsonb_build_object(
          'challenge_id', p_challenge_id,
          'completion_version', v_participant.completion_version,
          'compensates_action', 'community_challenge_complete'
        )
      );
      PERFORM public.rebuild_xp_profile_from_ledger(p_user_id);
    END IF;

    v_wallet_result := public.reverse_community_challenge_wallet_reward(
      p_user_id,
      v_participant.id,
      greatest(v_participant.completion_version, 1),
      'Community challenge evidence reversed: ' || coalesce(v_challenge.title, 'Challenge')
    );

    UPDATE public.challenge_participants
    SET current_progress = v_new_progress,
        completed_at = NULL,
        reward_reversed_at = now(),
        reward_settlement_finalized_at = CASE
          WHEN v_challenge.end_date < v_qatar_today THEN now()
          ELSE reward_settlement_finalized_at
        END,
        updated_at = now()
    WHERE id = v_participant.id;

  ELSE
    UPDATE public.challenge_participants
    SET current_progress = v_new_progress,
        reward_settlement_finalized_at = CASE
          WHEN v_challenge.end_date < v_qatar_today THEN now()
          ELSE reward_settlement_finalized_at
        END,
        updated_at = now()
    WHERE id = v_participant.id;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'completed', v_challenge.target_value > 0 AND v_new_progress >= v_challenge.target_value,
    'progress', v_new_progress,
    'target', v_challenge.target_value,
    'reward_version', coalesce(v_reward_version, v_participant.completion_version),
    'xp', v_xp_result,
    'wallet', v_wallet_result,
    'settlement_finalized', v_challenge.end_date < v_qatar_today,
    'reason_code', CASE lower(coalesce(v_challenge.challenge_type, ''))
      WHEN 'meals' THEN 'verified_meal_logs'
      WHEN 'meal_logging' THEN 'verified_meal_logs'
      WHEN 'activity' THEN 'verified_activity_days'
      WHEN 'workout' THEN 'verified_activity_days'
      WHEN 'water' THEN 'verified_hydration_days'
      WHEN 'hydration' THEN 'verified_hydration_days'
      ELSE 'verified_challenge_evidence'
    END
  );
END;
$$;


ALTER FUNCTION "public"."apply_community_challenge_progress"("p_user_id" "uuid", "p_challenge_id" "uuid") OWNER TO "postgres";

--
-- Name: apply_dynamic_delivery_fee(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."apply_dynamic_delivery_fee"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_quote_id UUID;
  v_quote public.delivery_fee_quotes%ROWTYPE;
  v_breakdown JSONB;
  v_is_secondary BOOLEAN := FALSE;
BEGIN
  IF TG_OP = 'UPDATE'
    AND OLD.scheduled_date IS NOT DISTINCT FROM NEW.scheduled_date
    AND OLD.delivery_time_slot IS NOT DISTINCT FROM NEW.delivery_time_slot
    AND OLD.delivery_address_id IS NOT DISTINCT FROM NEW.delivery_address_id
    AND OLD.delivery_type IS NOT DISTINCT FROM NEW.delivery_type
    AND OLD.customization_data IS NOT DISTINCT FROM NEW.customization_data THEN
    RETURN NEW;
  END IF;

  v_quote_id := NULLIF(NEW.customization_data ->> '_delivery_quote_id', '')::UUID;
  NEW.customization_data := COALESCE(NEW.customization_data, '{}'::JSONB) - '_delivery_quote_id';

  IF NEW.delivery_address_id IS NULL OR NULLIF(TRIM(NEW.delivery_time_slot), '') IS NULL THEN
    NEW.delivery_fee := 0;
    NEW.delivery_fee_base := 0;
    NEW.delivery_fee_surge := 0;
    NEW.delivery_fee_rule_id := NULL;
    NEW.delivery_fee_quote_id := NULL;
    NEW.delivery_fee_context := jsonb_build_object('message', 'Delivery details are incomplete.');
    NEW.delivery_fee_calculated_at := now();
    RETURN NEW;
  END IF;

  IF TG_OP = 'INSERT' AND NEW.request_batch_id IS NOT NULL THEN
    SELECT EXISTS (
      SELECT 1
      FROM public.meal_schedules existing
      WHERE existing.user_id = NEW.user_id
        AND existing.request_batch_id = NEW.request_batch_id
        AND existing.scheduled_date = NEW.scheduled_date
        AND existing.delivery_time_slot = NEW.delivery_time_slot
        AND existing.delivery_address_id = NEW.delivery_address_id
    ) INTO v_is_secondary;
  END IF;

  IF v_is_secondary THEN
    NEW.delivery_fee := 0;
    NEW.delivery_fee_base := 0;
    NEW.delivery_fee_surge := 0;
    NEW.delivery_fee_rule_id := NULL;
    NEW.delivery_fee_quote_id := v_quote_id;
    NEW.delivery_fee_group_primary := FALSE;
    NEW.delivery_fee_context := jsonb_build_object(
      'message', 'Combined with another delivery in this booking.',
      'request_batch_id', NEW.request_batch_id
    );
    NEW.delivery_fee_calculated_at := now();
    RETURN NEW;
  END IF;

  IF v_quote_id IS NOT NULL THEN
    SELECT * INTO v_quote
    FROM public.delivery_fee_quotes quote
    WHERE quote.id = v_quote_id
      AND quote.user_id = NEW.user_id
      AND quote.scheduled_date = NEW.scheduled_date
      AND quote.delivery_time_slot = NEW.delivery_time_slot
      AND quote.delivery_address_id = NEW.delivery_address_id
      AND quote.expires_at > now()
      AND quote.consumed_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'DELIVERY_QUOTE_INVALID_OR_EXPIRED';
    END IF;

    NEW.delivery_fee := v_quote.total_fee;
    NEW.delivery_fee_base := v_quote.base_fee;
    NEW.delivery_fee_surge := v_quote.surge_fee;
    NEW.delivery_fee_rule_id := v_quote.rule_id;
    NEW.delivery_fee_quote_id := v_quote.id;
    NEW.delivery_fee_context := v_quote.pricing_context;
    UPDATE public.delivery_fee_quotes SET consumed_at = now() WHERE id = v_quote.id;
  ELSE
    v_breakdown := public.calculate_delivery_fee_breakdown(
      NEW.user_id,
      NEW.scheduled_date,
      NEW.delivery_time_slot,
      NEW.delivery_address_id,
      CASE WHEN NEW.delivery_type = 'express' THEN 'express' ELSE 'standard' END,
      COALESCE(NEW.addons_total, 0)
    );
    NEW.delivery_fee := COALESCE((v_breakdown ->> 'total_fee')::NUMERIC, 0);
    NEW.delivery_fee_base := COALESCE((v_breakdown ->> 'base_fee')::NUMERIC, 0);
    NEW.delivery_fee_surge := COALESCE((v_breakdown ->> 'surge_fee')::NUMERIC, 0);
    NEW.delivery_fee_rule_id := NULLIF(v_breakdown ->> 'rule_id', '')::UUID;
    NEW.delivery_fee_quote_id := NULL;
    NEW.delivery_fee_context := v_breakdown;
  END IF;

  NEW.delivery_fee_group_primary := TRUE;
  NEW.delivery_fee_calculated_at := now();
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."apply_dynamic_delivery_fee"() OWNER TO "postgres";

--
-- Name: apply_meal_nutrition_quality(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."apply_meal_nutrition_quality"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_result JSONB;
BEGIN
  v_result := public.calculate_nutrient_completeness(jsonb_build_object(
    'calories', NEW.calories,
    'protein_g', NEW.protein_g,
    'carbs_g', NEW.carbs_g,
    'fat_g', NEW.fat_g,
    'fiber_g', NEW.fiber_g,
    'sugar_g', NEW.sugar_g,
    'sodium_mg', NEW.sodium_mg
  ));

  NEW.nutrient_completeness_score := COALESCE((v_result ->> 'score')::INTEGER, 0);
  NEW.nutrient_missing_codes := COALESCE(
    ARRAY(SELECT jsonb_array_elements_text(v_result -> 'missing_codes')),
    ARRAY[]::TEXT[]
  );
  NEW.nutrient_invalid_codes := COALESCE(
    ARRAY(SELECT jsonb_array_elements_text(v_result -> 'invalid_codes')),
    ARRAY[]::TEXT[]
  );
  NEW.nutrition_version := GREATEST(COALESCE(NEW.nutrition_version, 1), 1);
  NEW.nutrition_provenance := COALESCE(NEW.nutrition_provenance, '{}'::JSONB)
    || jsonb_build_object(
      'version', NEW.nutrition_version,
      'captured_at', NOW(),
      'source', COALESCE(NEW.nutrition_provenance ->> 'source', 'partner_entered')
    );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."apply_meal_nutrition_quality"() OWNER TO "postgres";

--
-- Name: apply_recovery_offer("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."apply_recovery_offer"("p_subscription_id" "uuid", "p_offer_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sub public.subscriptions%ROWTYPE;
  v_offer public.recovery_offers%ROWTYPE;
  v_plan public.subscription_plans%ROWTYPE;
BEGIN
  SELECT * INTO v_sub FROM public.subscriptions
  WHERE id = p_subscription_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'Subscription not found'); END IF;
  IF auth.uid() IS NULL OR v_sub.user_id <> auth.uid() THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authorized');
  END IF;

  SELECT * INTO v_offer FROM public.recovery_offers
  WHERE id = p_offer_id AND is_active;
  IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'Offer not found or inactive'); END IF;

  SELECT * INTO v_plan FROM public.subscription_plans
  WHERE tier = COALESCE(v_offer.target_tier, v_sub.tier)
    AND is_active
  ORDER BY CASE WHEN billing_interval = COALESCE(v_sub.billing_interval, 'monthly') THEN 0 ELSE 1 END,
    price_qar
  LIMIT 1;

  UPDATE public.subscriptions
  SET status = 'active', active = true, expired_at = NULL,
      tier = COALESCE(v_offer.target_tier, tier),
      plan = COALESCE(v_offer.target_tier, plan),
      start_date = CURRENT_DATE,
      end_date = CURRENT_DATE + GREATEST(COALESCE(v_offer.free_days, 30), 1),
      next_renewal_date = CURRENT_DATE + 30,
      meals_per_month = COALESCE(v_plan.meals_per_month, meals_per_month, 0)
        + COALESCE(v_offer.bonus_credits, 0),
      meals_used_this_month = 0, meals_used_this_week = 0,
      week_start_date = CURRENT_DATE, month_start_date = CURRENT_DATE,
      current_discount_percent = COALESCE(v_offer.discount_percent, 0),
      discount_expires_at = CASE WHEN COALESCE(v_offer.discount_percent, 0) > 0
        THEN CURRENT_DATE + GREATEST(COALESCE(v_offer.discount_duration_months, 1), 1) * 30
        ELSE NULL END,
      updated_at = now()
  WHERE id = p_subscription_id;

  UPDATE public.subscription_recovery
  SET recovery_status = 'reactivated', accepted_offer_id = v_offer.id,
      accepted_at = now(), reactivated_at = now(),
      reactivation_tier = COALESCE(v_offer.target_tier, v_sub.tier),
      new_subscription_id = p_subscription_id,
      conversion_value_qar = COALESCE(v_plan.price_qar, 0), updated_at = now()
  WHERE user_id = v_sub.user_id
    AND subscription_id = p_subscription_id
    AND recovery_status IN ('pending', 'offer_viewed', 'offer_accepted');

  INSERT INTO public.retention_audit_logs
    (user_id, subscription_id, action_type, action_details, triggered_by, triggered_by_user_id)
  VALUES
    (v_sub.user_id, p_subscription_id, 'subscription_renewed',
     jsonb_build_object('action', 'recovery_reactivation', 'offer_id', v_offer.id,
       'offer_type', v_offer.offer_type), 'user', auth.uid());

  RETURN jsonb_build_object('success', true, 'message', 'Recovery offer applied');
END;
$$;


ALTER FUNCTION "public"."apply_recovery_offer"("p_subscription_id" "uuid", "p_offer_id" "uuid") OWNER TO "postgres";

--
-- Name: assert_self_or_admin("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."assert_self_or_admin"("p_user_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF auth.role() <> 'service_role'
     AND (auth.uid() IS NULL OR (auth.uid() <> p_user_id AND NOT public.has_role(auth.uid(), 'admin'::public.app_role))) THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;
END;
$$;


ALTER FUNCTION "public"."assert_self_or_admin"("p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: assign_driver_to_queue("uuid", "uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."assign_driver_to_queue"("p_queue_id" "uuid", "p_driver_id" "uuid", "p_expiry_minutes" integer DEFAULT 5) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_queue_record RECORD;
BEGIN
  -- Get queue item
  SELECT * INTO v_queue_record
  FROM public.delivery_queue
  WHERE id = p_queue_id
  FOR UPDATE;
  
  IF v_queue_record IS NULL THEN
    RAISE EXCEPTION 'Queue item not found: %', p_queue_id;
  END IF;
  
  IF v_queue_record.status != 'waiting' THEN
    RAISE EXCEPTION 'Queue item is not waiting: %', v_queue_record.status;
  END IF;
  
  -- Update queue item
  UPDATE public.delivery_queue
  SET 
    status = 'assigned',
    assigned_driver_id = p_driver_id,
    previous_driver_ids = array_append(previous_driver_ids, p_driver_id),
    assignment_attempts = assignment_attempts + 1,
    assigned_at = now(),
    expires_at = now() + (p_expiry_minutes || ' minutes')::interval,
    updated_at = now()
  WHERE id = p_queue_id;
  
  -- Also update the order
  UPDATE public.orders
  SET 
    driver_id = p_driver_id,
    status = 'driver_assigned',
    updated_at = now()
  WHERE id = v_queue_record.order_id;
  
  RETURN true;
END;
$$;


ALTER FUNCTION "public"."assign_driver_to_queue"("p_queue_id" "uuid", "p_driver_id" "uuid", "p_expiry_minutes" integer) OWNER TO "postgres";

--
-- Name: assign_driver_with_lock("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."assign_driver_with_lock"("p_job_id" "uuid", "p_driver_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_job_record RECORD;
    v_driver_record RECORD;
    v_result JSONB;
    v_lock_key BIGINT;
    v_uuid_clean TEXT;
BEGIN
    -- Remove hyphens from UUID and take first 16 chars for lock key
    v_uuid_clean := REPLACE(p_job_id::text, '-', '');
    
    -- Convert to bigint for advisory lock (using first 16 hex chars)
    v_lock_key := ('x' || LEFT(v_uuid_clean, 16))::bit(64)::bigint;

    IF NOT pg_try_advisory_xact_lock(v_lock_key) THEN
        RETURN jsonb_build_object('success', false, 'error', 'Job is currently being processed', 'code', 'LOCKED', 'job_id', p_job_id);
    END IF;

    SELECT * INTO v_job_record
    FROM delivery_jobs
    WHERE id = p_job_id
    FOR UPDATE SKIP LOCKED;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Delivery job not found', 'code', 'NOT_FOUND');
    END IF;

    IF v_job_record.driver_id IS NOT NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Job already assigned', 'code', 'ALREADY_ASSIGNED', 'assigned_driver_id', v_job_record.driver_id);
    END IF;

    IF v_job_record.status NOT IN ('pending', 'ready_for_pickup') THEN
        RETURN jsonb_build_object('success', false, 'error', 'Job not in assignable state: ' || v_job_record.status, 'code', 'INVALID_STATE');
    END IF;

    SELECT * INTO v_driver_record
    FROM drivers
    WHERE id = p_driver_id AND is_online = true AND is_active = true
    FOR UPDATE SKIP LOCKED;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Driver not available', 'code', 'DRIVER_UNAVAILABLE');
    END IF;

    IF EXISTS (SELECT 1 FROM delivery_jobs WHERE driver_id = p_driver_id AND status IN ('assigned', 'picked_up', 'in_transit') AND id != p_job_id) THEN
        RETURN jsonb_build_object('success', false, 'error', 'Driver already assigned to active job', 'code', 'DRIVER_BUSY');
    END IF;

    BEGIN
        UPDATE delivery_jobs
        SET driver_id = p_driver_id, status = 'assigned', assigned_at = NOW(),
            assignment_attempted_at = NOW(), updated_at = NOW()
        WHERE id = p_job_id;

        UPDATE drivers
        SET current_job_id = p_job_id, updated_at = NOW()
        WHERE id = p_driver_id;

        SELECT jsonb_build_object('success', true, 'job_id', p_job_id, 'driver_id', p_driver_id, 'status', 'assigned', 'assigned_at', NOW()) INTO v_result;
        RETURN v_result;

    EXCEPTION WHEN OTHERS THEN
        RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'code', SQLSTATE);
    END;
END;
$$;


ALTER FUNCTION "public"."assign_driver_with_lock"("p_job_id" "uuid", "p_driver_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "assign_driver_with_lock"("p_job_id" "uuid", "p_driver_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."assign_driver_with_lock"("p_job_id" "uuid", "p_driver_id" "uuid") IS 'Atomically assigns a driver to a delivery job with advisory locking. Fixed to properly handle UUID format with hyphens.';


--
-- Name: authenticate_partner_api_request("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."authenticate_partner_api_request"("p_api_key" "uuid", "p_api_secret" "text") RETURNS TABLE("partner_id" "uuid", "name" "text", "permissions" "jsonb", "rate_limit" integer, "authenticated" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_partner RECORD;
    v_secret_hash TEXT;
BEGIN
    -- Look up partner by API key
    SELECT * INTO v_partner
    FROM partners
    WHERE api_key = p_api_key
    AND status = 'active';
    
    IF v_partner IS NULL THEN
        RETURN QUERY SELECT NULL::UUID, NULL::TEXT, NULL::JSONB, NULL::INTEGER, FALSE;
        RETURN;
    END IF;
    
    -- Verify secret
    IF NOT security.verify_api_secret(p_api_secret, v_partner.api_secret_hash) THEN
        -- Log failed authentication attempt
        INSERT INTO security.api_auth_failures (partner_id, attempted_at, ip_address)
        VALUES (v_partner.id, now(), inet_client_addr());
        
        RETURN QUERY SELECT NULL::UUID, NULL::TEXT, NULL::JSONB, NULL::INTEGER, FALSE;
        RETURN;
    END IF;
    
    -- Update last used timestamp
    UPDATE partners
    SET last_used_at = now()
    WHERE id = v_partner.id;
    
    RETURN QUERY SELECT 
        v_partner.id,
        v_partner.name,
        v_partner.permissions,
        v_partner.rate_limit,
        TRUE;
END;
$$;


ALTER FUNCTION "public"."authenticate_partner_api_request"("p_api_key" "uuid", "p_api_secret" "text") OWNER TO "postgres";

--
-- Name: auto_rotate_api_keys(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."auto_rotate_api_keys"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_count INTEGER := 0;
    v_partner RECORD;
    v_new_secret TEXT;
BEGIN
    -- Find partners with keys due for rotation
    FOR v_partner IN 
        SELECT id 
        FROM partners 
        WHERE rotation_due_at < now()
        AND status = 'active'
    LOOP
        -- Generate new credentials (secret only, keep same API key)
        v_new_secret := encode(gen_random_bytes(32), 'hex');
        
        UPDATE partners
        SET 
            api_secret_hash = (SELECT hash FROM security.hash_api_secret(v_new_secret)),
            api_secret_salt = (SELECT salt FROM security.hash_api_secret(v_new_secret)),
            last_rotated_at = now(),
            rotation_due_at = now() + INTERVAL '90 days',
            updated_at = now()
        WHERE id = v_partner.id;
        
        -- Log rotation event
        INSERT INTO security.api_key_rotation_log (partner_id, rotated_at, auto_rotated)
        VALUES (v_partner.id, now(), TRUE);
        
        v_count := v_count + 1;
    END LOOP;
    
    RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."auto_rotate_api_keys"() OWNER TO "postgres";

--
-- Name: auto_select_branch_on_schedule(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."auto_select_branch_on_schedule"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_nearest_branch_id UUID;
BEGIN
  -- Only process if restaurant_branch_id is not already set
  IF NEW.restaurant_branch_id IS NULL THEN
    v_nearest_branch_id := public.select_nearest_branch_for_meal(
      NEW.meal_id,
      NEW.user_id,
      NEW.delivery_address_id
    );
    
    -- Only set if a branch was found
    IF v_nearest_branch_id IS NOT NULL THEN
      NEW.restaurant_branch_id := v_nearest_branch_id;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


