--
-- Name: award_xp("uuid", integer, "text", "text", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."award_xp"("p_user_id" "uuid", "p_xp_amount" integer, "p_reason" "text" DEFAULT 'Activity'::"text", "p_action_type" "text" DEFAULT 'activity'::"text", "p_source_id" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_current_xp INTEGER;
  v_current_level INTEGER;
  v_new_xp INTEGER;
  v_new_level INTEGER;
  v_xp_to_next INTEGER;
  v_leveled_up BOOLEAN := false;
  v_transaction_id UUID;
  v_progress_rewards JSONB;
BEGIN
  SELECT COALESCE(xp, 0), COALESCE(level, 1)
  INTO v_current_xp, v_current_level
  FROM public.profiles
  WHERE user_id = p_user_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User profile not found');
  END IF;

  INSERT INTO public.xp_transactions (
    user_id,
    action_type,
    source_id,
    xp_amount,
    reason,
    metadata
  )
  VALUES (
    p_user_id,
    p_action_type,
    p_source_id,
    p_xp_amount,
    p_reason,
    COALESCE(p_metadata, '{}'::jsonb)
  )
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_transaction_id;

  IF v_transaction_id IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'duplicate', true,
      'xp_awarded', 0,
      'total_xp', v_current_xp,
      'new_level', v_current_level,
      'leveled_up', false,
      'reason', p_reason
    );
  END IF;

  v_new_xp := GREATEST(0, v_current_xp + p_xp_amount);
  v_new_level := v_current_level;
  v_xp_to_next := GREATEST(100, v_new_level * 100);

  WHILE v_new_xp >= v_xp_to_next LOOP
    v_new_xp := v_new_xp - v_xp_to_next;
    v_new_level := v_new_level + 1;
    v_xp_to_next := GREATEST(100, v_new_level * 100);
    v_leveled_up := true;
  END LOOP;

  WHILE v_new_xp < 0 AND v_new_level > 1 LOOP
    v_new_level := v_new_level - 1;
    v_xp_to_next := GREATEST(100, v_new_level * 100);
    v_new_xp := v_new_xp + v_xp_to_next;
  END LOOP;

  UPDATE public.profiles
  SET
    xp = v_new_xp,
    level = v_new_level,
    updated_at = now()
  WHERE user_id = p_user_id;

  v_progress_rewards := public.grant_progress_rewards(p_user_id);

  RETURN jsonb_build_object(
    'success', true,
    'transaction_id', v_transaction_id,
    'xp_awarded', p_xp_amount,
    'total_xp', v_new_xp,
    'new_level', v_new_level,
    'leveled_up', v_leveled_up,
    'xp_to_next_level', v_xp_to_next - v_new_xp,
    'reason', p_reason,
    'rewards', v_progress_rewards
  );
END;
$$;


ALTER FUNCTION "public"."award_xp"("p_user_id" "uuid", "p_xp_amount" integer, "p_reason" "text", "p_action_type" "text", "p_source_id" "text", "p_metadata" "jsonb") OWNER TO "postgres";

