--
-- Name: book_recovery_session("uuid", "uuid", "text", integer, "date", time without time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."book_recovery_session"("p_user_id" "uuid", "p_partner_id" "uuid", "p_service_name" "text", "p_credits_used" integer, "p_booking_date" "date", "p_booking_time" time without time zone) RETURNS json
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_booking_id uuid;
  v_qr_code text;
  v_remaining int;
BEGIN
  -- Check credits first
  SELECT total_credits - used_credits INTO v_remaining
  FROM member_recovery_credits
  WHERE user_id = p_user_id 
    AND period_start = date_trunc('month', CURRENT_DATE)::date;
  
  IF v_remaining IS NULL OR v_remaining < p_credits_used THEN
    RAISE EXCEPTION 'Insufficient credits. Available: %, Required: %', 
      COALESCE(v_remaining, 0), p_credits_used;
  END IF;
  
  -- Generate QR code
  v_qr_code := 'NR-' || EXTRACT(EPOCH FROM NOW())::bigint::text || '-' || 
    SUBSTR(MD5(RANDOM()::text), 1, 6)::text;
  
  -- Create booking
  INSERT INTO recovery_bookings (
    user_id, partner_id, service_name, credits_used, 
    booking_date, booking_time, qr_code, status
  ) VALUES (
    p_user_id, p_partner_id, p_service_name, p_credits_used,
    p_booking_date, p_booking_time, v_qr_code, 'booked'
  ) RETURNING id INTO v_booking_id;
  
  -- Update credits
  UPDATE member_recovery_credits
  SET used_credits = used_credits + p_credits_used
  WHERE user_id = p_user_id 
    AND period_start = date_trunc('month', CURRENT_DATE)::date;
  
  RETURN json_build_object(
    'id', v_booking_id,
    'qr_code', v_qr_code,
    'partner_id', p_partner_id,
    'service_name', p_service_name,
    'credits_used', p_credits_used,
    'booking_date', p_booking_date,
    'booking_time', p_booking_time
  );
END;
$$;


ALTER FUNCTION "public"."book_recovery_session"("p_user_id" "uuid", "p_partner_id" "uuid", "p_service_name" "text", "p_credits_used" integer, "p_booking_date" "date", "p_booking_time" time without time zone) OWNER TO "postgres";

--
-- Name: calculate_affiliate_commissions(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_affiliate_commissions"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_profile RECORD;
  v_settings JSONB;
  v_referrers UUID[];
  v_rates NUMERIC[];
  v_index INTEGER;
  v_amount NUMERIC(10, 2);
  v_inserted_id UUID;
  v_commission RECORD;
BEGIN
  IF NEW.status::TEXT = 'delivered'
    AND (TG_OP = 'INSERT' OR OLD.status::TEXT IS DISTINCT FROM 'delivered') THEN
    SELECT tier1_referrer_id, tier2_referrer_id, tier3_referrer_id
    INTO v_profile
    FROM public.profiles
    WHERE user_id = NEW.user_id;

    SELECT value
    INTO v_settings
    FROM public.platform_settings
    WHERE key = 'affiliate_settings'
    ORDER BY updated_at DESC
    LIMIT 1;

    IF NOT COALESCE((v_settings ->> 'enabled')::BOOLEAN, FALSE) THEN
      RETURN NEW;
    END IF;

    v_referrers := ARRAY[
      v_profile.tier1_referrer_id,
      v_profile.tier2_referrer_id,
      v_profile.tier3_referrer_id
    ];
    v_rates := ARRAY[
      COALESCE((v_settings ->> 'tier1_commission')::NUMERIC, 10),
      COALESCE((v_settings ->> 'tier2_commission')::NUMERIC, 5),
      COALESCE((v_settings ->> 'tier3_commission')::NUMERIC, 2)
    ];

    FOR v_index IN 1..3 LOOP
      IF v_referrers[v_index] IS NULL THEN
        CONTINUE;
      END IF;

      v_amount := ROUND(COALESCE(NEW.total_amount, 0) * v_rates[v_index] / 100, 2);
      IF v_amount <= 0 THEN
        CONTINUE;
      END IF;

      v_inserted_id := NULL;

      UPDATE public.affiliate_commissions ac
      SET status = 'approved'
      WHERE ac.order_id = NEW.id
        AND ac.tier = v_index
        AND ac.user_id = v_referrers[v_index]
        AND ac.status = 'pending'
      RETURNING ac.id, ac.commission_amount
      INTO v_inserted_id, v_amount;

      IF v_inserted_id IS NOT NULL THEN
        UPDATE public.profiles
        SET affiliate_balance = COALESCE(affiliate_balance, 0) + v_amount,
            total_affiliate_earnings = COALESCE(total_affiliate_earnings, 0) + v_amount,
            updated_at = NOW()
        WHERE user_id = v_referrers[v_index];
        CONTINUE;
      END IF;

      INSERT INTO public.affiliate_commissions (
        user_id,
        source_user_id,
        order_id,
        tier,
        order_amount,
        commission_rate,
        commission_amount,
        status
      )
      VALUES (
        v_referrers[v_index],
        NEW.user_id,
        NEW.id,
        v_index,
        NEW.total_amount,
        v_rates[v_index],
        v_amount,
        'approved'
      )
      ON CONFLICT DO NOTHING
      RETURNING id INTO v_inserted_id;

      IF v_inserted_id IS NOT NULL THEN
        UPDATE public.profiles
        SET affiliate_balance = COALESCE(affiliate_balance, 0) + v_amount,
            total_affiliate_earnings = COALESCE(total_affiliate_earnings, 0) + v_amount,
            updated_at = NOW()
        WHERE user_id = v_referrers[v_index];
      END IF;
    END LOOP;
  ELSIF NEW.status::TEXT = 'cancelled'
    AND TG_OP = 'UPDATE'
    AND OLD.status::TEXT = 'delivered' THEN
    FOR v_commission IN
      UPDATE public.affiliate_commissions ac
      SET status = 'cancelled'
      WHERE ac.order_id = NEW.id
        AND ac.status IN ('approved', 'paid')
      RETURNING ac.user_id, ac.commission_amount
    LOOP
      UPDATE public.profiles
      SET affiliate_balance = COALESCE(affiliate_balance, 0) - v_commission.commission_amount,
          total_affiliate_earnings = GREATEST(
            0,
            COALESCE(total_affiliate_earnings, 0) - v_commission.commission_amount
          ),
          updated_at = NOW()
      WHERE user_id = v_commission.user_id;
    END LOOP;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."calculate_affiliate_commissions"() OWNER TO "postgres";

