--
-- Name: calculate_community_challenge_progress("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_community_challenge_progress"("p_user_id" "uuid", "p_challenge_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_challenge public.community_challenges%ROWTYPE;
  v_type TEXT;
  v_progress INTEGER := 0;
  v_protein_target INTEGER := 120;
  v_window_start TIMESTAMPTZ;
  v_window_end TIMESTAMPTZ;
BEGIN
  SELECT * INTO v_challenge
  FROM public.community_challenges
  WHERE id = p_challenge_id;

  IF NOT FOUND THEN
    RETURN 0;
  END IF;

  v_type := lower(coalesce(v_challenge.challenge_type, ''));
  v_window_start := v_challenge.start_date::TIMESTAMP AT TIME ZONE 'Asia/Qatar';
  v_window_end := (v_challenge.end_date + 1)::TIMESTAMP AT TIME ZONE 'Asia/Qatar';

  IF v_type IN ('meals', 'meal_logging') THEN
    SELECT count(*)::INTEGER INTO v_progress
    FROM public.meal_history mh
    WHERE mh.user_id = p_user_id
      AND mh.logged_at >= v_window_start
      AND mh.logged_at < v_window_end;

  ELSIF v_type = 'streak' THEN
    SELECT count(DISTINCT pl.log_date)::INTEGER INTO v_progress
    FROM public.progress_logs pl
    WHERE pl.user_id = p_user_id
      AND pl.log_date BETWEEN v_challenge.start_date AND v_challenge.end_date
      AND coalesce(pl.calories_consumed, 0) > 0;

  ELSIF v_type IN ('protein', 'nutrition') THEN
    SELECT coalesce((
      SELECT ng.protein_target_g
      FROM public.nutrition_goals ng
      WHERE ng.user_id = p_user_id AND ng.is_active = true
      ORDER BY ng.created_at DESC
      LIMIT 1
    ), 120) INTO v_protein_target;

    SELECT count(DISTINCT pl.log_date)::INTEGER INTO v_progress
    FROM public.progress_logs pl
    WHERE pl.user_id = p_user_id
      AND pl.log_date BETWEEN v_challenge.start_date AND v_challenge.end_date
      AND coalesce(pl.protein_consumed_g, 0) >= greatest(v_protein_target, 1);

  ELSIF v_type IN ('water', 'hydration') THEN
    SELECT count(*)::INTEGER INTO v_progress
    FROM (
      SELECT sum(coalesce(we.amount_ml, 0)) AS total_ml
      FROM public.water_entries we
      WHERE we.user_id = p_user_id
        AND we.log_date BETWEEN v_challenge.start_date AND v_challenge.end_date
      GROUP BY we.log_date
    ) hydration_days
    WHERE hydration_days.total_ml >= 2500;

  ELSIF v_type IN ('activity', 'workout') THEN
    SELECT count(DISTINCT ws.session_date)::INTEGER INTO v_progress
    FROM public.workout_sessions ws
    WHERE ws.user_id = p_user_id
      AND ws.session_date BETWEEN v_challenge.start_date AND v_challenge.end_date
      AND (coalesce(ws.duration_minutes, 0) > 0 OR coalesce(ws.calories_burned, 0) > 0);

  ELSIF v_type = 'coach' THEN
    IF to_regclass('public.program_meal_completions') IS NOT NULL THEN
      SELECT count(*)::INTEGER INTO v_progress
      FROM public.program_meal_completions pmc
      WHERE pmc.client_id = p_user_id
        AND pmc.completed_at >= v_window_start
        AND pmc.completed_at < v_window_end;
    END IF;

    IF to_regclass('public.program_exercise_completions') IS NOT NULL THEN
      v_progress := v_progress + coalesce((
        SELECT count(*)::INTEGER
        FROM public.program_exercise_completions pec
        WHERE pec.client_id = p_user_id
          AND pec.completed_at >= v_window_start
          AND pec.completed_at < v_window_end
      ), 0);
    END IF;

    IF to_regclass('public.coach_workout_sessions') IS NOT NULL THEN
      v_progress := v_progress + coalesce((
        SELECT count(*)::INTEGER
        FROM public.coach_workout_sessions cws
        WHERE cws.user_id = p_user_id
          AND cws.completed_at >= v_window_start
          AND cws.completed_at < v_window_end
      ), 0);
    END IF;

  ELSIF v_type = 'referral' THEN
    SELECT count(*)::INTEGER INTO v_progress
    FROM public.referrals r
    WHERE r.referrer_id = p_user_id
      AND r.status = 'completed'
      AND r.completed_at >= v_window_start
      AND r.completed_at < v_window_end;

  ELSIF v_type = 'subscription' THEN
    SELECT count(*)::INTEGER INTO v_progress
    FROM generate_series(v_challenge.start_date, v_challenge.end_date, interval '1 day') challenge_day(day)
    WHERE EXISTS (
      SELECT 1
      FROM public.subscriptions s
      WHERE s.user_id = p_user_id
        AND (s.active = true OR s.status = 'active')
        AND coalesce(s.start_date::DATE, s.created_at::DATE, v_challenge.start_date) <= challenge_day.day::DATE
        AND coalesce(s.end_date::DATE, s.next_renewal_date::DATE, v_challenge.end_date) >= challenge_day.day::DATE
    );

  ELSE
    SELECT coalesce(cp.current_progress, 0) INTO v_progress
    FROM public.challenge_participants cp
    WHERE cp.user_id = p_user_id
      AND cp.challenge_id = p_challenge_id
    LIMIT 1;
  END IF;

  RETURN greatest(coalesce(v_progress, 0), 0);
END;
$$;


ALTER FUNCTION "public"."calculate_community_challenge_progress"("p_user_id" "uuid", "p_challenge_id" "uuid") OWNER TO "postgres";

--
-- Name: calculate_daily_margin("date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_daily_margin"("p_date" "date") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_report_id UUID;
  v_subscription_revenue NUMERIC(10,2);
  v_total_payouts NUMERIC(10,2);
  v_total_meals INTEGER;
  v_active_subs INTEGER;
  v_gross_margin NUMERIC(10,2);
  v_margin_pct NUMERIC(5,2);
BEGIN
  -- Calculate subscription revenue for the date
  SELECT COALESCE(SUM(price), 0)
  INTO v_subscription_revenue
  FROM public.subscriptions
  WHERE DATE(start_date) = p_date
    AND status = 'active';
  
  -- Calculate total payouts for meals served on this date
  SELECT COALESCE(SUM(net_amount), 0), COUNT(*)
  INTO v_total_payouts, v_total_meals
  FROM public.partner_earnings
  WHERE DATE(created_at) = p_date
    AND status = 'paid';
  
  -- Count active subscriptions
  SELECT COUNT(*)
  INTO v_active_subs
  FROM public.subscriptions
  WHERE status = 'active'
    AND start_date <= p_date
    AND (end_date IS NULL OR end_date >= p_date);
  
  -- Calculate margin
  v_gross_margin := v_subscription_revenue - v_total_payouts;
  v_margin_pct := CASE 
    WHEN v_subscription_revenue > 0 
    THEN ROUND((v_gross_margin / v_subscription_revenue) * 100, 2)
    ELSE 0 
  END;
  
  -- Insert or update report
  INSERT INTO public.daily_margin_reports (
    report_date,
    new_subscriptions_revenue,
    total_subscription_revenue,
    total_restaurant_payouts,
    gross_margin,
    gross_margin_percentage,
    total_meals_served,
    active_subscriptions
  ) VALUES (
    p_date,
    v_subscription_revenue,
    v_subscription_revenue,
    v_total_payouts,
    v_gross_margin,
    v_margin_pct,
    v_total_meals,
    v_active_subs
  )
  ON CONFLICT (report_date) DO UPDATE SET
    new_subscriptions_revenue = EXCLUDED.new_subscriptions_revenue,
    total_subscription_revenue = EXCLUDED.total_subscription_revenue,
    total_restaurant_payouts = EXCLUDED.total_restaurant_payouts,
    gross_margin = EXCLUDED.gross_margin,
    gross_margin_percentage = EXCLUDED.gross_margin_percentage,
    total_meals_served = EXCLUDED.total_meals_served,
    active_subscriptions = EXCLUDED.active_subscriptions,
    updated_at = now()
  RETURNING id INTO v_report_id;
  
  RETURN v_report_id;
END;
$$;


ALTER FUNCTION "public"."calculate_daily_margin"("p_date" "date") OWNER TO "postgres";

--
-- Name: calculate_delivery_fee_breakdown("uuid", "date", "text", "uuid", "text", numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_delivery_fee_breakdown"("p_user_id" "uuid", "p_scheduled_date" "date", "p_delivery_time_slot" "text", "p_delivery_address_id" "uuid", "p_delivery_type" "text" DEFAULT 'standard'::"text", "p_order_total" numeric DEFAULT 0) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_settings JSONB := '{}'::JSONB;
  v_enabled BOOLEAN := FALSE;
  v_surge_enabled BOOLEAN := FALSE;
  v_base_fee NUMERIC(10, 2) := 0;
  v_free_threshold NUMERIC(10, 2) := 0;
  v_global_max_surcharge NUMERIC(10, 2) := 25;
  v_slot_time TIME;
  v_city TEXT;
  v_demand_count INTEGER := 0;
  v_rule public.delivery_surge_rules%ROWTYPE;
  v_surge_fee NUMERIC(10, 2) := 0;
  v_total_fee NUMERIC(10, 2) := 0;
BEGIN
  IF p_user_id IS NULL OR p_scheduled_date IS NULL
    OR NULLIF(TRIM(p_delivery_time_slot), '') IS NULL
    OR p_delivery_address_id IS NULL THEN
    RETURN jsonb_build_object(
      'base_fee', 0, 'surge_fee', 0, 'total_fee', 0,
      'demand_count', 0, 'message', 'Delivery details are incomplete.'
    );
  END IF;

  IF p_delivery_type NOT IN ('standard', 'express') THEN
    RAISE EXCEPTION 'DELIVERY_TYPE_INVALID';
  END IF;

  BEGIN
    v_slot_time := to_timestamp(UPPER(TRIM(p_delivery_time_slot)), 'HH12:MI AM')::TIME;
  EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION 'DELIVERY_TIME_SLOT_INVALID';
  END;

  SELECT ua.city
    INTO v_city
  FROM public.user_addresses ua
  WHERE ua.id = p_delivery_address_id
    AND ua.user_id = p_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'DELIVERY_ADDRESS_NOT_FOUND';
  END IF;

  SELECT ps.value
    INTO v_settings
  FROM public.platform_settings ps
  WHERE ps.key = 'delivery_fees';

  v_settings := COALESCE(v_settings, '{}'::JSONB);
  v_enabled := COALESCE((v_settings ->> 'enabled')::BOOLEAN, FALSE);
  v_surge_enabled := COALESCE((v_settings ->> 'surge_enabled')::BOOLEAN, FALSE);
  v_free_threshold := GREATEST(COALESCE((v_settings ->> 'free_threshold')::NUMERIC, 0), 0);
  v_global_max_surcharge := GREATEST(COALESCE((v_settings ->> 'max_surcharge')::NUMERIC, 25), 0);

  IF v_enabled THEN
    v_base_fee := CASE p_delivery_type
      WHEN 'express' THEN GREATEST(COALESCE((v_settings ->> 'express')::NUMERIC, 0), 0)
      ELSE GREATEST(COALESCE((v_settings ->> 'standard')::NUMERIC, 0), 0)
    END;
  END IF;

  IF v_free_threshold > 0 AND COALESCE(p_order_total, 0) >= v_free_threshold THEN
    v_base_fee := 0;
  END IF;

  SELECT COUNT(*)::INTEGER
    INTO v_demand_count
  FROM public.meal_schedules ms
  JOIN public.user_addresses ua ON ua.id = ms.delivery_address_id
  WHERE ms.scheduled_date = p_scheduled_date
    AND ms.delivery_time_slot = p_delivery_time_slot
    AND LOWER(COALESCE(ua.city, '')) = LOWER(COALESCE(v_city, ''))
    AND COALESCE(ms.order_status, 'pending') NOT IN ('cancelled', 'rejected');

  IF v_enabled AND v_surge_enabled AND v_base_fee > 0 THEN
    SELECT rule.*
      INTO v_rule
    FROM public.delivery_surge_rules rule
    WHERE rule.enabled = TRUE
      AND (rule.effective_from IS NULL OR rule.effective_from <= now())
      AND (rule.effective_until IS NULL OR rule.effective_until > now())
      AND (
        cardinality(rule.days_of_week) = 0
        OR EXTRACT(DOW FROM p_scheduled_date)::SMALLINT = ANY(rule.days_of_week)
      )
      AND (
        rule.start_time IS NULL OR rule.end_time IS NULL
        OR CASE
          WHEN rule.start_time <= rule.end_time
            THEN v_slot_time BETWEEN rule.start_time AND rule.end_time
          ELSE v_slot_time >= rule.start_time OR v_slot_time <= rule.end_time
        END
      )
      AND (
        cardinality(rule.cities) = 0
        OR EXISTS (
          SELECT 1 FROM unnest(rule.cities) city_name
          WHERE LOWER(city_name) = LOWER(v_city)
        )
      )
      AND v_demand_count >= rule.demand_threshold
    ORDER BY rule.priority DESC, rule.demand_threshold DESC, rule.created_at ASC
    LIMIT 1;

    IF FOUND THEN
      v_surge_fee := LEAST(
        GREATEST(ROUND(v_base_fee * (v_rule.multiplier - 1) + v_rule.flat_surcharge, 2), 0),
        v_rule.max_surcharge,
        v_global_max_surcharge
      );
    END IF;
  END IF;

  v_total_fee := ROUND(v_base_fee + v_surge_fee, 2);

  RETURN jsonb_build_object(
    'base_fee', v_base_fee,
    'surge_fee', v_surge_fee,
    'total_fee', v_total_fee,
    'rule_id', v_rule.id,
    'rule_name', v_rule.name,
    'message', CASE
      WHEN v_surge_fee > 0 THEN v_rule.customer_message
      WHEN v_total_fee = 0 THEN 'Free delivery'
      ELSE 'Standard delivery fee'
    END,
    'demand_count', v_demand_count,
    'city', v_city,
    'delivery_type', p_delivery_type,
    'calculated_at', now()
  );
END;
$$;


ALTER FUNCTION "public"."calculate_delivery_fee_breakdown"("p_user_id" "uuid", "p_scheduled_date" "date", "p_delivery_time_slot" "text", "p_delivery_address_id" "uuid", "p_delivery_type" "text", "p_order_total" numeric) OWNER TO "postgres";

--
-- Name: calculate_delivery_priority("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_delivery_priority"("p_order_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_base_score INTEGER := 50;
  v_order RECORD;
BEGIN
  -- Get order details
  SELECT 
    o.id,
    o.tip_amount,
    o.created_at,
    o.estimated_delivery_time,
    s.tier as subscription_tier
  INTO v_order
  FROM public.orders o
  LEFT JOIN public.subscriptions s ON s.user_id = o.user_id AND s.status = 'active'
  WHERE o.id = p_order_id;
  
  IF v_order IS NULL THEN
    RETURN v_base_score;
  END IF;
  
  -- Tip bonus (up to +20 points)
  IF v_order.tip_amount > 0 THEN
    v_base_score := v_base_score + LEAST((v_order.tip_amount / 5)::INTEGER * 5, 20);
  END IF;
  
  -- VIP subscription bonus (+15 points)
  IF v_order.subscription_tier = 'vip' THEN
    v_base_score := v_base_score + 15;
  END IF;
  
  -- Waiting time bonus (+1 point per 5 minutes waiting, up to +15)
  v_base_score := v_base_score + LEAST(
    EXTRACT(EPOCH FROM (now() - v_order.created_at)) / 300,
    15
  )::INTEGER;
  
  -- Urgent delivery bonus (+10 points if within 30 minutes of estimated time)
  IF v_order.estimated_delivery_time IS NOT NULL 
     AND v_order.estimated_delivery_time - now() < interval '30 minutes' THEN
    v_base_score := v_base_score + 10;
  END IF;
  
  RETURN LEAST(v_base_score, 100);
END;
$$;


ALTER FUNCTION "public"."calculate_delivery_priority"("p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: calculate_driver_earnings(numeric, numeric, "text", "uuid", numeric, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_driver_earnings"("p_delivery_fee" numeric, "p_tip_amount" numeric DEFAULT 0, "p_city" "text" DEFAULT NULL::"text", "p_restaurant_id" "uuid" DEFAULT NULL::"uuid", "p_distance_km" numeric DEFAULT NULL::numeric, "p_order_time" timestamp with time zone DEFAULT "now"()) RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_settings JSONB;
  v_base NUMERIC := 0;
  v_percentage NUMERIC := 80;
BEGIN
  SELECT ps.value
  INTO v_settings
  FROM public.platform_settings ps
  WHERE ps.key = 'driver_settings'
  ORDER BY ps.updated_at DESC
  LIMIT 1;

  v_base := COALESCE(NULLIF(v_settings ->> 'default_base_earning', '')::NUMERIC, 0);
  v_percentage := LEAST(
    GREATEST(COALESCE(NULLIF(v_settings ->> 'default_percentage', '')::NUMERIC, 80), 0),
    100
  );

  RETURN ROUND(
    v_base
      + GREATEST(COALESCE(p_delivery_fee, 0), 0) * v_percentage / 100
      + GREATEST(COALESCE(p_tip_amount, 0), 0),
    2
  );
END;
$$;


ALTER FUNCTION "public"."calculate_driver_earnings"("p_delivery_fee" numeric, "p_tip_amount" numeric, "p_city" "text", "p_restaurant_id" "uuid", "p_distance_km" numeric, "p_order_time" timestamp with time zone) OWNER TO "postgres";

