-- Name: FUNCTION "calculate_driver_earnings"("p_delivery_fee" numeric, "p_tip_amount" numeric, "p_city" "text", "p_restaurant_id" "uuid", "p_distance_km" numeric, "p_order_time" timestamp with time zone); Type: COMMENT; Schema: public; Owner: postgres
