--
-- Name: calculate_next_retry(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_next_retry"("attempt_count" integer) RETURNS timestamp with time zone
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    base_delay INTEGER := 60; -- 1 minute base
    max_delay INTEGER := 14400; -- 4 hours max
    delay INTEGER;
BEGIN
    -- Exponential backoff: 1min, 5min, 15min, 1hr, 4hr
    delay := LEAST(
        base_delay * POWER(3, attempt_count - 1),
        max_delay
    );
    
    -- Add jitter (±10%) to prevent thundering herd
    delay := delay + (random() * delay * 0.2 - delay * 0.1)::INTEGER;
    
    RETURN NOW() + (delay || ' seconds')::INTERVAL;
END;
$$;


ALTER FUNCTION "public"."calculate_next_retry"("attempt_count" integer) OWNER TO "postgres";

--
-- Name: FUNCTION "calculate_next_retry"("attempt_count" integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."calculate_next_retry"("attempt_count" integer) IS 'Calculates next retry time with exponential backoff and jitter';


--
-- Name: calculate_nps_score("date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_nps_score"("p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date") RETURNS TABLE("total_responses" bigint, "promoters" bigint, "passives" bigint, "detractors" bigint, "nps_score" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  RETURN QUERY
  WITH counts AS (
    SELECT 
      COUNT(*) as total,
      COUNT(*) FILTER (WHERE score >= 9) as promoter_count,
      COUNT(*) FILTER (WHERE score >= 7 AND score <= 8) as passive_count,
      COUNT(*) FILTER (WHERE score <= 6) as detractor_count
    FROM public.nps_responses
    WHERE (p_start_date IS NULL OR responded_at::date >= p_start_date)
      AND (p_end_date IS NULL OR responded_at::date <= p_end_date)
  )
  SELECT 
    counts.total,
    counts.promoter_count,
    counts.passive_count,
    counts.detractor_count,
    CASE 
      WHEN counts.total = 0 THEN 0
      ELSE ROUND(((counts.promoter_count::NUMERIC - counts.detractor_count::NUMERIC) / counts.total::NUMERIC) * 100, 2)
    END as nps_score
  FROM counts;
END;
$$;


ALTER FUNCTION "public"."calculate_nps_score"("p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";

