--
-- Name: calculate_nutrient_completeness("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_nutrient_completeness"("p_nutrition" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_required TEXT[] := ARRAY['calories', 'protein_g', 'carbs_g', 'fat_g'];
  v_quality TEXT[] := ARRAY['fiber_g', 'sugar_g', 'sodium_mg'];
  v_all TEXT[] := v_required || v_quality;
  v_code TEXT;
  v_value NUMERIC;
  v_present_required INTEGER := 0;
  v_present_quality INTEGER := 0;
  v_missing TEXT[] := ARRAY[]::TEXT[];
  v_invalid TEXT[] := ARRAY[]::TEXT[];
BEGIN
  FOREACH v_code IN ARRAY v_all LOOP
    IF NOT p_nutrition ? v_code OR NULLIF(BTRIM(p_nutrition ->> v_code), '') IS NULL THEN
      v_missing := array_append(v_missing, v_code);
    ELSE
      BEGIN
        v_value := (p_nutrition ->> v_code)::NUMERIC;
        IF v_value < 0 THEN
          v_invalid := array_append(v_invalid, v_code);
        ELSIF v_code = ANY(v_required) THEN
          v_present_required := v_present_required + 1;
        ELSE
          v_present_quality := v_present_quality + 1;
        END IF;
      EXCEPTION WHEN invalid_text_representation THEN
        v_invalid := array_append(v_invalid, v_code);
      END;
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'score', ROUND((v_present_required::NUMERIC / array_length(v_required, 1)) * 70 + (v_present_quality::NUMERIC / array_length(v_quality, 1)) * 30)::INTEGER,
    'missing_codes', v_missing,
    'invalid_codes', v_invalid,
    'required_missing_codes', (
      SELECT COALESCE(array_agg(code), ARRAY[]::TEXT[])
      FROM unnest(v_required) AS code
      WHERE code = ANY(v_missing) OR code = ANY(v_invalid)
    )
  );
END;
$$;


ALTER FUNCTION "public"."calculate_nutrient_completeness"("p_nutrition" "jsonb") OWNER TO "postgres";

--
-- Name: calculate_order_commission(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_order_commission"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  restaurant_commission numeric;
  global_commission numeric;
BEGIN
  -- 1. Try to get the per-restaurant commission rate
  SELECT r.commission_rate INTO restaurant_commission
  FROM public.restaurants r
  WHERE r.id = NEW.restaurant_id;

  -- 2. If the restaurant has a commission_rate set and > 0, use it
  IF restaurant_commission IS NOT NULL AND restaurant_commission > 0 THEN
    NEW.commission_rate := restaurant_commission;
  ELSE
    -- 3. Fall back to the global platform setting
    SELECT COALESCE((value->>'restaurant')::numeric, 18)
    INTO global_commission
    FROM public.platform_settings
    WHERE key = 'commission_rates';

    NEW.commission_rate := COALESCE(global_commission, 18);
  END IF;

  -- Calculate commission and partner earnings
  NEW.commission_amount := ROUND((NEW.total_price * NEW.commission_rate / 100)::numeric, 2);
  NEW.partner_earnings := NEW.total_price - NEW.commission_amount;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."calculate_order_commission"() OWNER TO "postgres";

--
-- Name: calculate_restaurant_rating("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
