--
-- Name: calculate_user_streak("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_user_streak"("user_uuid" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(user_uuid);
  RETURN public.calculate_user_streak_trusted(user_uuid);
END;
$$;


ALTER FUNCTION "public"."calculate_user_streak"("user_uuid" "uuid") OWNER TO "postgres";

--
-- Name: calculate_user_streak_trusted("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_user_streak_trusted"("user_uuid" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    current_streak INTEGER := 0;
    last_log_date DATE;
    today DATE := CURRENT_DATE;
BEGIN
    -- Get the most recent log date
    SELECT MAX(log_date) INTO last_log_date
    FROM public.progress_logs
    WHERE user_id = user_uuid;
    
    -- If no logs, streak is 0
    IF last_log_date IS NULL THEN
        RETURN 0;
    END IF;
    
    -- If last log was not today or yesterday, streak is broken
    IF last_log_date < today - INTERVAL '1 day' THEN
        RETURN 0;
    END IF;
    
    -- Calculate streak by counting consecutive days backward from last log
    current_streak := 1;
    
    WHILE EXISTS (
        SELECT 1 FROM public.progress_logs
        WHERE user_id = user_uuid
        AND log_date = last_log_date - (current_streak || ' days')::INTERVAL
    ) LOOP
        current_streak := current_streak + 1;
    END LOOP;
    
    RETURN current_streak;
END;
$$;


ALTER FUNCTION "public"."calculate_user_streak_trusted"("user_uuid" "uuid") OWNER TO "postgres";

