-- Name: FUNCTION "calculate_user_streak_trusted"("user_uuid" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."calculate_user_streak_trusted"("user_uuid" "uuid") IS 'Calculates the current consecutive day streak for a user based on progress_logs entries';


--
-- Name: calculate_weekly_adherence("uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_weekly_adherence"("p_user_id" "uuid", "p_week_start" "date") RETURNS TABLE("adherence_rate" numeric, "avg_calories" integer, "days_logged" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_user_id);
  RETURN QUERY SELECT * FROM public.calculate_weekly_adherence_trusted(p_user_id, p_week_start);
END;
$$;


ALTER FUNCTION "public"."calculate_weekly_adherence"("p_user_id" "uuid", "p_week_start" "date") OWNER TO "postgres";

--
-- Name: calculate_weekly_adherence_trusted("uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_weekly_adherence_trusted"("p_user_id" "uuid", "p_week_start" "date") RETURNS TABLE("adherence_rate" numeric, "avg_calories" integer, "days_logged" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_target_calories INTEGER;
BEGIN
  SELECT daily_calorie_target INTO v_target_calories
  FROM profiles WHERE user_id = p_user_id;

  RETURN QUERY
  SELECT 
    CASE 
      WHEN COUNT(*) = 0 THEN 0
      ELSE COUNT(CASE WHEN ABS(calories_consumed - v_target_calories) <= v_target_calories * 0.1 THEN 1 END)::DECIMAL / COUNT(*)
    END,
    COALESCE(AVG(calories_consumed)::INTEGER, 0),
    COUNT(*)::INTEGER
  FROM progress_logs
  WHERE user_id = p_user_id
    AND log_date >= p_week_start
    AND log_date < p_week_start + INTERVAL '7 days';
END;
$$;


ALTER FUNCTION "public"."calculate_weekly_adherence_trusted"("p_user_id" "uuid", "p_week_start" "date") OWNER TO "postgres";

