-- Name: calculate_weight_change_rate("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_weight_change_rate"("p_user_id" "uuid", "p_weeks" integer) RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_user_id);
  RETURN public.calculate_weight_change_rate_trusted(p_user_id, p_weeks);
END;
$$;


ALTER FUNCTION "public"."calculate_weight_change_rate"("p_user_id" "uuid", "p_weeks" integer) OWNER TO "postgres";

--
-- Name: calculate_weight_change_rate_trusted("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."calculate_weight_change_rate_trusted"("p_user_id" "uuid", "p_weeks" integer DEFAULT 4) RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_start_weight DECIMAL;
  v_end_weight DECIMAL;
BEGIN
  SELECT weight_kg INTO v_start_weight
  FROM progress_logs
  WHERE user_id = p_user_id AND weight_kg IS NOT NULL
  ORDER BY log_date ASC
  LIMIT 1 OFFSET (SELECT COUNT(*) / 2 FROM progress_logs WHERE user_id = p_user_id AND weight_kg IS NOT NULL);

  SELECT weight_kg INTO v_end_weight
  FROM progress_logs
  WHERE user_id = p_user_id AND weight_kg IS NOT NULL
  ORDER BY log_date DESC
  LIMIT 1;

  RETURN CASE 
    WHEN v_start_weight IS NULL OR v_end_weight IS NULL THEN 0
    ELSE (v_end_weight - v_start_weight) / NULLIF(p_weeks, 0)
  END;
END;
$$;


ALTER FUNCTION "public"."calculate_weight_change_rate_trusted"("p_user_id" "uuid", "p_weeks" integer) OWNER TO "postgres";

