--
-- Name: can_cancel_order("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."can_cancel_order"("p_order_id" "uuid", "p_role" "text" DEFAULT 'customer'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_order RECORD;
  v_can_cancel BOOLEAN;
  v_reason TEXT;
BEGIN
  SELECT id, status, user_id
  INTO v_order
  FROM public.orders
  WHERE id = p_order_id;
  
  IF v_order IS NULL THEN
    RETURN jsonb_build_object(
      'can_cancel', false,
      'reason', 'Order not found'
    );
  END IF;
  
  IF v_order.status = 'cancelled' THEN
    RETURN jsonb_build_object(
      'can_cancel', false,
      'reason', 'Order is already cancelled'
    );
  END IF;
  
  IF v_order.status IN ('delivered', 'completed') THEN
    RETURN jsonb_build_object(
      'can_cancel', false,
      'reason', 'Delivered or completed orders cannot be cancelled'
    );
  END IF;
  
  CASE p_role
    WHEN 'customer' THEN
      v_can_cancel := v_order.status IN ('pending', 'confirmed');
      v_reason := CASE 
        WHEN v_can_cancel THEN 'Can be cancelled'
        ELSE format('Orders in %s status cannot be cancelled by customers', v_order.status)
      END;
      
    WHEN 'partner' THEN
      v_can_cancel := v_order.status IN ('pending', 'confirmed', 'preparing');
      v_reason := CASE 
        WHEN v_can_cancel THEN 'Can be cancelled'
        ELSE format('Orders in %s status cannot be cancelled by partners', v_order.status)
      END;
      
    WHEN 'admin' THEN
      v_can_cancel := v_order.status NOT IN ('delivered', 'completed');
      v_reason := 'Admins can cancel orders in any status except delivered/completed';
      
    ELSE
      v_can_cancel := false;
      v_reason := 'Invalid role';
  END CASE;
  
  RETURN jsonb_build_object(
    'can_cancel', v_can_cancel,
    'reason', v_reason,
    'current_status', v_order.status,
    'role', p_role
  );
END;
$$;


ALTER FUNCTION "public"."can_cancel_order"("p_order_id" "uuid", "p_role" "text") OWNER TO "postgres";

