-- Name: FUNCTION "can_cancel_order"("p_order_id" "uuid", "p_role" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."can_cancel_order"("p_order_id" "uuid", "p_role" "text") IS 'Checks if an order can be cancelled by a given role';


