-- Name: can_manage_fleet_city("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."can_manage_fleet_city"("p_city_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  SELECT public.has_role(auth.uid(), 'admin'::public.app_role)
    OR EXISTS (
      SELECT 1
      FROM public.fleet_managers fm
      WHERE fm.auth_user_id = auth.uid()
        AND fm.is_active = true
        AND (
          fm.role = 'super_admin'
          OR (p_city_id IS NOT NULL AND p_city_id = ANY(COALESCE(fm.assigned_city_ids, ARRAY[]::uuid[])))
        )
    );
$$;


