--
-- Name: cancel_coach_subscription("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."cancel_coach_subscription"("p_subscription_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_subscription public.coach_subscriptions%ROWTYPE;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;

  SELECT *
    INTO v_subscription
  FROM public.coach_subscriptions
  WHERE id = p_subscription_id
    AND client_id = auth.uid()
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'COACH_SUBSCRIPTION_NOT_FOUND';
  END IF;

  IF v_subscription.status = 'active' THEN
    UPDATE public.coach_subscriptions
    SET status = 'cancelled',
        auto_renew = FALSE,
        updated_at = NOW()
    WHERE id = v_subscription.id;
  END IF;

  RETURN jsonb_build_object(
    'success', TRUE,
    'subscription_id', v_subscription.id,
    'status', CASE
      WHEN v_subscription.status = 'active' THEN 'cancelled'
      ELSE v_subscription.status
    END,
    'access_until', v_subscription.end_date
  );
END;
$$;


ALTER FUNCTION "public"."cancel_coach_subscription"("p_subscription_id" "uuid") OWNER TO "postgres";

