--

COMMENT ON FUNCTION "public"."cancel_coach_subscription"("p_subscription_id" "uuid") IS 'Cancels the authenticated client coach subscription without granting direct table writes.';


--
-- Name: cancel_customer_order("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."cancel_customer_order"("p_order_id" "uuid", "p_reason" "text" DEFAULT 'Customer cancellation'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_order public.orders%ROWTYPE;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  SELECT *
    INTO v_order
  FROM public.orders o
  WHERE o.id = p_order_id
    AND o.user_id = v_actor
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'ORDER_NOT_FOUND';
  END IF;

  IF v_order.status = 'cancelled' THEN
    RETURN jsonb_build_object(
      'success', TRUE,
      'already_cancelled', TRUE,
      'order_id', v_order.id,
      'refund_amount', 0
    );
  END IF;

  IF v_order.status <> 'pending' THEN
    RAISE EXCEPTION 'ORDER_CANNOT_BE_CANCELLED';
  END IF;

  RETURN public.process_direct_order_cancellation(
    v_order.id,
    v_actor,
    'customer',
    COALESCE(NULLIF(TRIM(p_reason), ''), 'Customer cancellation')
  );
END;
$$;


ALTER FUNCTION "public"."cancel_customer_order"("p_order_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: cancel_meal_schedule("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."cancel_meal_schedule"("p_schedule_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_schedule RECORD; v_restaurant RECORD; v_active_job_count INTEGER;
  v_wallet_id UUID; v_wallet_balance NUMERIC;
  v_cancelled_earnings_count INTEGER; v_cancelled_jobs_count INTEGER;
  v_updated_notifications_count INTEGER;
BEGIN
  SELECT ms.id, ms.user_id, ms.order_status, ms.meal_id, ms.addons_total,
         m.name AS meal_name, m.restaurant_id
  INTO v_schedule FROM meal_schedules ms LEFT JOIN meals m ON m.id = ms.meal_id
  WHERE ms.id = p_schedule_id AND ms.user_id = (select auth.uid())
  FOR UPDATE OF ms;
  IF NOT FOUND THEN RAISE EXCEPTION 'Order not found or you do not have permission to cancel it.'; END IF;
  IF v_schedule.order_status NOT IN ('pending','confirmed') THEN RAISE EXCEPTION 'Orders in "%" status cannot be cancelled.', v_schedule.order_status; END IF;
  SELECT COUNT(*) INTO v_active_job_count FROM delivery_jobs WHERE schedule_id = p_schedule_id AND status IN ('preparing','ready','out_for_delivery','picked_up');
  IF v_active_job_count > 0 THEN RAISE EXCEPTION 'Cannot cancel: a driver is already preparing or delivering this order. Please contact support.'; END IF;
  UPDATE delivery_jobs SET status = 'cancelled', updated_at = NOW() WHERE schedule_id = p_schedule_id AND status IN ('pending','scheduled','assigned');
  GET DIAGNOSTICS v_cancelled_jobs_count = ROW_COUNT;
  DELETE FROM delivery_queue WHERE metadata->>'schedule_id' = p_schedule_id::TEXT AND status IN ('queued','assigned','accepted');
  UPDATE meal_schedules SET order_status = 'cancelled', cancellation_reason = p_reason, updated_at = NOW() WHERE id = p_schedule_id;
  UPDATE subscriptions SET meals_used_this_month = GREATEST(0, COALESCE(meals_used_this_month,0) - 1), meals_used_this_week = GREATEST(0, COALESCE(meals_used_this_week,0) - 1)
  WHERE user_id = v_schedule.user_id AND status = 'active' AND id = (SELECT id FROM subscriptions WHERE user_id = v_schedule.user_id AND status = 'active' ORDER BY created_at DESC LIMIT 1);
  IF EXISTS (SELECT 1 FROM wallet_transactions wt WHERE wt.user_id = v_schedule.user_id AND wt.type = 'debit' AND wt.description = 'Extra meal credit purchase'
    AND wt.created_at >= (SELECT created_at FROM meal_schedules WHERE id = p_schedule_id) - INTERVAL '1 hour'
    AND wt.created_at <= (SELECT created_at FROM meal_schedules WHERE id = p_schedule_id) + INTERVAL '1 hour') THEN
    UPDATE subscriptions SET meals_per_month = GREATEST(1, COALESCE(meals_per_month,0) - 1)
    WHERE user_id = v_schedule.user_id AND status = 'active' AND id = (SELECT id FROM subscriptions WHERE user_id = v_schedule.user_id AND status = 'active' ORDER BY created_at DESC LIMIT 1);
  END IF;
  IF v_schedule.addons_total IS NOT NULL AND v_schedule.addons_total > 0 THEN
    SELECT id, COALESCE(balance, 0) INTO v_wallet_id, v_wallet_balance FROM customer_wallets WHERE user_id = v_schedule.user_id;
    UPDATE customer_wallets SET balance = COALESCE(balance, 0) + v_schedule.addons_total, total_credits = COALESCE(total_credits, 0) + v_schedule.addons_total, updated_at = NOW() WHERE user_id = v_schedule.user_id;
    INSERT INTO wallet_transactions (wallet_id, user_id, amount, type, reference_type, reference_id, description, balance_after, created_at)
    VALUES (v_wallet_id, v_schedule.user_id, v_schedule.addons_total, 'refund', 'order', p_schedule_id, 'Meal cancellation refund - addons for ' || COALESCE(v_schedule.meal_name, 'meal'), COALESCE(v_wallet_balance, 0) + v_schedule.addons_total, NOW());
  END IF;
  UPDATE partner_earnings SET status = 'cancelled' WHERE meal_schedule_id = p_schedule_id AND status IN ('pending','paid');
  GET DIAGNOSTICS v_cancelled_earnings_count = ROW_COUNT;
  UPDATE notifications SET status = 'read' WHERE user_id = v_schedule.user_id AND type = 'meal_scheduled' AND (data->>'schedule_id')::TEXT = p_schedule_id::TEXT AND status = 'unread';
  GET DIAGNOSTICS v_updated_notifications_count = ROW_COUNT;
  BEGIN
    IF v_schedule.restaurant_id IS NOT NULL THEN
      SELECT id, name, owner_id INTO v_restaurant FROM restaurants WHERE id = v_schedule.restaurant_id;
      IF v_restaurant.owner_id IS NOT NULL THEN
        INSERT INTO notifications (user_id, type, title, message, status, data)
        VALUES (v_restaurant.owner_id, 'order_update', 'Order Cancelled by Customer', 'A customer has cancelled their order for ' || COALESCE(v_schedule.meal_name, 'a meal') || '.', 'unread', jsonb_build_object('schedule_id', p_schedule_id, 'meal_name', COALESCE(v_schedule.meal_name, ''), 'cancelled_by', 'customer'));
      END IF;
    END IF;
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'Failed to notify partner for schedule %: %', p_schedule_id, SQLERRM; END;
  BEGIN
    INSERT INTO notifications (user_id, type, title, message, status, data)
    VALUES (v_schedule.user_id, 'order_update', 'Meal Cancelled', 'Your scheduled meal for ' || COALESCE(v_schedule.meal_name, 'a meal') || ' has been cancelled. Your meal credit has been refunded.', 'unread', jsonb_build_object('schedule_id', p_schedule_id, 'meal_name', COALESCE(v_schedule.meal_name, ''), 'action', 'cancelled', 'credit_refunded', true));
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'Failed to notify customer for schedule %: %', p_schedule_id, SQLERRM; END;
  RETURN jsonb_build_object('success', true, 'schedule_id', p_schedule_id, 'refunded_addons', COALESCE(v_schedule.addons_total, 0), 'cancelled_earnings', v_cancelled_earnings_count, 'cancelled_jobs', v_cancelled_jobs_count, 'marked_notifications_read', v_updated_notifications_count);
END;
$$;


ALTER FUNCTION "public"."cancel_meal_schedule"("p_schedule_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: cancel_recovery_booking("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."cancel_recovery_booking"("p_booking_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_now TIMESTAMP := NOW() AT TIME ZONE 'Asia/Qatar';
  v_booking public.recovery_bookings%ROWTYPE;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  SELECT *
    INTO v_booking
  FROM public.recovery_bookings rb
  WHERE rb.id = p_booking_id
    AND rb.user_id = v_actor
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'RECOVERY_BOOKING_NOT_FOUND';
  END IF;

  IF v_booking.status = 'cancelled' THEN
    RETURN jsonb_build_object(
      'success', TRUE,
      'already_cancelled', TRUE,
      'booking_id', v_booking.id
    );
  END IF;

  IF v_booking.status <> 'booked' THEN
    RAISE EXCEPTION 'RECOVERY_BOOKING_CANNOT_BE_CANCELLED';
  END IF;

  IF (v_booking.booking_date + v_booking.booking_time)
    <= v_now + INTERVAL '2 hours' THEN
    RAISE EXCEPTION 'RECOVERY_CANCELLATION_WINDOW_CLOSED';
  END IF;

  UPDATE public.recovery_bookings
  SET status = 'cancelled'
  WHERE id = v_booking.id;

  UPDATE public.member_recovery_credits
  SET used_credits = GREATEST(0, used_credits - v_booking.credits_used)
  WHERE user_id = v_actor
    AND period_start = v_booking.credit_period_start;

  RETURN jsonb_build_object(
    'success', TRUE,
    'already_cancelled', FALSE,
    'booking_id', v_booking.id,
    'credits_restored', v_booking.credits_used
  );
END;
$$;


ALTER FUNCTION "public"."cancel_recovery_booking"("p_booking_id" "uuid") OWNER TO "postgres";

--
-- Name: cancel_subscription_freeze("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."cancel_subscription_freeze"("p_freeze_id" "uuid", "p_reason" "text" DEFAULT 'User cancelled'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_freeze public.subscription_freezes%ROWTYPE;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;

  SELECT * INTO v_freeze
  FROM public.subscription_freezes sf
  WHERE sf.id = p_freeze_id
    AND sf.status = 'scheduled'
    AND (
      sf.user_id = v_actor
      OR public.has_role(v_actor, 'admin')
    )
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'SCHEDULED_FREEZE_NOT_FOUND';
  END IF;

  UPDATE public.subscription_freezes
  SET status = 'cancelled',
      cancelled_at = now(),
      cancelled_reason = LEFT(COALESCE(NULLIF(trim(p_reason), ''), 'Cancelled'), 500)
  WHERE id = v_freeze.id;

  UPDATE public.subscriptions
  SET freeze_days_used = GREATEST(0, COALESCE(freeze_days_used, 0) - v_freeze.freeze_days),
      next_renewal_date = next_renewal_date - v_freeze.freeze_days,
      end_date = end_date - v_freeze.freeze_days,
      updated_at = now()
  WHERE id = v_freeze.subscription_id;

  RETURN jsonb_build_object('success', true, 'freeze_id', v_freeze.id, 'status', 'cancelled');
END;
$$;


ALTER FUNCTION "public"."cancel_subscription_freeze"("p_freeze_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: check_and_award_badges("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_and_award_badges"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_user_id);
  RETURN public.check_and_award_badges_trusted(p_user_id);
END;
$$;


ALTER FUNCTION "public"."check_and_award_badges"("p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: check_and_award_badges_trusted("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_and_award_badges_trusted"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_streak_days INTEGER;
  v_meals_logged INTEGER;
  v_level INTEGER;
  v_referral_count INTEGER;
  v_calorie_target NUMERIC;
  v_protein_target NUMERIC;
  v_current_weight NUMERIC;
  v_target_weight NUMERIC;
  v_requirement_met BOOLEAN;
  v_metric INTEGER;
  v_inserted_badge_id TEXT;
  v_badge_record public.badges%ROWTYPE;
  v_awarded_badges TEXT[] := ARRAY[]::TEXT[];
  v_reward_results JSONB := '[]'::jsonb;
BEGIN
  IF auth.uid() IS NULL OR p_user_id <> auth.uid() THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  SELECT
    COALESCE(streak_days, 0),
    COALESCE(total_meals_logged, 0),
    COALESCE(level, 1),
    FLOOR(COALESCE(referral_rewards_earned, 0))::INTEGER,
    COALESCE(daily_calorie_target, 0),
    COALESCE(protein_target_g, 0),
    current_weight_kg,
    target_weight_kg
  INTO
    v_streak_days,
    v_meals_logged,
    v_level,
    v_referral_count,
    v_calorie_target,
    v_protein_target,
    v_current_weight,
    v_target_weight
  FROM public.profiles
  WHERE user_id = p_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'PROFILE_NOT_FOUND';
  END IF;

  FOR v_badge_record IN SELECT * FROM public.badges LOOP
    IF EXISTS (
      SELECT 1 FROM public.user_badges
      WHERE user_id = p_user_id AND badge_id = v_badge_record.id
    ) THEN
      CONTINUE;
    END IF;

    v_requirement_met := FALSE;
    v_metric := 0;

    CASE v_badge_record.requirement_type
      WHEN 'streak_days' THEN
        v_requirement_met := v_streak_days >= v_badge_record.requirement_value;

      WHEN 'meals_logged' THEN
        v_requirement_met := v_meals_logged >= v_badge_record.requirement_value;

      WHEN 'level' THEN
        v_requirement_met := v_level >= v_badge_record.requirement_value;

      WHEN 'referrals' THEN
        v_requirement_met := v_referral_count >= v_badge_record.requirement_value;

      WHEN 'weight_goal' THEN
        v_requirement_met := v_current_weight IS NOT NULL
          AND v_target_weight IS NOT NULL
          AND v_current_weight <= v_target_weight;

      WHEN 'unique_restaurants' THEN
        SELECT COUNT(DISTINCT ms.restaurant_id)::INTEGER
        INTO v_metric
        FROM public.meal_schedules ms
        WHERE ms.user_id = p_user_id
          AND ms.restaurant_id IS NOT NULL
          AND ms.order_status IN ('delivered', 'completed');
        v_requirement_met := v_metric >= v_badge_record.requirement_value;

      WHEN 'unique_salads' THEN
        SELECT COUNT(DISTINCT ms.meal_id)::INTEGER
        INTO v_metric
        FROM public.meal_schedules ms
        JOIN public.meals m ON m.id = ms.meal_id
        WHERE ms.user_id = p_user_id
          AND ms.order_status IN ('delivered', 'completed')
          AND LOWER(m.name) LIKE '%salad%';
        v_requirement_met := v_metric >= v_badge_record.requirement_value;

      WHEN 'water_streak' THEN
        WITH qualifying_days AS (
          SELECT we.log_date
          FROM public.water_entries we
          WHERE we.user_id = p_user_id
            AND we.log_date <= CURRENT_DATE
          GROUP BY we.log_date
          HAVING SUM(GREATEST(COALESCE(we.amount_ml, 0), 0)) >= 2000
        ), grouped_days AS (
          SELECT
            log_date,
            log_date - (ROW_NUMBER() OVER (ORDER BY log_date))::INTEGER AS streak_group
          FROM qualifying_days
        )
        SELECT COALESCE(MAX(streak_length), 0)::INTEGER
        INTO v_metric
        FROM (
          SELECT COUNT(*) AS streak_length
          FROM grouped_days
          GROUP BY streak_group
        ) streaks;
        v_requirement_met := v_metric >= v_badge_record.requirement_value;

      WHEN 'protein_target_streak' THEN
        IF v_protein_target > 0 THEN
          WITH qualifying_days AS (
            SELECT pl.log_date
            FROM public.progress_logs pl
            WHERE pl.user_id = p_user_id
              AND pl.log_date <= CURRENT_DATE
              AND COALESCE(pl.protein_consumed_g, 0) >= v_protein_target
          ), grouped_days AS (
            SELECT
              log_date,
              log_date - (ROW_NUMBER() OVER (ORDER BY log_date))::INTEGER AS streak_group
            FROM qualifying_days
          )
          SELECT COALESCE(MAX(streak_length), 0)::INTEGER
          INTO v_metric
          FROM (
            SELECT COUNT(*) AS streak_length
            FROM grouped_days
            GROUP BY streak_group
          ) streaks;
          v_requirement_met := v_metric >= v_badge_record.requirement_value;
        END IF;

      WHEN 'goal_streak' THEN
        IF v_calorie_target > 0 THEN
          WITH qualifying_days AS (
            SELECT pl.log_date
            FROM public.progress_logs pl
            WHERE pl.user_id = p_user_id
              AND pl.log_date <= CURRENT_DATE
              AND COALESCE(pl.calories_consumed, 0) >= v_calorie_target
          ), grouped_days AS (
            SELECT
              log_date,
              log_date - (ROW_NUMBER() OVER (ORDER BY log_date))::INTEGER AS streak_group
            FROM qualifying_days
          )
          SELECT COALESCE(MAX(streak_length), 0)::INTEGER
          INTO v_metric
          FROM (
            SELECT COUNT(*) AS streak_length
            FROM grouped_days
            GROUP BY streak_group
          ) streaks;
          v_requirement_met := v_metric >= v_badge_record.requirement_value;
        END IF;

      WHEN 'subscription_months' THEN
        SELECT COALESCE(MAX(
          EXTRACT(YEAR FROM AGE(CURRENT_DATE, s.start_date::DATE))::INTEGER * 12
          + EXTRACT(MONTH FROM AGE(CURRENT_DATE, s.start_date::DATE))::INTEGER
        ), 0)::INTEGER
        INTO v_metric
        FROM public.subscriptions s
        WHERE s.user_id = p_user_id
          AND s.status <> 'cancelled'
          AND s.start_date::DATE <= CURRENT_DATE;
        v_requirement_met := v_metric >= v_badge_record.requirement_value;

      ELSE
        v_requirement_met := FALSE;
    END CASE;

    IF v_requirement_met THEN
      v_inserted_badge_id := NULL;
      INSERT INTO public.user_badges (user_id, badge_id)
      VALUES (p_user_id, v_badge_record.id)
      ON CONFLICT DO NOTHING
      RETURNING badge_id INTO v_inserted_badge_id;

      IF v_inserted_badge_id IS NULL THEN
        CONTINUE;
      END IF;

      PERFORM public.award_xp(
        p_user_id,
        v_badge_record.xp_reward,
        'Badge unlocked: ' || v_badge_record.name,
        'badge_unlock',
        v_badge_record.id,
        jsonb_build_object('badge_id', v_badge_record.id)
      );

      v_reward_results := v_reward_results || jsonb_build_array(public.grant_badge_reward(p_user_id, v_badge_record.id));
      v_awarded_badges := array_append(v_awarded_badges, v_badge_record.id);
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'awarded_badges', v_awarded_badges,
    'count', COALESCE(array_length(v_awarded_badges, 1), 0),
    'rewards', v_reward_results
  );
END;
$$;


ALTER FUNCTION "public"."check_and_award_badges_trusted"("p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "check_and_award_badges_trusted"("p_user_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."check_and_award_badges_trusted"("p_user_id" "uuid") IS 'Checks user stats and awards eligible badges';


--
-- Name: check_and_expire_subscriptions(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_and_expire_subscriptions"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_subscription RECORD;
  v_expired_count INTEGER := 0;
  v_recovery_count INTEGER := 0;
BEGIN
  FOR v_subscription IN
    SELECT s.id, s.user_id, s.end_date, s.tier
    FROM public.subscriptions s
    WHERE s.status = 'cancelled'
      AND s.end_date IS NOT NULL
      AND s.end_date < CURRENT_DATE
      AND s.expired_at IS NULL
    FOR UPDATE SKIP LOCKED
  LOOP
    UPDATE public.subscriptions s
    SET status = 'expired',
        active = false,
        expired_at = COALESCE(s.expired_at, now()),
        updated_at = now()
    WHERE s.id = v_subscription.id;
    v_expired_count := v_expired_count + 1;

    IF NOT EXISTS (
      SELECT 1 FROM public.subscription_recovery sr
      WHERE sr.subscription_id = v_subscription.id
        AND sr.recovery_status IN ('pending', 'offer_viewed', 'offer_accepted')
    ) THEN
      INSERT INTO public.subscription_recovery (
        user_id, subscription_id, expired_at, recovery_status,
        next_notif_due_at, reactivation_tier, created_at, updated_at
      ) VALUES (
        v_subscription.user_id, v_subscription.id,
        COALESCE(v_subscription.end_date::TIMESTAMPTZ, now()),
        'pending', now(), v_subscription.tier, now(), now()
      );
      v_recovery_count := v_recovery_count + 1;
    END IF;

    INSERT INTO public.retention_audit_logs (
      user_id, subscription_id, action_type, action_details, triggered_by
    ) VALUES (
      v_subscription.user_id, v_subscription.id, 'subscription_expired',
      jsonb_build_object('end_date', v_subscription.end_date), 'system'
    );
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'expired_subscriptions', v_expired_count,
    'recoveries_created', v_recovery_count
  );
END;
$$;


ALTER FUNCTION "public"."check_and_expire_subscriptions"() OWNER TO "postgres";

--
-- Name: check_and_reset_monthly_quota(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_and_reset_monthly_quota"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_current_month DATE;
BEGIN
    v_current_month := DATE_TRUNC('month', CURRENT_DATE);
    
    -- If month_start_date is from a previous month, reset the counter
    IF NEW.month_start_date IS NULL OR NEW.month_start_date < v_current_month THEN
        NEW.meals_used_this_month := 0;
        NEW.month_start_date := v_current_month;
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_and_reset_monthly_quota"() OWNER TO "postgres";

--
-- Name: check_coach_milestones(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_coach_milestones"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  coach_record RECORD;
  v_streak_days int;
  v_first_weight decimal;
  v_latest_weight decimal;
  v_adherence_days int;
  v_missed_meal_days int;
  v_coach_id uuid;
BEGIN
  -- Determine the client_id and context based on the trigger source table
  -- TG_TABLE_NAME holds the name of the table that fired the trigger

  -- 1. Streak milestones (trigger on user_streaks)
  IF TG_TABLE_NAME = 'user_streaks' THEN
    SELECT current_streak INTO v_streak_days
    FROM user_streaks
    WHERE user_id = NEW.user_id AND streak_type = 'logging'
    ORDER BY updated_at DESC
    LIMIT 1;

    -- Find active coaches for this client
    FOR coach_record IN
      SELECT coach_id FROM coach_client_assignments
      WHERE client_id = NEW.user_id AND status = 'active'
    LOOP
      v_coach_id := coach_record.coach_id;

      -- Streak milestones: 7, 14, 30 days
      IF v_streak_days IN (7, 14, 30) THEN
        INSERT INTO notifications (user_id, type, title, message, data)
        VALUES (
          v_coach_id,
          'coach_milestone',
          'Client streak milestone!',
          'Your client has reached a ' || v_streak_days || '-day logging streak!',
          jsonb_build_object(
            'client_id', NEW.user_id,
            'milestone_type', 'streak',
            'value', v_streak_days
          )
        );
      END IF;
    END LOOP;
  END IF;

  -- 2. Weight milestones (trigger on body_measurements)
  IF TG_TABLE_NAME = 'body_measurements' THEN
    -- Find active coaches
    FOR coach_record IN
      SELECT coach_id FROM coach_client_assignments
      WHERE client_id = NEW.user_id AND status = 'active'
    LOOP
      v_coach_id := coach_record.coach_id;

      -- Get first weight entry in the last 30 days
      SELECT weight_kg INTO v_first_weight
      FROM body_measurements
      WHERE user_id = NEW.user_id
        AND log_date >= (CURRENT_DATE - INTERVAL '30 days')
      ORDER BY log_date ASC
      LIMIT 1;

      -- Get latest weight
      SELECT weight_kg INTO v_latest_weight
      FROM body_measurements
      WHERE user_id = NEW.user_id
      ORDER BY log_date DESC
      LIMIT 1;

      IF v_first_weight IS NOT NULL AND v_latest_weight IS NOT NULL THEN
        -- Check weight milestones: -2kg, -5kg, goal reached
        IF v_first_weight - v_latest_weight >= 5 THEN
          INSERT INTO notifications (user_id, type, title, message, data)
          VALUES (
            v_coach_id,
            'coach_milestone',
            'Client weight milestone!',
            'Your client has lost 5 kg!',
            jsonb_build_object(
              'client_id', NEW.user_id,
              'milestone_type', 'weight',
              'value', ROUND((v_first_weight - v_latest_weight)::numeric, 1)
            )
          );
        ELSIF v_first_weight - v_latest_weight >= 2 THEN
          -- Only fire once per milestone
          INSERT INTO notifications (user_id, type, title, message, data)
          VALUES (
            v_coach_id,
            'coach_milestone',
            'Client weight milestone!',
            'Your client has lost 2 kg!',
            jsonb_build_object(
              'client_id', NEW.user_id,
              'milestone_type', 'weight',
              'value', 2
            )
          );
        END IF;
      END IF;
    END LOOP;
  END IF;

  -- 3. Adherence milestones (trigger on meal_schedules)
  IF TG_TABLE_NAME = 'meal_schedules' THEN
    FOR coach_record IN
      SELECT coach_id FROM coach_client_assignments
      WHERE client_id = NEW.user_id AND status = 'active'
    LOOP
      v_coach_id := coach_record.coach_id;

      -- Check last 3 days adherence
      WITH daily_adherence AS (
        SELECT
          scheduled_date::date AS day,
          COUNT(*) AS total_meals,
          COUNT(*) FILTER (WHERE order_status IN ('delivered', 'completed')) AS eaten_meals
        FROM meal_schedules
        WHERE user_id = NEW.user_id
          AND scheduled_date >= (CURRENT_DATE - INTERVAL '3 days')
        GROUP BY scheduled_date::date
      )
      SELECT COUNT(*) INTO v_adherence_days
      FROM daily_adherence
      WHERE total_meals > 0 AND (eaten_meals::float / total_meals::float) < 0.5;

      IF v_adherence_days >= 3 THEN
        INSERT INTO notifications (user_id, type, title, message, data)
        VALUES (
          v_coach_id,
          'coach_milestone',
          'Client adherence alert',
          'Your client has been below 50% meal adherence for 3 consecutive days.',
          jsonb_build_object(
            'client_id', NEW.user_id,
            'milestone_type', 'adherence',
            'value', v_adherence_days
          )
        );
      END IF;

      -- Check consecutive missed meal days
      WITH daily_meals AS (
        SELECT
          scheduled_date::date AS day,
          COUNT(*) AS total_meals
        FROM meal_schedules
        WHERE user_id = NEW.user_id
          AND scheduled_date >= (CURRENT_DATE - INTERVAL '2 days')
        GROUP BY scheduled_date::date
      )
      SELECT COUNT(*) INTO v_missed_meal_days
      FROM daily_meals
      WHERE total_meals = 0;

      IF v_missed_meal_days >= 2 THEN
        INSERT INTO notifications (user_id, type, title, message, data)
        VALUES (
          v_coach_id,
          'coach_milestone',
          'Client missed meals',
          'Your client has no scheduled meals for ' || v_missed_meal_days || ' consecutive days.',
          jsonb_build_object(
            'client_id', NEW.user_id,
            'milestone_type', 'missed_meals',
            'value', v_missed_meal_days
          )
        );
      END IF;
    END LOOP;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_coach_milestones"() OWNER TO "postgres";

--
-- Name: check_ingredient_interactions("uuid", "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_ingredient_interactions"("p_user_id" "uuid", "p_ingredient_names" "text"[]) RETURNS TABLE("interaction_id" "uuid", "active_ingredient" "text", "medication_name" "text", "food_ingredient" "text", "severity" "text", "description" "text", "recommendation" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF auth.uid() IS NULL OR p_user_id <> auth.uid() THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  IF COALESCE(cardinality(p_ingredient_names), 0) > 100 THEN
    RAISE EXCEPTION 'TOO_MANY_INGREDIENTS';
  END IF;

  RETURN QUERY
  SELECT q.*
  FROM (
    SELECT DISTINCT
      fmi.id,
      fmi.active_ingredient,
      um.medication_name,
      fmi.food_ingredient,
      fmi.severity,
      fmi.description,
      fmi.recommendation
    FROM public.user_medications um
    JOIN public.food_medicine_interactions fmi
      ON lower(fmi.active_ingredient) = lower(um.active_ingredient)
    JOIN unnest(p_ingredient_names) ing(name)
      ON lower(ing.name) LIKE '%' || lower(fmi.food_ingredient) || '%'
        OR lower(fmi.food_ingredient) LIKE '%' || lower(ing.name) || '%'
    WHERE um.user_id = p_user_id
  ) q
  ORDER BY CASE q.severity
    WHEN 'severe' THEN 1
    WHEN 'moderate' THEN 2
    WHEN 'mild' THEN 3
  END;
END;
$$;


ALTER FUNCTION "public"."check_ingredient_interactions"("p_user_id" "uuid", "p_ingredient_names" "text"[]) OWNER TO "postgres";

--
-- Name: check_meal_interactions("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_meal_interactions"("p_user_id" "uuid", "p_meal_id" "uuid") RETURNS TABLE("interaction_id" "uuid", "active_ingredient" "text", "medication_name" "text", "food_ingredient" "text", "severity" "text", "description" "text", "recommendation" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF auth.uid() IS NULL OR p_user_id <> auth.uid() THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  RETURN QUERY
  SELECT q.*
  FROM (
    SELECT DISTINCT
      fmi.id,
      fmi.active_ingredient,
      um.medication_name,
      fmi.food_ingredient,
      fmi.severity,
      fmi.description,
      fmi.recommendation
    FROM public.user_medications um
    JOIN public.food_medicine_interactions fmi
      ON lower(fmi.active_ingredient) = lower(um.active_ingredient)
    JOIN public.meal_ingredients mi
      ON lower(mi.name) LIKE '%' || lower(fmi.food_ingredient) || '%'
        OR lower(fmi.food_ingredient) LIKE '%' || lower(mi.name) || '%'
    WHERE um.user_id = p_user_id
      AND mi.meal_id = p_meal_id
  ) q
  ORDER BY CASE q.severity
    WHEN 'severe' THEN 1
    WHEN 'moderate' THEN 2
    WHEN 'mild' THEN 3
  END;
END;
$$;


ALTER FUNCTION "public"."check_meal_interactions"("p_user_id" "uuid", "p_meal_id" "uuid") OWNER TO "postgres";

--
-- Name: check_referral_milestones(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_referral_milestones"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_referral_count INTEGER;
  milestone RECORD;
  existing_achievement UUID;
BEGIN
  IF NEW.tier1_referrer_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF TG_OP = 'INSERT' OR OLD.tier1_referrer_id IS DISTINCT FROM NEW.tier1_referrer_id THEN
    PERFORM public.award_xp(
      NEW.tier1_referrer_id,
      100,
      'Friend referred',
      'friend_referred',
      NEW.user_id::text,
      jsonb_build_object('referred_user_id', NEW.user_id)
    );

    UPDATE public.profiles
    SET referral_rewards_earned = COALESCE(referral_rewards_earned, 0) + 1
    WHERE user_id = NEW.tier1_referrer_id;
  END IF;

  SELECT COUNT(*) INTO v_referral_count
  FROM public.profiles
  WHERE tier1_referrer_id = NEW.tier1_referrer_id;

  FOR milestone IN
    SELECT id, referral_count AS required_count, bonus_amount
    FROM public.referral_milestones
    WHERE is_active = true AND referral_count <= v_referral_count
    ORDER BY referral_count ASC
  LOOP
    SELECT id INTO existing_achievement
    FROM public.user_milestone_achievements
    WHERE user_id = NEW.tier1_referrer_id AND milestone_id = milestone.id;

    IF existing_achievement IS NULL THEN
      INSERT INTO public.user_milestone_achievements (user_id, milestone_id, bonus_credited, credited_at)
      VALUES (NEW.tier1_referrer_id, milestone.id, true, now());

      UPDATE public.profiles
      SET
        affiliate_balance = COALESCE(affiliate_balance, 0) + milestone.bonus_amount,
        total_affiliate_earnings = COALESCE(total_affiliate_earnings, 0) + milestone.bonus_amount
      WHERE user_id = NEW.tier1_referrer_id;
    END IF;
  END LOOP;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_referral_milestones"() OWNER TO "postgres";

--
-- Name: check_restaurant_capacity("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_restaurant_capacity"("p_restaurant_id" "uuid") RETURNS TABLE("can_accept" boolean, "current_orders" integer, "max_capacity" integer, "remaining_capacity" integer, "message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_restaurant RECORD;
    v_remaining INTEGER;
BEGIN
    -- Get restaurant capacity info
    SELECT 
        id,
        max_meals_per_day,
        current_day_orders,
        daily_reset_at
    INTO v_restaurant
    FROM public.restaurants
    WHERE id = p_restaurant_id;
    
    IF NOT FOUND THEN
        RETURN QUERY SELECT 
            FALSE, 
            0, 
            0, 
            0, 
            'Restaurant not found'::TEXT;
        RETURN;
    END IF;
    
    -- Check if we need to reset for a new day
    IF v_restaurant.daily_reset_at < date_trunc('day', NOW()) THEN
        -- Reset the count
        UPDATE public.restaurants
        SET 
            current_day_orders = 0,
            daily_reset_at = NOW()
        WHERE id = p_restaurant_id;
        
        v_restaurant.current_day_orders := 0;
    END IF;
    
    -- Calculate remaining capacity
    v_remaining := v_restaurant.max_meals_per_day - v_restaurant.current_day_orders;
    
    -- Return capacity info
    RETURN QUERY SELECT 
        v_remaining > 0,
        v_restaurant.current_day_orders,
        v_restaurant.max_meals_per_day,
        GREATEST(v_remaining, 0),
        CASE 
            WHEN v_remaining > 0 THEN 
                format('Capacity available: %s/%s orders', 
                    v_restaurant.current_day_orders, 
                    v_restaurant.max_meals_per_day)
            ELSE 
                format('Restaurant at capacity: %s/%s orders. Try again tomorrow.',
                    v_restaurant.current_day_orders,
                    v_restaurant.max_meals_per_day)
        END;
END;
$$;


ALTER FUNCTION "public"."check_restaurant_capacity"("p_restaurant_id" "uuid") OWNER TO "postgres";

