-- Name: FUNCTION "check_restaurant_capacity"("p_restaurant_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."check_restaurant_capacity"("p_restaurant_id" "uuid") IS 'Checks if restaurant can accept more orders';


--
-- Name: claim_delivery_atomic("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."claim_delivery_atomic"("p_delivery_id" "uuid", "p_driver_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_job_record RECORD;
    v_driver_record RECORD;
    v_result JSONB;
    v_lock_key BIGINT;
    v_uuid_clean TEXT;
BEGIN
    -- Remove hyphens from UUID and take first 16 chars for lock key
    v_uuid_clean := REPLACE(p_delivery_id::text, '-', '');
    
    -- Convert to bigint for advisory lock (using first 16 hex chars)
    v_lock_key := ('x' || LEFT(v_uuid_clean, 16))::bit(64)::bigint;

    -- Try to acquire advisory lock (non-blocking)
    IF NOT pg_try_advisory_xact_lock(v_lock_key) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Delivery is currently being processed by another request',
            'code', 'LOCKED',
            'delivery_id', p_delivery_id
        );
    END IF;

    -- Get delivery job with row lock
    SELECT * INTO v_job_record
    FROM delivery_jobs
    WHERE id = p_delivery_id
    FOR UPDATE SKIP LOCKED;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Delivery job not found',
            'code', 'NOT_FOUND',
            'delivery_id', p_delivery_id
        );
    END IF;

    -- Check if already assigned to another driver
    IF v_job_record.driver_id IS NOT NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Delivery already claimed by another driver',
            'code', 'ALREADY_CLAIMED',
            'delivery_id', p_delivery_id,
            'assigned_driver_id', v_job_record.driver_id
        );
    END IF;

    -- Check if job is in claimable state
    IF v_job_record.status NOT IN ('pending', 'assigned') THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Delivery is not available for claiming: ' || v_job_record.status,
            'code', 'INVALID_STATE',
            'delivery_id', p_delivery_id,
            'current_status', v_job_record.status
        );
    END IF;

    -- Verify driver exists and is online
    SELECT * INTO v_driver_record
    FROM drivers
    WHERE id = p_driver_id
    AND is_online = true
    AND is_active = true
    FOR UPDATE SKIP LOCKED;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Driver not found or not online',
            'code', 'DRIVER_UNAVAILABLE',
            'delivery_id', p_delivery_id,
            'driver_id', p_driver_id
        );
    END IF;

    -- Check if driver is already assigned to another active delivery
    IF EXISTS (
        SELECT 1 FROM delivery_jobs 
        WHERE driver_id = p_driver_id 
        AND status IN ('assigned', 'accepted', 'picked_up', 'in_transit')
        AND id != p_delivery_id
    ) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Driver is already assigned to another active delivery',
            'code', 'DRIVER_BUSY',
            'delivery_id', p_delivery_id,
            'driver_id', p_driver_id
        );
    END IF;

    -- Perform atomic claim
    BEGIN
        -- Update delivery job
        UPDATE delivery_jobs
        SET driver_id = p_driver_id,
            status = 'assigned',
            assigned_at = NOW(),
            updated_at = NOW()
        WHERE id = p_delivery_id;

        -- Return success
        SELECT jsonb_build_object(
            'success', true,
            'delivery_id', p_delivery_id,
            'driver_id', p_driver_id,
            'status', 'assigned',
            'assigned_at', NOW()
        ) INTO v_result;

        RETURN v_result;

    EXCEPTION WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', SQLERRM,
            'code', SQLSTATE,
            'delivery_id', p_delivery_id
        );
    END;
END;
$$;


ALTER FUNCTION "public"."claim_delivery_atomic"("p_delivery_id" "uuid", "p_driver_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "claim_delivery_atomic"("p_delivery_id" "uuid", "p_driver_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."claim_delivery_atomic"("p_delivery_id" "uuid", "p_driver_id" "uuid") IS 'Atomically claims a delivery job for a driver with advisory locking. Works with delivery_jobs table.';


--
-- Name: claim_delivery_job("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."claim_delivery_job"("p_job_id" "uuid", "p_driver_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_driver public.drivers%ROWTYPE;
  v_job public.delivery_jobs%ROWTYPE;
BEGIN
  IF v_actor IS NULL THEN
    RETURN jsonb_build_object('success', false, 'code', 'UNAUTHORIZED', 'error', 'Authentication required');
  END IF;

  SELECT * INTO v_driver
  FROM public.drivers
  WHERE id = p_driver_id
  FOR UPDATE;

  IF NOT FOUND OR v_driver.user_id <> v_actor THEN
    RETURN jsonb_build_object('success', false, 'code', 'UNAUTHORIZED', 'error', 'Driver identity mismatch');
  END IF;

  IF NOT COALESCE(v_driver.is_active, false)
     OR NOT COALESCE(v_driver.is_online, false)
     OR COALESCE(v_driver.approval_status::TEXT, 'pending') <> 'approved' THEN
    RETURN jsonb_build_object('success', false, 'code', 'DRIVER_UNAVAILABLE', 'error', 'Driver is not available');
  END IF;

  SELECT * INTO v_job
  FROM public.delivery_jobs
  WHERE id = p_job_id
  FOR UPDATE SKIP LOCKED;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'code', 'LOCKED', 'error', 'Delivery is currently being processed');
  END IF;

  IF v_job.status <> 'pending' THEN
    RETURN jsonb_build_object('success', false, 'code', 'INVALID_STATE', 'error', 'Delivery is no longer available');
  END IF;

  IF v_job.driver_id IS NOT NULL THEN
    RETURN jsonb_build_object('success', false, 'code', 'ALREADY_CLAIMED', 'error', 'Delivery was already claimed');
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.delivery_jobs
    WHERE driver_id = p_driver_id
      AND status IN ('assigned', 'accepted', 'picked_up', 'in_transit')
      AND id <> p_job_id
  ) THEN
    RETURN jsonb_build_object('success', false, 'code', 'DRIVER_BUSY', 'error', 'Driver already has an active delivery');
  END IF;

  PERFORM set_config('app.delivery_claim_authorized', 'true', true);

  UPDATE public.delivery_jobs
  SET driver_id = p_driver_id,
      status = 'assigned',
      assigned_at = now(),
      assignment_attempted_at = now(),
      updated_at = now()
  WHERE id = p_job_id;

  UPDATE public.drivers
  SET current_job_id = p_job_id,
      updated_at = now()
  WHERE id = p_driver_id;

  INSERT INTO public.driver_assignment_history (
    job_id, driver_id, action, reason, performed_by, performed_at
  ) VALUES (
    p_job_id, p_driver_id, 'assigned', 'Driver self-claim', v_actor, now()
  );

  RETURN jsonb_build_object('success', true, 'job_id', p_job_id, 'driver_id', p_driver_id);
END;
$$;


ALTER FUNCTION "public"."claim_delivery_job"("p_job_id" "uuid", "p_driver_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "claim_delivery_job"("p_job_id" "uuid", "p_driver_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."claim_delivery_job"("p_job_id" "uuid", "p_driver_id" "uuid") IS 'Wrapper function that uses assign_driver_with_lock for atomic delivery job claiming.
Returns standardized JSON response for frontend consumption.';


--
-- Name: claim_notification_event_deliveries(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."claim_notification_event_deliveries"("p_limit" integer DEFAULT 50, "p_lease_seconds" integer DEFAULT 120) RETURNS TABLE("delivery_id" "uuid", "notification_id" "uuid", "user_id" "uuid", "dedupe_key" "text", "attempt_count" integer, "max_attempts" integer, "lease_token" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public', 'pg_temp'
    AS $$
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RAISE EXCEPTION 'service_role_required';
  END IF;

  RETURN QUERY
  WITH candidates AS (
    SELECT delivery.id
    FROM security.notification_event_deliveries delivery
    WHERE delivery.channel = 'push'
      AND delivery.notification_id IS NOT NULL
      AND (
        (delivery.status IN ('pending', 'deferred', 'failed') AND delivery.next_attempt_at <= now())
        OR (delivery.status = 'processing' AND delivery.lease_expires_at <= now())
      )
    ORDER BY delivery.next_attempt_at, delivery.created_at, delivery.id
    FOR UPDATE SKIP LOCKED
    LIMIT GREATEST(1, LEAST(COALESCE(p_limit, 50), 250))
  ), claimed AS (
    UPDATE security.notification_event_deliveries delivery
    SET status = 'processing',
        attempt_count = LEAST(delivery.attempt_count + 1, 20),
        lease_token = gen_random_uuid(),
        lease_expires_at = now() + make_interval(secs => GREATEST(30, LEAST(COALESCE(p_lease_seconds, 120), 600))),
        last_error_code = NULL,
        updated_at = now()
    FROM candidates
    WHERE delivery.id = candidates.id
    RETURNING delivery.id, delivery.notification_id, delivery.user_id,
      delivery.dedupe_key, delivery.attempt_count, delivery.max_attempts,
      delivery.lease_token
  )
  SELECT * FROM claimed;
END;
$$;


ALTER FUNCTION "public"."claim_notification_event_deliveries"("p_limit" integer, "p_lease_seconds" integer) OWNER TO "postgres";

--
-- Name: claim_streak_reward("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."claim_streak_reward"("p_reward_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_reward public.streak_rewards%ROWTYPE;
  v_streak_days INTEGER;
  v_wallet public.customer_wallets%ROWTYPE;
  v_balance_after NUMERIC(10, 2);
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  SELECT *
    INTO v_reward
  FROM public.streak_rewards
  WHERE id = p_reward_id
    AND is_active = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'REWARD_NOT_FOUND';
  END IF;

  SELECT COALESCE(streak_days, 0)
    INTO v_streak_days
  FROM public.profiles
  WHERE user_id = v_user_id;

  IF COALESCE(v_streak_days, 0) < v_reward.streak_days THEN
    RAISE EXCEPTION 'REWARD_NOT_EARNED';
  END IF;

  INSERT INTO public.streak_rewards_claimed (
    user_id,
    reward_id,
    streak_days,
    reward_type,
    reward_value
  ) VALUES (
    v_user_id,
    v_reward.id,
    v_reward.streak_days,
    v_reward.reward_type,
    v_reward.reward_value
  )
  ON CONFLICT (user_id, reward_id) DO NOTHING;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success', TRUE,
      'already_claimed', TRUE,
      'reward_id', v_reward.id
    );
  END IF;

  IF v_reward.reward_type = 'bonus_credit' AND v_reward.reward_value > 0 THEN
    SELECT *
      INTO v_wallet
    FROM public.customer_wallets
    WHERE user_id = v_user_id
    FOR UPDATE;

    IF NOT FOUND THEN
      INSERT INTO public.customer_wallets (
        user_id, balance, total_credits, total_debits, is_active
      ) VALUES (
        v_user_id, 0, 0, 0, TRUE
      )
      RETURNING * INTO v_wallet;
    END IF;

    v_balance_after := COALESCE(v_wallet.balance, 0) + v_reward.reward_value;

    UPDATE public.customer_wallets
    SET balance = v_balance_after,
        total_credits = COALESCE(total_credits, 0) + v_reward.reward_value,
        updated_at = NOW()
    WHERE id = v_wallet.id;

    INSERT INTO public.wallet_transactions (
      wallet_id,
      user_id,
      type,
      amount,
      balance_after,
      reference_type,
      reference_id,
      description,
      metadata
    ) VALUES (
      v_wallet.id,
      v_user_id,
      'bonus',
      v_reward.reward_value,
      v_balance_after,
      'streak_reward',
      v_reward.id,
      'Streak reward',
      jsonb_build_object('streak_days', v_reward.streak_days)
    );
  END IF;

  RETURN jsonb_build_object(
    'success', TRUE,
    'already_claimed', FALSE,
    'reward_id', v_reward.id,
    'reward_type', v_reward.reward_type,
    'reward_value', v_reward.reward_value,
    'wallet_balance', v_balance_after
  );
END;
$$;


ALTER FUNCTION "public"."claim_streak_reward"("p_reward_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "claim_streak_reward"("p_reward_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."claim_streak_reward"("p_reward_id" "uuid") IS 'Validates streak eligibility and atomically fulfills the configured reward.';


