-- Name: complete_ai_coach_request("uuid", "uuid", "text", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."complete_ai_coach_request"("p_user_id" "uuid", "p_request_id" "uuid", "p_status" "text", "p_output_chars" integer DEFAULT 0) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RAISE EXCEPTION 'SERVICE_ROLE_REQUIRED';
  END IF;
  IF p_status NOT IN ('completed', 'failed') OR p_output_chars < 0 THEN
    RAISE EXCEPTION 'INVALID_AI_COMPLETION';
  END IF;

  UPDATE public.ai_coach_request_ledger
  SET status = p_status,
      output_chars = p_output_chars,
      completed_at = clock_timestamp()
  WHERE request_id = p_request_id
    AND user_id = p_user_id
    AND status = 'reserved';
END;
$$;


