--
-- Name: complete_meal_atomic("uuid", "uuid", "date", integer, integer, integer, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."complete_meal_atomic"("p_schedule_id" "uuid", "p_user_id" "uuid", "p_log_date" "date", "p_calories" integer DEFAULT 0, "p_protein_g" integer DEFAULT 0, "p_carbs_g" integer DEFAULT 0, "p_fat_g" integer DEFAULT 0, "p_fiber_g" integer DEFAULT 0) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_schedule_record RECORD;
  v_existing_progress RECORD;
  v_result JSONB;
  v_meal_name TEXT;
  v_logged_at TIMESTAMPTZ;
  v_xp_result JSONB;
  v_daily_target INTEGER;
  v_total_calories INTEGER;
  v_daily_xp_result JSONB;
BEGIN
  IF auth.uid() IS NULL OR p_user_id <> auth.uid() THEN
    RETURN jsonb_build_object('s', false, 'e', 'forbidden', 'c', 'FORBIDDEN');
  END IF;

  SELECT ms.*, m.calories, m.protein_g, m.carbs_g, m.fat_g, m.fiber_g, m.name
  INTO v_schedule_record
  FROM public.meal_schedules ms
  JOIN public.meals m ON ms.meal_id = m.id
  WHERE ms.id = p_schedule_id
    AND ms.user_id = p_user_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('s', false, 'e', 'not found', 'c', 'NOT_FOUND');
  END IF;

  IF v_schedule_record.is_completed THEN
    RETURN jsonb_build_object('s', true, 'm', 'already done', 'a', true);
  END IF;

  -- Nutrition and log date are authoritative server data. Caller-supplied
  -- values are retained in the legacy signature only for compatibility.
  p_log_date := v_schedule_record.scheduled_date::DATE;
  p_calories := COALESCE(v_schedule_record.calories, 0);
  p_protein_g := COALESCE(v_schedule_record.protein_g, 0);
  p_carbs_g := COALESCE(v_schedule_record.carbs_g, 0);
  p_fat_g := COALESCE(v_schedule_record.fat_g, 0);
  p_fiber_g := COALESCE(v_schedule_record.fiber_g, 0);

  v_meal_name := v_schedule_record.name;
  v_logged_at := now();

  SELECT *
  INTO v_existing_progress
  FROM public.progress_logs
  WHERE user_id = p_user_id
    AND log_date = p_log_date
  FOR UPDATE;

  UPDATE public.meal_schedules
  SET is_completed = true,
      completed_at = now(),
      updated_at = now()
  WHERE id = p_schedule_id;

  IF v_existing_progress IS NULL THEN
    INSERT INTO public.progress_logs (
      user_id,
      log_date,
      calories_consumed,
      protein_consumed_g,
      carbs_consumed_g,
      fat_consumed_g,
      fiber_consumed_g,
      created_at,
      updated_at
    )
    VALUES (
      p_user_id,
      p_log_date,
      p_calories,
      p_protein_g,
      p_carbs_g,
      p_fat_g,
      p_fiber_g,
      now(),
      now()
    );
  ELSE
    UPDATE public.progress_logs
    SET calories_consumed = COALESCE(calories_consumed, 0) + p_calories,
        protein_consumed_g = COALESCE(protein_consumed_g, 0) + p_protein_g,
        carbs_consumed_g = COALESCE(carbs_consumed_g, 0) + p_carbs_g,
        fat_consumed_g = COALESCE(fat_consumed_g, 0) + p_fat_g,
        fiber_consumed_g = COALESCE(fiber_consumed_g, 0) + p_fiber_g,
        updated_at = now()
    WHERE id = v_existing_progress.id;
  END IF;

  INSERT INTO public.meal_history (
    user_id,
    name,
    calories,
    protein_g,
    carbs_g,
    fat_g,
    logged_at,
    schedule_id,
    source
  )
  VALUES (
    p_user_id,
    COALESCE(v_meal_name, 'Meal'),
    p_calories,
    p_protein_g,
    p_carbs_g,
    p_fat_g,
    v_logged_at,
    p_schedule_id,
    'scheduled'
  );

  UPDATE public.profiles
  SET total_meals_logged = COALESCE(total_meals_logged, 0) + 1,
      updated_at = now()
  WHERE user_id = p_user_id;

  SELECT COALESCE(daily_calorie_target, 0)
  INTO v_daily_target
  FROM public.profiles
  WHERE user_id = p_user_id;

  SELECT COALESCE(calories_consumed, 0)
  INTO v_total_calories
  FROM public.progress_logs
  WHERE user_id = p_user_id
    AND log_date = p_log_date;

  v_xp_result := public.award_xp(
    p_user_id,
    10,
    'Scheduled meal completed',
    'meal_completed',
    p_schedule_id::text,
    jsonb_build_object('schedule_id', p_schedule_id, 'log_date', p_log_date)
  );

  IF v_daily_target > 0 AND v_total_calories >= v_daily_target THEN
    v_daily_xp_result := public.award_xp(
      p_user_id,
      25,
      'Daily nutrition goal completed',
      'daily_nutrition_complete',
      p_log_date::text,
      jsonb_build_object(
        'log_date', p_log_date,
        'calories_consumed', v_total_calories,
        'daily_calorie_target', v_daily_target
      )
    );
  END IF;

  v_result := jsonb_build_object(
    's', true,
    'id', p_schedule_id,
    'c', true,
    'a', false,
    'xp', v_xp_result,
    'daily_xp', v_daily_xp_result,
    'n', jsonb_build_object(
      'cal', p_calories,
      'pro', p_protein_g,
      'car', p_carbs_g,
      'fat', p_fat_g,
      'fib', p_fiber_g
    )
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."complete_meal_atomic"("p_schedule_id" "uuid", "p_user_id" "uuid", "p_log_date" "date", "p_calories" integer, "p_protein_g" integer, "p_carbs_g" integer, "p_fat_g" integer, "p_fiber_g" integer) OWNER TO "postgres";

--
-- Name: complete_notification_event_delivery("uuid", "uuid", boolean, boolean, "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."complete_notification_event_delivery"("p_delivery_id" "uuid", "p_lease_token" "uuid", "p_success" boolean, "p_retryable" boolean DEFAULT true, "p_error_code" "text" DEFAULT NULL::"text", "p_provider_message_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public', 'pg_temp'
    AS $$
DECLARE
  v_delivery security.notification_event_deliveries%ROWTYPE;
  v_status TEXT;
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RAISE EXCEPTION 'service_role_required';
  END IF;

  SELECT * INTO v_delivery
  FROM security.notification_event_deliveries
  WHERE id = p_delivery_id
    AND lease_token = p_lease_token
    AND status = 'processing'
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'notification_delivery_lease_invalid';
  END IF;

  IF COALESCE(p_success, false) THEN
    v_status := 'delivered';
    UPDATE security.notification_event_deliveries
    SET status = v_status,
        delivered_at = now(),
        provider_message_id = NULLIF(left(COALESCE(p_provider_message_id, ''), 250), ''),
        retryable = false,
        last_error_code = NULL,
        lease_token = NULL,
        lease_expires_at = NULL,
        analytics_event = 'notification_delivery_succeeded',
        updated_at = now()
    WHERE id = p_delivery_id;
  ELSE
    v_status := CASE
      WHEN NOT COALESCE(p_retryable, true) OR v_delivery.attempt_count >= v_delivery.max_attempts
        THEN 'dead_letter'
      ELSE 'failed'
    END;

    UPDATE security.notification_event_deliveries
    SET status = v_status,
        retryable = COALESCE(p_retryable, true),
        last_error_code = COALESCE(
          security.safe_notification_error_code(p_error_code),
          'notification_delivery_failed'
        ),
        next_attempt_at = now() + make_interval(
          secs => LEAST(21600, (60 * power(5, GREATEST(attempt_count - 1, 0)))::INTEGER)
        ),
        failed_at = now(),
        lease_token = NULL,
        lease_expires_at = NULL,
        analytics_event = CASE
          WHEN v_status = 'dead_letter' THEN 'notification_dead_lettered'
          ELSE 'notification_delivery_failed'
        END,
        updated_at = now()
    WHERE id = p_delivery_id;
  END IF;

  RETURN jsonb_build_object(
    'delivery_id', p_delivery_id,
    'status', v_status,
    'attempt_count', v_delivery.attempt_count
  );
END;
$$;


ALTER FUNCTION "public"."complete_notification_event_delivery"("p_delivery_id" "uuid", "p_lease_token" "uuid", "p_success" boolean, "p_retryable" boolean, "p_error_code" "text", "p_provider_message_id" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "complete_notification_event_delivery"("p_delivery_id" "uuid", "p_lease_token" "uuid", "p_success" boolean, "p_retryable" boolean, "p_error_code" "text", "p_provider_message_id" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."complete_notification_event_delivery"("p_delivery_id" "uuid", "p_lease_token" "uuid", "p_success" boolean, "p_retryable" boolean, "p_error_code" "text", "p_provider_message_id" "text") IS 'Completes a leased delivery with bounded exponential retry and dead-letter routing.';


--
-- Name: complete_outdoor_activity("jsonb", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."complete_outdoor_activity"("p_activity" "jsonb", "p_points" "jsonb" DEFAULT '[]'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_existing public.outdoor_activity_sessions%ROWTYPE;
  v_outdoor_id uuid;
  v_workout_id uuid;
  v_source text := trim(COALESCE(p_activity->>'source', 'gps'));
  v_fingerprint text := trim(COALESCE(p_activity->>'source_fingerprint', ''));
  v_local_id text := trim(COALESCE(p_activity->>'local_session_id', ''));
  v_type text := lower(trim(COALESCE(p_activity->>'activity_type', '')));
  v_started_at timestamptz;
  v_ended_at timestamptz;
  v_duration integer;
  v_moving integer;
  v_calories integer;
  v_point_count integer;
  v_source_external_id text;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'AUTHENTICATION_REQUIRED'; END IF;
  IF v_local_id = '' OR length(v_local_id) > 160 THEN RAISE EXCEPTION 'INVALID_LOCAL_SESSION_ID'; END IF;
  IF v_fingerprint = '' OR length(v_fingerprint) > 160 THEN RAISE EXCEPTION 'INVALID_SOURCE_FINGERPRINT'; END IF;
  IF v_type NOT IN ('walking', 'running', 'cycling') THEN RAISE EXCEPTION 'INVALID_ACTIVITY_TYPE'; END IF;
  IF v_source NOT IN ('gps', 'import_gpx', 'import_tcx', 'import_fit', 'google_fit', 'health_connect', 'apple_health') THEN
    RAISE EXCEPTION 'INVALID_ACTIVITY_SOURCE';
  END IF;
  IF jsonb_typeof(p_points) <> 'array' THEN RAISE EXCEPTION 'INVALID_ROUTE_POINTS'; END IF;

  v_point_count := jsonb_array_length(p_points);
  IF v_point_count > 20000 THEN RAISE EXCEPTION 'ROUTE_POINT_LIMIT_EXCEEDED'; END IF;
  IF v_source = 'gps' AND v_point_count < 2 THEN RAISE EXCEPTION 'ROUTE_POINTS_REQUIRED'; END IF;

  v_started_at := (p_activity->>'started_at')::timestamptz;
  v_ended_at := (p_activity->>'ended_at')::timestamptz;
  v_duration := (p_activity->>'duration_seconds')::integer;
  v_moving := COALESCE((p_activity->>'moving_seconds')::integer, v_duration);
  v_calories := COALESCE((p_activity->>'calories_burned')::integer, 0);
  IF v_ended_at < v_started_at OR v_duration <= 0 OR v_duration > 604800 THEN RAISE EXCEPTION 'INVALID_ACTIVITY_TIME'; END IF;
  IF v_moving < 0 OR v_moving > v_duration THEN RAISE EXCEPTION 'INVALID_MOVING_TIME'; END IF;

  SELECT * INTO v_existing
  FROM public.outdoor_activity_sessions
  WHERE user_id = v_user_id
    AND (local_session_id = v_local_id OR (source = v_source AND source_fingerprint = v_fingerprint))
  LIMIT 1;
  IF FOUND THEN
    RETURN jsonb_build_object(
      'success', true,
      'deduplicated', true,
      'outdoor_session_id', v_existing.id,
      'workout_session_id', v_existing.workout_session_id
    );
  END IF;

  -- Include the user in the external key because the legacy unique index is global.
  v_source_external_id := v_user_id::text || ':' || v_fingerprint;
  INSERT INTO public.workout_sessions (
    user_id, session_date, workout_type, duration_minutes, calories_burned,
    source, source_external_id, confirmed, created_at, external_metadata
  ) VALUES (
    v_user_id,
    (v_started_at AT TIME ZONE 'Asia/Qatar')::date,
    initcap(v_type),
    GREATEST(1, round(v_moving / 60.0)::integer),
    v_calories,
    'outdoor_activity',
    v_source_external_id,
    true,
    v_started_at,
    jsonb_build_object(
      'distance_m', COALESCE((p_activity->>'distance_m')::numeric, 0),
      'calorie_source', p_activity->>'calorie_source',
      'route_visibility', COALESCE(p_activity->>'route_visibility', 'private')
    )
  )
  ON CONFLICT (source, source_external_id) DO UPDATE
    SET confirmed = true
    WHERE public.workout_sessions.user_id = v_user_id
  RETURNING id INTO v_workout_id;
  IF v_workout_id IS NULL THEN RAISE EXCEPTION 'ACTIVITY_OWNERSHIP_CONFLICT'; END IF;

  INSERT INTO public.outdoor_activity_sessions (
    user_id, workout_session_id, local_session_id, source, source_fingerprint,
    activity_type, started_at, ended_at, duration_seconds, moving_seconds,
    distance_m, elevation_gain_m, average_pace_seconds_per_km,
    calories_burned, calorie_source, average_heart_rate, max_heart_rate,
    heart_rate_zones, route_visibility, auto_pause_enabled, import_format
  ) VALUES (
    v_user_id, v_workout_id, v_local_id, v_source, v_fingerprint,
    v_type, v_started_at, v_ended_at, v_duration, v_moving,
    COALESCE((p_activity->>'distance_m')::numeric, 0),
    COALESCE((p_activity->>'elevation_gain_m')::numeric, 0),
    NULLIF(p_activity->>'average_pace_seconds_per_km', '')::numeric,
    v_calories, COALESCE(p_activity->>'calorie_source', 'gps_met_estimate'),
    NULLIF(p_activity->>'average_heart_rate', '')::integer,
    NULLIF(p_activity->>'max_heart_rate', '')::integer,
    COALESCE(p_activity->'heart_rate_zones', '{}'::jsonb),
    COALESCE(p_activity->>'route_visibility', 'private'),
    COALESCE((p_activity->>'auto_pause_enabled')::boolean, true),
    NULLIF(p_activity->>'import_format', '')
  ) RETURNING id INTO v_outdoor_id;

  INSERT INTO public.outdoor_activity_route_points (
    session_id, user_id, sequence_number, recorded_at, latitude, longitude,
    accuracy_m, altitude_m, speed_mps, heading_degrees, heart_rate
  )
  SELECT
    v_outdoor_id, v_user_id, point.ordinality - 1,
    (point.value->>'recorded_at')::timestamptz,
    (point.value->>'latitude')::double precision,
    (point.value->>'longitude')::double precision,
    NULLIF(point.value->>'accuracy', '')::numeric,
    NULLIF(point.value->>'altitude', '')::numeric,
    NULLIF(point.value->>'speed', '')::numeric,
    NULLIF(point.value->>'heading', '')::numeric,
    NULLIF(point.value->>'heart_rate', '')::integer
  FROM jsonb_array_elements(p_points) WITH ORDINALITY AS point(value, ordinality);

  RETURN jsonb_build_object(
    'success', true,
    'deduplicated', false,
    'outdoor_session_id', v_outdoor_id,
    'workout_session_id', v_workout_id
  );
END;
$$;


ALTER FUNCTION "public"."complete_outdoor_activity"("p_activity" "jsonb", "p_points" "jsonb") OWNER TO "postgres";

