--
-- Name: create_delivery_for_schedule(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_delivery_for_schedule"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.order_status = 'preparing' AND OLD.order_status != 'preparing' THEN
    INSERT INTO public.deliveries (
      schedule_id,
      restaurant_id,
      user_id,
      pickup_address,
      delivery_address,
      delivery_fee,
      tip_amount
    )
    SELECT 
      NEW.id,
      m.restaurant_id,
      NEW.user_id,
      COALESCE(r.address, 'Restaurant Address'),
      COALESCE(ua.address_line1 || ' ' || COALESCE(ua.address_line2, '') || ', ' || ua.city, 'Customer Address'),
      3.00,
      0
    FROM public.meals m
    JOIN public.restaurants r ON r.id = m.restaurant_id
    LEFT JOIN public.user_addresses ua ON ua.user_id = NEW.user_id AND ua.is_default = true
    WHERE m.id = NEW.meal_id;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_delivery_for_schedule"() OWNER TO "postgres";

--
-- Name: create_delivery_from_order(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_delivery_from_order"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Only create delivery if status changed to 'preparing' and no delivery exists
  IF NEW.status = 'preparing' AND OLD.status != 'preparing' THEN
    -- Check if delivery already exists for this order
    IF NOT EXISTS (
      SELECT 1 FROM public.deliveries WHERE order_id = NEW.id
    ) THEN
      INSERT INTO public.deliveries (
        order_id,
        driver_id,
        restaurant_id,
        user_id,
        status,
        pickup_address,
        delivery_address,
        delivery_lat,
        delivery_lng,
        delivery_fee,
        tip_amount
      )
      SELECT 
        NEW.id,
        NULL, -- No driver assigned yet
        NEW.restaurant_id,
        NEW.user_id,
        'pending',
        COALESCE(r.address, 'Restaurant Address'),
        NEW.delivery_address,
        NEW.delivery_lat,
        NEW.delivery_lng,
        COALESCE(NEW.delivery_fee, 3.00),
        COALESCE(NEW.tip_amount, 0)
      FROM public.restaurants r
      WHERE r.id = NEW.restaurant_id;
      
      -- Update preparing timestamp
      NEW.preparing_at = now();
    END IF;
  END IF;
  
  -- Update timestamps based on status changes
  IF NEW.status = 'ready_for_pickup' AND OLD.status != 'ready_for_pickup' THEN
    NEW.ready_for_pickup_at = now();
  END IF;
  
  IF NEW.status = 'picked_up' AND OLD.status != 'picked_up' THEN
    NEW.picked_up_at = now();
  END IF;
  
  IF NEW.status = 'delivered' AND OLD.status != 'delivered' THEN
    NEW.delivered_at = now();
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_delivery_from_order"() OWNER TO "postgres";

--
-- Name: create_delivery_from_schedule(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_delivery_from_schedule"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.order_status = 'preparing' AND OLD.order_status != 'preparing' THEN
    -- Check if delivery already exists
    IF NOT EXISTS (
      SELECT 1 FROM public.deliveries WHERE schedule_id = NEW.id
    ) THEN
      INSERT INTO public.deliveries (
        schedule_id,
        order_id,
        driver_id,
        restaurant_id,
        user_id,
        status,
        pickup_address,
        delivery_address,
        delivery_fee,
        tip_amount
      )
      SELECT 
        NEW.id,
        NULL,
        NULL,
        m.restaurant_id,
        NEW.user_id,
        'pending',
        COALESCE(r.address, 'Restaurant Address'),
        COALESCE(ua.address_line1 || ' ' || COALESCE(ua.address_line2, '') || ', ' || ua.city, 'Customer Address'),
        COALESCE(NEW.delivery_fee, 3.00),
        0
      FROM public.meals m
      JOIN public.restaurants r ON r.id = m.restaurant_id
      LEFT JOIN public.user_addresses ua ON ua.user_id = NEW.user_id AND ua.is_default = true
      WHERE m.id = NEW.meal_id;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


