--
-- Name: create_delivery_job_on_ready(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_delivery_job_on_ready"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.order_status = 'ready' AND OLD.order_status != 'ready' THEN
    -- Check if job already exists
    IF NOT EXISTS (
      SELECT 1 FROM delivery_jobs 
      WHERE schedule_id = NEW.id
    ) THEN
      INSERT INTO delivery_jobs (schedule_id, status)
      VALUES (NEW.id, 'pending');
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


