--
-- Name: create_delivery_verification(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_delivery_verification"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
    -- Only generate code when status changes to assigned/accepted
    IF (NEW.status IN ('assigned', 'accepted')) AND 
       (OLD.status IS NULL OR OLD.status NOT IN ('assigned', 'accepted', 'picked_up')) THEN
        NEW.pickup_verification_code := generate_pickup_verification_code();
        NEW.verification_expires_at := NOW() + INTERVAL '15 minutes';
    END IF;
    
    -- Clear verification code when picked up
    IF NEW.status = 'picked_up' AND OLD.status != 'picked_up' THEN
        NEW.pickup_verification_code := NULL;
        NEW.verification_expires_at := NULL;
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_delivery_verification"() OWNER TO "postgres";

--
-- Name: create_driver_payout_for_operator("uuid", "date", "date", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_driver_payout_for_operator"("p_driver_id" "uuid", "p_period_start" "date", "p_period_end" "date", "p_request_key" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_details JSONB;
BEGIN
  IF v_actor IS NULL OR NOT (
    public.has_role(v_actor, 'admin')
    OR public.is_active_fleet_operator(v_actor)
  ) THEN
    RAISE EXCEPTION 'FLEET_OPERATOR_REQUIRED';
  END IF;

  SELECT d.payout_details INTO v_details
  FROM public.drivers d
  WHERE d.id = p_driver_id;

  IF v_details IS NULL THEN
    RAISE EXCEPTION 'DRIVER_BANK_DETAILS_REQUIRED';
  END IF;

  RETURN public.reserve_driver_payout(
    p_driver_id,
    p_request_key,
    p_period_start,
    p_period_end,
    v_details,
    v_actor
  );
END;
$$;


ALTER FUNCTION "public"."create_driver_payout_for_operator"("p_driver_id" "uuid", "p_period_start" "date", "p_period_end" "date", "p_request_key" "uuid") OWNER TO "postgres";

--
-- Name: create_initial_coach_earning(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_initial_coach_earning"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_commission NUMERIC;
BEGIN
  IF NEW.status <> 'active'
    OR NEW.payment_id IS NULL
    OR NEW.transaction_id IS NULL
    OR NOT EXISTS (
      SELECT 1
      FROM public.payments p
      WHERE p.id = NEW.payment_id
        AND p.user_id = NEW.client_id
        AND p.payment_type = 'coach_subscription'
        AND ROUND(p.amount::NUMERIC, 2) = ROUND(NEW.price::NUMERIC, 2)
    ) THEN
    RAISE EXCEPTION 'VERIFIED_COACH_PAYMENT_REQUIRED';
  END IF;

  SELECT commission_pct
    INTO v_commission
  FROM public.platform_commission_config
  ORDER BY updated_at DESC
  LIMIT 1;

  v_commission := COALESCE(v_commission, 20);

  INSERT INTO public.coach_earnings (
    coach_id,
    client_id,
    subscription_id,
    amount,
    commission_pct,
    commission_amount,
    net_amount,
    transaction_type,
    status
  ) VALUES (
    NEW.coach_id,
    NEW.client_id,
    NEW.id,
    NEW.price,
    v_commission,
    ROUND(NEW.price * v_commission / 100, 2),
    ROUND(NEW.price - (NEW.price * v_commission / 100), 2),
    'subscription',
    'pending'
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_initial_coach_earning"() OWNER TO "postgres";

--
-- Name: create_notifications_from_announcement(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_notifications_from_announcement"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_user RECORD;
    v_notification_type TEXT;
BEGIN
    -- Only create notifications if announcement is active and starting now or in the past
    IF NEW.is_active = true AND NEW.starts_at <= NOW() THEN
        -- Map announcement type to notification type
        v_notification_type := CASE NEW.type
            WHEN 'info' THEN 'general'
            WHEN 'warning' THEN 'subscription_alert'
            WHEN 'success' THEN 'order_update'
            WHEN 'error' THEN 'subscription_alert'
            ELSE 'general'
        END;

        -- Create notifications for target audience
        FOR v_user IN 
            SELECT id 
            FROM auth.users 
            WHERE id NOT IN (
                -- Exclude users who already have this notification
                SELECT user_id 
                FROM notifications 
                WHERE related_entity_id = NEW.id 
                AND related_entity_type = 'announcement'
            )
            AND CASE NEW.target_audience
                WHEN 'all' THEN true
                WHEN 'customers' THEN EXISTS (
                    SELECT 1 FROM profiles 
                    WHERE user_id = auth.users.id 
                    AND (role = 'customer' OR role = 'user' OR role IS NULL)
                )
                WHEN 'partners' THEN EXISTS (
                    SELECT 1 FROM restaurants 
                    WHERE owner_id = auth.users.id
                    AND is_active = true
                )
                WHEN 'admins' THEN EXISTS (
                    SELECT 1 FROM profiles 
                    WHERE user_id = auth.users.id 
                    AND role = 'admin'
                )
                ELSE true
            END
        LOOP
            INSERT INTO notifications (
                user_id,
                type,
                title,
                message,
                status,
                data,
                related_entity_type,
                related_entity_id
            ) VALUES (
                v_user.id,
                v_notification_type::notification_type,
                NEW.title,
                NEW.message,
                'unread',
                jsonb_build_object(
                    'announcement_id', NEW.id,
                    'announcement_type', NEW.type,
                    'target_audience', NEW.target_audience
                ),
                'announcement',
                NEW.id
            )
            ON CONFLICT DO NOTHING;
        END LOOP;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_notifications_from_announcement"() OWNER TO "postgres";

--
-- Name: create_order_notification(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_order_notification"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Only create notification if status changed
  IF NEW.status != OLD.status THEN
    INSERT INTO public.notifications (user_id, type, title, message, metadata)
    SELECT 
      NEW.user_id,
      'order_update',
      CASE NEW.status
        WHEN 'confirmed' THEN 'Order Confirmed!'
        WHEN 'preparing' THEN 'Being Prepared'
        WHEN 'driver_assigned' THEN 'Driver Assigned'
        WHEN 'picked_up' THEN 'Order Picked Up'
        WHEN 'out_for_delivery' THEN 'Out for Delivery'
        WHEN 'delivered' THEN 'Delivered!'
        ELSE 'Order Update'
      END,
      CASE NEW.status
        WHEN 'confirmed' THEN 'Your order has been confirmed and will be prepared soon.'
        WHEN 'preparing' THEN 'Your meal is now being prepared in the kitchen.'
        WHEN 'driver_assigned' THEN 'A driver has been assigned to your order.'
        WHEN 'picked_up' THEN 'Your order has been picked up and is on its way!'
        WHEN 'out_for_delivery' THEN 'Your order is out for delivery and will arrive soon.'
        WHEN 'delivered' THEN 'Your order has been delivered. Enjoy your meal!'
        ELSE 'Your order status has been updated.'
      END,
      jsonb_build_object('order_id', NEW.id, 'status', NEW.status);
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_order_notification"() OWNER TO "postgres";

--
-- Name: create_partner_application_from_signup(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_partner_application_from_signup"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_metadata jsonb := COALESCE(NEW.raw_user_meta_data, '{}'::jsonb);
  v_restaurant_name text := NULLIF(BTRIM(v_metadata ->> 'restaurant_name'), '');
BEGIN
  IF v_metadata ->> 'account_type' IS DISTINCT FROM 'partner' THEN
    RETURN NEW;
  END IF;

  IF v_restaurant_name IS NULL OR char_length(v_restaurant_name) < 2 THEN
    RAISE EXCEPTION 'PARTNER_RESTAURANT_NAME_REQUIRED';
  END IF;

  INSERT INTO public.user_roles (user_id, role)
  VALUES (NEW.id, 'partner'::public.app_role)
  ON CONFLICT (user_id, role) DO NOTHING;

  INSERT INTO public.profiles (user_id, full_name, email)
  VALUES (
    NEW.id,
    NULLIF(BTRIM(v_metadata ->> 'full_name'), ''),
    NEW.email
  )
  ON CONFLICT (user_id) DO UPDATE
  SET full_name = COALESCE(EXCLUDED.full_name, public.profiles.full_name),
      email = COALESCE(EXCLUDED.email, public.profiles.email);

  INSERT INTO public.restaurants (
    owner_id,
    name,
    description,
    phone,
    address,
    email,
    approval_status,
    is_active
  )
  SELECT
    NEW.id,
    v_restaurant_name,
    NULLIF(BTRIM(v_metadata ->> 'restaurant_description'), ''),
    NULLIF(BTRIM(v_metadata ->> 'restaurant_phone'), ''),
    NULLIF(BTRIM(v_metadata ->> 'restaurant_address'), ''),
    NEW.email,
    'pending'::public.approval_status,
    false
  WHERE NOT EXISTS (
    SELECT 1 FROM public.restaurants r WHERE r.owner_id = NEW.id
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_partner_application_from_signup"() OWNER TO "postgres";

--
-- Name: create_partner_earning(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_partner_earning"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_restaurant_id UUID;
  v_payout_amount NUMERIC(10, 2);
BEGIN
  IF NEW.order_status::TEXT <> 'delivered'
    OR (TG_OP = 'UPDATE' AND OLD.order_status::TEXT = 'delivered') THEN
    RETURN NEW;
  END IF;

  SELECT r.id, GREATEST(COALESCE(r.payout_rate, 0), 0)
  INTO v_restaurant_id, v_payout_amount
  FROM public.meals m
  JOIN public.restaurants r ON r.id = m.restaurant_id
  WHERE m.id = NEW.meal_id;

  IF v_restaurant_id IS NULL OR v_payout_amount <= 0 THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.partner_earnings (
    restaurant_id,
    meal_schedule_id,
    gross_amount,
    platform_fee,
    delivery_fee,
    net_amount,
    status
  )
  VALUES (
    v_restaurant_id,
    NEW.id,
    v_payout_amount,
    0,
    0,
    v_payout_amount,
    'pending'
  )
  ON CONFLICT (meal_schedule_id) WHERE meal_schedule_id IS NOT NULL DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_partner_earning"() OWNER TO "postgres";

--
-- Name: create_partner_order_earning(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_partner_order_earning"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_rate NUMERIC;
  v_gross NUMERIC;
  v_fee NUMERIC;
  v_net NUMERIC;
BEGIN
  IF NEW.user_id IS NULL
    OR NEW.restaurant_id IS NULL
    OR NEW.status::TEXT <> 'delivered'
    OR (TG_OP = 'UPDATE' AND OLD.status::TEXT = 'delivered') THEN
    RETURN NEW;
  END IF;

  SELECT COALESCE(r.commission_rate, 18)
  INTO v_rate
  FROM public.restaurants r
  WHERE r.id = NEW.restaurant_id;

  v_gross := GREATEST(COALESCE(NEW.total_amount, 0) - COALESCE(NEW.delivery_fee, 0), 0);
  v_fee := ROUND(v_gross * LEAST(GREATEST(COALESCE(v_rate, 18), 0), 100) / 100, 2);
  v_net := GREATEST(v_gross - v_fee, 0);

  IF v_net <= 0 THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.partner_earnings (
    restaurant_id,
    order_id,
    gross_amount,
    platform_fee,
    delivery_fee,
    net_amount,
    status
  )
  VALUES (
    NEW.restaurant_id,
    NEW.id,
    v_gross,
    v_fee,
    COALESCE(NEW.delivery_fee, 0),
    v_net,
    'pending'
  )
  ON CONFLICT (order_id) WHERE order_id IS NOT NULL DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_partner_order_earning"() OWNER TO "postgres";

--
-- Name: create_recovery_booking("uuid", "text", "date", time without time zone, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_recovery_booking"("p_partner_id" "uuid", "p_service_name" "text", "p_booking_date" "date", "p_booking_time" time without time zone, "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_today DATE := (NOW() AT TIME ZONE 'Asia/Qatar')::DATE;
  v_period_start DATE := DATE_TRUNC('month', (NOW() AT TIME ZONE 'Asia/Qatar')::DATE)::DATE;
  v_partner public.recovery_partners%ROWTYPE;
  v_service JSONB;
  v_required_credits INTEGER;
  v_booking public.recovery_bookings%ROWTYPE;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  IF p_booking_date < v_today OR p_booking_date > v_today + 90 THEN
    RAISE EXCEPTION 'RECOVERY_BOOKING_DATE_INVALID';
  END IF;

  SELECT *
    INTO v_partner
  FROM public.recovery_partners rp
  WHERE rp.id = p_partner_id
    AND rp.is_active = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'RECOVERY_PARTNER_NOT_FOUND';
  END IF;

  SELECT service
    INTO v_service
  FROM JSONB_ARRAY_ELEMENTS(COALESCE(v_partner.services, '[]'::JSONB)) AS item(service)
  WHERE service ->> 'name' = p_service_name
  LIMIT 1;

  v_required_credits := COALESCE((v_service ->> 'credits_required')::INTEGER, 0);
  IF v_service IS NULL OR v_required_credits <= 0 THEN
    RAISE EXCEPTION 'RECOVERY_SERVICE_NOT_FOUND';
  END IF;

  PERFORM public.get_or_create_recovery_credits();
  PERFORM pg_advisory_xact_lock(
    hashtextextended(
      'recovery-slot:' || p_partner_id::TEXT || ':'
        || p_booking_date::TEXT || ':' || p_booking_time::TEXT,
      0
    )
  );

  IF EXISTS (
    SELECT 1
    FROM public.recovery_bookings rb
    WHERE rb.partner_id = p_partner_id
      AND rb.booking_date = p_booking_date
      AND rb.booking_time = p_booking_time
      AND rb.status = 'booked'
  ) THEN
    RAISE EXCEPTION 'RECOVERY_SLOT_UNAVAILABLE';
  END IF;

  UPDATE public.member_recovery_credits mrc
  SET used_credits = mrc.used_credits + v_required_credits
  WHERE mrc.user_id = v_actor
    AND mrc.period_start = v_period_start
    AND mrc.used_credits + v_required_credits <= mrc.total_credits;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'INSUFFICIENT_RECOVERY_CREDITS';
  END IF;

  INSERT INTO public.recovery_bookings (
    user_id,
    partner_id,
    service_name,
    credits_used,
    booking_date,
    booking_time,
    status,
    qr_code,
    notes,
    credit_period_start
  ) VALUES (
    v_actor,
    p_partner_id,
    p_service_name,
    v_required_credits,
    p_booking_date,
    p_booking_time,
    'booked',
    'NR-' || UPPER(SUBSTRING(REPLACE(gen_random_uuid()::TEXT, '-', ''), 1, 20)),
    LEFT(NULLIF(TRIM(p_notes), ''), 500),
    v_period_start
  )
  RETURNING * INTO v_booking;

  RETURN TO_JSONB(v_booking);
END;
$$;


ALTER FUNCTION "public"."create_recovery_booking"("p_partner_id" "uuid", "p_service_name" "text", "p_booking_date" "date", "p_booking_time" time without time zone, "p_notes" "text") OWNER TO "postgres";

--
-- Name: create_wallet_topup_invoice("uuid", numeric, numeric, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_wallet_topup_invoice"("p_user_id" "uuid", "p_amount" numeric, "p_bonus_amount" numeric DEFAULT 0, "p_payment_reference" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_invoice_id UUID;
  v_invoice_number TEXT;
  v_total_amount NUMERIC(10, 2);
BEGIN
  v_invoice_number := public.generate_invoice_number('wallet_topup');
  v_total_amount := p_amount + p_bonus_amount;
  
  -- Create invoice
  INSERT INTO public.invoices (
    invoice_number,
    user_id,
    invoice_type,
    amount,
    total_amount,
    status,
    paid_at,
    metadata
  ) VALUES (
    v_invoice_number,
    p_user_id,
    'wallet_topup',
    p_amount,
    v_total_amount,
    'paid',
    now(),
    jsonb_build_object(
      'bonus_amount', p_bonus_amount,
      'payment_reference', p_payment_reference
    )
  )
  RETURNING id INTO v_invoice_id;
  
  -- Create invoice items
  INSERT INTO public.invoice_items (invoice_id, description, quantity, unit_price, total_price)
  VALUES 
    (v_invoice_id, 'Wallet Top-up', 1, p_amount, p_amount);
  
  IF p_bonus_amount > 0 THEN
    INSERT INTO public.invoice_items (invoice_id, description, quantity, unit_price, total_price)
    VALUES (v_invoice_id, 'Bonus Credit', 1, p_bonus_amount, p_bonus_amount);
  END IF;
  
  RETURN v_invoice_id;
END;
$$;


ALTER FUNCTION "public"."create_wallet_topup_invoice"("p_user_id" "uuid", "p_amount" numeric, "p_bonus_amount" numeric, "p_payment_reference" "text") OWNER TO "postgres";

--
-- Name: create_weekly_ai_check_in(smallint, smallint, smallint, smallint, numeric, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_weekly_ai_check_in"("p_energy_rating" smallint, "p_hunger_rating" smallint, "p_recovery_rating" smallint, "p_plan_adherence_rating" smallint, "p_weight_kg" numeric DEFAULT NULL::numeric, "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user_id UUID := (SELECT auth.uid());
  v_week_start DATE := CURRENT_DATE - EXTRACT(DOW FROM CURRENT_DATE)::INTEGER;
  v_current_calories INTEGER;
  v_current_protein INTEGER;
  v_current_carbs INTEGER;
  v_current_fat INTEGER;
  v_new_calories INTEGER;
  v_new_protein INTEGER;
  v_new_carbs INTEGER;
  v_new_fat INTEGER;
  v_goal_type TEXT;
  v_days_logged INTEGER := 0;
  v_days_on_target INTEGER := 0;
  v_adherence NUMERIC := 0;
  v_first_weight NUMERIC;
  v_last_weight NUMERIC;
  v_weight_count INTEGER := 0;
  v_weight_change NUMERIC;
  v_confidence NUMERIC := 0.62;
  v_summary TEXT;
  v_result JSONB;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'AUTHENTICATION_REQUIRED'; END IF;
  IF p_energy_rating NOT BETWEEN 1 AND 5
     OR p_hunger_rating NOT BETWEEN 1 AND 5
     OR p_recovery_rating NOT BETWEEN 1 AND 5
     OR p_plan_adherence_rating NOT BETWEEN 1 AND 5
     OR (p_weight_kg IS NOT NULL AND p_weight_kg NOT BETWEEN 25 AND 350)
     OR char_length(COALESCE(p_notes, '')) > 500
  THEN
    RAISE EXCEPTION 'INVALID_WEEKLY_CHECK_IN';
  END IF;

  SELECT
    COALESCE(goal.daily_calorie_target, profile.daily_calorie_target, 2000),
    COALESCE(goal.protein_target_g, profile.protein_target_g, 120),
    COALESCE(goal.carbs_target_g, profile.carbs_target_g, 250),
    COALESCE(goal.fat_target_g, profile.fat_target_g, 65),
    lower(CASE
      WHEN goal.goal_type IS NOT NULL THEN goal.goal_type::TEXT
      WHEN profile.health_goal IS NOT NULL THEN profile.health_goal::TEXT
      ELSE 'maintenance'
    END)
  INTO v_current_calories, v_current_protein, v_current_carbs, v_current_fat, v_goal_type
  FROM public.profiles AS profile
  LEFT JOIN LATERAL (
    SELECT nutrition_goal.*
    FROM public.nutrition_goals AS nutrition_goal
    WHERE nutrition_goal.user_id = profile.user_id
      AND nutrition_goal.is_active = true
    ORDER BY nutrition_goal.created_at DESC
    LIMIT 1
  ) AS goal ON true
  WHERE profile.user_id = v_user_id;

  IF v_current_calories IS NULL THEN RAISE EXCEPTION 'PROFILE_NOT_FOUND'; END IF;

  SELECT
    COUNT(DISTINCT log_date)::INTEGER,
    COUNT(DISTINCT log_date) FILTER (
      WHERE ABS(calories_consumed - v_current_calories) <= v_current_calories * 0.10
    )::INTEGER
  INTO v_days_logged, v_days_on_target
  FROM public.progress_logs
  WHERE user_id = v_user_id
    AND log_date BETWEEN v_week_start AND v_week_start + 6
    AND calories_consumed IS NOT NULL;

  v_adherence := CASE
    WHEN v_days_logged = 0 THEN 0
    ELSE LEAST(1, v_days_on_target::NUMERIC / v_days_logged)
  END;

  SELECT
    (ARRAY_AGG(weight_kg ORDER BY log_date ASC))[1],
    (ARRAY_AGG(weight_kg ORDER BY log_date DESC))[1],
    COUNT(*)::INTEGER
  INTO v_first_weight, v_last_weight, v_weight_count
  FROM public.body_measurements
  WHERE user_id = v_user_id
    AND weight_kg IS NOT NULL
    AND log_date >= CURRENT_DATE - 28;

  v_weight_change := CASE WHEN v_weight_count >= 2 THEN ROUND(v_last_weight - v_first_weight, 2) ELSE NULL END;
  v_new_calories := v_current_calories;
  v_new_protein := v_current_protein;
  v_new_carbs := v_current_carbs;
  v_new_fat := v_current_fat;

  IF v_days_logged < 3 OR p_plan_adherence_rating <= 2 THEN
    v_summary := 'There is not enough consistent data to change your targets safely. Keep the current plan and log at least three days before the next review.';
    v_confidence := 0.60;
  ELSIF p_energy_rating <= 2 OR p_recovery_rating <= 2 OR p_hunger_rating >= 4 THEN
    v_summary := 'Your energy, recovery, or hunger feedback suggests holding the current targets for another week instead of reducing intake.';
    v_confidence := 0.72;
  ELSIF v_weight_count < 2 THEN
    v_summary := 'Your meal data is useful, but a second weight check-in will make target changes more reliable. Keep the current targets this week.';
    v_confidence := 0.68;
  ELSIF v_goal_type IN ('weight_loss', 'lose', 'lose_weight') AND ABS(v_weight_change) < 0.20 AND v_adherence >= 0.50 THEN
    v_new_calories := GREATEST(1200, v_current_calories - 100);
    v_new_protein := ROUND((v_new_calories * 0.35) / 4.0);
    v_new_carbs := ROUND((v_new_calories * 0.35) / 4.0);
    v_new_fat := ROUND((v_new_calories * 0.30) / 9.0);
    v_summary := 'Your logged intake was reasonably consistent while weight stayed stable. A small 100 kcal adjustment is suggested for the next week.';
    v_confidence := 0.82;
  ELSIF v_goal_type IN ('muscle_gain', 'gain', 'gain_weight') AND ABS(v_weight_change) < 0.20 AND v_adherence >= 0.50 THEN
    v_new_calories := LEAST(4000, v_current_calories + 150);
    v_new_protein := ROUND((v_new_calories * 0.30) / 4.0);
    v_new_carbs := ROUND((v_new_calories * 0.45) / 4.0);
    v_new_fat := ROUND((v_new_calories * 0.25) / 9.0);
    v_summary := 'Your logged intake was consistent while weight stayed stable. A modest calorie increase is suggested to support your goal.';
    v_confidence := 0.82;
  ELSE
    v_summary := 'Your current targets remain aligned with the available progress data and your weekly feedback. No macro change is recommended.';
    v_confidence := 0.86;
  END IF;

  INSERT INTO public.weekly_ai_check_ins (
    user_id, week_start, energy_rating, hunger_rating, recovery_rating,
    plan_adherence_rating, weight_kg, notes, status, adjustment_id,
    current_targets, proposed_targets, review_summary, confidence,
    days_logged, adherence_rate, weight_change_kg, updated_at, resolved_at
  ) VALUES (
    v_user_id, v_week_start, p_energy_rating, p_hunger_rating, p_recovery_rating,
    p_plan_adherence_rating, p_weight_kg, NULLIF(trim(p_notes), ''), 'reviewed', NULL,
    jsonb_build_object('calories', v_current_calories, 'protein', v_current_protein, 'carbs', v_current_carbs, 'fat', v_current_fat),
    jsonb_build_object('calories', v_new_calories, 'protein', v_new_protein, 'carbs', v_new_carbs, 'fat', v_new_fat),
    v_summary, v_confidence, LEAST(v_days_logged, 7), v_adherence, v_weight_change, now(), NULL
  )
  ON CONFLICT (user_id, week_start) DO UPDATE
  SET energy_rating = EXCLUDED.energy_rating, hunger_rating = EXCLUDED.hunger_rating,
      recovery_rating = EXCLUDED.recovery_rating, plan_adherence_rating = EXCLUDED.plan_adherence_rating,
      weight_kg = EXCLUDED.weight_kg, notes = EXCLUDED.notes, status = 'reviewed', adjustment_id = NULL,
      current_targets = EXCLUDED.current_targets, proposed_targets = EXCLUDED.proposed_targets,
      review_summary = EXCLUDED.review_summary, confidence = EXCLUDED.confidence,
      days_logged = EXCLUDED.days_logged, adherence_rate = EXCLUDED.adherence_rate,
      weight_change_kg = EXCLUDED.weight_change_kg, updated_at = now(), resolved_at = NULL
  RETURNING to_jsonb(weekly_ai_check_ins) INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."create_weekly_ai_check_in"("p_energy_rating" smallint, "p_hunger_rating" smallint, "p_recovery_rating" smallint, "p_plan_adherence_rating" smallint, "p_weight_kg" numeric, "p_notes" "text") OWNER TO "postgres";

--
-- Name: credit_driver_wallet(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."credit_driver_wallet"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.status = 'delivered' AND OLD.status != 'delivered' THEN
    UPDATE public.drivers
    SET 
      wallet_balance = wallet_balance + NEW.delivery_fee + NEW.tip_amount,
      total_deliveries = total_deliveries + 1,
      updated_at = now()
    WHERE id = NEW.driver_id;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."credit_driver_wallet"() OWNER TO "postgres";

--
-- Name: credit_driver_wallet_from_delivery_job(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."credit_driver_wallet_from_delivery_job"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_amount NUMERIC(10, 2);
  v_balance NUMERIC(10, 2);
BEGIN
  IF NEW.status::TEXT <> 'delivered'
    OR OLD.status::TEXT = 'delivered'
    OR NEW.driver_id IS NULL THEN
    RETURN NEW;
  END IF;

  PERFORM 1 FROM public.drivers WHERE id = NEW.driver_id FOR UPDATE;

  IF EXISTS (
    SELECT 1
    FROM public.driver_wallet_transactions dwt
    WHERE dwt.driver_id = NEW.driver_id
      AND dwt.reference_type = 'delivery'
      AND dwt.reference_id = NEW.id
      AND dwt.type = 'credit'
  ) THEN
    RETURN NEW;
  END IF;

  v_amount := COALESCE(
    NULLIF(NEW.driver_earnings, 0),
    public.calculate_driver_earnings(
      COALESCE(NEW.delivery_fee, 0),
      COALESCE(NEW.tip_amount, 0),
      NULL,
      NEW.restaurant_id,
      NEW.estimated_distance_km,
      COALESCE(NEW.created_at, now())
    )
  );

  PERFORM set_config('app.driver_finance_authorized', 'true', true);

  UPDATE public.drivers
  SET wallet_balance = COALESCE(wallet_balance, 0) + v_amount,
      total_earnings = COALESCE(total_earnings, 0) + v_amount,
      total_deliveries = COALESCE(total_deliveries, 0) + 1,
      updated_at = now()
  WHERE id = NEW.driver_id
  RETURNING wallet_balance INTO v_balance;

  INSERT INTO public.driver_wallet_transactions (
    driver_id,
    type,
    amount,
    balance_after,
    reference_type,
    reference_id,
    description,
    metadata
  )
  VALUES (
    NEW.driver_id,
    'credit',
    v_amount,
    v_balance,
    'delivery',
    NEW.id,
    'Delivery earnings',
    jsonb_build_object('delivery_job_id', NEW.id)
  )
  ON CONFLICT DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."credit_driver_wallet_from_delivery_job"() OWNER TO "postgres";

--
-- Name: credit_driver_wallet_from_jobs(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."credit_driver_wallet_from_jobs"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Only process when status changes TO 'completed' or 'delivered'
  IF NEW.status IN ('completed', 'delivered') AND 
     (OLD.status IS NULL OR OLD.status NOT IN ('completed', 'delivered')) THEN
    -- Credit driver wallet with the driver_earnings amount
    UPDATE public.drivers
    SET 
      wallet_balance = COALESCE(wallet_balance, 0) + COALESCE(NEW.driver_earnings, 0),
      total_deliveries = COALESCE(total_deliveries, 0) + 1,
      updated_at = NOW()
    WHERE id = NEW.driver_id;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."credit_driver_wallet_from_jobs"() OWNER TO "postgres";

--
-- Name: FUNCTION "credit_driver_wallet_from_jobs"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."credit_driver_wallet_from_jobs"() IS 'Credits driver wallet_balance when a delivery_job is marked as delivered';


--
-- Name: credit_wallet("uuid", numeric, "text", "text", "uuid", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."credit_wallet"("p_user_id" "uuid", "p_amount" numeric, "p_type" "text", "p_reference_type" "text" DEFAULT NULL::"text", "p_reference_id" "uuid" DEFAULT NULL::"uuid", "p_description" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_transaction_id UUID;
  v_wallet_id UUID;
  v_new_balance NUMERIC;
BEGIN
  IF p_amount <= 0 THEN
    RAISE EXCEPTION 'Credit amount must be positive';
  END IF;

  INSERT INTO public.customer_wallets (user_id, balance, total_credits, total_debits, is_active)
  VALUES (p_user_id, 0, 0, 0, true)
  ON CONFLICT (user_id) DO NOTHING;

  UPDATE public.customer_wallets
  SET balance = COALESCE(balance, 0) + p_amount,
      total_credits = COALESCE(total_credits, 0) + p_amount,
      updated_at = now()
  WHERE user_id = p_user_id AND COALESCE(is_active, true)
  RETURNING id, balance INTO v_wallet_id, v_new_balance;

  IF v_wallet_id IS NULL THEN
    RAISE EXCEPTION 'Wallet not found or inactive';
  END IF;

  INSERT INTO public.wallet_transactions (
    wallet_id, user_id, type, amount, balance_after,
    reference_type, reference_id, description, metadata
  ) VALUES (
    v_wallet_id, p_user_id, p_type, p_amount, v_new_balance,
    p_reference_type, p_reference_id, p_description, COALESCE(p_metadata, '{}'::JSONB)
  ) RETURNING id INTO v_transaction_id;

  RETURN v_transaction_id;
END;
$$;


ALTER FUNCTION "public"."credit_wallet"("p_user_id" "uuid", "p_amount" numeric, "p_type" "text", "p_reference_type" "text", "p_reference_id" "uuid", "p_description" "text", "p_metadata" "jsonb") OWNER TO "postgres";

--
-- Name: customer_confirm_order_received("text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."customer_confirm_order_received"("p_source" "text", "p_order_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_schedule public.meal_schedules%ROWTYPE;
  v_order public.orders%ROWTYPE;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  IF p_source = 'meal_schedule' THEN
    SELECT ms.*
      INTO v_schedule
    FROM public.meal_schedules ms
    WHERE ms.id = p_order_id
      AND ms.user_id = v_actor
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'ORDER_NOT_FOUND_OR_ACCESS_DENIED';
    END IF;
    IF v_schedule.order_status <> 'delivered' THEN
      RAISE EXCEPTION 'ORDER_MUST_BE_DELIVERED_FIRST';
    END IF;

    PERFORM public.update_order_status(p_order_id, 'completed', 'customer');
    RETURN jsonb_build_object(
      'success', TRUE,
      'source', p_source,
      'order_id', p_order_id,
      'status', 'completed'
    );
  END IF;

  IF p_source <> 'order' THEN
    RAISE EXCEPTION 'INVALID_ORDER_SOURCE';
  END IF;

  SELECT o.*
    INTO v_order
  FROM public.orders o
  WHERE o.id = p_order_id
    AND o.user_id = v_actor
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'ORDER_NOT_FOUND_OR_ACCESS_DENIED';
  END IF;
  IF v_order.status <> 'delivered' THEN
    RAISE EXCEPTION 'ORDER_MUST_BE_DELIVERED_FIRST';
  END IF;

  -- The ownership and state checks above authorize this narrow transition.
  PERFORM set_config('request.jwt.claim.role', 'service_role', TRUE);

  UPDATE public.delivery_jobs
  SET status = 'completed',
      updated_at = NOW()
  WHERE order_id = p_order_id
    AND status = 'delivered';

  UPDATE public.orders
  SET status = 'completed',
      updated_at = NOW()
  WHERE id = p_order_id;

  RETURN jsonb_build_object(
    'success', TRUE,
    'source', p_source,
    'order_id', p_order_id,
    'status', 'completed'
  );
END;
$$;


ALTER FUNCTION "public"."customer_confirm_order_received"("p_source" "text", "p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: deactivate_old_push_tokens("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."deactivate_old_push_tokens"("p_user_id" "uuid", "p_keep_count" integer DEFAULT 5) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_deactivated_count INTEGER;
BEGIN
  WITH tokens_to_deactivate AS (
    SELECT id
    FROM public.push_tokens
    WHERE user_id = p_user_id
      AND is_active = true
    ORDER BY last_used_at DESC
    OFFSET p_keep_count
  )
  UPDATE public.push_tokens
  SET is_active = false,
      updated_at = now()
  WHERE id IN (SELECT id FROM tokens_to_deactivate);
  
  GET DIAGNOSTICS v_deactivated_count = ROW_COUNT;
  RETURN v_deactivated_count;
END;
$$;


ALTER FUNCTION "public"."deactivate_old_push_tokens"("p_user_id" "uuid", "p_keep_count" integer) OWNER TO "postgres";

--
-- Name: debit_wallet("uuid", numeric, "text", "uuid", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."debit_wallet"("p_user_id" "uuid", "p_amount" numeric, "p_reference_type" "text" DEFAULT NULL::"text", "p_reference_id" "uuid" DEFAULT NULL::"uuid", "p_description" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor_id UUID := auth.uid();
  v_is_service BOOLEAN := COALESCE(auth.role(), '') = 'service_role';
  v_wallet public.customer_wallets%ROWTYPE;
  v_balance_after NUMERIC(10, 2);
  v_transaction_id UUID;
BEGIN
  IF NOT v_is_service AND (v_actor_id IS NULL OR p_user_id <> v_actor_id) THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  IF p_amount IS NULL OR p_amount <= 0 THEN
    RAISE EXCEPTION 'INVALID_WALLET_AMOUNT';
  END IF;

  SELECT *
    INTO v_wallet
  FROM public.customer_wallets
  WHERE user_id = p_user_id
    AND is_active = TRUE
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'WALLET_NOT_FOUND';
  END IF;

  IF COALESCE(v_wallet.balance, 0) < p_amount THEN
    RAISE EXCEPTION 'INSUFFICIENT_WALLET_BALANCE';
  END IF;

  v_balance_after := v_wallet.balance - p_amount;

  UPDATE public.customer_wallets
  SET balance = v_balance_after,
      total_debits = COALESCE(total_debits, 0) + p_amount,
      updated_at = NOW()
  WHERE id = v_wallet.id;

  INSERT INTO public.wallet_transactions (
    wallet_id,
    user_id,
    type,
    amount,
    balance_after,
    reference_type,
    reference_id,
    description,
    metadata
  ) VALUES (
    v_wallet.id,
    p_user_id,
    'debit',
    p_amount,
    v_balance_after,
    p_reference_type,
    p_reference_id,
    p_description,
    p_metadata
  )
  RETURNING id INTO v_transaction_id;

  RETURN v_transaction_id;
END;
$$;


ALTER FUNCTION "public"."debit_wallet"("p_user_id" "uuid", "p_amount" numeric, "p_reference_type" "text", "p_reference_id" "uuid", "p_description" "text", "p_metadata" "jsonb") OWNER TO "postgres";

--
-- Name: decline_delivery_assignment("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."decline_delivery_assignment"("p_queue_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_queue_record RECORD;
  v_driver_id UUID;
BEGIN
  -- Get driver ID from auth
  SELECT id INTO v_driver_id
  FROM public.drivers
  WHERE user_id = auth.uid();
  
  IF v_driver_id IS NULL THEN
    RAISE EXCEPTION 'User is not a registered driver';
  END IF;
  
  -- Get queue item
  SELECT * INTO v_queue_record
  FROM public.delivery_queue
  WHERE id = p_queue_id
    AND assigned_driver_id = v_driver_id
    AND status = 'assigned'
  FOR UPDATE;
  
  IF v_queue_record IS NULL THEN
    RAISE EXCEPTION 'Delivery assignment not found or not assigned to you';
  END IF;
  
  -- Decline assignment - return to waiting queue
  UPDATE public.delivery_queue
  SET 
    status = 'waiting',
    assigned_driver_id = NULL,
    assigned_at = NULL,
    expires_at = now() + interval '30 minutes',
    metadata = jsonb_set(
      COALESCE(metadata, '{}'::jsonb),
      '{decline_reasons}',
      COALESCE(metadata->'decline_reasons', '[]'::jsonb) || jsonb_build_array(p_reason)
    ),
    updated_at = now()
  WHERE id = p_queue_id;
  
  -- Clear driver from order
  UPDATE public.orders
  SET 
    driver_id = NULL,
    status = 'preparing',
    updated_at = now()
  WHERE id = v_queue_record.order_id;
  
  RETURN true;
END;
$$;


ALTER FUNCTION "public"."decline_delivery_assignment"("p_queue_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: decrement_addon_usage("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."decrement_addon_usage"("addon_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_restaurant_id uuid;
BEGIN
  SELECT restaurant_id INTO v_restaurant_id FROM public.restaurant_addons WHERE id = addon_id;
  IF v_restaurant_id IS NULL OR NOT (
    auth.role() = 'service_role'
    OR public.has_role(auth.uid(), 'admin'::public.app_role)
    OR public.is_restaurant_operator(v_restaurant_id, auth.uid())
  ) THEN
    RAISE EXCEPTION 'RESTAURANT_OPERATOR_REQUIRED';
  END IF;
  UPDATE public.restaurant_addons SET usage_count = GREATEST(usage_count - 1, 0) WHERE id = addon_id;
END;
$$;


ALTER FUNCTION "public"."decrement_addon_usage"("addon_id" "uuid") OWNER TO "postgres";

--
-- Name: decrement_monthly_meal_usage("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."decrement_monthly_meal_usage"("p_subscription_id" "uuid", "p_count" integer DEFAULT 1) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
IF NOT EXISTS (SELECT 1 FROM subscriptions WHERE id = p_subscription_id) THEN RAISE EXCEPTION 'subscription not found'; END IF;
UPDATE subscriptions SET meals_used_this_month = GREATEST(0, COALESCE(meals_used_this_month, 0) - p_count), meals_used_this_week = GREATEST(0, COALESCE(meals_used_this_week, 0) - p_count) WHERE id = p_subscription_id;
RETURN true;
END;
$$;


ALTER FUNCTION "public"."decrement_monthly_meal_usage"("p_subscription_id" "uuid", "p_count" integer) OWNER TO "postgres";

