--
-- Name: delete_meal_entry_atomic("uuid", "uuid", "text", integer, integer, integer, integer, timestamp with time zone, "uuid", "date", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."delete_meal_entry_atomic"("p_user_id" "uuid", "p_meal_history_id" "uuid", "p_meal_name" "text", "p_calories" integer DEFAULT 0, "p_protein_g" integer DEFAULT 0, "p_carbs_g" integer DEFAULT 0, "p_fat_g" integer DEFAULT 0, "p_logged_at" timestamp with time zone DEFAULT "now"(), "p_schedule_id" "uuid" DEFAULT NULL::"uuid", "p_scheduled_date" "date" DEFAULT NULL::"date", "p_xp_amount" integer DEFAULT 10) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_history public.meal_history%ROWTYPE;
  v_log_date DATE;
  v_audit_id UUID;
  v_xp_deducted INTEGER := 0;
BEGIN
  IF v_user_id IS NULL OR p_user_id IS DISTINCT FROM v_user_id THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  SELECT *
  INTO v_history
  FROM public.meal_history mh
  WHERE mh.id = p_meal_history_id
    AND mh.user_id = v_user_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'MEAL_HISTORY_NOT_FOUND';
  END IF;

  v_log_date := (COALESCE(v_history.logged_at, v_history.created_at, NOW()) AT TIME ZONE 'Asia/Qatar')::DATE;

  UPDATE public.progress_logs
  SET calories_consumed = GREATEST(0, COALESCE(calories_consumed, 0) - COALESCE(v_history.calories, 0)),
      protein_consumed_g = GREATEST(0, COALESCE(protein_consumed_g, 0) - COALESCE(v_history.protein_g, 0)),
      carbs_consumed_g = GREATEST(0, COALESCE(carbs_consumed_g, 0) - COALESCE(v_history.carbs_g, 0)),
      fat_consumed_g = GREATEST(0, COALESCE(fat_consumed_g, 0) - COALESCE(v_history.fat_g, 0)),
      updated_at = NOW()
  WHERE user_id = v_user_id
    AND log_date = v_log_date;

  IF v_history.schedule_id IS NOT NULL THEN
    UPDATE public.meal_schedules
    SET is_completed = FALSE,
        completed_at = NULL,
        updated_at = NOW()
    WHERE id = v_history.schedule_id
      AND user_id = v_user_id;
  END IF;

  INSERT INTO public.meal_history_audit (
    user_id,
    meal_history_id,
    meal_name,
    calories,
    protein_g,
    carbs_g,
    fat_g,
    logged_at,
    action
  )
  VALUES (
    v_user_id,
    v_history.id,
    v_history.name,
    v_history.calories,
    v_history.protein_g,
    v_history.carbs_g,
    v_history.fat_g,
    v_history.logged_at,
    'delete'
  )
  RETURNING id INTO v_audit_id;

  DELETE FROM public.meal_history
  WHERE id = v_history.id;

  IF EXISTS (
    SELECT 1
    FROM public.xp_transactions xt
    WHERE xt.user_id = v_user_id
      AND xt.action_type = 'manual_meal_log'
      AND xt.source_id = v_history.id::TEXT
      AND xt.xp_amount > 0
  ) THEN
    PERFORM public.award_xp(
      v_user_id,
      -10,
      'Meal log deleted',
      'manual_meal_deleted',
      v_history.id::TEXT,
      jsonb_build_object('meal_history_id', v_history.id)
    );
    v_xp_deducted := 10;
  ELSIF v_history.schedule_id IS NOT NULL AND EXISTS (
    SELECT 1
    FROM public.xp_transactions xt
    WHERE xt.user_id = v_user_id
      AND xt.action_type = 'meal_completed'
      AND xt.source_id = v_history.schedule_id::TEXT
      AND xt.xp_amount > 0
  ) THEN
    PERFORM public.award_xp(
      v_user_id,
      -10,
      'Scheduled meal log deleted',
      'meal_uncompleted',
      v_history.schedule_id::TEXT,
      jsonb_build_object('schedule_id', v_history.schedule_id)
    );
    v_xp_deducted := 10;
  END IF;

  UPDATE public.profiles p
  SET total_meals_logged = counts.meal_count,
      updated_at = NOW()
  FROM (
    SELECT COUNT(*)::INTEGER AS meal_count
    FROM public.meal_history mh
    WHERE mh.user_id = v_user_id
  ) counts
  WHERE p.user_id = v_user_id;

  RETURN jsonb_build_object(
    'success', TRUE,
    'audit_id', v_audit_id,
    'xp_deducted', v_xp_deducted,
    'meal_deleted', v_history.name
  );
END;
$$;


ALTER FUNCTION "public"."delete_meal_entry_atomic"("p_user_id" "uuid", "p_meal_history_id" "uuid", "p_meal_name" "text", "p_calories" integer, "p_protein_g" integer, "p_carbs_g" integer, "p_fat_g" integer, "p_logged_at" timestamp with time zone, "p_schedule_id" "uuid", "p_scheduled_date" "date", "p_xp_amount" integer) OWNER TO "postgres";

--
-- Name: delete_meal_review("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."delete_meal_review"("p_review_id" "uuid", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_user_id);
  RETURN public.delete_meal_review_trusted(p_review_id, p_user_id);
END;
$$;


ALTER FUNCTION "public"."delete_meal_review"("p_review_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: delete_meal_review_trusted("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."delete_meal_review_trusted"("p_review_id" "uuid", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    -- Verify ownership
    IF NOT EXISTS (
        SELECT 1 FROM meal_reviews 
        WHERE id = p_review_id AND user_id = p_user_id
    ) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Review not found or not authorized',
            'code', 'NOT_AUTHORIZED'
        );
    END IF;
    
    DELETE FROM meal_reviews WHERE id = p_review_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'message', 'Review deleted successfully'
    );
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM,
        'code', SQLSTATE
    );
END;
$$;


ALTER FUNCTION "public"."delete_meal_review_trusted"("p_review_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: detect_weight_plateau("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."detect_weight_plateau"("p_user_id" "uuid", "p_weeks_threshold" integer) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_user_id);
  RETURN public.detect_weight_plateau_trusted(p_user_id, p_weeks_threshold);
END;
$$;


ALTER FUNCTION "public"."detect_weight_plateau"("p_user_id" "uuid", "p_weeks_threshold" integer) OWNER TO "postgres";

--
-- Name: detect_weight_plateau_trusted("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."detect_weight_plateau_trusted"("p_user_id" "uuid", "p_weeks_threshold" integer DEFAULT 3) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_first_weight DECIMAL;
  v_latest_weight DECIMAL;
  v_weeks_logged INTEGER;
BEGIN
  SELECT 
    MIN(weight_kg),
    MAX(weight_kg),
    COUNT(DISTINCT DATE_TRUNC('week', log_date))
  INTO v_first_weight, v_latest_weight, v_weeks_logged
  FROM progress_logs
  WHERE user_id = p_user_id
    AND weight_kg IS NOT NULL
    AND log_date >= CURRENT_DATE - INTERVAL '12 weeks';

  RETURN v_weeks_logged >= p_weeks_threshold 
    AND ABS(COALESCE(v_latest_weight, 0) - COALESCE(v_first_weight, 0)) < 0.5;
END;
$$;


ALTER FUNCTION "public"."detect_weight_plateau_trusted"("p_user_id" "uuid", "p_weeks_threshold" integer) OWNER TO "postgres";

--
-- Name: dismiss_recovery("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."dismiss_recovery"("p_subscription_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_recovery_id UUID;
BEGIN
  SELECT user_id INTO v_user_id FROM public.subscriptions WHERE id = p_subscription_id;
  IF v_user_id IS NULL THEN RETURN jsonb_build_object('success', false, 'error', 'Subscription not found'); END IF;
  IF auth.uid() IS NULL OR auth.uid() <> v_user_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authorized');
  END IF;

  UPDATE public.subscription_recovery
  SET recovery_status = 'dismissed', updated_at = now()
  WHERE id = (
    SELECT sr.id FROM public.subscription_recovery sr
    WHERE sr.user_id = v_user_id
      AND sr.subscription_id = p_subscription_id
      AND sr.recovery_status IN ('pending', 'offer_viewed')
    ORDER BY sr.created_at DESC LIMIT 1
  ) RETURNING id INTO v_recovery_id;

  IF v_recovery_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'No active recovery found');
  END IF;

  INSERT INTO public.retention_audit_logs
    (user_id, subscription_id, action_type, action_details, triggered_by, triggered_by_user_id)
  VALUES
    (v_user_id, p_subscription_id, 'recovery_dismissed',
     jsonb_build_object('recovery_id', v_recovery_id), 'user', auth.uid());

  RETURN jsonb_build_object('success', true, 'message', 'Recovery dismissed');
END;
$$;


ALTER FUNCTION "public"."dismiss_recovery"("p_subscription_id" "uuid") OWNER TO "postgres";

--
-- Name: emit_domain_event("text", "text", "uuid", "uuid", "text", "jsonb", "uuid", "uuid", "uuid", "text", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."emit_domain_event"("p_event_type" "text", "p_aggregate_type" "text", "p_aggregate_id" "uuid", "p_audience_user_id" "uuid", "p_idempotency_key" "text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_actor_id" "uuid" DEFAULT NULL::"uuid", "p_correlation_id" "uuid" DEFAULT NULL::"uuid", "p_causation_id" "uuid" DEFAULT NULL::"uuid", "p_privacy_classification" "text" DEFAULT 'standard'::"text", "p_occurred_at" timestamp with time zone DEFAULT "now"()) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public', 'pg_temp'
    AS $$
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RAISE EXCEPTION 'service_role_required';
  END IF;

  RETURN security.enqueue_domain_event(
    p_event_type, p_aggregate_type, p_aggregate_id, p_audience_user_id,
    p_idempotency_key, p_payload, p_actor_id, p_correlation_id,
    p_causation_id, p_privacy_classification, p_occurred_at
  );
END;
$$;


