--
-- Name: escalate_to_manual_assignment("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."escalate_to_manual_assignment"("p_queue_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  UPDATE public.delivery_queue
  SET 
    status = 'manual_escalation',
    escalation_reason = p_reason,
    escalated_at = now(),
    escalated_by = auth.uid(),
    updated_at = now()
  WHERE id = p_queue_id
    AND status IN ('waiting', 'assigned', 'expired');
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Queue item not found or cannot be escalated';
  END IF;
  
  RETURN true;
END;
$$;


