-- Name: generate_weekly_report("uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."generate_weekly_report"("p_user_id" "uuid", "p_week_start" "date") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_user_id);
  RETURN public.generate_weekly_report_trusted(p_user_id, p_week_start);
END;
$$;


ALTER FUNCTION "public"."generate_weekly_report"("p_user_id" "uuid", "p_week_start" "date") OWNER TO "postgres";

--
-- Name: generate_weekly_report_trusted("uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."generate_weekly_report_trusted"("p_user_id" "uuid", "p_week_start" "date") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_report_id UUID;
    v_week_end DATE;
    v_avg_calories DECIMAL(8,2);
    v_avg_protein DECIMAL(6,2);
    v_avg_carbs DECIMAL(6,2);
    v_avg_fat DECIMAL(6,2);
    v_days_logged INTEGER;
    v_goal_calories INTEGER;
BEGIN
    v_week_end := p_week_start + INTERVAL '6 days';
    
    -- Get user's calorie goal
    SELECT daily_calorie_target INTO v_goal_calories
    FROM public.nutrition_goals
    WHERE user_id = p_user_id AND is_active = true
    LIMIT 1;
    
    IF v_goal_calories IS NULL THEN
        v_goal_calories := 2000;
    END IF;
    
    -- Calculate averages
    SELECT 
        AVG(calories_consumed),
        AVG(protein_consumed_g),
        AVG(carbs_consumed_g),
        AVG(fat_consumed_g),
        COUNT(*)
    INTO v_avg_calories, v_avg_protein, v_avg_carbs, v_avg_fat, v_days_logged
    FROM public.progress_logs
    WHERE user_id = p_user_id
    AND log_date >= p_week_start
    AND log_date <= v_week_end;
    
    -- Insert or update report
    INSERT INTO public.weekly_nutrition_reports (
        user_id,
        week_start_date,
        week_end_date,
        avg_calories,
        avg_protein,
        avg_carbs,
        avg_fat,
        days_logged,
        days_on_target,
        consistency_score,
        report_data
    )
    VALUES (
        p_user_id,
        p_week_start,
        v_week_end,
        COALESCE(v_avg_calories, 0),
        COALESCE(v_avg_protein, 0),
        COALESCE(v_avg_carbs, 0),
        COALESCE(v_avg_fat, 0),
        v_days_logged,
        0,
        0,
        jsonb_build_object(
            'goal_calories', v_goal_calories,
            'variance', COALESCE(v_avg_calories, 0) - v_goal_calories
        )
    )
    ON CONFLICT (user_id, week_start_date)
    DO UPDATE SET
        avg_calories = EXCLUDED.avg_calories,
        avg_protein = EXCLUDED.avg_protein,
        avg_carbs = EXCLUDED.avg_carbs,
        avg_fat = EXCLUDED.avg_fat,
        days_logged = EXCLUDED.days_logged,
        report_data = EXCLUDED.report_data,
        generated_at = NOW()
    RETURNING id INTO v_report_id;
    
    RETURN v_report_id;
END;
$$;


ALTER FUNCTION "public"."generate_weekly_report_trusted"("p_user_id" "uuid", "p_week_start" "date") OWNER TO "postgres";

