CREATE OR REPLACE FUNCTION "public"."get_active_challenges"("p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "title" "text", "description" "text", "challenge_type" "text", "difficulty_level" "text", "category" "text", "target_value" integer, "reward_points" integer, "xp_reward" integer, "wallet_reward_amount" numeric, "participant_count" integer, "start_date" "date", "end_date" "date", "is_joined" boolean, "user_progress" integer, "user_rank" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id uuid := COALESCE(p_user_id, auth.uid());
BEGIN
  PERFORM public.assert_self_or_admin(v_user_id);
  RETURN QUERY SELECT * FROM public.get_active_challenges_trusted(v_user_id);
END;
$$;


ALTER FUNCTION "public"."get_active_challenges"("p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: get_active_challenges_trusted("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_active_challenges_trusted"("p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "title" "text", "description" "text", "challenge_type" "text", "difficulty_level" "text", "category" "text", "target_value" integer, "reward_points" integer, "xp_reward" integer, "wallet_reward_amount" numeric, "participant_count" integer, "start_date" "date", "end_date" "date", "is_joined" boolean, "user_progress" integer, "user_rank" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    cc.id,
    cc.title,
    cc.description,
    cc.challenge_type::TEXT,
    cc.difficulty_level::TEXT,
    cc.category::TEXT,
    cc.target_value::INTEGER,
    cc.reward_points::INTEGER,
    cc.xp_reward::INTEGER,
    cc.wallet_reward_amount,
    cc.participant_count::INTEGER,
    cc.start_date::DATE,
    cc.end_date::DATE,
    p_user_id IS NOT NULL AND EXISTS (
      SELECT 1
      FROM public.challenge_participants cp2
      WHERE cp2.challenge_id = cc.id
        AND cp2.user_id = p_user_id
    ) AS is_joined,
    COALESCE(cp.current_progress, 0)::INTEGER AS user_progress,
    COALESCE(cl.rank, 0)::INTEGER AS user_rank
  FROM public.community_challenges cc
  LEFT JOIN public.challenge_participants cp ON cc.id = cp.challenge_id AND cp.user_id = p_user_id
  LEFT JOIN public.challenge_leaderboard cl ON cc.id = cl.challenge_id AND cl.user_id = p_user_id
  WHERE cc.is_active = true
    AND cc.start_date <= CURRENT_DATE
    AND cc.end_date >= CURRENT_DATE
  ORDER BY cc.start_date DESC;
END;
$$;


ALTER FUNCTION "public"."get_active_challenges_trusted"("p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: get_affiliate_leaderboard_earnings(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_affiliate_leaderboard_earnings"("limit_count" integer DEFAULT 10) RETURNS TABLE("id" "uuid", "full_name" "text", "avatar_url" "text", "total_affiliate_earnings" numeric, "affiliate_tier" "text", "referral_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    p.id,
    p.full_name,
    p.avatar_url,
    COALESCE(p.total_affiliate_earnings, 0) as total_affiliate_earnings,
    COALESCE(p.affiliate_tier, 'bronze') as affiliate_tier,
    (
      SELECT COUNT(*)::BIGINT 
      FROM profiles ref 
      WHERE ref.tier1_referrer_id = p.user_id
    ) as referral_count
  FROM profiles p
  WHERE COALESCE(p.total_affiliate_earnings, 0) > 0
  ORDER BY p.total_affiliate_earnings DESC NULLS LAST
  LIMIT limit_count;
END;
$$;


ALTER FUNCTION "public"."get_affiliate_leaderboard_earnings"("limit_count" integer) OWNER TO "postgres";

