-- Name: get_affiliate_leaderboard_referrals(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_affiliate_leaderboard_referrals"("limit_count" integer DEFAULT 10) RETURNS TABLE("id" "uuid", "full_name" "text", "avatar_url" "text", "total_affiliate_earnings" numeric, "affiliate_tier" "text", "referral_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    p.id,
    p.full_name,
    p.avatar_url,
    COALESCE(p.total_affiliate_earnings, 0) as total_affiliate_earnings,
    COALESCE(p.affiliate_tier, 'bronze') as affiliate_tier,
    (
      SELECT COUNT(*)::BIGINT 
      FROM profiles ref 
      WHERE ref.tier1_referrer_id = p.user_id
    ) as referral_count
  FROM profiles p
  WHERE EXISTS (SELECT 1 FROM profiles ref WHERE ref.tier1_referrer_id = p.user_id)
  ORDER BY referral_count DESC
  LIMIT limit_count;
END;
