--
-- Name: get_cancellation_stats("date", "date", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_cancellation_stats"("p_start_date" "date", "p_end_date" "date", "p_restaurant_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF auth.role() <> 'service_role'
     AND NOT public.has_role(auth.uid(), 'admin'::public.app_role)
     AND (p_restaurant_id IS NULL OR NOT public.is_restaurant_operator(p_restaurant_id, auth.uid())) THEN
    RAISE EXCEPTION 'RESTAURANT_OPERATOR_REQUIRED';
  END IF;
  RETURN public.get_cancellation_stats_trusted(p_start_date, p_end_date, p_restaurant_id);
END;
$$;


ALTER FUNCTION "public"."get_cancellation_stats"("p_start_date" "date", "p_end_date" "date", "p_restaurant_id" "uuid") OWNER TO "postgres";

--
-- Name: get_cancellation_stats_trusted("date", "date", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_cancellation_stats_trusted"("p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date", "p_restaurant_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_result JSONB;
BEGIN
  SELECT jsonb_build_object(
    'total_cancellations', COUNT(*),
    'by_category', jsonb_object_agg(
      COALESCE(reason_category, 'unknown'), 
      cnt
    ),
    'by_role', jsonb_object_agg(
      COALESCE(cancelled_by_role, 'unknown'), 
      cnt
    ),
    'total_refunded', COALESCE(SUM(refund_amount), 0),
    'total_fees', COALESCE(SUM(cancellation_fee), 0)
  )
  INTO v_result
  FROM (
    SELECT 
      reason_category,
      cancelled_by_role,
      COUNT(*) as cnt,
      SUM(refund_amount) as refund_amount,
      SUM(cancellation_fee) as cancellation_fee
    FROM public.order_cancellations oc
    JOIN public.orders o ON o.id = oc.order_id
    WHERE (p_start_date IS NULL OR oc.created_at::date >= p_start_date)
      AND (p_end_date IS NULL OR oc.created_at::date <= p_end_date)
      AND (p_restaurant_id IS NULL OR o.restaurant_id = p_restaurant_id)
    GROUP BY reason_category, cancelled_by_role
  ) sub;
  
  RETURN COALESCE(v_result, '{}'::jsonb);
END;
$$;


ALTER FUNCTION "public"."get_cancellation_stats_trusted"("p_start_date" "date", "p_end_date" "date", "p_restaurant_id" "uuid") OWNER TO "postgres";

--
-- Name: get_challenge_team_state("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_challenge_team_state"("p_challenge_id" "uuid") RETURNS "jsonb"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH challenge AS (
    SELECT id, target_value, team_size
    FROM public.community_challenges
    WHERE id = p_challenge_id AND participation_mode = 'team'
  ),
  my_membership AS (
    SELECT ctm.team_id, ctm.role
    FROM public.challenge_team_members ctm
    WHERE ctm.challenge_id = p_challenge_id AND ctm.user_id = auth.uid()
  ),
  team_stats AS (
    SELECT
      ct.id,
      ct.name,
      ct.join_code,
      ct.captain_id,
      count(ctm.id)::INTEGER AS member_count,
      coalesce(sum(cp.current_progress), 0)::INTEGER AS total_progress,
      coalesce(round(avg(
        least(cp.current_progress, c.target_value)::numeric /
        greatest(c.target_value, 1) * 100
      )), 0)::INTEGER AS progress_percent
    FROM public.challenge_teams ct
    JOIN challenge c ON c.id = ct.challenge_id
    LEFT JOIN public.challenge_team_members ctm ON ctm.team_id = ct.id
    LEFT JOIN public.challenge_participants cp
      ON cp.challenge_id = ct.challenge_id AND cp.user_id = ctm.user_id
    WHERE ct.challenge_id = p_challenge_id
    GROUP BY ct.id
  ),
  ranked AS (
    SELECT ts.*, rank() OVER (
      ORDER BY ts.progress_percent DESC, ts.total_progress DESC, ts.member_count DESC, ts.name
    )::INTEGER AS rank
    FROM team_stats ts
  ),
  my_team AS (
    SELECT r.*, mm.role
    FROM ranked r JOIN my_membership mm ON mm.team_id = r.id
  ),
  my_members AS (
    SELECT jsonb_agg(jsonb_build_object(
      'user_id', ctm.user_id,
      'name', coalesce(nullif(p.full_name, ''), 'Nutrio member'),
      'avatar_url', p.avatar_url,
      'role', ctm.role,
      'progress', coalesce(cp.current_progress, 0)
    ) ORDER BY ctm.role = 'captain' DESC, cp.current_progress DESC, ctm.joined_at) AS value
    FROM my_membership mm
    JOIN public.challenge_team_members ctm ON ctm.team_id = mm.team_id
    LEFT JOIN public.profiles p ON p.user_id = ctm.user_id
    LEFT JOIN public.challenge_participants cp
      ON cp.challenge_id = p_challenge_id AND cp.user_id = ctm.user_id
  )
  SELECT jsonb_build_object(
    'team', (SELECT to_jsonb(mt) FROM my_team mt),
    'members', coalesce((SELECT value FROM my_members), '[]'::jsonb),
    'leaderboard', coalesce((
      SELECT jsonb_agg(jsonb_build_object(
        'team_id', r.id,
        'name', r.name,
        'member_count', r.member_count,
        'progress_percent', r.progress_percent,
        'total_progress', r.total_progress,
        'rank', r.rank
      ) ORDER BY r.rank, r.name)
      FROM (SELECT * FROM ranked ORDER BY rank, name LIMIT 10) r
    ), '[]'::jsonb),
    'team_size', coalesce((SELECT team_size FROM challenge), 5)
  );
$$;


ALTER FUNCTION "public"."get_challenge_team_state"("p_challenge_id" "uuid") OWNER TO "postgres";

--
-- Name: get_coach_available_balance("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_coach_available_balance"("p_coach_id" "uuid" DEFAULT NULL::"uuid") RETURNS numeric
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_coach_id UUID := COALESCE(p_coach_id, auth.uid());
  v_settled NUMERIC(12, 2);
  v_reserved NUMERIC(12, 2);
BEGIN
  IF v_actor IS NULL OR (
    v_coach_id IS DISTINCT FROM v_actor
    AND NOT COALESCE(public.has_role(v_actor, 'admin'), FALSE)
  ) THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  SELECT COALESCE(SUM(ce.net_amount), 0)
  INTO v_settled
  FROM public.coach_earnings ce
  WHERE ce.coach_id = v_coach_id
    AND ce.status = 'settled';

  SELECT COALESCE(SUM(cwr.amount), 0)
  INTO v_reserved
  FROM public.coach_withdrawal_requests cwr
  WHERE cwr.coach_id = v_coach_id
    AND cwr.status IN ('pending', 'approved', 'processed');

  RETURN GREATEST(0, v_settled - v_reserved);
END;
$$;


ALTER FUNCTION "public"."get_coach_available_balance"("p_coach_id" "uuid") OWNER TO "postgres";

--
-- Name: get_current_weekly_ai_check_in(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_current_weekly_ai_check_in"() RETURNS "jsonb"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  SELECT to_jsonb(check_in)
  FROM public.weekly_ai_check_ins AS check_in
  WHERE check_in.user_id = (SELECT auth.uid())
    AND check_in.week_start = (
      CURRENT_DATE - EXTRACT(DOW FROM CURRENT_DATE)::INTEGER
    )
  LIMIT 1;
$$;


ALTER FUNCTION "public"."get_current_weekly_ai_check_in"() OWNER TO "postgres";

--
-- Name: get_customer_delivery_tracking("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_customer_delivery_tracking"("p_source_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_job public.delivery_jobs%ROWTYPE;
  v_driver JSONB;
  v_location JSONB;
  v_eta JSONB;
  v_driver_lat DOUBLE PRECISION;
  v_driver_lng DOUBLE PRECISION;
  v_delivery_lat DOUBLE PRECISION;
  v_delivery_lng DOUBLE PRECISION;
  v_speed_kmh DOUBLE PRECISION;
  v_gps_age_minutes DOUBLE PRECISION;
  v_distance_km DOUBLE PRECISION;
  v_eta_minutes INTEGER;
  v_total_minutes INTEGER;
  v_elapsed_minutes DOUBLE PRECISION;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;

  SELECT dj.* INTO v_job
  FROM public.delivery_jobs dj
  WHERE (dj.schedule_id = p_source_id OR dj.order_id = p_source_id)
    AND (
      EXISTS (
        SELECT 1 FROM public.meal_schedules ms
        WHERE ms.id = dj.schedule_id AND ms.user_id = v_actor
      )
      OR EXISTS (
        SELECT 1 FROM public.orders o
        WHERE o.id = dj.order_id AND o.user_id = v_actor
      )
    )
  ORDER BY dj.created_at DESC, dj.id
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'delivery_job', NULL,
      'latest_location', NULL,
      'eta_prediction', NULL
    );
  END IF;

  IF v_job.driver_id IS NOT NULL
     AND v_job.status IN ('assigned', 'accepted', 'picked_up', 'in_transit') THEN
    SELECT jsonb_build_object(
      'id', d.id,
      'full_name', d.full_name,
      'phone_number', d.phone_number,
      'vehicle_type', d.vehicle_type,
      'vehicle_make', d.vehicle_make,
      'vehicle_model', d.vehicle_model,
      'license_plate', d.license_plate,
      'rating', d.rating,
      'total_deliveries', d.total_deliveries
    )
    INTO v_driver
    FROM public.drivers d
    WHERE d.id = v_job.driver_id
      AND d.city_id = v_job.city_id;
  END IF;

  IF v_job.driver_id IS NOT NULL
     AND v_job.status IN ('assigned', 'accepted', 'picked_up', 'in_transit') THEN
    SELECT jsonb_build_object(
      'lat', d.current_lat,
      'lng', d.current_lng,
      'updated_at', GREATEST(dl.timestamp, d.last_location_update, d.last_location_at),
      'speed_kmh', dl.speed_kmh,
      'heading', dl.heading
    )
    INTO v_location
    FROM public.drivers d
    LEFT JOIN LATERAL (
      SELECT l.timestamp, l.speed_kmh, l.heading
      FROM public.driver_locations l
      WHERE l.driver_id = d.id
      ORDER BY l.timestamp DESC NULLS LAST, l.id DESC
      LIMIT 1
    ) dl ON true
    WHERE d.id = v_job.driver_id
      AND d.city_id = v_job.city_id
      AND d.current_lat IS NOT NULL
      AND d.current_lng IS NOT NULL
      AND GREATEST(dl.timestamp, d.last_location_update, d.last_location_at)
        >= COALESCE(v_job.accepted_at, v_job.assigned_at, v_job.created_at);
  END IF;

  IF v_location IS NOT NULL
     AND v_job.delivery_lat IS NOT NULL
     AND v_job.delivery_lng IS NOT NULL THEN
    v_driver_lat := (v_location ->> 'lat')::DOUBLE PRECISION;
    v_driver_lng := (v_location ->> 'lng')::DOUBLE PRECISION;
    v_delivery_lat := v_job.delivery_lat::DOUBLE PRECISION;
    v_delivery_lng := v_job.delivery_lng::DOUBLE PRECISION;
    v_speed_kmh := NULLIF((v_location ->> 'speed_kmh')::DOUBLE PRECISION, 0);
    v_gps_age_minutes := EXTRACT(EPOCH FROM (now() - ((v_location ->> 'updated_at')::TIMESTAMPTZ))) / 60;

    v_distance_km := GREATEST(
      0.05,
      6371 * 2 * ASIN(SQRT(
        POWER(SIN(RADIANS(v_delivery_lat - v_driver_lat) / 2), 2)
        + COS(RADIANS(v_driver_lat))
        * COS(RADIANS(v_delivery_lat))
        * POWER(SIN(RADIANS(v_delivery_lng - v_driver_lng) / 2), 2)
      )) * 1.22
    );

    v_speed_kmh := CASE
      WHEN v_speed_kmh IS NULL OR v_speed_kmh < 3 THEN 28
      WHEN v_gps_age_minutes > 5 THEN GREATEST(12, LEAST(75, v_speed_kmh * 0.8))
      ELSE GREATEST(12, LEAST(75, v_speed_kmh))
    END;

    v_eta_minutes := GREATEST(1, CEIL((v_distance_km / v_speed_kmh) * 60 + 2)::INTEGER);
    v_eta := jsonb_build_object(
      'minutes', v_eta_minutes,
      'distanceKm', ROUND(v_distance_km::NUMERIC, 2),
      'confidence', CASE WHEN v_gps_age_minutes > 5 THEN 'stale' ELSE 'live' END,
      'source', 'gps',
      'gpsAgeMinutes', ROUND(GREATEST(0, v_gps_age_minutes)::NUMERIC, 0)
    );
  ELSIF v_job.estimated_distance_km IS NOT NULL AND v_job.estimated_distance_km > 0 THEN
    v_total_minutes := CEIL((v_job.estimated_distance_km::DOUBLE PRECISION / 28) * 60 + 2)::INTEGER;
    v_elapsed_minutes := CASE
      WHEN v_job.picked_up_at IS NULL THEN 0
      ELSE GREATEST(0, EXTRACT(EPOCH FROM (now() - v_job.picked_up_at)) / 60)
    END;
    v_eta_minutes := GREATEST(1, CEIL(v_total_minutes - v_elapsed_minutes)::INTEGER);
    v_eta := jsonb_build_object(
      'minutes', v_eta_minutes,
      'distanceKm', ROUND(v_job.estimated_distance_km::NUMERIC, 2),
      'confidence', 'estimated',
      'source', 'distance',
      'gpsAgeMinutes', NULL
    );
  END IF;

  RETURN jsonb_build_object(
    'delivery_job', jsonb_build_object(
      'id', v_job.id,
      'status', v_job.status,
      'schedule_id', v_job.schedule_id,
      'order_id', v_job.order_id,
      'driver_id', v_job.driver_id,
      'assigned_at', v_job.assigned_at,
      'picked_up_at', v_job.picked_up_at,
      'delivered_at', v_job.delivered_at,
      'created_at', v_job.created_at,
      'driver', v_driver
    ),
    'latest_location', v_location,
    'eta_prediction', v_eta
  );
END;
$$;


