--
-- Name: get_customer_driver_ids_trusted("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_customer_driver_ids_trusted"("customer_uuid" "uuid") RETURNS TABLE("driver_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT DISTINCT dj.driver_id
    FROM delivery_jobs dj
    JOIN meal_schedules ms ON dj.schedule_id = ms.id
    WHERE ms.user_id = customer_uuid
    AND dj.driver_id IS NOT NULL;
END;
$$;


