-- Name: get_friend_requests_trusted("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_friend_requests_trusted"("p_user_id" "uuid") RETURNS TABLE("friendship_id" "uuid", "requester_name" "text", "requester_email" "text", "requester_avatar" "text", "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  SELECT
    f.id,
    COALESCE(p.full_name, 'Unknown'),
    u.email,
    p.avatar_url,
    f.created_at
  FROM friendships f
  JOIN profiles p ON p.user_id = f.requester_id
  JOIN auth.users u ON u.id = f.requester_id
  WHERE f.target_id = p_user_id
    AND f.status = 'pending'
  ORDER BY f.created_at DESC;
$$;


