--
-- Name: get_friends_trusted("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_friends_trusted"("p_user_id" "uuid") RETURNS TABLE("friendship_id" "uuid", "friend_user_id" "uuid", "friend_name" "text", "friend_email" "text", "friend_avatar" "text", "current_streak" integer, "show_weight" boolean, "show_progress" boolean)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  SELECT
    f.id,
    CASE WHEN f.requester_id = p_user_id THEN f.target_id ELSE f.requester_id END,
    COALESCE(p.full_name, 'Unknown'),
    u.email,
    p.avatar_url,
    COALESCE(s.current_streak, 0),
    CASE WHEN f.requester_id = p_user_id THEN f.show_weight ELSE false END,
    f.show_progress
  FROM friendships f
  JOIN profiles p ON p.user_id = CASE WHEN f.requester_id = p_user_id THEN f.target_id ELSE f.requester_id END
  JOIN auth.users u ON u.id = CASE WHEN f.requester_id = p_user_id THEN f.target_id ELSE f.requester_id END
  LEFT JOIN user_streaks s ON s.user_id = CASE WHEN f.requester_id = p_user_id THEN f.target_id ELSE f.requester_id END AND s.streak_type = 'logging'
  WHERE f.status = 'accepted'
    AND (f.requester_id = p_user_id OR f.target_id = p_user_id)
  ORDER BY COALESCE(s.current_streak, 0) DESC;
$$;


ALTER FUNCTION "public"."get_friends_trusted"("p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: get_google_fit_server_credentials("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_google_fit_server_credentials"("p_user_id" "uuid") RETURNS TABLE("access_token" "text", "refresh_token" "text", "expires_at" bigint)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'security', 'public', 'extensions', 'pg_temp'
    AS $$
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RAISE EXCEPTION 'Service role required';
  END IF;

  RETURN QUERY
  SELECT
    security.decrypt_oauth_token(ui.access_token_encrypted),
    CASE
      WHEN ui.refresh_token_encrypted IS NOT NULL
        THEN security.decrypt_oauth_token(ui.refresh_token_encrypted)
      ELSE NULL
    END,
    ui.expires_at::BIGINT
  FROM public.user_integrations ui
  WHERE ui.user_id = p_user_id
    AND ui.provider = 'google_fit'
    AND ui.access_token_encrypted IS NOT NULL
  LIMIT 1;
END;
$$;


