--
-- Name: get_meal_reviews("uuid", integer, integer, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_meal_reviews"("p_meal_id" "uuid", "p_limit" integer DEFAULT 10, "p_offset" integer DEFAULT 0, "p_sort_by" "text" DEFAULT 'newest'::"text") RETURNS TABLE("review_id" "uuid", "user_id" "uuid", "user_name" "text", "user_avatar" "text", "rating" integer, "title" "text", "review_text" "text", "photo_urls" "text"[], "is_verified_purchase" boolean, "would_recommend" boolean, "tags" "text"[], "helpful_count" integer, "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    mr.id,
    mr.user_id,
    COALESCE(p.full_name, 'Anonymous')::TEXT,
    p.avatar_url::TEXT,
    mr.rating,
    mr.title::TEXT,
    mr.review_text,
    COALESCE(mr.photo_urls, ARRAY[]::TEXT[]),
    COALESCE(mr.is_verified_purchase, false),
    mr.would_recommend,
    COALESCE(mr.tags, ARRAY[]::TEXT[]),
    COALESCE(mr.helpful_count, 0),
    mr.created_at
  FROM public.meal_reviews mr
  LEFT JOIN public.profiles p ON p.user_id = mr.user_id
  WHERE mr.meal_id = p_meal_id
    AND COALESCE(mr.is_approved, false)
  ORDER BY
    CASE WHEN p_sort_by = 'newest' THEN mr.created_at END DESC,
    CASE WHEN p_sort_by = 'highest' THEN mr.rating END DESC,
    CASE WHEN p_sort_by = 'lowest' THEN mr.rating END ASC,
    CASE WHEN p_sort_by = 'helpful' THEN mr.helpful_count END DESC,
    mr.created_at DESC
  LIMIT LEAST(GREATEST(p_limit, 1), 50)
  OFFSET GREATEST(p_offset, 0);
$$;


ALTER FUNCTION "public"."get_meal_reviews"("p_meal_id" "uuid", "p_limit" integer, "p_offset" integer, "p_sort_by" "text") OWNER TO "postgres";

--
-- Name: get_meal_with_translation("uuid", "public"."language_code"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_meal_with_translation"("p_meal_id" "uuid", "p_language_code" "public"."language_code" DEFAULT 'en'::"public"."language_code") RETURNS TABLE("id" "uuid", "restaurant_id" "uuid", "name" "text", "description" "text", "image_url" "text", "price" numeric, "calories" integer, "protein_g" numeric, "carbs_g" numeric, "fat_g" numeric, "fiber_g" numeric, "prep_time_minutes" integer, "is_available" boolean, "rating" numeric, "order_count" integer, "is_translated" boolean, "is_auto_translated" boolean, "review_status" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT 
    m.id,
    m.restaurant_id,
    COALESCE(mt.name, m.name) as name,
    COALESCE(mt.description, m.description) as description,
    m.image_url,
    m.price,
    m.calories,
    m.protein_g,
    m.carbs_g,
    m.fat_g,
    m.fiber_g,
    m.prep_time_minutes,
    m.is_available,
    m.rating,
    m.order_count,
    (mt.id IS NOT NULL) as is_translated,
    COALESCE(mt.is_auto_translated, false) as is_auto_translated,
    COALESCE(mt.review_status, 'none') as review_status
  FROM public.meals m
  LEFT JOIN public.meal_translations mt ON m.id = mt.meal_id AND mt.language_code = p_language_code
  WHERE m.id = p_meal_id;
$$;


