--
-- Name: get_my_adherence_summary(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_my_adherence_summary"() RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_today DATE := (now() AT TIME ZONE 'Asia/Qatar')::DATE;
  v_week_start DATE;
  v_goal public.adherence_goals%ROWTYPE;
  v_completed_days INTEGER;
  v_strength INTEGER;
  v_rows JSONB := '[]'::JSONB;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'AUTHENTICATION_REQUIRED'; END IF;
  v_week_start := v_today - (extract(isodow FROM v_today)::INTEGER - 1);

  FOR v_goal IN
    SELECT * FROM public.adherence_goals
    WHERE user_id = v_user_id AND is_active
    ORDER BY metric
  LOOP
    SELECT count(*)::INTEGER INTO v_completed_days
    FROM generate_series(v_week_start, v_today, interval '1 day') AS day(value)
    WHERE public.adherence_daily_value(v_user_id, v_goal.metric, day.value::DATE)
      >= v_goal.target_value;

    SELECT coalesce(round(
      100 * sum(weekly.ratio * weekly.weight) / nullif(sum(weekly.weight), 0)
    ), 0)::INTEGER
    INTO v_strength
    FROM (
      SELECT
        least(
          1::NUMERIC,
          count(*) FILTER (
            WHERE evidence.day::DATE <= v_today
              AND public.adherence_daily_value(
                v_user_id,
                v_goal.metric,
                evidence.day::DATE
              ) >= v_goal.target_value
          )::NUMERIC / v_goal.frequency_per_week
        ) AS ratio,
        power(0.84::NUMERIC, age.week_age)::NUMERIC AS weight
      FROM generate_series(0, 11) AS age(week_age)
      CROSS JOIN LATERAL generate_series(
        v_week_start - (age.week_age * 7),
        v_week_start - (age.week_age * 7) + 6,
        interval '1 day'
      ) AS evidence(day)
      GROUP BY age.week_age
    ) weekly;

    v_rows := v_rows || jsonb_build_array(jsonb_build_object(
      'id', v_goal.id,
      'metric', v_goal.metric,
      'frequency_per_week', v_goal.frequency_per_week,
      'target_value', v_goal.target_value,
      'completed_days', v_completed_days,
      'remaining_days', greatest(v_goal.frequency_per_week - v_completed_days, 0),
      'strength', least(greatest(coalesce(v_strength, 0), 0), 100),
      'reason_code', CASE
        WHEN v_completed_days >= v_goal.frequency_per_week THEN 'on_track'
        WHEN coalesce(v_strength, 0) >= 70 THEN 'strong_history'
        WHEN coalesce(v_strength, 0) >= 35 THEN 'building'
        ELSE 'getting_started'
      END
    ));
  END LOOP;

  RETURN jsonb_build_object(
    'week_start', v_week_start,
    'today', v_today,
    'goals', v_rows
  );
END;
$$;


ALTER FUNCTION "public"."get_my_adherence_summary"() OWNER TO "postgres";

--
-- Name: get_nps_trend_by_month(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_nps_trend_by_month"("p_months" integer) RETURNS TABLE("month" "text", "total_responses" bigint, "nps_score" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF auth.role() <> 'service_role' AND NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;
  RETURN QUERY SELECT * FROM public.get_nps_trend_by_month_trusted(p_months);
END;
$$;


ALTER FUNCTION "public"."get_nps_trend_by_month"("p_months" integer) OWNER TO "postgres";

--
-- Name: get_nps_trend_by_month_trusted(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_nps_trend_by_month_trusted"("p_months" integer DEFAULT 6) RETURNS TABLE("month" "text", "total_responses" bigint, "nps_score" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  RETURN QUERY
  WITH monthly_scores AS (
    SELECT 
      TO_CHAR(DATE_TRUNC('month', responded_at), 'YYYY-MM') as month_key,
      COUNT(*) as responses,
      COUNT(*) FILTER (WHERE score >= 9) as promoters,
      COUNT(*) FILTER (WHERE score <= 6) as detractors
    FROM public.nps_responses
    WHERE responded_at >= now() - (p_months || ' months')::interval
    GROUP BY DATE_TRUNC('month', responded_at)
  )
  SELECT 
    monthly_scores.month_key,
    monthly_scores.responses,
    CASE 
      WHEN monthly_scores.responses = 0 THEN 0
      ELSE ROUND(((monthly_scores.promoters::NUMERIC - monthly_scores.detractors::NUMERIC) / monthly_scores.responses::NUMERIC) * 100, 2)
    END as calculated_nps
  FROM monthly_scores
  ORDER BY monthly_scores.month_key DESC;
END;
$$;


ALTER FUNCTION "public"."get_nps_trend_by_month_trusted"("p_months" integer) OWNER TO "postgres";

