--
-- Name: get_or_create_customer_wallet(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_or_create_customer_wallet"() RETURNS "public"."customer_wallets"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_wallet public.customer_wallets%ROWTYPE;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  PERFORM pg_advisory_xact_lock(hashtextextended('wallet:' || v_actor::TEXT, 0));

  SELECT *
    INTO v_wallet
  FROM public.customer_wallets cw
  WHERE cw.user_id = v_actor
  FOR UPDATE;

  IF NOT FOUND THEN
    INSERT INTO public.customer_wallets (
      user_id,
      balance,
      total_credits,
      total_debits,
      is_active
    ) VALUES (
      v_actor,
      0,
      0,
      0,
      TRUE
    )
    RETURNING * INTO v_wallet;
  END IF;

  RETURN v_wallet;
END;
$$;


ALTER FUNCTION "public"."get_or_create_customer_wallet"() OWNER TO "postgres";

--
-- Name: get_or_create_recovery_credits(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_or_create_recovery_credits"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_today DATE := (NOW() AT TIME ZONE 'Asia/Qatar')::DATE;
  v_period_start DATE;
  v_period_end DATE;
  v_enabled BOOLEAN := FALSE;
  v_monthly_credits INTEGER := 0;
  v_credits public.member_recovery_credits%ROWTYPE;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  v_period_start := DATE_TRUNC('month', v_today)::DATE;
  v_period_end := (v_period_start + INTERVAL '1 month' - INTERVAL '1 day')::DATE;

  IF EXISTS (
    SELECT 1
    FROM public.subscriptions s
    WHERE s.user_id = v_actor
      AND s.status IN ('active', 'cancelled')
      AND COALESCE(s.end_date::DATE, v_today - 1) >= v_today
  ) THEN
    SELECT
      COALESCE((ps.value ->> 'enabled')::BOOLEAN, FALSE),
      GREATEST(0, COALESCE((ps.value ->> 'monthly_credits')::INTEGER, 0))
      INTO v_enabled, v_monthly_credits
    FROM public.platform_settings ps
    WHERE ps.key = 'recovery_credits';
  END IF;

  IF NOT COALESCE(v_enabled, FALSE) THEN
    v_monthly_credits := 0;
  END IF;

  PERFORM pg_advisory_xact_lock(
    hashtextextended('recovery:' || v_actor::TEXT || ':' || v_period_start::TEXT, 0)
  );

  INSERT INTO public.member_recovery_credits (
    user_id,
    total_credits,
    used_credits,
    period_start,
    period_end
  ) VALUES (
    v_actor,
    v_monthly_credits,
    0,
    v_period_start,
    v_period_end
  )
  ON CONFLICT (user_id, period_start)
  DO UPDATE SET
    total_credits = GREATEST(
      EXCLUDED.total_credits,
      public.member_recovery_credits.used_credits
    ),
    period_end = EXCLUDED.period_end
  RETURNING * INTO v_credits;

  RETURN TO_JSONB(v_credits);
END;
$$;


ALTER FUNCTION "public"."get_or_create_recovery_credits"() OWNER TO "postgres";

--
-- Name: get_order_meal_consumption("text", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_order_meal_consumption"("p_source_type" "text", "p_source_id" "uuid", "p_source_meal_id" "uuid") RETURNS "jsonb"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  SELECT COALESCE(
    (
      SELECT to_jsonb(mc)
      FROM public.meal_consumptions mc
      WHERE mc.user_id = (SELECT auth.uid())
        AND mc.source_type = LOWER(p_source_type)
        AND mc.source_id = p_source_id
        AND mc.source_meal_id = p_source_meal_id
    ),
    'null'::JSONB
  );
$$;


ALTER FUNCTION "public"."get_order_meal_consumption"("p_source_type" "text", "p_source_id" "uuid", "p_source_meal_id" "uuid") OWNER TO "postgres";

--
-- Name: get_own_health_tracking_goals(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_own_health_tracking_goals"() RETURNS TABLE("water_goal_ml" integer, "step_goal" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  RETURN QUERY
  SELECT
    COALESCE(
      goals.water_goal_ml,
      (settings.value ->> 'water_goal_ml')::INTEGER,
      2500
    ),
    COALESCE(
      goals.step_goal,
      (settings.value ->> 'step_goal')::INTEGER,
      6000
    )
  FROM (SELECT 1) seed
  LEFT JOIN public.user_health_tracking_goals goals
    ON goals.user_id = v_actor
  LEFT JOIN public.platform_settings settings
    ON settings.key = 'health_tracking_goals';
END;
$$;


ALTER FUNCTION "public"."get_own_health_tracking_goals"() OWNER TO "postgres";

--
-- Name: get_recovery_offers(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_recovery_offers"() RETURNS TABLE("id" "uuid", "offer_type" "text", "name" "text", "description" "text", "discount_percent" integer, "bonus_credits" integer, "free_days" integer, "downgrade_to_tier" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_days INTEGER;
  v_recovery_id UUID;
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;

  SELECT sr.id, GREATEST(0, EXTRACT(DAY FROM now() - sr.expired_at)::INTEGER)
  INTO v_recovery_id, v_days
  FROM public.subscription_recovery sr
  WHERE sr.user_id = auth.uid()
    AND sr.recovery_status IN ('pending', 'offer_viewed')
  ORDER BY sr.created_at DESC LIMIT 1;

  IF v_recovery_id IS NULL THEN RETURN; END IF;

  UPDATE public.subscription_recovery
  SET recovery_status = 'offer_viewed', viewed_at = COALESCE(viewed_at, now()), updated_at = now()
  WHERE subscription_recovery.id = v_recovery_id;

  RETURN QUERY
  SELECT ro.id,
    CASE WHEN ro.offer_type = 'downgrade' THEN 'downgrade_retention' ELSE ro.offer_type END::TEXT,
    ro.name::TEXT, ro.description,
    ro.discount_percent, ro.bonus_credits, ro.free_days, ro.target_tier::TEXT
  FROM public.recovery_offers ro
  WHERE ro.is_active
    AND v_days BETWEEN ro.days_since_expiry_min AND ro.days_since_expiry_max
  ORDER BY ro.priority, ro.created_at DESC
  LIMIT 3;
END;
$$;


ALTER FUNCTION "public"."get_recovery_offers"() OWNER TO "postgres";

--
-- Name: get_recovery_status("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_recovery_status"("p_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_recovery public.subscription_recovery%ROWTYPE;
BEGIN
  IF auth.uid() IS NOT NULL
     AND auth.uid() <> p_user_id
     AND NOT public.has_role(auth.uid(), 'admin') THEN
    RAISE EXCEPTION 'Not authorized';
  END IF;

  SELECT * INTO v_recovery
  FROM public.subscription_recovery
  WHERE user_id = p_user_id
  ORDER BY created_at DESC
  LIMIT 1;

  IF NOT FOUND THEN RETURN NULL; END IF;

  RETURN jsonb_build_object(
    'id', v_recovery.id,
    'subscription_id', v_recovery.subscription_id,
    'status', v_recovery.recovery_status,
    'expired_at', v_recovery.expired_at,
    'recovery_offer_id', v_recovery.accepted_offer_id,
    'offer_applied_at', v_recovery.accepted_at,
    'reactivated_at', v_recovery.reactivated_at,
    'notification_stage', 0,
    'days_since_expiry', GREATEST(0, EXTRACT(DAY FROM now() - v_recovery.expired_at)::INTEGER)
  );
END;
$$;


ALTER FUNCTION "public"."get_recovery_status"("p_user_id" "uuid") OWNER TO "postgres";

