--

CREATE OR REPLACE FUNCTION "public"."get_skip_analytics"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date") RETURNS TABLE("reason_type" character varying, "total_skips" bigint, "percentage" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id uuid := COALESCE(p_user_id, auth.uid());
BEGIN
  PERFORM public.assert_self_or_admin(v_user_id);
  RETURN QUERY SELECT * FROM public.get_skip_analytics_trusted(v_user_id, p_start_date, p_end_date);
END;
$$;


ALTER FUNCTION "public"."get_skip_analytics"("p_user_id" "uuid", "p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";

--
-- Name: get_skip_analytics_trusted("uuid", "date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_skip_analytics_trusted"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date") RETURNS TABLE("reason_type" character varying, "total_skips" bigint, "percentage" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        msr.reason_type,
        COUNT(*)::BIGINT as total_skips,
        ROUND(COUNT(*) * 100.0 / SUM(COUNT(*)) OVER (), 2) as percentage
    FROM meal_skip_reasons msr
    WHERE (p_user_id IS NULL OR msr.user_id = p_user_id)
        AND (p_start_date IS NULL OR msr.scheduled_date >= p_start_date)
        AND (p_end_date IS NULL OR msr.scheduled_date <= p_end_date)
    GROUP BY msr.reason_type
    ORDER BY total_skips DESC;
END;
$$;


ALTER FUNCTION "public"."get_skip_analytics_trusted"("p_user_id" "uuid", "p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";

