--

CREATE OR REPLACE FUNCTION "public"."get_user_affiliate_rank"("user_uuid" "uuid") RETURNS TABLE("earnings" integer, "referrals" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(user_uuid);
  RETURN QUERY SELECT * FROM public.get_user_affiliate_rank_trusted(user_uuid);
END;
$$;


ALTER FUNCTION "public"."get_user_affiliate_rank"("user_uuid" "uuid") OWNER TO "postgres";

--
-- Name: get_user_affiliate_rank_trusted("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_user_affiliate_rank_trusted"("user_uuid" "uuid") RETURNS TABLE("earnings" integer, "referrals" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  earnings_rank INTEGER;
  referrals_rank INTEGER;
  user_earnings NUMERIC;
  user_referral_count BIGINT;
BEGIN
  -- Get user's earnings
  SELECT COALESCE(p.total_affiliate_earnings, 0) INTO user_earnings
  FROM profiles p WHERE p.user_id = user_uuid;
  
  -- Get user's referral count
  SELECT COUNT(*)::BIGINT INTO user_referral_count
  FROM profiles ref WHERE ref.tier1_referrer_id = user_uuid;
  
  -- Calculate earnings rank
  SELECT COUNT(*)::INTEGER + 1 INTO earnings_rank
  FROM profiles p
  WHERE COALESCE(p.total_affiliate_earnings, 0) > COALESCE(user_earnings, 0);
  
  -- Calculate referrals rank
  SELECT COUNT(*)::INTEGER + 1 INTO referrals_rank
  FROM profiles p
  WHERE (SELECT COUNT(*) FROM profiles ref WHERE ref.tier1_referrer_id = p.user_id) > user_referral_count;
  
  RETURN QUERY SELECT earnings_rank, referrals_rank;
END;
$$;


ALTER FUNCTION "public"."get_user_affiliate_rank_trusted"("user_uuid" "uuid") OWNER TO "postgres";

