--
-- Name: get_win_back_offers("uuid", "uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."get_win_back_offers"("p_user_id" "uuid", "p_subscription_id" "uuid", "p_step" integer) RETURNS TABLE("offer_id" "uuid", "offer_code" character varying, "offer_type" character varying, "name" character varying, "description" "text", "pause_duration_days" integer, "discount_percent" integer, "discount_duration_months" integer, "target_tier" character varying, "bonus_credits" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_subscription public.subscriptions%ROWTYPE;
  v_months_subscribed INTEGER;
  v_previous_cancellations INTEGER;
BEGIN
  IF auth.uid() IS NULL OR p_user_id IS DISTINCT FROM auth.uid() THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  IF p_step NOT BETWEEN 2 AND 4 THEN
    RETURN;
  END IF;

  SELECT * INTO v_subscription
  FROM public.subscriptions s
  WHERE s.id = p_subscription_id
    AND s.user_id = p_user_id
    AND s.status::TEXT IN ('active', 'pending');

  IF NOT FOUND THEN
    RETURN;
  END IF;

  v_months_subscribed := GREATEST(
    0,
    COALESCE(EXTRACT(YEAR FROM age(now(), v_subscription.created_at))::INTEGER, 0) * 12
      + COALESCE(EXTRACT(MONTH FROM age(now(), v_subscription.created_at))::INTEGER, 0)
  );

  SELECT COUNT(*)::INTEGER INTO v_previous_cancellations
  FROM public.cancellation_attempts ca
  WHERE ca.user_id = p_user_id
    AND ca.final_action = 'cancelled';

  RETURN QUERY
  SELECT
    wbo.id,
    wbo.offer_code,
    wbo.offer_type,
    wbo.name,
    wbo.description,
    wbo.pause_duration_days,
    wbo.discount_percent,
    wbo.discount_duration_months,
    wbo.target_tier,
    wbo.bonus_credits
  FROM public.win_back_offers wbo
  WHERE wbo.is_active = true
    AND wbo.offer_type = 'pause'
    AND p_step = 2
    AND COALESCE(v_subscription.tier, v_subscription.plan, 'basic') = ANY(wbo.applicable_tiers)
    AND v_months_subscribed >= COALESCE(wbo.min_subscription_months, 0)
    AND v_previous_cancellations <= COALESCE(wbo.max_previous_cancellations, 999)
    AND NOT EXISTS (
      SELECT 1
      FROM public.cancellation_attempts used
      WHERE used.subscription_id = p_subscription_id
        AND used.offer_accepted = true
        AND used.final_action = 'paused'
        AND used.resolved_at >= now() - interval '90 days'
    )
  ORDER BY wbo.priority ASC, wbo.created_at DESC
  LIMIT 3;
END;
$$;


ALTER FUNCTION "public"."get_win_back_offers"("p_user_id" "uuid", "p_subscription_id" "uuid", "p_step" integer) OWNER TO "postgres";

--
-- Name: grant_badge_reward("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."grant_badge_reward"("p_user_id" "uuid", "p_badge_id" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_reward public.reward_definitions%ROWTYPE;
  v_reward_transaction_id UUID;
  v_wallet_transaction_id UUID;
  v_granted JSONB := '[]'::jsonb;
BEGIN
  FOR v_reward IN
    SELECT *
    FROM public.reward_definitions
    WHERE is_active = true
      AND badge_id = p_badge_id
  LOOP
    v_reward_transaction_id := NULL;

    INSERT INTO public.reward_transactions (
      user_id,
      reward_definition_id,
      badge_id,
      reward_type,
      reward_value,
      metadata
    )
    VALUES (
      p_user_id,
      v_reward.id,
      p_badge_id,
      v_reward.reward_type,
      v_reward.reward_value,
      jsonb_build_object('source', 'badge_unlock')
    )
    ON CONFLICT DO NOTHING
    RETURNING id INTO v_reward_transaction_id;

    IF v_reward_transaction_id IS NULL THEN
      CONTINUE;
    END IF;

    IF v_reward.reward_type = 'wallet_credit' AND v_reward.reward_value > 0 THEN
      v_wallet_transaction_id := public.credit_wallet(
        p_user_id,
        v_reward.reward_value,
        'reward',
        'reward',
        v_reward_transaction_id,
        v_reward.title,
        jsonb_build_object('badge_id', p_badge_id, 'reward_definition_id', v_reward.id)
      );

      UPDATE public.reward_transactions
      SET wallet_transaction_id = v_wallet_transaction_id
      WHERE id = v_reward_transaction_id;
    END IF;

    v_granted := v_granted || jsonb_build_array(jsonb_build_object(
      'reward_id', v_reward.id,
      'title', v_reward.title,
      'reward_type', v_reward.reward_type,
      'reward_value', v_reward.reward_value
    ));
  END LOOP;

  RETURN jsonb_build_object('success', true, 'rewards', v_granted);
END;
$$;


ALTER FUNCTION "public"."grant_badge_reward"("p_user_id" "uuid", "p_badge_id" "text") OWNER TO "postgres";

--
-- Name: grant_community_challenge_wallet_reward("uuid", "uuid", "uuid", integer, "text", numeric, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."grant_community_challenge_wallet_reward"("p_user_id" "uuid", "p_challenge_id" "uuid", "p_participant_id" "uuid", "p_completion_version" integer, "p_source_key" "text", "p_gross_amount" numeric, "p_challenge_title" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_existing public.community_challenge_reward_settlements%ROWTYPE;
  v_wallet public.customer_wallets%ROWTYPE;
  v_recovery_applied NUMERIC(10, 2) := 0;
  v_credited_amount NUMERIC(10, 2) := 0;
  v_wallet_transaction_id UUID;
  v_reward_transaction_id UUID;
  v_settlement_id UUID;
  v_gross_amount NUMERIC(10, 2) := greatest(coalesce(p_gross_amount, 0), 0);
BEGIN
  IF p_user_id IS NULL OR p_challenge_id IS NULL OR p_participant_id IS NULL
     OR p_completion_version <= 0 OR nullif(btrim(p_source_key), '') IS NULL THEN
    RAISE EXCEPTION 'INVALID_CHALLENGE_REWARD_INPUT';
  END IF;

  PERFORM pg_advisory_xact_lock(
    hashtextextended('challenge-wallet:' || p_user_id::TEXT || ':' || p_source_key, 0)
  );

  SELECT * INTO v_existing
  FROM public.community_challenge_reward_settlements
  WHERE participant_id = p_participant_id
    AND completion_version = p_completion_version;

  IF FOUND THEN
    RETURN jsonb_build_object(
      'success', true,
      'duplicate', true,
      'settlement_id', v_existing.id,
      'gross_amount', v_existing.gross_amount,
      'credited_amount', v_existing.credited_amount,
      'recovery_applied', v_existing.recovery_applied,
      'status', v_existing.status
    );
  END IF;

  INSERT INTO public.customer_wallets (
    user_id, balance, total_credits, total_debits, is_active, reward_adjustment_due
  ) VALUES (
    p_user_id, 0, 0, 0, true, 0
  )
  ON CONFLICT (user_id) DO NOTHING;

  SELECT * INTO v_wallet
  FROM public.customer_wallets
  WHERE user_id = p_user_id
    AND coalesce(is_active, true)
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'WALLET_NOT_FOUND_OR_INACTIVE';
  END IF;

  v_recovery_applied := least(coalesce(v_wallet.reward_adjustment_due, 0), v_gross_amount);
  v_credited_amount := v_gross_amount - v_recovery_applied;

  UPDATE public.customer_wallets
  SET balance = coalesce(balance, 0) + v_credited_amount,
      total_credits = coalesce(total_credits, 0) + v_credited_amount,
      reward_adjustment_due = greatest(coalesce(reward_adjustment_due, 0) - v_recovery_applied, 0),
      updated_at = now()
  WHERE id = v_wallet.id;

  IF v_credited_amount > 0 THEN
    INSERT INTO public.wallet_transactions (
      wallet_id,
      user_id,
      type,
      amount,
      balance_after,
      reference_type,
      reference_id,
      description,
      metadata,
      idempotency_key
    ) VALUES (
      v_wallet.id,
      p_user_id,
      'bonus',
      v_credited_amount,
      coalesce(v_wallet.balance, 0) + v_credited_amount,
      'community_challenge',
      p_challenge_id,
      'Community challenge reward: ' || coalesce(p_challenge_title, 'Challenge'),
      jsonb_build_object(
        'source_key', p_source_key,
        'completion_version', p_completion_version,
        'gross_amount', v_gross_amount,
        'credited_amount', v_credited_amount,
        'recovery_applied', v_recovery_applied
      ),
      'challenge-reward:' || p_user_id::TEXT || ':' || p_source_key
    )
    RETURNING id INTO v_wallet_transaction_id;
  END IF;

  INSERT INTO public.reward_transactions (
    user_id,
    reward_type,
    reward_value,
    status,
    wallet_transaction_id,
    metadata
  ) VALUES (
    p_user_id,
    'wallet_credit',
    v_credited_amount,
    CASE WHEN v_credited_amount > 0 THEN 'granted' ELSE 'expired' END,
    v_wallet_transaction_id,
    jsonb_build_object(
      'source_key', p_source_key,
      'challenge_id', p_challenge_id,
      'completion_version', p_completion_version,
      'gross_amount', v_gross_amount,
      'credited_amount', v_credited_amount,
      'recovery_applied', v_recovery_applied
    )
  )
  RETURNING id INTO v_reward_transaction_id;

  INSERT INTO public.community_challenge_reward_settlements (
    participant_id,
    challenge_id,
    user_id,
    completion_version,
    source_key,
    gross_amount,
    credited_amount,
    recovery_applied,
    wallet_transaction_id,
    reward_transaction_id,
    metadata
  ) VALUES (
    p_participant_id,
    p_challenge_id,
    p_user_id,
    p_completion_version,
    p_source_key,
    v_gross_amount,
    v_credited_amount,
    v_recovery_applied,
    v_wallet_transaction_id,
    v_reward_transaction_id,
    jsonb_build_object('challenge_title', p_challenge_title)
  )
  RETURNING id INTO v_settlement_id;

  UPDATE public.challenge_participants
  SET reward_wallet_gross_amount = v_gross_amount,
      reward_wallet_credited_amount = v_credited_amount,
      reward_wallet_recovery_applied = v_recovery_applied,
      reward_wallet_pending_recovery = 0,
      reward_wallet_transaction_id = v_wallet_transaction_id,
      reward_wallet_reversal_transaction_id = NULL,
      reward_wallet_reversed_at = NULL,
      updated_at = now()
  WHERE id = p_participant_id;

  RETURN jsonb_build_object(
    'success', true,
    'duplicate', false,
    'settlement_id', v_settlement_id,
    'gross_amount', v_gross_amount,
    'credited_amount', v_credited_amount,
    'recovery_applied', v_recovery_applied,
    'wallet_transaction_id', v_wallet_transaction_id
  );
END;
$$;


ALTER FUNCTION "public"."grant_community_challenge_wallet_reward"("p_user_id" "uuid", "p_challenge_id" "uuid", "p_participant_id" "uuid", "p_completion_version" integer, "p_source_key" "text", "p_gross_amount" numeric, "p_challenge_title" "text") OWNER TO "postgres";

--
-- Name: grant_progress_rewards("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."grant_progress_rewards"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_reward public.reward_definitions%ROWTYPE;
  v_reward_transaction_id UUID;
  v_wallet_transaction_id UUID;
  v_lifetime_xp INTEGER;
  v_level INTEGER;
  v_granted JSONB := '[]'::jsonb;
BEGIN
  SELECT COALESCE(SUM(GREATEST(xp_amount, 0)), 0)
  INTO v_lifetime_xp
  FROM public.xp_transactions
  WHERE user_id = p_user_id;

  SELECT COALESCE(level, 1)
  INTO v_level
  FROM public.profiles
  WHERE user_id = p_user_id;

  FOR v_reward IN
    SELECT *
    FROM public.reward_definitions
    WHERE is_active = true
      AND badge_id IS NULL
      AND (
        (xp_required IS NOT NULL AND xp_required <= v_lifetime_xp)
        OR (level_required IS NOT NULL AND level_required <= v_level)
      )
    ORDER BY COALESCE(xp_required, 2147483647), COALESCE(level_required, 2147483647)
  LOOP
    v_reward_transaction_id := NULL;

    INSERT INTO public.reward_transactions (
      user_id,
      reward_definition_id,
      reward_type,
      reward_value,
      metadata
    )
    VALUES (
      p_user_id,
      v_reward.id,
      v_reward.reward_type,
      v_reward.reward_value,
      jsonb_build_object(
        'source', 'progress_reward',
        'lifetime_xp', v_lifetime_xp,
        'level', v_level
      )
    )
    ON CONFLICT DO NOTHING
    RETURNING id INTO v_reward_transaction_id;

    IF v_reward_transaction_id IS NULL THEN
      CONTINUE;
    END IF;

    IF v_reward.reward_type = 'wallet_credit' AND v_reward.reward_value > 0 THEN
      v_wallet_transaction_id := public.credit_wallet(
        p_user_id,
        v_reward.reward_value,
        'reward',
        'reward',
        v_reward_transaction_id,
        v_reward.title,
        jsonb_build_object('reward_definition_id', v_reward.id)
      );

      UPDATE public.reward_transactions
      SET wallet_transaction_id = v_wallet_transaction_id
      WHERE id = v_reward_transaction_id;
    END IF;

    v_granted := v_granted || jsonb_build_array(jsonb_build_object(
      'reward_id', v_reward.id,
      'title', v_reward.title,
      'reward_type', v_reward.reward_type,
      'reward_value', v_reward.reward_value
    ));
  END LOOP;

  RETURN jsonb_build_object('success', true, 'rewards', v_granted);
END;
$$;


ALTER FUNCTION "public"."grant_progress_rewards"("p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: guard_driver_financial_fields(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."guard_driver_financial_fields"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF (
    OLD.wallet_balance IS DISTINCT FROM NEW.wallet_balance
    OR OLD.total_earnings IS DISTINCT FROM NEW.total_earnings
    OR OLD.total_deliveries IS DISTINCT FROM NEW.total_deliveries
  )
  AND COALESCE(current_setting('app.driver_finance_authorized', true), '') <> 'true'
  AND COALESCE(current_setting('request.jwt.claim.role', true), '') <> 'service_role'
  AND NOT public.has_role(auth.uid(), 'admin') THEN
    RAISE EXCEPTION 'DRIVER_FINANCIAL_FIELDS_ARE_SERVER_MANAGED';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."guard_driver_financial_fields"() OWNER TO "postgres";

--
-- Name: guard_order_financial_fields(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."guard_order_financial_fields"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_is_trusted BOOLEAN :=
    COALESCE(auth.role(), '') = 'service_role'
    OR session_user IN ('postgres', 'supabase_admin')
    OR public.has_role(v_actor, 'admin');
BEGIN
  IF NOT v_is_trusted AND (
    NEW.user_id IS DISTINCT FROM OLD.user_id
    OR NEW.restaurant_id IS DISTINCT FROM OLD.restaurant_id
    OR NEW.restaurant_branch_id IS DISTINCT FROM OLD.restaurant_branch_id
    OR NEW.meal_id IS DISTINCT FROM OLD.meal_id
    OR NEW.order_type IS DISTINCT FROM OLD.order_type
    OR NEW.total_amount IS DISTINCT FROM OLD.total_amount
    OR NEW.delivery_fee IS DISTINCT FROM OLD.delivery_fee
    OR NEW.tip_amount IS DISTINCT FROM OLD.tip_amount
    OR NEW.commission_amount IS DISTINCT FROM OLD.commission_amount
    OR NEW.commission_rate IS DISTINCT FROM OLD.commission_rate
    OR NEW.restaurant_payout IS DISTINCT FROM OLD.restaurant_payout
  ) THEN
    RAISE EXCEPTION 'ORDER_FINANCIAL_FIELDS_ARE_SERVER_MANAGED';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."guard_order_financial_fields"() OWNER TO "postgres";

--
-- Name: handle_delivery_status_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."handle_delivery_status_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_customer_phone TEXT;
  v_customer_name TEXT;
  v_driver_name TEXT;
  v_restaurant_name TEXT;
  v_meal_name TEXT;
  v_message TEXT;
  v_delivery_address TEXT;
BEGIN
  -- Get customer information from meal_schedule and meals
  SELECT 
    ua.phone,
    COALESCE(p.full_name, 'Customer'),
    m.name  -- Get meal name from meals table
  INTO v_customer_phone, v_customer_name, v_meal_name
  FROM meal_schedules ms
  JOIN meals m ON m.id = ms.meal_id  -- Join to get meal name
  LEFT JOIN profiles p ON p.user_id = ms.user_id
  LEFT JOIN user_addresses ua ON ua.user_id = ms.user_id AND ua.is_default = true
  WHERE ms.id = NEW.schedule_id;
  
  -- Get restaurant name
  SELECT r.name INTO v_restaurant_name
  FROM restaurants r
  WHERE r.id = NEW.restaurant_id;
  
  -- Get driver name if assigned
  SELECT p.full_name INTO v_driver_name
  FROM drivers d
  LEFT JOIN profiles p ON p.user_id = d.user_id
  WHERE d.id = NEW.driver_id;
  
  -- Handle different status changes
  CASE NEW.status
    WHEN 'pending' THEN
      -- New delivery created - notify customer
      IF v_customer_phone IS NOT NULL THEN
        v_message := format(
          'Hello %s! Your meal "%s" from %s is being prepared. We will notify you when a driver is assigned.',
          v_customer_name,
          v_meal_name,
          v_restaurant_name
        );
        PERFORM send_whatsapp_notification(v_customer_phone, v_message, 'order_preparing');
      END IF;
      
    WHEN 'claimed' THEN
      -- Driver claimed - notify customer
      IF v_customer_phone IS NOT NULL AND v_driver_name IS NOT NULL THEN
        v_message := format(
          'Great news %s! Driver %s has been assigned to deliver your "%s" from %s. You will receive another notification when they are on the way.',
          v_customer_name,
          v_driver_name,
          v_meal_name,
          v_restaurant_name
        );
        PERFORM send_whatsapp_notification(v_customer_phone, v_message, 'driver_assigned');
      END IF;
      
    WHEN 'picked_up' THEN
      -- Driver picked up - notify customer
      IF v_customer_phone IS NOT NULL THEN
        v_message := format(
          'Hi %s! Your "%s" has been picked up from %s and is on the way to you. Estimated delivery: 20-30 minutes.',
          v_customer_name,
          v_meal_name,
          v_restaurant_name
        );
        PERFORM send_whatsapp_notification(v_customer_phone, v_message, 'order_picked_up');
      END IF;
      
    WHEN 'on_the_way' THEN
      -- Driver on the way - notify customer
      IF v_customer_phone IS NOT NULL THEN
        v_message := format(
          'Your %s from %s is almost there! The driver is on the way to your location.',
          v_meal_name,
          v_restaurant_name
        );
        PERFORM send_whatsapp_notification(v_customer_phone, v_message, 'driver_nearby');
      END IF;
      
    WHEN 'delivered' THEN
      -- Delivery complete - notify customer
      IF v_customer_phone IS NOT NULL THEN
        v_message := format(
          'Hello %s! Your "%s" from %s has been delivered. Enjoy your meal! Thank you for using NutrioFuel.',
          v_customer_name,
          v_meal_name,
          v_restaurant_name
        );
        PERFORM send_whatsapp_notification(v_customer_phone, v_message, 'order_delivered');
      END IF;
      
    WHEN 'cancelled' THEN
      -- Delivery cancelled - notify customer
      IF v_customer_phone IS NOT NULL THEN
        v_message := format(
          'We apologize %s. Your delivery for "%s" from %s has been cancelled. Please contact support for assistance.',
          v_customer_name,
          v_meal_name,
          v_restaurant_name
        );
        PERFORM send_whatsapp_notification(v_customer_phone, v_message, 'order_cancelled');
      END IF;
  END CASE;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_delivery_status_change"() OWNER TO "postgres";

--
-- Name: handle_meal_translation(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."handle_meal_translation"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Detect language of the meal name (basic detection)
  -- For now, assume English if not specified
  IF NEW.primary_language IS NULL THEN
    NEW.primary_language := 'en';
  END IF;
  
  -- Mark meal for translation if primary language is English
  -- The actual translation will be done via Edge Function
  IF NEW.primary_language = 'en' THEN
    -- Insert placeholder translation record (Edge Function will fill it)
    INSERT INTO public.meal_translations (
      meal_id,
      language_code,
      name,
      description,
      is_auto_translated,
      review_status,
      source_text_hash
    ) VALUES (
      NEW.id,
      'ar',
      NEW.name, -- Temporary: will be overwritten by translation
      NEW.description,
      true,
      'pending',
      md5(COALESCE(NEW.name, '') || COALESCE(NEW.description, ''))
    )
    ON CONFLICT (meal_id, language_code) DO NOTHING;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_meal_translation"() OWNER TO "postgres";

--
-- Name: handle_new_auth_user(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."handle_new_auth_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Insert new user into public.users table
  INSERT INTO public.users (id, email, full_name, phone)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.raw_user_meta_data->>'name'),
    NEW.raw_user_meta_data->>'phone'
  );
  
  RETURN NEW;
EXCEPTION
  WHEN OTHERS THEN
    -- Log the error but don't prevent user creation
    RAISE WARNING 'Failed to create public.users record for user %: %', NEW.id, SQLERRM;
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_new_auth_user"() OWNER TO "postgres";

--
-- Name: handle_new_user(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO public.profiles (user_id, full_name, created_at)
  VALUES (
    NEW.id,
    COALESCE(NULLIF(NEW.raw_user_meta_data ->> 'full_name', ''), NEW.email),
    COALESCE(NEW.created_at, now())
  )
  ON CONFLICT (user_id) DO UPDATE
  SET full_name = COALESCE(public.profiles.full_name, EXCLUDED.full_name);

  INSERT INTO public.user_roles (user_id, role)
  VALUES (NEW.id, 'user')
  ON CONFLICT (user_id, role) DO NOTHING;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_new_user"() OWNER TO "postgres";

--
-- Name: has_role("uuid", "public"."app_role"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."has_role"("_user_id" "uuid", "_role" "public"."app_role") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.user_roles
    WHERE user_id = _user_id
      AND role = _role
  )
$$;


ALTER FUNCTION "public"."has_role"("_user_id" "uuid", "_role" "public"."app_role") OWNER TO "postgres";

--
-- Name: has_staff_permission("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."has_staff_permission"("p_restaurant_id" "uuid", "p_permission" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1 
        FROM staff_members sm
        JOIN staff_roles sr ON sm.role_id = sr.id
        WHERE sm.restaurant_id = p_restaurant_id 
        AND sm.user_id = auth.uid()
        AND sm.is_active = true
        AND sr.permissions @> jsonb_build_array(p_permission)
    );
END;
$$;


