-- Name: has_user_submitted_nps("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."has_user_submitted_nps"("p_user_id" "uuid", "p_order_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_user_id);
  RETURN public.has_user_submitted_nps_trusted(p_user_id, p_order_id);
