ALTER FUNCTION "public"."has_user_submitted_nps"("p_user_id" "uuid", "p_order_id" "uuid") OWNER TO "postgres";

--
-- Name: has_user_submitted_nps_trusted("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

