--
-- Name: haversine_km(numeric, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."haversine_km"("p_lat1" numeric, "p_lon1" numeric, "p_lat2" numeric, "p_lon2" numeric) RETURNS numeric
    LANGUAGE "sql" IMMUTABLE STRICT
    SET "search_path" TO 'public', 'pg_temp'
    AS $_$
  SELECT ROUND(
    (
      6371 * 2 * ASIN(
        SQRT(
          POWER(SIN(RADIANS(($3 - $1) / 2)), 2)
          + COS(RADIANS($1)) * COS(RADIANS($3))
          * POWER(SIN(RADIANS(($4 - $2) / 2)), 2)
        )
      )
    )::NUMERIC,
    2
  );
$_$;


ALTER FUNCTION "public"."haversine_km"("p_lat1" numeric, "p_lon1" numeric, "p_lat2" numeric, "p_lon2" numeric) OWNER TO "postgres";

--
-- Name: health_context_ai_summary_internal("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."health_context_ai_summary_internal"("p_user_id" "uuid", "p_days" integer DEFAULT 30) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_result JSONB;
BEGIN
  IF p_user_id IS NULL OR p_days NOT BETWEEN 7 AND 90 THEN RETURN NULL; END IF;
  IF NOT public.health_context_feature_enabled() THEN RETURN NULL; END IF;
  IF NOT EXISTS (
    SELECT 1 FROM public.health_context_preferences preferences
    WHERE preferences.user_id = p_user_id AND preferences.journal_enabled
  ) THEN RETURN NULL; END IF;
  IF NOT EXISTS (
    SELECT 1 FROM public.ai_data_consents consent
    WHERE consent.user_id = p_user_id
      AND consent.purpose = 'health_context_summary'
      AND consent.status = 'granted'
      AND consent.policy_version = '2026-07-health-context-ai-v1'
  ) THEN RETURN NULL; END IF;

  WITH entries AS (
    SELECT entry.*
    FROM public.health_context_entries entry
    WHERE entry.user_id = p_user_id
      AND entry.entry_date >= CURRENT_DATE - (p_days - 1)
  ), phase_groups AS (
    SELECT cycle_phase, count(*)::INTEGER AS entry_count,
      round(avg(appetite)::NUMERIC, 1) AS average_appetite,
      round(avg(energy)::NUMERIC, 1) AS average_energy
    FROM entries
    WHERE cycle_phase IS NOT NULL
    GROUP BY cycle_phase
    HAVING count(*) >= 3
  )
  SELECT CASE WHEN count(*) < 3 THEN NULL ELSE jsonb_build_object(
    'window_days', p_days,
    'days_logged', count(*),
    'average_mood', round(avg(mood)::NUMERIC, 1),
    'average_stress', round(avg(stress)::NUMERIC, 1),
    'average_appetite', round(avg(appetite)::NUMERIC, 1),
    'average_energy', round(avg(energy)::NUMERIC, 1),
    'digestive_discomfort_days', count(*) FILTER (WHERE symptom_severity >= 2),
    'cycle_phase_observations', COALESCE((SELECT jsonb_agg(to_jsonb(phase_groups) ORDER BY cycle_phase) FROM phase_groups), '[]'::JSONB)
  ) END INTO v_result
  FROM entries;
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."health_context_ai_summary_internal"("p_user_id" "uuid", "p_days" integer) OWNER TO "postgres";

--
-- Name: health_context_feature_enabled(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."health_context_feature_enabled"() RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_value JSONB;
  v_enabled BOOLEAN := false;
  v_rollout_percent INTEGER := 0;
BEGIN
  SELECT settings.value INTO v_value
  FROM public.platform_settings settings
  WHERE settings.key = 'phase1-health-context';

  IF NOT FOUND THEN
    RETURN false;
  END IF;

  v_enabled := coalesce((v_value->>'enabled')::BOOLEAN, false);
  v_rollout_percent := greatest(
    least(coalesce((v_value->>'rollout_percent')::INTEGER, 0), 100),
    0
  );

  IF NOT v_enabled OR v_rollout_percent <= 0 THEN
    RETURN false;
  END IF;

  IF v_rollout_percent >= 100 THEN
    RETURN true;
  END IF;

  IF v_actor IS NULL THEN
    RETURN false;
  END IF;

  RETURN mod(abs(hashtext(v_actor::TEXT)::BIGINT), 100) < v_rollout_percent;
END;
$$;


ALTER FUNCTION "public"."health_context_feature_enabled"() OWNER TO "postgres";

--
-- Name: FUNCTION "health_context_feature_enabled"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."health_context_feature_enabled"() IS 'Checks the health-context rollout flag and assigns authenticated users deterministically when rollout is below 100 percent.';


--
-- Name: increment_addon_usage("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."increment_addon_usage"("addon_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_restaurant_id uuid;
BEGIN
  SELECT restaurant_id INTO v_restaurant_id FROM public.restaurant_addons WHERE id = addon_id;
  IF v_restaurant_id IS NULL OR NOT (
    auth.role() = 'service_role'
    OR public.has_role(auth.uid(), 'admin'::public.app_role)
    OR public.is_restaurant_operator(v_restaurant_id, auth.uid())
  ) THEN
    RAISE EXCEPTION 'RESTAURANT_OPERATOR_REQUIRED';
  END IF;
  UPDATE public.restaurant_addons SET usage_count = usage_count + 1 WHERE id = addon_id;
END;
$$;


ALTER FUNCTION "public"."increment_addon_usage"("addon_id" "uuid") OWNER TO "postgres";

--
-- Name: increment_meal_usage("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."increment_meal_usage"("p_subscription_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_updated_rows INTEGER;
BEGIN
  -- Atomic update: Only increment if quota allows
  -- meals_per_week = 0 means unlimited
  WITH updated AS (
    UPDATE public.subscriptions
    SET meals_used_this_week = meals_used_this_week + 1
    WHERE id = p_subscription_id 
      AND status = 'active'
      AND (meals_per_week = 0 OR meals_used_this_week < meals_per_week)
    RETURNING id
  )
  SELECT COUNT(*) INTO v_updated_rows FROM updated;
  
  RETURN v_updated_rows > 0;
END;
$$;


ALTER FUNCTION "public"."increment_meal_usage"("p_subscription_id" "uuid") OWNER TO "postgres";

--
-- Name: increment_monthly_meal_usage("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."increment_monthly_meal_usage"("p_subscription_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_subscription public.subscriptions%ROWTYPE;
  v_current_month DATE := DATE_TRUNC('month', CURRENT_DATE)::DATE;
  v_current_week DATE := DATE_TRUNC('week', CURRENT_DATE)::DATE;
  v_monthly_used INTEGER;
  v_weekly_used INTEGER;
  v_rollover_result JSONB;
BEGIN
  IF v_user_id IS NULL THEN
    RETURN FALSE;
  END IF;

  SELECT *
    INTO v_subscription
  FROM public.subscriptions
  WHERE id = p_subscription_id
    AND user_id = v_user_id
    AND status IN ('active', 'cancelled')
    AND (
      status = 'active'
      OR COALESCE(end_date, CURRENT_DATE - 1) >= CURRENT_DATE
    )
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  IF COALESCE(v_subscription.tier, '') <> 'vip' THEN
    v_rollover_result := public.use_rollover_credit_if_available(
      p_subscription_id,
      v_user_id
    );

    IF COALESCE((v_rollover_result ->> 'used_rollover')::BOOLEAN, FALSE) THEN
      RETURN TRUE;
    END IF;
  END IF;

  v_monthly_used := CASE
    WHEN v_subscription.month_start_date IS NULL
      OR v_subscription.month_start_date < v_current_month THEN 0
    ELSE COALESCE(v_subscription.meals_used_this_month, 0)
  END;

  v_weekly_used := CASE
    WHEN v_subscription.week_start_date IS NULL
      OR v_subscription.week_start_date < v_current_week THEN 0
    ELSE COALESCE(v_subscription.meals_used_this_week, 0)
  END;

  IF COALESCE(v_subscription.tier, '') <> 'vip'
    AND COALESCE(v_subscription.meals_per_month, 0) > 0
    AND v_monthly_used >= v_subscription.meals_per_month THEN
    RETURN FALSE;
  END IF;

  IF COALESCE(v_subscription.tier, '') <> 'vip'
    AND COALESCE(v_subscription.meals_per_week, 0) > 0
    AND v_weekly_used >= v_subscription.meals_per_week THEN
    RETURN FALSE;
  END IF;

  UPDATE public.subscriptions
  SET meals_used_this_month = v_monthly_used + 1,
      month_start_date = v_current_month,
      meals_used_this_week = v_weekly_used + 1,
      week_start_date = v_current_week,
      updated_at = NOW()
  WHERE id = v_subscription.id;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."increment_monthly_meal_usage"("p_subscription_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "increment_monthly_meal_usage"("p_subscription_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."increment_monthly_meal_usage"("p_subscription_id" "uuid") IS 'Consumes active rollover meal credits before incrementing current-cycle meal usage.';


