-- Name: increment_restaurant_order_count("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."increment_restaurant_order_count"("p_restaurant_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_capacity_check RECORD;
BEGIN
    -- Check capacity first
    SELECT * INTO v_capacity_check
    FROM check_restaurant_capacity(p_restaurant_id);
    
    IF NOT v_capacity_check.can_accept THEN
        RETURN FALSE;
    END IF;
    
    -- Increment the count
    UPDATE public.restaurants
    SET current_day_orders = current_day_orders + 1
    WHERE id = p_restaurant_id;
    
    RETURN TRUE;
END;
$$;


