--
-- Name: increment_snack_usage("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."increment_snack_usage"("p_subscription_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_subscription public.subscriptions%ROWTYPE;
BEGIN
  IF v_user_id IS NULL THEN
    RETURN FALSE;
  END IF;

  SELECT *
    INTO v_subscription
  FROM public.subscriptions
  WHERE id = p_subscription_id
    AND user_id = v_user_id
    AND status IN ('active', 'cancelled')
    AND (
      status = 'active'
      OR COALESCE(end_date, CURRENT_DATE - 1) >= CURRENT_DATE
    )
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  IF COALESCE(v_subscription.tier, '') <> 'vip'
    AND (
      COALESCE(v_subscription.snacks_per_month, 0) <= 0
      OR COALESCE(v_subscription.snacks_used_this_month, 0)
        >= v_subscription.snacks_per_month
    ) THEN
    RETURN FALSE;
  END IF;

  UPDATE public.subscriptions
  SET snacks_used_this_month = COALESCE(snacks_used_this_month, 0) + 1,
      updated_at = NOW()
  WHERE id = v_subscription.id;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."increment_snack_usage"("p_subscription_id" "uuid") OWNER TO "postgres";

--
-- Name: ingest_wearable_metric_samples("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."ingest_wearable_metric_samples"("p_samples" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_sample jsonb;
  v_metric_date date;
  v_changed integer;
  v_changed_count integer := 0;
  v_unchanged_count integer := 0;
  v_rejected_count integer := 0;
  v_dates date[] := '{}';
begin
  if v_user_id is null then
    raise exception 'AUTH_REQUIRED' using errcode = '42501';
  end if;

  if jsonb_typeof(p_samples) <> 'array' then
    raise exception 'SAMPLES_MUST_BE_ARRAY';
  end if;

  if jsonb_array_length(p_samples) > 500 then
    raise exception 'TOO_MANY_SAMPLES';
  end if;

  for v_sample in select value from jsonb_array_elements(p_samples)
  loop
    begin
      v_metric_date := (v_sample ->> 'metric_date')::date;

      insert into public.wearable_metric_samples (
        user_id,
        provider,
        metric_type,
        metric_date,
        start_at,
        end_at,
        value,
        unit,
        external_id,
        dedupe_key,
        checksum,
        source_app,
        device_id,
        sync_status,
        raw,
        synced_at,
        deleted_at,
        updated_at
      )
      values (
        v_user_id,
        v_sample ->> 'provider',
        v_sample ->> 'metric_type',
        v_metric_date,
        (v_sample ->> 'start_at')::timestamptz,
        (v_sample ->> 'end_at')::timestamptz,
        (v_sample ->> 'value')::numeric,
        v_sample ->> 'unit',
        nullif(v_sample ->> 'external_id', ''),
        v_sample ->> 'dedupe_key',
        v_sample ->> 'checksum',
        nullif(v_sample ->> 'source_app', ''),
        nullif(v_sample ->> 'device_id', ''),
        coalesce(nullif(v_sample ->> 'sync_status', ''), 'synced'),
        coalesce(v_sample -> 'raw', '{}'::jsonb),
        now(),
        null,
        now()
      )
      on conflict (user_id, dedupe_key)
      do update set
        provider = excluded.provider,
        metric_type = excluded.metric_type,
        metric_date = excluded.metric_date,
        start_at = excluded.start_at,
        end_at = excluded.end_at,
        value = excluded.value,
        unit = excluded.unit,
        external_id = excluded.external_id,
        checksum = excluded.checksum,
        source_app = excluded.source_app,
        device_id = excluded.device_id,
        sync_status = excluded.sync_status,
        raw = excluded.raw,
        synced_at = excluded.synced_at,
        deleted_at = null,
        updated_at = now()
      where public.wearable_metric_samples.checksum is distinct from excluded.checksum
         or public.wearable_metric_samples.deleted_at is not null
         or public.wearable_metric_samples.sync_status is distinct from excluded.sync_status;

      get diagnostics v_changed = row_count;
      if v_changed = 0 then
        v_unchanged_count := v_unchanged_count + 1;
      else
        v_changed_count := v_changed_count + 1;
      end if;

      v_dates := array_append(v_dates, v_metric_date);
    exception
      when others then
        v_rejected_count := v_rejected_count + 1;
    end;
  end loop;

  for v_metric_date in select distinct unnest(v_dates)
  loop
    perform public.rebuild_health_daily_metrics_from_wearables(v_user_id, v_metric_date);
  end loop;

  return jsonb_build_object(
    'ok', true,
    'inserted_or_updated', v_changed_count,
    'unchanged', v_unchanged_count,
    'rejected', v_rejected_count
  );
end;
$$;


ALTER FUNCTION "public"."ingest_wearable_metric_samples"("p_samples" "jsonb") OWNER TO "postgres";

