--
-- Name: invoke_notification_event_worker(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."invoke_notification_event_worker"() RETURNS bigint
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'vault', 'net', 'public', 'pg_temp'
    AS $$
DECLARE
  v_secret TEXT;
  v_request_id BIGINT;
BEGIN
  SELECT decrypted_secret INTO v_secret
  FROM vault.decrypted_secrets
  WHERE name = 'notification_worker_secret'
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_secret IS NULL THEN
    RAISE EXCEPTION 'notification_worker_secret_unavailable';
  END IF;

  SELECT net.http_post(
    url := 'https://loepcagitrijlfksawfm.supabase.co/functions/v1/process-notification-events',
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'x-notification-worker-secret', v_secret
    ),
    body := '{"limit":50}'::JSONB,
    timeout_milliseconds := 25000
  ) INTO v_request_id;

  RETURN v_request_id;
END;
$$;


ALTER FUNCTION "public"."invoke_notification_event_worker"() OWNER TO "postgres";

