--
-- Name: is_restaurant_operator("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."is_restaurant_operator"("p_restaurant_id" "uuid", "p_user_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  SELECT p_user_id IS NOT NULL AND (
    EXISTS (
      SELECT 1
      FROM public.restaurants r
      WHERE r.id = p_restaurant_id
        AND r.owner_id = p_user_id
        AND (
          public.has_role(p_user_id, 'partner'::public.app_role)
          OR public.has_role(p_user_id, 'restaurant'::public.app_role)
        )
    )
    OR EXISTS (
      SELECT 1
      FROM public.restaurant_staff rs
      WHERE rs.restaurant_id = p_restaurant_id
        AND rs.user_id = p_user_id
        AND rs.is_active = true
    )
  );
$$;


