-- Name: is_restaurant_staff("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."is_restaurant_staff"("p_restaurant_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1 
        FROM staff_members 
        WHERE restaurant_id = p_restaurant_id 
        AND user_id = auth.uid()
        AND is_active = true
    );
END;
$$;


ALTER FUNCTION "public"."is_restaurant_staff"("p_restaurant_id" "uuid") OWNER TO "postgres";

--
-- Name: join_challenge("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."join_challenge"("p_challenge_id" "uuid", "p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID := coalesce(p_user_id, auth.uid());
  v_challenge public.community_challenges%ROWTYPE;
  v_participant_id UUID;
BEGIN
  IF auth.uid() IS NULL OR v_user_id <> auth.uid() THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authorized');
  END IF;

  SELECT *
  INTO v_challenge
  FROM public.community_challenges
  WHERE id = p_challenge_id
    AND is_active = true
    AND start_date <= current_date
    AND end_date >= current_date;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Challenge not found or inactive');
  END IF;

  INSERT INTO public.challenge_participants (challenge_id, user_id, current_progress)
  VALUES (p_challenge_id, v_user_id, 0)
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_participant_id;

  IF v_participant_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Already joined this challenge');
  END IF;

  UPDATE public.community_challenges
  SET participant_count = (
    SELECT count(*)::INTEGER
    FROM public.challenge_participants
    WHERE challenge_id = p_challenge_id
  )
  WHERE id = p_challenge_id;

  RETURN public.apply_community_challenge_progress(v_user_id, p_challenge_id)
    || jsonb_build_object('participant_id', v_participant_id, 'joined', true);
END;
$$;


ALTER FUNCTION "public"."join_challenge"("p_challenge_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "join_challenge"("p_challenge_id" "uuid", "p_user_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."join_challenge"("p_challenge_id" "uuid", "p_user_id" "uuid") IS 'Allow user to join an active community challenge';


--
-- Name: join_challenge_team("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."join_challenge_team"("p_join_code" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_team public.challenge_teams%ROWTYPE;
  v_team_size INTEGER;
  v_member_count INTEGER;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'Authentication required'; END IF;

  SELECT ct.*
  INTO v_team
  FROM public.challenge_teams ct
  JOIN public.community_challenges cc ON cc.id = ct.challenge_id
  WHERE ct.join_code = upper(btrim(coalesce(p_join_code, '')))
    AND cc.participation_mode = 'team'
    AND cc.is_active = true
    AND current_date BETWEEN cc.start_date AND cc.end_date
  FOR UPDATE OF ct;

  IF NOT FOUND THEN RAISE EXCEPTION 'Team code is invalid or expired'; END IF;

  SELECT team_size INTO v_team_size
  FROM public.community_challenges
  WHERE id = v_team.challenge_id;

  IF NOT EXISTS (
    SELECT 1 FROM public.challenge_participants cp
    WHERE cp.challenge_id = v_team.challenge_id AND cp.user_id = v_user_id
  ) THEN
    RAISE EXCEPTION 'Join the challenge before joining a team';
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.challenge_team_members ctm
    WHERE ctm.challenge_id = v_team.challenge_id AND ctm.user_id = v_user_id
  ) THEN
    RAISE EXCEPTION 'You already belong to a team in this challenge';
  END IF;

  SELECT count(*) INTO v_member_count
  FROM public.challenge_team_members WHERE team_id = v_team.id;
  IF v_member_count >= v_team_size THEN RAISE EXCEPTION 'This team is full'; END IF;

  INSERT INTO public.challenge_team_members (challenge_id, team_id, user_id)
  VALUES (v_team.challenge_id, v_team.id, v_user_id);

  RETURN jsonb_build_object('success', true, 'team_id', v_team.id);
END;
$$;


ALTER FUNCTION "public"."join_challenge_team"("p_join_code" "text") OWNER TO "postgres";

--
-- Name: leave_challenge_team("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."leave_challenge_team"("p_team_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_role TEXT;
  v_next_captain UUID;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'Authentication required'; END IF;

  SELECT role INTO v_role
  FROM public.challenge_team_members
  WHERE team_id = p_team_id AND user_id = v_user_id
  FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'You are not a member of this team'; END IF;

  IF v_role = 'captain' THEN
    SELECT user_id INTO v_next_captain
    FROM public.challenge_team_members
    WHERE team_id = p_team_id AND user_id <> v_user_id
    ORDER BY joined_at, id
    LIMIT 1;

    IF v_next_captain IS NULL THEN
      DELETE FROM public.challenge_teams WHERE id = p_team_id;
      RETURN jsonb_build_object('success', true, 'team_deleted', true);
    END IF;

    DELETE FROM public.challenge_team_members
    WHERE team_id = p_team_id AND user_id = v_user_id;
    UPDATE public.challenge_team_members
    SET role = 'captain'
    WHERE team_id = p_team_id AND user_id = v_next_captain;
    UPDATE public.challenge_teams
    SET captain_id = v_next_captain, updated_at = now()
    WHERE id = p_team_id;
  ELSE
    DELETE FROM public.challenge_team_members
    WHERE team_id = p_team_id AND user_id = v_user_id;
  END IF;

  RETURN jsonb_build_object('success', true, 'team_deleted', false);
END;
$$;


ALTER FUNCTION "public"."leave_challenge_team"("p_team_id" "uuid") OWNER TO "postgres";

--
-- Name: log_manual_meal_items("jsonb", "date", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."log_manual_meal_items"("p_items" "jsonb", "p_log_date" "date" DEFAULT NULL::"date", "p_request_id" "uuid" DEFAULT "gen_random_uuid"(), "p_source" "text" DEFAULT 'manual'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_today DATE := (NOW() AT TIME ZONE 'Asia/Qatar')::DATE;
  v_source TEXT;
  v_item JSONB;
  v_item_index INTEGER;
  v_name TEXT;
  v_image_url TEXT;
  v_calories INTEGER;
  v_protein INTEGER;
  v_carbs INTEGER;
  v_fat INTEGER;
  v_total_calories INTEGER := 0;
  v_total_protein INTEGER := 0;
  v_total_carbs INTEGER := 0;
  v_total_fat INTEGER := 0;
  v_history_id UUID;
  v_history_ids UUID[] := ARRAY[]::UUID[];
  v_existing_ids UUID[];
  v_daily_award_count INTEGER := 0;
  v_remaining_awards INTEGER := 0;
  v_xp_awarded INTEGER := 0;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;

  IF p_request_id IS NULL THEN
    RAISE EXCEPTION 'REQUEST_ID_REQUIRED';
  END IF;

  PERFORM pg_advisory_xact_lock(hashtextextended(p_request_id::TEXT, 0));

  SELECT ARRAY_AGG(mh.id ORDER BY mh.source_item_index)
  INTO v_existing_ids
  FROM public.meal_history mh
  WHERE mh.user_id = v_user_id
    AND mh.source_request_id = p_request_id;

  IF COALESCE(array_length(v_existing_ids, 1), 0) > 0 THEN
    RETURN jsonb_build_object(
      'success', TRUE,
      'duplicate', TRUE,
      'history_ids', to_jsonb(v_existing_ids),
      'xp_awarded', 0
    );
  END IF;

  p_log_date := COALESCE(p_log_date, v_today);
  IF p_log_date < v_today - 365 OR p_log_date > v_today THEN
    RAISE EXCEPTION 'INVALID_LOG_DATE';
  END IF;

  IF jsonb_typeof(p_items) <> 'array'
    OR jsonb_array_length(p_items) < 1
    OR jsonb_array_length(p_items) > 20 THEN
    RAISE EXCEPTION 'INVALID_MEAL_ITEMS';
  END IF;

  v_source := LEFT(
    REGEXP_REPLACE(COALESCE(NULLIF(BTRIM(p_source), ''), 'manual'), '[^a-zA-Z0-9_-]', '', 'g'),
    40
  );
  IF v_source = '' THEN
    v_source := 'manual';
  END IF;

  FOR v_item, v_item_index IN
    SELECT value, ordinality::INTEGER
    FROM jsonb_array_elements(p_items) WITH ORDINALITY
  LOOP
    v_name := BTRIM(COALESCE(v_item ->> 'name', ''));
    v_image_url := NULLIF(BTRIM(v_item ->> 'image_url'), '');
    v_calories := ROUND(COALESCE((v_item ->> 'calories')::NUMERIC, 0));
    v_protein := ROUND(COALESCE((v_item ->> 'protein_g')::NUMERIC, 0));
    v_carbs := ROUND(COALESCE((v_item ->> 'carbs_g')::NUMERIC, 0));
    v_fat := ROUND(COALESCE((v_item ->> 'fat_g')::NUMERIC, 0));

    IF v_name = '' OR LENGTH(v_name) > 120
      OR v_calories < 0 OR v_calories > 5000
      OR v_protein < 0 OR v_protein > 1000
      OR v_carbs < 0 OR v_carbs > 1000
      OR v_fat < 0 OR v_fat > 1000
      OR COALESCE(LENGTH(v_image_url), 0) > 2048 THEN
      RAISE EXCEPTION 'INVALID_MEAL_ITEM_AT_INDEX_%', v_item_index;
    END IF;

    IF v_calories = 0 AND v_protein = 0 AND v_carbs = 0 AND v_fat = 0 THEN
      RAISE EXCEPTION 'EMPTY_NUTRITION_AT_INDEX_%', v_item_index;
    END IF;

    INSERT INTO public.meal_history (
      user_id,
      name,
      calories,
      protein_g,
      carbs_g,
      fat_g,
      image_url,
      logged_at,
      source,
      source_request_id,
      source_item_index
    )
    VALUES (
      v_user_id,
      v_name,
      v_calories,
      v_protein,
      v_carbs,
      v_fat,
      v_image_url,
      (p_log_date::TIMESTAMP + LOCALTIME) AT TIME ZONE 'Asia/Qatar',
      v_source,
      p_request_id,
      v_item_index
    )
    RETURNING id INTO v_history_id;

    v_history_ids := array_append(v_history_ids, v_history_id);
    v_total_calories := v_total_calories + v_calories;
    v_total_protein := v_total_protein + v_protein;
    v_total_carbs := v_total_carbs + v_carbs;
    v_total_fat := v_total_fat + v_fat;
  END LOOP;

  INSERT INTO public.progress_logs (
    user_id,
    log_date,
    calories_consumed,
    protein_consumed_g,
    carbs_consumed_g,
    fat_consumed_g,
    created_at,
    updated_at
  )
  VALUES (
    v_user_id,
    p_log_date,
    v_total_calories,
    v_total_protein,
    v_total_carbs,
    v_total_fat,
    NOW(),
    NOW()
  )
  ON CONFLICT (user_id, log_date) DO UPDATE
  SET calories_consumed = COALESCE(public.progress_logs.calories_consumed, 0) + EXCLUDED.calories_consumed,
      protein_consumed_g = COALESCE(public.progress_logs.protein_consumed_g, 0) + EXCLUDED.protein_consumed_g,
      carbs_consumed_g = COALESCE(public.progress_logs.carbs_consumed_g, 0) + EXCLUDED.carbs_consumed_g,
      fat_consumed_g = COALESCE(public.progress_logs.fat_consumed_g, 0) + EXCLUDED.fat_consumed_g,
      updated_at = NOW();

  SELECT COUNT(*)::INTEGER
  INTO v_daily_award_count
  FROM public.xp_transactions xt
  WHERE xt.user_id = v_user_id
    AND xt.action_type = 'manual_meal_log'
    AND xt.xp_amount > 0
    AND (xt.created_at AT TIME ZONE 'Asia/Qatar')::DATE = v_today;

  IF p_log_date = v_today THEN
    v_remaining_awards := GREATEST(0, 3 - v_daily_award_count);
    FOREACH v_history_id IN ARRAY v_history_ids LOOP
      EXIT WHEN v_remaining_awards <= 0;
      PERFORM public.award_xp(
        v_user_id,
        10,
        'Meal logged',
        'manual_meal_log',
        v_history_id::TEXT,
        jsonb_build_object('meal_history_id', v_history_id, 'log_date', p_log_date, 'source', v_source)
      );
      v_remaining_awards := v_remaining_awards - 1;
      v_xp_awarded := v_xp_awarded + 10;
    END LOOP;
  END IF;

  UPDATE public.profiles p
  SET total_meals_logged = counts.meal_count,
      updated_at = NOW()
  FROM (
    SELECT COUNT(*)::INTEGER AS meal_count
    FROM public.meal_history mh
    WHERE mh.user_id = v_user_id
  ) counts
  WHERE p.user_id = v_user_id;

  PERFORM public.check_and_award_badges(v_user_id);

  RETURN jsonb_build_object(
    'success', TRUE,
    'duplicate', FALSE,
    'history_ids', to_jsonb(v_history_ids),
    'logged_count', array_length(v_history_ids, 1),
    'calories', v_total_calories,
    'protein', v_total_protein,
    'carbs', v_total_carbs,
    'fat', v_total_fat,
    'xp_awarded', v_xp_awarded
  );
END;
$$;


ALTER FUNCTION "public"."log_manual_meal_items"("p_items" "jsonb", "p_log_date" "date", "p_request_id" "uuid", "p_source" "text") OWNER TO "postgres";

--
-- Name: log_manual_meal_items_v2("jsonb", "date", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."log_manual_meal_items_v2"("p_items" "jsonb", "p_log_date" "date" DEFAULT NULL::"date", "p_request_id" "uuid" DEFAULT "gen_random_uuid"(), "p_source" "text" DEFAULT 'manual'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_today DATE := (NOW() AT TIME ZONE 'Asia/Qatar')::DATE;
  v_source TEXT;
  v_item JSONB;
  v_item_index INTEGER;
  v_name TEXT;
  v_image_url TEXT;
  v_calories INTEGER;
  v_protein INTEGER;
  v_carbs INTEGER;
  v_fat INTEGER;
  v_fiber NUMERIC(8, 2);
  v_sugar NUMERIC(8, 2);
  v_sodium NUMERIC(10, 2);
  v_total_calories INTEGER := 0;
  v_total_protein INTEGER := 0;
  v_total_carbs INTEGER := 0;
  v_total_fat INTEGER := 0;
  v_total_fiber NUMERIC(10, 2) := 0;
  v_total_sugar NUMERIC(10, 2) := 0;
  v_total_sodium NUMERIC(12, 2) := 0;
  v_history_id UUID;
  v_history_ids UUID[] := ARRAY[]::UUID[];
  v_existing_ids UUID[];
  v_daily_award_count INTEGER := 0;
  v_remaining_awards INTEGER := 0;
  v_xp_awarded INTEGER := 0;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;
  IF p_request_id IS NULL THEN
    RAISE EXCEPTION 'REQUEST_ID_REQUIRED';
  END IF;

  PERFORM pg_advisory_xact_lock(hashtextextended(p_request_id::TEXT, 0));

  SELECT ARRAY_AGG(mh.id ORDER BY mh.source_item_index)
  INTO v_existing_ids
  FROM public.meal_history mh
  WHERE mh.user_id = v_user_id
    AND mh.source_request_id = p_request_id;

  IF COALESCE(array_length(v_existing_ids, 1), 0) > 0 THEN
    RETURN jsonb_build_object(
      'success', TRUE,
      'duplicate', TRUE,
      'history_ids', to_jsonb(v_existing_ids),
      'logged_count', array_length(v_existing_ids, 1),
      'xp_awarded', 0
    );
  END IF;

  p_log_date := COALESCE(p_log_date, v_today);
  IF p_log_date < v_today - 365 OR p_log_date > v_today THEN
    RAISE EXCEPTION 'INVALID_LOG_DATE';
  END IF;
  IF jsonb_typeof(p_items) <> 'array'
    OR jsonb_array_length(p_items) < 1
    OR jsonb_array_length(p_items) > 20 THEN
    RAISE EXCEPTION 'INVALID_MEAL_ITEMS';
  END IF;

  v_source := LEFT(
    REGEXP_REPLACE(COALESCE(NULLIF(BTRIM(p_source), ''), 'manual'), '[^a-zA-Z0-9_-]', '', 'g'),
    40
  );
  IF v_source = '' THEN v_source := 'manual'; END IF;

  FOR v_item, v_item_index IN
    SELECT value, ordinality::INTEGER
    FROM jsonb_array_elements(p_items) WITH ORDINALITY
  LOOP
    v_name := BTRIM(COALESCE(v_item ->> 'name', ''));
    v_image_url := NULLIF(BTRIM(v_item ->> 'image_url'), '');
    v_calories := ROUND(COALESCE((v_item ->> 'calories')::NUMERIC, 0));
    v_protein := ROUND(COALESCE((v_item ->> 'protein_g')::NUMERIC, 0));
    v_carbs := ROUND(COALESCE((v_item ->> 'carbs_g')::NUMERIC, 0));
    v_fat := ROUND(COALESCE((v_item ->> 'fat_g')::NUMERIC, 0));
    v_fiber := ROUND(COALESCE((v_item ->> 'fiber_g')::NUMERIC, 0), 2);
    v_sugar := ROUND(COALESCE((v_item ->> 'sugar_g')::NUMERIC, 0), 2);
    v_sodium := ROUND(COALESCE((v_item ->> 'sodium_mg')::NUMERIC, 0), 2);

    IF v_name = '' OR LENGTH(v_name) > 120
      OR v_calories < 0 OR v_calories > 5000
      OR v_protein < 0 OR v_protein > 1000
      OR v_carbs < 0 OR v_carbs > 1000
      OR v_fat < 0 OR v_fat > 1000
      OR v_fiber < 0 OR v_fiber > 1000
      OR v_sugar < 0 OR v_sugar > 1000
      OR v_sodium < 0 OR v_sodium > 100000
      OR COALESCE(LENGTH(v_image_url), 0) > 2048 THEN
      RAISE EXCEPTION 'INVALID_MEAL_ITEM_AT_INDEX_%', v_item_index;
    END IF;
    IF v_calories = 0 AND v_protein = 0 AND v_carbs = 0 AND v_fat = 0 THEN
      RAISE EXCEPTION 'EMPTY_NUTRITION_AT_INDEX_%', v_item_index;
    END IF;

    INSERT INTO public.meal_history (
      user_id, name, calories, protein_g, carbs_g, fat_g,
      fiber_g, sugar_g, sodium_mg, nutrient_data, image_url, logged_at,
      source, source_request_id, source_item_index
    ) VALUES (
      v_user_id, v_name, v_calories, v_protein, v_carbs, v_fat,
      v_fiber, v_sugar, v_sodium,
      jsonb_strip_nulls(v_item - ARRAY['name', 'calories', 'protein_g', 'carbs_g', 'fat_g', 'image_url']::TEXT[]),
      v_image_url,
      (p_log_date::TIMESTAMP + LOCALTIME) AT TIME ZONE 'Asia/Qatar',
      v_source, p_request_id, v_item_index
    ) RETURNING id INTO v_history_id;

    v_history_ids := array_append(v_history_ids, v_history_id);
    v_total_calories := v_total_calories + v_calories;
    v_total_protein := v_total_protein + v_protein;
    v_total_carbs := v_total_carbs + v_carbs;
    v_total_fat := v_total_fat + v_fat;
    v_total_fiber := v_total_fiber + v_fiber;
    v_total_sugar := v_total_sugar + v_sugar;
    v_total_sodium := v_total_sodium + v_sodium;
  END LOOP;

  INSERT INTO public.progress_logs (
    user_id, log_date, calories_consumed, protein_consumed_g,
    carbs_consumed_g, fat_consumed_g, fiber_consumed_g, created_at, updated_at
  ) VALUES (
    v_user_id, p_log_date, v_total_calories, v_total_protein,
    v_total_carbs, v_total_fat, v_total_fiber, NOW(), NOW()
  )
  ON CONFLICT (user_id, log_date) DO UPDATE SET
    calories_consumed = COALESCE(public.progress_logs.calories_consumed, 0) + EXCLUDED.calories_consumed,
    protein_consumed_g = COALESCE(public.progress_logs.protein_consumed_g, 0) + EXCLUDED.protein_consumed_g,
    carbs_consumed_g = COALESCE(public.progress_logs.carbs_consumed_g, 0) + EXCLUDED.carbs_consumed_g,
    fat_consumed_g = COALESCE(public.progress_logs.fat_consumed_g, 0) + EXCLUDED.fat_consumed_g,
    fiber_consumed_g = COALESCE(public.progress_logs.fiber_consumed_g, 0) + EXCLUDED.fiber_consumed_g,
    updated_at = NOW();

  SELECT COUNT(*)::INTEGER INTO v_daily_award_count
  FROM public.xp_transactions xt
  WHERE xt.user_id = v_user_id
    AND xt.action_type = 'manual_meal_log'
    AND xt.xp_amount > 0
    AND (xt.created_at AT TIME ZONE 'Asia/Qatar')::DATE = v_today;

  IF p_log_date = v_today THEN
    v_remaining_awards := GREATEST(0, 3 - v_daily_award_count);
    FOREACH v_history_id IN ARRAY v_history_ids LOOP
      EXIT WHEN v_remaining_awards <= 0;
      PERFORM public.award_xp(
        v_user_id, 10, 'Meal logged', 'manual_meal_log', v_history_id::TEXT,
        jsonb_build_object('meal_history_id', v_history_id, 'log_date', p_log_date, 'source', v_source)
      );
      v_remaining_awards := v_remaining_awards - 1;
      v_xp_awarded := v_xp_awarded + 10;
    END LOOP;
  END IF;

  UPDATE public.profiles p
  SET total_meals_logged = counts.meal_count, updated_at = NOW()
  FROM (
    SELECT COUNT(*)::INTEGER AS meal_count
    FROM public.meal_history mh
    WHERE mh.user_id = v_user_id
  ) counts
  WHERE p.user_id = v_user_id;

  PERFORM public.check_and_award_badges(v_user_id);

  RETURN jsonb_build_object(
    'success', TRUE,
    'duplicate', FALSE,
    'history_ids', to_jsonb(v_history_ids),
    'logged_count', array_length(v_history_ids, 1),
    'calories', v_total_calories,
    'protein', v_total_protein,
    'carbs', v_total_carbs,
    'fat', v_total_fat,
    'fiber', v_total_fiber,
    'sugar', v_total_sugar,
    'sodium', v_total_sodium,
    'xp_awarded', v_xp_awarded
  );
END;
$$;


ALTER FUNCTION "public"."log_manual_meal_items_v2"("p_items" "jsonb", "p_log_date" "date", "p_request_id" "uuid", "p_source" "text") OWNER TO "postgres";

--
-- Name: mark_all_notifications_as_read(); Type: FUNCTION; Schema: public; Owner: postgres
--

