-- Name: mark_webhook_delivered("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."mark_webhook_delivered"("p_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
    UPDATE public.webhook_delivery_queue
    SET 
        status = 'delivered',
        delivered_at = NOW(),
        last_attempt_at = NOW()
    WHERE id = p_id;
END;
$$;


ALTER FUNCTION "public"."mark_webhook_delivered"("p_id" "uuid") OWNER TO "postgres";

--
-- Name: mark_webhook_failed("uuid", "text", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."mark_webhook_failed"("p_id" "uuid", "p_error" "text", "p_http_status" integer DEFAULT NULL::integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_queue_record RECORD;
BEGIN
    SELECT * INTO v_queue_record
    FROM public.webhook_delivery_queue
    WHERE id = p_id;
    
    IF NOT FOUND THEN
        RETURN;
    END IF;
    
    -- Check if max attempts reached
    IF v_queue_record.attempt_count >= v_queue_record.max_attempts THEN
        -- Move to dead letter queue (just mark as failed)
        UPDATE public.webhook_delivery_queue
        SET 
            status = 'failed',
            last_error = p_error,
            last_http_status = p_http_status,
            last_attempt_at = NOW()
        WHERE id = p_id;
        
        -- Log for manual review
        RAISE WARNING 'Webhook % failed after % attempts: %', 
            p_id, v_queue_record.attempt_count, p_error;
    ELSE
        -- Schedule retry
        UPDATE public.webhook_delivery_queue
        SET 
            status = 'pending',
            attempt_count = attempt_count + 1,
            last_error = p_error,
            last_http_status = p_http_status,
            last_attempt_at = NOW(),
            next_retry_at = calculate_next_retry(attempt_count + 1)
        WHERE id = p_id;
    END IF;
END;
$$;


ALTER FUNCTION "public"."mark_webhook_failed"("p_id" "uuid", "p_error" "text", "p_http_status" integer) OWNER TO "postgres";

