--
-- Name: notify_drivers_new_delivery(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."notify_drivers_new_delivery"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_driver RECORD;
  v_restaurant_name TEXT;
  v_delivery_area TEXT;
BEGIN
  -- Only notify for pending deliveries
  IF NEW.status != 'pending' THEN
    RETURN NEW;
  END IF;
  
  -- Get restaurant info
  SELECT r.name INTO v_restaurant_name
  FROM restaurants r
  WHERE r.id = NEW.restaurant_id;
  
  -- Get delivery area (city from address)
  v_delivery_area := split_part(NEW.delivery_address, ',', 2);
  
  -- Notify all online drivers
  FOR v_driver IN
    SELECT d.id, d.user_id, p.full_name, d.phone_number  -- Use d.phone_number instead of p.phone
    FROM drivers d
    LEFT JOIN profiles p ON p.user_id = d.user_id
    WHERE d.is_online = true
      AND d.approval_status = 'approved'
  LOOP
    IF v_driver.phone_number IS NOT NULL THEN
      PERFORM send_whatsapp_notification(
        v_driver.phone_number,
        format(
          'New delivery opportunity! Pickup from %s, delivery to %s. Delivery fee: QAR %s. Open the app to claim.',
          v_restaurant_name,
          trim(v_delivery_area),
          NEW.delivery_fee
        ),
        'new_delivery_available'
      );
    END IF;
  END LOOP;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_drivers_new_delivery"() OWNER TO "postgres";

--
-- Name: notify_meal_delivered(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."notify_meal_delivered"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_meal RECORD;
BEGIN
  IF NEW.user_id IS NULL
    OR NEW.status::TEXT <> 'delivered'
    OR (TG_OP = 'UPDATE' AND OLD.status::TEXT = 'delivered') THEN
    RETURN NEW;
  END IF;

  FOR v_meal IN
    WITH ordered_meals AS (
      SELECT
        oi.meal_id,
        MAX(COALESCE(oi.nutrition_snapshot ->> 'meal_name', oi.meal_name, m.name)) AS meal_name,
        SUM(COALESCE((oi.nutrition_snapshot ->> 'calories')::NUMERIC, m.calories, 0) * GREATEST(oi.quantity, 1)) AS calories,
        SUM(COALESCE((oi.nutrition_snapshot ->> 'protein_g')::NUMERIC, m.protein_g, m.protein, 0) * GREATEST(oi.quantity, 1)) AS protein_g,
        SUM(COALESCE((oi.nutrition_snapshot ->> 'carbs_g')::NUMERIC, m.carbs_g, m.carbs, 0) * GREATEST(oi.quantity, 1)) AS carbs_g,
        SUM(COALESCE((oi.nutrition_snapshot ->> 'fat_g')::NUMERIC, m.fat_g, m.fats, 0) * GREATEST(oi.quantity, 1)) AS fat_g
      FROM public.order_items oi
      LEFT JOIN public.meals m ON m.id = oi.meal_id
      WHERE oi.order_id = NEW.id
        AND oi.meal_id IS NOT NULL
      GROUP BY oi.meal_id
    ), fallback_meal AS (
      SELECT
        NEW.meal_id AS meal_id,
        snapshot ->> 'meal_name' AS meal_name,
        COALESCE((snapshot ->> 'calories')::NUMERIC, 0) AS calories,
        COALESCE((snapshot ->> 'protein_g')::NUMERIC, 0) AS protein_g,
        COALESCE((snapshot ->> 'carbs_g')::NUMERIC, 0) AS carbs_g,
        COALESCE((snapshot ->> 'fat_g')::NUMERIC, 0) AS fat_g
      FROM (SELECT public.get_meal_nutrition_snapshot(NEW.meal_id) AS snapshot) source
      WHERE NEW.meal_id IS NOT NULL
        AND NOT EXISTS (SELECT 1 FROM ordered_meals)
    )
    SELECT * FROM ordered_meals
    UNION ALL
    SELECT * FROM fallback_meal
  LOOP
    INSERT INTO public.notifications (
      user_id, type, title, message, status, data,
      related_entity_type, related_entity_id, created_at
    ) VALUES (
      NEW.user_id,
      'order_delivered'::public.notification_type,
      'Meal delivered - confirm what you ate',
      format('%s was delivered. Record the portion you actually ate.', COALESCE(v_meal.meal_name, 'Your meal')),
      'unread'::public.notification_status,
      jsonb_build_object(
        'source_type', 'order',
        'source_id', NEW.id,
        'order_id', NEW.id,
        'meal_id', v_meal.meal_id,
        'meal_name', v_meal.meal_name,
        'calories', v_meal.calories,
        'protein_g', v_meal.protein_g,
        'carbs_g', v_meal.carbs_g,
        'fat_g', v_meal.fat_g,
        'action', 'confirm_consumption'
      ),
      'order',
      NEW.id,
      NOW()
    )
    ON CONFLICT DO NOTHING;
  END LOOP;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_meal_delivered"() OWNER TO "postgres";

--
-- Name: FUNCTION "notify_meal_delivered"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."notify_meal_delivered"() IS 'Creates a notification when an order is marked as delivered with meal details';


--
-- Name: notify_partner_delivery_claimed(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."notify_partner_delivery_claimed"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_partner_phone TEXT;
  v_partner_name TEXT;
  v_driver_name TEXT;
  v_meal_name TEXT;
BEGIN
  -- Only proceed if driver was just assigned
  IF OLD.driver_id IS NOT NULL OR NEW.driver_id IS NULL THEN
    RETURN NEW;
  END IF;
  
  -- Get partner info from restaurant and meals
  SELECT 
    r.phone,
    r.name,
    m.name  -- Get meal name from meals table
  INTO v_partner_phone, v_partner_name, v_meal_name
  FROM restaurants r
  JOIN meal_schedules ms ON ms.restaurant_id = r.id
  JOIN meals m ON m.id = ms.meal_id  -- Join to get meal name
  WHERE ms.id = NEW.schedule_id;
  
  -- Get driver name
  SELECT p.full_name INTO v_driver_name
  FROM drivers d
  LEFT JOIN profiles p ON p.user_id = d.user_id
  WHERE d.id = NEW.driver_id;
  
  -- Notify partner
  IF v_partner_phone IS NOT NULL THEN
    PERFORM send_whatsapp_notification(
      v_partner_phone,
      format(
        'Driver %s has been assigned to deliver "%s". Please prepare the order for pickup.',
        COALESCE(v_driver_name, 'A driver'),
        v_meal_name
      ),
      'driver_assigned_partner'
    );
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_partner_delivery_claimed"() OWNER TO "postgres";

--
-- Name: notify_scheduled_meal_delivered(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."notify_scheduled_meal_delivered"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_snapshot JSONB;
BEGIN
  IF NEW.user_id IS NULL
    OR NEW.order_status <> 'delivered'
    OR (TG_OP = 'UPDATE' AND OLD.order_status = 'delivered') THEN
    RETURN NEW;
  END IF;

  v_snapshot := COALESCE(
    NEW.nutrition_snapshot,
    public.get_meal_nutrition_snapshot(NEW.meal_id)
  );

  INSERT INTO public.notifications (
    user_id, type, title, message, status, data,
    related_entity_type, related_entity_id, created_at
  ) VALUES (
    NEW.user_id,
    'order_delivered'::public.notification_type,
    'Meal delivered - confirm what you ate',
    format('%s was delivered. Record the portion you actually ate.', COALESCE(v_snapshot ->> 'meal_name', 'Your meal')),
    'unread'::public.notification_status,
    jsonb_build_object(
      'source_type', 'meal_schedule',
      'source_id', NEW.id,
      'order_id', NEW.id,
      'meal_id', NEW.meal_id,
      'meal_name', v_snapshot ->> 'meal_name',
      'calories', COALESCE((v_snapshot ->> 'calories')::NUMERIC, 0),
      'protein_g', COALESCE((v_snapshot ->> 'protein_g')::NUMERIC, 0),
      'carbs_g', COALESCE((v_snapshot ->> 'carbs_g')::NUMERIC, 0),
      'fat_g', COALESCE((v_snapshot ->> 'fat_g')::NUMERIC, 0),
      'action', 'confirm_consumption'
    ),
    'meal_schedule',
    NEW.id,
    NOW()
  )
  ON CONFLICT DO NOTHING;

  RETURN NEW;
END;
$$;


