-- Name: partner_confirm_handover("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."partner_confirm_handover"("p_delivery_job_id" "uuid", "p_partner_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_partner_user_id);
  RETURN public.partner_confirm_handover_trusted(p_delivery_job_id, p_partner_user_id);
END;
$$;


ALTER FUNCTION "public"."partner_confirm_handover"("p_delivery_job_id" "uuid", "p_partner_user_id" "uuid") OWNER TO "postgres";

--
-- Name: partner_confirm_handover("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."partner_confirm_handover"("p_delivery_job_id" "uuid", "p_partner_user_id" "uuid", "p_reason" "text" DEFAULT 'Partner override'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_job public.delivery_jobs%ROWTYPE;
BEGIN
  IF v_actor IS NULL OR p_partner_user_id IS DISTINCT FROM v_actor THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  IF length(trim(COALESCE(p_reason, ''))) NOT BETWEEN 3 AND 500 THEN
    RETURN jsonb_build_object('success', false, 'error', 'A short handover reason is required');
  END IF;

  SELECT dj.*
  INTO v_job
  FROM public.delivery_jobs dj
  LEFT JOIN public.meal_schedules ms ON ms.id = dj.schedule_id
  LEFT JOIN public.meals m ON m.id = ms.meal_id
  WHERE dj.id = p_delivery_job_id
    AND dj.status IN ('assigned', 'accepted')
    AND dj.driver_id IS NOT NULL
    AND (
      public.has_role(v_actor, 'admin')
      OR public.is_restaurant_operator(COALESCE(dj.restaurant_id, m.restaurant_id), v_actor)
    )
  FOR UPDATE OF dj;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Delivery is not ready for handover');
  END IF;

  UPDATE public.delivery_jobs
  SET status = 'picked_up',
      picked_up_at = COALESCE(picked_up_at, now()),
      handover_method = 'partner_override',
      verification_attempts = 0,
      is_verification_locked = false,
      verification_code_hash = NULL,
      pickup_verification_code = NULL,
      verification_expires_at = NULL,
      delivery_notes = concat_ws(E'\n', NULLIF(delivery_notes, ''), 'Handover override: ' || trim(p_reason)),
      updated_at = now()
  WHERE id = v_job.id;

  RETURN jsonb_build_object(
    'success', true,
    'message', 'Handover confirmed by partner',
    'job_id', v_job.id,
    'status', 'picked_up'
  );
END;
$$;


ALTER FUNCTION "public"."partner_confirm_handover"("p_delivery_job_id" "uuid", "p_partner_user_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: partner_confirm_handover_trusted("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."partner_confirm_handover_trusted"("p_delivery_job_id" "uuid", "p_partner_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_job RECORD;
    v_is_owner BOOLEAN;
BEGIN
    -- Verify partner owns the restaurant
    SELECT dj.* INTO v_job
    FROM delivery_jobs dj
    JOIN restaurants r ON dj.restaurant_id = r.id
    WHERE dj.id = p_delivery_job_id
    AND r.owner_id = p_partner_user_id;
    
    IF v_job IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Unauthorized or job not found',
            'code', 'UNAUTHORIZED'
        );
    END IF;
    
    IF v_job.status != 'accepted' THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Driver must accept delivery first',
            'code', 'NOT_ACCEPTED'
        );
    END IF;
    
    -- Update delivery job
    UPDATE delivery_jobs
    SET 
        status = 'picked_up',
        picked_up_at = NOW(),
        handover_method = 'partner_override',
        pickup_verification_code = NULL,
        verification_expires_at = NULL,
        updated_at = NOW()
    WHERE id = p_delivery_job_id;
    
    -- Update related meal_schedule
    UPDATE meal_schedules
    SET order_status = 'out_for_delivery',
        updated_at = NOW()
    WHERE id = v_job.schedule_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'message', 'Handover confirmed by partner',
        'delivery_job_id', p_delivery_job_id
    );
END;
$$;


ALTER FUNCTION "public"."partner_confirm_handover_trusted"("p_delivery_job_id" "uuid", "p_partner_user_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "partner_confirm_handover_trusted"("p_delivery_job_id" "uuid", "p_partner_user_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."partner_confirm_handover_trusted"("p_delivery_job_id" "uuid", "p_partner_user_id" "uuid") IS 'Allow partner to manually confirm handover if driver has technical issues';


--
-- Name: partner_create_pos_order("uuid", "uuid", "jsonb", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."partner_create_pos_order"("p_client_request_id" "uuid", "p_restaurant_id" "uuid", "p_items" "jsonb", "p_customer_name" "text" DEFAULT NULL::"text", "p_phone_number" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_existing public.orders%ROWTYPE;
  v_item JSONB;
  v_meal public.meals%ROWTYPE;
  v_primary_meal_id UUID;
  v_total NUMERIC := 0;
  v_quantity INTEGER;
  v_item_index INTEGER := 0;
  v_notes TEXT;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;

  IF p_client_request_id IS NULL OR p_restaurant_id IS NULL THEN
    RAISE EXCEPTION 'INVALID_POS_REQUEST';
  END IF;

  IF NOT public.is_restaurant_operator(p_restaurant_id, v_actor) THEN
    RAISE EXCEPTION 'RESTAURANT_ACCESS_DENIED';
  END IF;

  SELECT *
    INTO v_existing
  FROM public.orders
  WHERE id = p_client_request_id;

  IF FOUND THEN
    IF v_existing.restaurant_id IS DISTINCT FROM p_restaurant_id THEN
      RAISE EXCEPTION 'POS_REQUEST_ID_CONFLICT';
    END IF;

    RETURN jsonb_build_object(
      'success', TRUE,
      'already_synced', TRUE,
      'order_id', v_existing.id
    );
  END IF;

  IF p_items IS NULL
     OR jsonb_typeof(p_items) <> 'array'
     OR jsonb_array_length(p_items) = 0
     OR jsonb_array_length(p_items) > 40 THEN
    RAISE EXCEPTION 'INVALID_POS_ITEMS';
  END IF;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
  LOOP
    v_item_index := v_item_index + 1;
    v_quantity := GREATEST(1, LEAST(99, COALESCE((v_item ->> 'quantity')::INTEGER, 1)));

    SELECT *
      INTO v_meal
    FROM public.meals
    WHERE id = (v_item ->> 'mealId')::UUID
      AND restaurant_id = p_restaurant_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'POS_MEAL_NOT_FOUND_OR_ACCESS_DENIED';
    END IF;

    IF v_primary_meal_id IS NULL THEN
      v_primary_meal_id := v_meal.id;
    END IF;

    v_total := v_total + (COALESCE(v_meal.price, 0) * v_quantity);
  END LOOP;

  v_notes := concat_ws(
    E'\n',
    NULLIF(TRIM(COALESCE(p_notes, '')), ''),
    CASE
      WHEN NULLIF(TRIM(COALESCE(p_customer_name, '')), '') IS NOT NULL
      THEN 'POS customer: ' || LEFT(TRIM(p_customer_name), 120)
    END,
    'POS offline ticket: ' || p_client_request_id::TEXT
  );

  INSERT INTO public.orders (
    id,
    restaurant_id,
    meal_id,
    order_type,
    status,
    total_amount,
    restaurant_payout,
    delivery_fee,
    phone_number,
    notes,
    special_instructions,
    created_at,
    updated_at
  )
  VALUES (
    p_client_request_id,
    p_restaurant_id,
    v_primary_meal_id,
    'pos',
    'confirmed',
    v_total,
    v_total,
    0,
    NULLIF(LEFT(TRIM(COALESCE(p_phone_number, '')), 32), ''),
    v_notes,
    'POS walk-in / counter order',
    now(),
    now()
  );

  v_item_index := 0;
  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
  LOOP
    v_item_index := v_item_index + 1;
    v_quantity := GREATEST(1, LEAST(99, COALESCE((v_item ->> 'quantity')::INTEGER, 1)));

    SELECT *
      INTO v_meal
    FROM public.meals
    WHERE id = (v_item ->> 'mealId')::UUID
      AND restaurant_id = p_restaurant_id;

    INSERT INTO public.kitchen_queue_items (
      order_source,
      order_id,
      item_key,
      item_name,
      quantity,
      status,
      updated_by
    )
    VALUES (
      'order',
      p_client_request_id,
      'pos:' || v_meal.id::TEXT || ':' || v_item_index::TEXT,
      v_meal.name,
      v_quantity,
      'queued',
      v_actor
    )
    ON CONFLICT (order_source, order_id, item_key) DO NOTHING;
  END LOOP;

  RETURN jsonb_build_object(
    'success', TRUE,
    'already_synced', FALSE,
    'order_id', p_client_request_id,
    'total_amount', v_total
  );
END;
$$;


ALTER FUNCTION "public"."partner_create_pos_order"("p_client_request_id" "uuid", "p_restaurant_id" "uuid", "p_items" "jsonb", "p_customer_name" "text", "p_phone_number" "text", "p_notes" "text") OWNER TO "postgres";

--
-- Name: kitchen_queue_items; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."kitchen_queue_items" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "order_source" "text" NOT NULL,
    "order_id" "uuid" NOT NULL,
    "item_key" "text" NOT NULL,
    "item_name" "text" NOT NULL,
    "quantity" integer DEFAULT 1 NOT NULL,
    "status" "text" DEFAULT 'queued'::"text" NOT NULL,
    "station" "text",
    "started_at" timestamp with time zone,
    "ready_at" timestamp with time zone,
    "updated_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "kitchen_queue_items_order_source_check" CHECK (("order_source" = ANY (ARRAY['order'::"text", 'meal_schedule'::"text"]))),
    CONSTRAINT "kitchen_queue_items_quantity_check" CHECK (("quantity" > 0)),
    CONSTRAINT "kitchen_queue_items_status_check" CHECK (("status" = ANY (ARRAY['queued'::"text", 'preparing'::"text", 'ready'::"text"])))
);


ALTER TABLE "public"."kitchen_queue_items" OWNER TO "postgres";

--
-- Name: partner_update_kitchen_item_status("text", "uuid", "text", "text", "text", integer, "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."partner_update_kitchen_item_status"("p_source" "text", "p_order_id" "uuid", "p_item_key" "text", "p_status" "text", "p_item_name" "text" DEFAULT NULL::"text", "p_quantity" integer DEFAULT 1, "p_all_item_keys" "text"[] DEFAULT NULL::"text"[]) RETURNS "public"."kitchen_queue_items"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_item public.kitchen_queue_items;
  v_authorized BOOLEAN := FALSE;
  v_all_ready BOOLEAN := FALSE;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF p_source NOT IN ('order', 'meal_schedule') THEN
    RAISE EXCEPTION 'Unsupported order source: %', p_source;
  END IF;

  IF p_status NOT IN ('queued', 'preparing', 'ready') THEN
    RAISE EXCEPTION 'Unsupported kitchen item status: %', p_status;
  END IF;

  IF p_source = 'meal_schedule' THEN
    SELECT EXISTS (
      SELECT 1
      FROM public.meal_schedules ms
      JOIN public.restaurants r ON r.id = ms.restaurant_id
      WHERE ms.id = p_order_id
        AND r.owner_id = auth.uid()
    ) INTO v_authorized;
  ELSE
    SELECT EXISTS (
      SELECT 1
      FROM public.orders o
      JOIN public.restaurants r ON r.id = o.restaurant_id
      WHERE o.id = p_order_id
        AND r.owner_id = auth.uid()
    ) INTO v_authorized;
  END IF;

  IF NOT v_authorized THEN
    RAISE EXCEPTION 'Not authorized to update this kitchen item';
  END IF;

  INSERT INTO public.kitchen_queue_items (
    order_source,
    order_id,
    item_key,
    item_name,
    quantity,
    status,
    started_at,
    ready_at,
    updated_by
  )
  VALUES (
    p_source,
    p_order_id,
    p_item_key,
    COALESCE(NULLIF(p_item_name, ''), p_item_key),
    GREATEST(COALESCE(p_quantity, 1), 1),
    p_status,
    CASE WHEN p_status IN ('preparing', 'ready') THEN now() ELSE NULL END,
    CASE WHEN p_status = 'ready' THEN now() ELSE NULL END,
    auth.uid()
  )
  ON CONFLICT (order_source, order_id, item_key)
  DO UPDATE SET
    item_name = COALESCE(NULLIF(EXCLUDED.item_name, ''), kitchen_queue_items.item_name),
    quantity = GREATEST(EXCLUDED.quantity, 1),
    status = EXCLUDED.status,
    started_at = CASE
      WHEN EXCLUDED.status IN ('preparing', 'ready') THEN COALESCE(kitchen_queue_items.started_at, now())
      ELSE kitchen_queue_items.started_at
    END,
    ready_at = CASE
      WHEN EXCLUDED.status = 'ready' THEN COALESCE(kitchen_queue_items.ready_at, now())
      ELSE NULL
    END,
    updated_by = auth.uid(),
    updated_at = now()
  RETURNING * INTO v_item;

  IF p_status = 'preparing' THEN
    IF p_source = 'meal_schedule' THEN
      UPDATE public.meal_schedules
      SET order_status = 'preparing', updated_at = now()
      WHERE id = p_order_id
        AND COALESCE(order_status, 'pending') IN ('pending', 'confirmed');
    ELSE
      UPDATE public.orders
      SET status = 'preparing', preparing_at = COALESCE(preparing_at, now()), updated_at = now()
      WHERE id = p_order_id
        AND COALESCE(status, 'pending') IN ('pending', 'confirmed');
    END IF;
  END IF;

  IF p_status = 'ready' AND p_all_item_keys IS NOT NULL AND array_length(p_all_item_keys, 1) > 0 THEN
    SELECT NOT EXISTS (
      SELECT 1
      FROM unnest(p_all_item_keys) AS expected(item_key)
      LEFT JOIN public.kitchen_queue_items kqi
        ON kqi.order_source = p_source
       AND kqi.order_id = p_order_id
       AND kqi.item_key = expected.item_key
       AND kqi.status = 'ready'
      WHERE kqi.id IS NULL
    ) INTO v_all_ready;

    IF v_all_ready THEN
      IF p_source = 'meal_schedule' THEN
        UPDATE public.meal_schedules
        SET order_status = 'ready', updated_at = now()
        WHERE id = p_order_id
          AND COALESCE(order_status, 'pending') IN ('pending', 'confirmed', 'preparing');
      ELSE
        UPDATE public.orders
        SET status = 'ready_for_pickup',
            ready_for_pickup_at = COALESCE(ready_for_pickup_at, now()),
            updated_at = now()
        WHERE id = p_order_id
          AND COALESCE(status, 'pending') IN ('pending', 'confirmed', 'preparing');
      END IF;
    END IF;
  END IF;

  RETURN v_item;
END;
$$;


ALTER FUNCTION "public"."partner_update_kitchen_item_status"("p_source" "text", "p_order_id" "uuid", "p_item_key" "text", "p_status" "text", "p_item_name" "text", "p_quantity" integer, "p_all_item_keys" "text"[]) OWNER TO "postgres";

--
-- Name: partner_update_order_status("text", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."partner_update_order_status"("p_source" "text", "p_order_id" "uuid", "p_new_status" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_order public.orders%ROWTYPE;
  v_target public.order_status;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  IF p_source = 'meal_schedule' THEN
    PERFORM public.update_order_status(p_order_id, p_new_status, 'partner');
    RETURN jsonb_build_object(
      'success', TRUE,
      'source', 'meal_schedule',
      'order_id', p_order_id,
      'status', p_new_status
    );
  END IF;

  IF p_source <> 'order' THEN
    RAISE EXCEPTION 'INVALID_ORDER_SOURCE';
  END IF;

  v_target := CASE p_new_status
    WHEN 'ready' THEN 'ready_for_pickup'::public.order_status
    ELSE p_new_status::public.order_status
  END;

  SELECT o.*
    INTO v_order
  FROM public.orders o
  WHERE o.id = p_order_id
    AND o.restaurant_id IS NOT NULL
    AND public.is_restaurant_operator(o.restaurant_id, v_actor)
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'ORDER_NOT_FOUND_OR_ACCESS_DENIED';
  END IF;

  IF NOT (
    (v_order.status = 'pending' AND v_target IN ('confirmed', 'cancelled'))
    OR (v_order.status = 'confirmed' AND v_target IN ('preparing', 'cancelled'))
    OR (v_order.status = 'preparing' AND v_target IN ('ready_for_pickup', 'cancelled'))
    OR (v_order.status = 'ready_for_pickup' AND v_target = 'cancelled')
  ) THEN
    RAISE EXCEPTION 'INVALID_ORDER_STATUS_TRANSITION';
  END IF;

  IF v_target = 'cancelled' THEN
    RETURN public.process_direct_order_cancellation(
      v_order.id,
      v_actor,
      'partner',
      'Restaurant cancellation'
    );
  END IF;

  UPDATE public.orders
  SET status = v_target,
      preparing_at = CASE
        WHEN v_target = 'preparing' THEN COALESCE(preparing_at, NOW())
        ELSE preparing_at
      END,
      ready_for_pickup_at = CASE
        WHEN v_target = 'ready_for_pickup' THEN COALESCE(ready_for_pickup_at, NOW())
        ELSE ready_for_pickup_at
      END,
      updated_at = NOW()
  WHERE id = v_order.id;

  RETURN jsonb_build_object(
    'success', TRUE,
    'source', 'order',
    'order_id', v_order.id,
    'status', v_target
  );
END;
$$;


ALTER FUNCTION "public"."partner_update_order_status"("p_source" "text", "p_order_id" "uuid", "p_new_status" "text") OWNER TO "postgres";

--
-- Name: pause_subscription("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."pause_subscription"("p_subscription_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
BEGIN
  IF v_user_id IS NULL THEN
    RETURN FALSE;
  END IF;

  UPDATE public.subscriptions
  SET status = 'pending',
      active = FALSE,
      updated_at = NOW()
  WHERE id = p_subscription_id
    AND user_id = v_user_id
    AND status = 'active';

  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."pause_subscription"("p_subscription_id" "uuid") OWNER TO "postgres";

--
-- Name: prepare_sadad_payment("uuid", "text", "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."prepare_sadad_payment"("p_user_id" "uuid", "p_payment_type" "text", "p_reference_id" "uuid", "p_subscription_id" "uuid" DEFAULT NULL::"uuid", "p_coach_plan" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_payment_id UUID := gen_random_uuid();
  v_amount NUMERIC(10, 2);
  v_description TEXT;
  v_metadata JSONB;
  v_package RECORD;
  v_plan RECORD;
  v_coach_pricing RECORD;
  v_current_subscription RECORD;
  v_renewal_reservation public.subscription_renewal_processed%ROWTYPE;
  v_existing_payment public.payments%ROWTYPE;
  v_period_days INTEGER;
  v_remaining_days INTEGER;
  v_prorated_credit NUMERIC(10, 2) := 0;
BEGIN
  IF p_user_id IS NULL OR NOT EXISTS (
    SELECT 1 FROM auth.users u WHERE u.id = p_user_id
  ) THEN
    RAISE EXCEPTION 'PAYMENT_USER_NOT_FOUND';
  END IF;

  IF p_payment_type = 'wallet_topup' THEN
    SELECT id, name, amount, bonus_amount
      INTO v_package
    FROM public.wallet_topup_packages
    WHERE id = p_reference_id
      AND is_active = TRUE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'PAYMENT_PACKAGE_NOT_FOUND';
    END IF;

    v_amount := ROUND(v_package.amount::NUMERIC, 2);
    v_description := 'Wallet top-up - ' || v_package.name;
    v_metadata := jsonb_build_object(
      'package_id', v_package.id,
      'package_name', v_package.name,
      'paid_amount', v_amount,
      'bonus_amount', COALESCE(v_package.bonus_amount, 0)
    );
  ELSIF p_payment_type = 'subscription' THEN
    SELECT
      id,
      tier,
      billing_interval,
      price_qar,
      meals_per_month,
      meals_per_week,
      snacks_per_month,
      daily_meals,
      daily_snacks,
      discount_percent
      INTO v_plan
    FROM public.subscription_plans
    WHERE id = p_reference_id
      AND is_active = TRUE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'PAYMENT_PLAN_NOT_FOUND';
    END IF;

    IF p_subscription_id IS NULL THEN
      IF EXISTS (
        SELECT 1
        FROM public.subscriptions s
        WHERE s.user_id = p_user_id
          AND (
            s.status = 'active'
            OR (
              s.status = 'cancelled'
              AND COALESCE(s.end_date, CURRENT_DATE - 1) >= CURRENT_DATE
            )
          )
      ) THEN
        RAISE EXCEPTION 'ACTIVE_SUBSCRIPTION_EXISTS';
      END IF;

      v_amount := ROUND(v_plan.price_qar::NUMERIC, 2);
      v_description := 'Subscription purchase - ' || v_plan.tier;
      v_metadata := jsonb_build_object('mode', 'purchase');
    ELSE
      PERFORM pg_advisory_xact_lock(
        hashtextextended(p_subscription_id::TEXT, 0)
      );

      SELECT *
        INTO v_current_subscription
      FROM public.subscriptions s
      WHERE s.id = p_subscription_id
        AND s.user_id = p_user_id
        AND s.status IN ('active', 'cancelled', 'expired')
      FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'SUBSCRIPTION_NOT_FOUND';
      END IF;

      IF v_current_subscription.plan_id = v_plan.id
        OR (
          v_current_subscription.plan_id IS NULL
          AND v_current_subscription.tier = v_plan.tier
          AND COALESCE(v_current_subscription.billing_interval, 'monthly')
            = v_plan.billing_interval
        ) THEN
        IF v_current_subscription.end_date IS NULL
          OR v_current_subscription.end_date::DATE >= CURRENT_DATE THEN
          RAISE EXCEPTION 'SUBSCRIPTION_RENEWAL_TOO_EARLY';
        END IF;

        SELECT *
          INTO v_renewal_reservation
        FROM public.subscription_renewal_processed srp
        WHERE srp.subscription_id = p_subscription_id
          AND srp.source_cycle_end = COALESCE(
            v_current_subscription.end_date::DATE,
            CURRENT_DATE
          )
        FOR UPDATE;

        IF v_renewal_reservation.id IS NOT NULL
          AND v_renewal_reservation.status = 'success' THEN
          RAISE EXCEPTION 'SUBSCRIPTION_CYCLE_ALREADY_RENEWED';
        END IF;

        IF v_renewal_reservation.payment_id IS NOT NULL THEN
          SELECT *
            INTO v_existing_payment
          FROM public.payments p
          WHERE p.id = v_renewal_reservation.payment_id;

          IF v_existing_payment.id IS NOT NULL
            AND v_existing_payment.status = 'completed' THEN
            RAISE EXCEPTION 'PAYMENT_FULFILLMENT_RETRY_REQUIRED';
          END IF;

          IF v_existing_payment.id IS NOT NULL
            AND v_existing_payment.status IN ('pending', 'processing')
            AND v_existing_payment.fulfillment_status = 'pending'
            AND COALESCE(v_existing_payment.created_at, NOW() - INTERVAL '1 day')
              >= NOW() - INTERVAL '30 minutes' THEN
            RETURN jsonb_build_object(
              'payment_id', v_existing_payment.id,
              'amount', v_existing_payment.amount,
              'currency', v_existing_payment.currency,
              'payment_type', v_existing_payment.payment_type,
              'description', v_existing_payment.description,
              'metadata', v_existing_payment.metadata,
              'reused', TRUE
            );
          END IF;
        END IF;

        v_amount := ROUND(v_plan.price_qar::NUMERIC, 2);
        v_description := 'Subscription renewal - ' || v_plan.tier;
        v_metadata := jsonb_build_object(
          'mode', 'renewal',
          'subscription_id', p_subscription_id,
          'previous_end_date', v_current_subscription.end_date,
          'source_cycle_end', COALESCE(
            v_current_subscription.end_date::DATE,
            CURRENT_DATE
          )
        );
      ELSE
        IF v_current_subscription.end_date IS NOT NULL
          AND v_current_subscription.start_date IS NOT NULL
          AND v_current_subscription.end_date::DATE > CURRENT_DATE THEN
          v_period_days := GREATEST(
            1,
            v_current_subscription.end_date::DATE
              - v_current_subscription.start_date::DATE
          );
          v_remaining_days := GREATEST(
            0,
            v_current_subscription.end_date::DATE - CURRENT_DATE
          );
          v_prorated_credit := ROUND(
            COALESCE(v_current_subscription.price, 0)::NUMERIC
              * v_remaining_days::NUMERIC
              / v_period_days::NUMERIC,
            2
          );
        END IF;

        v_amount := ROUND(
          GREATEST(0, v_plan.price_qar::NUMERIC - v_prorated_credit),
          2
        );
        v_description := 'Subscription change - ' || v_plan.tier;
        v_metadata := jsonb_build_object(
          'mode', 'upgrade',
          'subscription_id', p_subscription_id,
          'prorated_credit', v_prorated_credit
        );
      END IF;
    END IF;

    v_metadata := v_metadata || jsonb_build_object(
      'plan_id', v_plan.id,
      'tier', v_plan.tier,
      'billing_interval', v_plan.billing_interval,
      'price_qar', v_plan.price_qar,
      'meals_per_month', v_plan.meals_per_month,
      'meals_per_week', v_plan.meals_per_week,
      'snacks_per_month', v_plan.snacks_per_month,
      'daily_meals', v_plan.daily_meals,
      'daily_snacks', v_plan.daily_snacks,
      'discount_percent', v_plan.discount_percent
    );
  ELSIF p_payment_type = 'coach_subscription' THEN
    IF p_reference_id = p_user_id THEN
      RAISE EXCEPTION 'COACH_SELF_SUBSCRIPTION_NOT_ALLOWED';
    END IF;

    IF p_coach_plan NOT IN ('weekly', 'monthly') THEN
      RAISE EXCEPTION 'COACH_PLAN_INVALID';
    END IF;

    SELECT
      coach_id,
      price_per_week,
      price_per_month,
      currency,
      is_active
      INTO v_coach_pricing
    FROM public.coach_pricing
    WHERE coach_id = p_reference_id
      AND is_active = TRUE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'COACH_PRICING_NOT_FOUND';
    END IF;

    UPDATE public.coach_subscriptions
    SET status = 'expired',
        updated_at = NOW()
    WHERE coach_id = p_reference_id
      AND client_id = p_user_id
      AND status IN ('active', 'cancelled')
      AND end_date <= NOW();

    IF EXISTS (
      SELECT 1
      FROM public.coach_subscriptions cs
      WHERE cs.coach_id = p_reference_id
        AND cs.client_id = p_user_id
        AND cs.status = 'active'
        AND cs.end_date > NOW()
    ) THEN
      RAISE EXCEPTION 'ACTIVE_COACH_SUBSCRIPTION_EXISTS';
    END IF;

    v_amount := ROUND(
      CASE
        WHEN p_coach_plan = 'weekly'
          THEN v_coach_pricing.price_per_week::NUMERIC
        ELSE v_coach_pricing.price_per_month::NUMERIC
      END,
      2
    );
    v_description := 'Coach subscription - ' || p_coach_plan;
    v_metadata := jsonb_build_object(
      'coach_id', p_reference_id,
      'coach_plan', p_coach_plan,
      'price_qar', v_amount,
      'currency', COALESCE(v_coach_pricing.currency, 'QAR')
    );
  ELSE
    RAISE EXCEPTION 'PAYMENT_TYPE_NOT_SUPPORTED';
  END IF;

  IF v_amount IS NULL OR v_amount <= 0 THEN
    RAISE EXCEPTION 'PAYMENT_NOT_REQUIRED';
  END IF;

  INSERT INTO public.payments (
    id,
    user_id,
    payment_type,
    amount,
    currency,
    status,
    payment_method,
    gateway,
    gateway_reference,
    description,
    metadata,
    idempotency_key,
    fulfillment_status,
    wallet_credited,
    created_at,
    updated_at
  ) VALUES (
    v_payment_id,
    p_user_id,
    p_payment_type,
    v_amount,
    'QAR',
    'pending',
    'sadad',
    'sadad',
    v_payment_id::TEXT,
    v_description,
    v_metadata,
    gen_random_uuid(),
    'pending',
    FALSE,
    NOW(),
    NOW()
  );

  IF p_payment_type = 'subscription'
    AND v_metadata ->> 'mode' = 'renewal' THEN
    IF v_renewal_reservation.id IS NOT NULL THEN
      UPDATE public.subscription_renewal_processed
      SET payment_id = v_payment_id,
          plan_id = (v_metadata ->> 'plan_id')::UUID,
          idempotency_key = format(
            'renewal_%s_%s',
            p_subscription_id,
            v_metadata ->> 'source_cycle_end'
          ),
          processed_at = NOW(),
          renewal_date = (v_metadata ->> 'source_cycle_end')::DATE + 1,
          credits_added = 0,
          rollover_credits = 0,
          amount = v_amount,
          status = 'pending',
          error_message = NULL,
          new_period_start = NULL,
          new_period_end = NULL,
          created_by = p_user_id
      WHERE id = v_renewal_reservation.id;
    ELSE
      INSERT INTO public.subscription_renewal_processed (
        subscription_id,
        payment_id,
        plan_id,
        idempotency_key,
        processed_at,
        renewal_date,
        source_cycle_end,
        credits_added,
        rollover_credits,
        amount,
        status,
        created_by
      ) VALUES (
        p_subscription_id,
        v_payment_id,
        (v_metadata ->> 'plan_id')::UUID,
        format(
          'renewal_%s_%s',
          p_subscription_id,
          v_metadata ->> 'source_cycle_end'
        ),
        NOW(),
        (v_metadata ->> 'source_cycle_end')::DATE + 1,
        (v_metadata ->> 'source_cycle_end')::DATE,
        0,
        0,
        v_amount,
        'pending',
        p_user_id
      );
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'payment_id', v_payment_id,
    'amount', v_amount,
    'currency', 'QAR',
    'payment_type', p_payment_type,
    'description', v_description,
    'metadata', v_metadata
  );
END;
$$;


