--
-- Name: process_direct_order_cancellation("uuid", "uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."process_direct_order_cancellation"("p_order_id" "uuid", "p_cancelled_by" "uuid", "p_cancelled_by_role" "text", "p_reason" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_order public.orders%ROWTYPE;
  v_refund_amount NUMERIC(10, 2);
  v_wallet_transaction_id UUID;
  v_cancellation_id UUID;
BEGIN
  IF p_cancelled_by_role NOT IN ('customer', 'partner', 'admin', 'system') THEN
    RAISE EXCEPTION 'INVALID_CANCELLATION_ROLE';
  END IF;

  SELECT o.* INTO v_order
  FROM public.orders o
  WHERE o.id = p_order_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'ORDER_NOT_FOUND';
  END IF;

  IF v_order.user_id IS NULL THEN
    RAISE EXCEPTION 'ORDER_CUSTOMER_NOT_FOUND';
  END IF;

  IF v_order.status = 'cancelled' THEN
    RETURN jsonb_build_object(
      'success', TRUE,
      'already_cancelled', TRUE,
      'order_id', v_order.id,
      'refund_amount', 0
    );
  END IF;

  IF p_cancelled_by_role = 'customer' AND v_order.status <> 'pending' THEN
    RAISE EXCEPTION 'ORDER_CANNOT_BE_CANCELLED';
  ELSIF p_cancelled_by_role = 'partner'
    AND v_order.status NOT IN ('pending', 'confirmed', 'preparing', 'ready_for_pickup') THEN
    RAISE EXCEPTION 'ORDER_CANNOT_BE_CANCELLED';
  ELSIF p_cancelled_by_role IN ('admin', 'system')
    AND v_order.status IN ('delivered', 'completed') THEN
    RAISE EXCEPTION 'ORDER_CANNOT_BE_CANCELLED';
  END IF;

  v_refund_amount := GREATEST(COALESCE(v_order.total_amount, 0), 0);
  IF v_refund_amount > 0 AND v_order.user_id IS NOT NULL THEN
    v_wallet_transaction_id := public.credit_wallet(
      v_order.user_id,
      v_refund_amount,
      'refund',
      'order',
      v_order.id,
      'Refund for cancelled order',
      jsonb_build_object(
        'order_id', v_order.id,
        'cancelled_by_role', p_cancelled_by_role,
        'reason', LEFT(COALESCE(NULLIF(TRIM(p_reason), ''), 'Order cancellation'), 500)
      )
    );
  END IF;

  PERFORM set_config('request.jwt.claim.role', 'service_role', TRUE);

  UPDATE public.delivery_jobs
  SET status = 'cancelled',
      failure_reason = LEFT(COALESCE(NULLIF(TRIM(p_reason), ''), 'Order cancellation'), 500),
      updated_at = NOW()
  WHERE order_id = v_order.id
    AND status IN ('pending', 'assigned', 'accepted');

  UPDATE public.orders
  SET status = 'cancelled', updated_at = NOW()
  WHERE id = v_order.id;

  INSERT INTO public.order_cancellations (
    order_id, user_id, cancelled_by, cancelled_by_role, reason,
    reason_category, refund_amount, refund_type, wallet_transaction_id,
    order_status_at_cancel, cancellation_fee
  ) VALUES (
    v_order.id,
    v_order.user_id,
    p_cancelled_by,
    p_cancelled_by_role,
    LEFT(COALESCE(NULLIF(TRIM(p_reason), ''), 'Order cancellation'), 500),
    'other',
    v_refund_amount,
    CASE WHEN v_refund_amount > 0 THEN 'full' ELSE 'none' END,
    v_wallet_transaction_id,
    v_order.status,
    0
  )
  RETURNING id INTO v_cancellation_id;

  RETURN jsonb_build_object(
    'success', TRUE,
    'already_cancelled', FALSE,
    'order_id', v_order.id,
    'cancellation_id', v_cancellation_id,
    'refund_amount', v_refund_amount,
    'wallet_transaction_id', v_wallet_transaction_id
  );
END;
$$;


ALTER FUNCTION "public"."process_direct_order_cancellation"("p_order_id" "uuid", "p_cancelled_by" "uuid", "p_cancelled_by_role" "text", "p_reason" "text") OWNER TO "postgres";

--
-- Name: process_driver_withdrawal("uuid", numeric, "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."process_driver_withdrawal"("p_driver_id" "uuid", "p_amount" numeric, "p_payment_method" "text" DEFAULT 'bank_transfer'::"text", "p_bank_name" "text" DEFAULT NULL::"text", "p_bank_account_number" "text" DEFAULT NULL::"text", "p_account_holder_name" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_current_balance NUMERIC(10, 2);
  v_balance_after NUMERIC(10, 2);
  v_withdrawal_id UUID;
BEGIN
  -- Get current balance
  SELECT wallet_balance INTO v_current_balance
  FROM public.drivers
  WHERE id = p_driver_id
  FOR UPDATE;
  
  IF v_current_balance < p_amount THEN
    RAISE EXCEPTION 'Insufficient balance. Current: %, Requested: %', v_current_balance, p_amount;
  END IF;
  
  -- Create withdrawal request
  INSERT INTO public.driver_withdrawals (
    driver_id, amount, payment_method,
    bank_name, bank_account_number, account_holder_name
  ) VALUES (
    p_driver_id, p_amount, p_payment_method,
    p_bank_name, p_bank_account_number, p_account_holder_name
  )
  RETURNING id INTO v_withdrawal_id;
  
  -- Deduct from driver balance
  UPDATE public.drivers
  SET 
    wallet_balance = wallet_balance - p_amount,
    updated_at = now()
  WHERE id = p_driver_id
  RETURNING wallet_balance INTO v_balance_after;
  
  -- Create transaction record
  INSERT INTO public.driver_wallet_transactions (
    driver_id, type, amount, balance_after,
    reference_type, reference_id, description
  ) VALUES (
    p_driver_id, 'withdrawal', p_amount, v_balance_after,
    'withdrawal', v_withdrawal_id, 'Withdrawal request created'
  );
  
  RETURN v_withdrawal_id;
END;
$$;


ALTER FUNCTION "public"."process_driver_withdrawal"("p_driver_id" "uuid", "p_amount" numeric, "p_payment_method" "text", "p_bank_name" "text", "p_bank_account_number" "text", "p_account_holder_name" "text") OWNER TO "postgres";

--
-- Name: process_notification_domain_events(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."process_notification_domain_events"("p_limit" integer DEFAULT 50, "p_lease_seconds" integer DEFAULT 120) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public', 'pg_temp'
    AS $$
DECLARE
  v_event RECORD;
  v_processed INTEGER := 0;
  v_failed INTEGER := 0;
  v_dead_lettered INTEGER := 0;
  v_error_code TEXT;
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RAISE EXCEPTION 'service_role_required';
  END IF;

  FOR v_event IN
    WITH candidates AS (
      SELECT id
      FROM security.domain_event_outbox
      WHERE (
        status IN ('pending', 'failed') AND next_attempt_at <= now()
      ) OR (
        status = 'processing' AND lease_expires_at <= now()
      )
      ORDER BY occurred_at, id
      FOR UPDATE SKIP LOCKED
      LIMIT GREATEST(1, LEAST(COALESCE(p_limit, 50), 250))
    ), claimed AS (
      UPDATE security.domain_event_outbox outbox
      SET status = 'processing',
          attempt_count = LEAST(outbox.attempt_count + 1, 20),
          lease_token = gen_random_uuid(),
          lease_expires_at = now() + make_interval(secs => GREATEST(30, LEAST(COALESCE(p_lease_seconds, 120), 600))),
          last_error_code = NULL
      FROM candidates
      WHERE outbox.id = candidates.id
      RETURNING outbox.id, outbox.attempt_count, outbox.max_attempts
    )
    SELECT * FROM claimed
  LOOP
    BEGIN
      PERFORM security.expand_domain_event(v_event.id);
      UPDATE security.domain_event_outbox
      SET status = 'completed',
          processed_at = now(),
          lease_token = NULL,
          lease_expires_at = NULL,
          last_error_code = NULL
      WHERE id = v_event.id;
      v_processed := v_processed + 1;
    EXCEPTION WHEN OTHERS THEN
      v_error_code := COALESCE(
        security.safe_notification_error_code(SQLSTATE || '_' || SQLERRM),
        'domain_event_processing_failed'
      );
      UPDATE security.domain_event_outbox
      SET status = CASE
            WHEN attempt_count >= max_attempts THEN 'dead_letter'
            ELSE 'failed'
          END,
          next_attempt_at = now() + make_interval(
            secs => LEAST(21600, (60 * power(5, GREATEST(attempt_count - 1, 0)))::INTEGER)
          ),
          lease_token = NULL,
          lease_expires_at = NULL,
          last_error_code = v_error_code
      WHERE id = v_event.id;

      IF v_event.attempt_count >= v_event.max_attempts THEN
        v_dead_lettered := v_dead_lettered + 1;
      ELSE
        v_failed := v_failed + 1;
      END IF;
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'processed', v_processed,
    'failed', v_failed,
    'dead_lettered', v_dead_lettered
  );
END;
$$;


ALTER FUNCTION "public"."process_notification_domain_events"("p_limit" integer, "p_lease_seconds" integer) OWNER TO "postgres";

--
-- Name: FUNCTION "process_notification_domain_events"("p_limit" integer, "p_lease_seconds" integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."process_notification_domain_events"("p_limit" integer, "p_lease_seconds" integer) IS 'Claims domain events with SKIP LOCKED and materializes preference-aware localized deliveries.';


--
-- Name: process_payment_atomic("uuid", "uuid", numeric, character varying, character varying, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."process_payment_atomic"("p_payment_id" "uuid", "p_user_id" "uuid", "p_amount" numeric, "p_payment_method" character varying, "p_gateway_reference" character varying, "p_description" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_payment_record RECORD;
    v_wallet_record RECORD;
    v_new_balance DECIMAL(10,2);
    v_result JSONB;
    v_transaction_id UUID;
BEGIN
    SELECT * INTO v_payment_record
    FROM payments
    WHERE id = p_payment_id
    FOR UPDATE SKIP LOCKED;

    IF FOUND THEN
        IF v_payment_record.status = 'completed' AND v_payment_record.wallet_credited THEN
            RETURN jsonb_build_object(
                'success', true,
                'message', 'Payment already processed',
                'already_processed', true,
                'payment_id', p_payment_id
            );
        ELSIF v_payment_record.status = 'processing' THEN
            RETURN jsonb_build_object(
                'success', false,
                'error', 'Payment is already being processed',
                'code', 'ALREADY_PROCESSING',
                'payment_id', p_payment_id
            );
        END IF;
    END IF;

    SELECT * INTO v_wallet_record
    FROM customer_wallets
    WHERE user_id = p_user_id
    FOR UPDATE;

    IF NOT FOUND THEN
        INSERT INTO customer_wallets (user_id, balance, total_credits, total_debits, is_active)
        VALUES (p_user_id, 0, 0, 0, true)
        RETURNING * INTO v_wallet_record;
    END IF;

    v_new_balance := COALESCE(v_wallet_record.balance, 0) + p_amount;

    BEGIN
        IF v_payment_record IS NULL THEN
            INSERT INTO payments (
                id, user_id, amount, status, gateway, gateway_reference,
                description, wallet_credited, processed_at, created_at
            ) VALUES (
                p_payment_id, p_user_id, p_amount, 'completed', p_payment_method,
                p_gateway_reference, p_description, true, NOW(), NOW()
            );
        ELSE
            UPDATE payments
            SET status = 'completed', wallet_credited = true, processed_at = NOW(), updated_at = NOW()
            WHERE id = p_payment_id;
        END IF;

        INSERT INTO wallet_transactions (
            wallet_id, user_id, type, amount, balance_after, description,
            reference_id, reference_type, created_at
        ) VALUES (
            v_wallet_record.id, p_user_id, 'credit', p_amount, v_new_balance,
            COALESCE(p_description, 'Wallet top-up'), p_payment_id, 'payment', NOW()
        )
        RETURNING id INTO v_transaction_id;

        UPDATE customer_wallets
        SET balance = v_new_balance, total_credits = COALESCE(total_credits, 0) + p_amount, updated_at = NOW()
        WHERE id = v_wallet_record.id;

        SELECT jsonb_build_object(
            'success', true, 'payment_id', p_payment_id, 'transaction_id', v_transaction_id,
            'amount', p_amount, 'new_balance', v_new_balance, 'wallet_id', v_wallet_record.id
        ) INTO v_result;

        RETURN v_result;

    EXCEPTION WHEN OTHERS THEN
        INSERT INTO payment_processing_errors (payment_id, user_id, error_message, error_code, attempted_at)
        VALUES (p_payment_id, p_user_id, SQLERRM, SQLSTATE, NOW());

        IF v_payment_record IS NOT NULL THEN
            UPDATE payments
            SET wallet_credit_error = SQLERRM, status = 'failed', updated_at = NOW()
            WHERE id = p_payment_id;
        END IF;

        RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'code', SQLSTATE, 'payment_id', p_payment_id);
    END;
END;
$$;


ALTER FUNCTION "public"."process_payment_atomic"("p_payment_id" "uuid", "p_user_id" "uuid", "p_amount" numeric, "p_payment_method" character varying, "p_gateway_reference" character varying, "p_description" "text") OWNER TO "postgres";

--
-- Name: propagate_schedule_branch_to_delivery_jobs(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."propagate_schedule_branch_to_delivery_jobs"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  UPDATE public.delivery_jobs dj
     SET restaurant_branch_id = NEW.restaurant_branch_id
   WHERE dj.schedule_id = NEW.id
     AND dj.restaurant_branch_id IS DISTINCT FROM NEW.restaurant_branch_id;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."propagate_schedule_branch_to_delivery_jobs"() OWNER TO "postgres";

--
-- Name: protect_driver_financial_and_approval_fields(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."protect_driver_financial_and_approval_fields"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF auth.uid() = OLD.user_id
     AND COALESCE(auth.jwt() ->> 'role', '') <> 'service_role'
     AND NOT public.has_role(auth.uid(), 'admin'::public.app_role)
     AND NOT public.can_manage_fleet_city(OLD.city_id)
     AND (
       NEW.user_id IS DISTINCT FROM OLD.user_id
       OR NEW.approval_status IS DISTINCT FROM OLD.approval_status
       OR NEW.is_active IS DISTINCT FROM OLD.is_active
       OR NEW.wallet_balance IS DISTINCT FROM OLD.wallet_balance
       OR NEW.total_earnings IS DISTINCT FROM OLD.total_earnings
       OR NEW.total_deliveries IS DISTINCT FROM OLD.total_deliveries
       OR NEW.rating IS DISTINCT FROM OLD.rating
       OR NEW.cancellation_rate IS DISTINCT FROM OLD.cancellation_rate
       OR NEW.payout_details IS DISTINCT FROM OLD.payout_details
       OR NEW.city_id IS DISTINCT FROM OLD.city_id
       OR NEW.assigned_zone_ids IS DISTINCT FROM OLD.assigned_zone_ids
     ) THEN
    RAISE EXCEPTION 'Driver financial, approval, and assignment fields require fleet approval';
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."protect_driver_financial_and_approval_fields"() OWNER TO "postgres";

--
-- Name: protect_fleet_manager_privileged_fields(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."protect_fleet_manager_privileged_fields"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF auth.uid() IS NOT NULL
     AND COALESCE(auth.jwt() ->> 'role', '') <> 'service_role'
     AND NOT public.has_role(auth.uid(), 'admin'::public.app_role)
     AND (
       NEW.auth_user_id IS DISTINCT FROM OLD.auth_user_id
       OR NEW.email IS DISTINCT FROM OLD.email
       OR NEW.role IS DISTINCT FROM OLD.role
       OR NEW.assigned_city_ids IS DISTINCT FROM OLD.assigned_city_ids
       OR NEW.is_active IS DISTINCT FROM OLD.is_active
       OR NEW.country IS DISTINCT FROM OLD.country
     ) THEN
    RAISE EXCEPTION 'Fleet manager privileged fields may only be changed by an administrator';
  END IF;
  RETURN NEW;
END;
$$;


