-- Name: FUNCTION "protect_profile_system_fields"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."protect_profile_system_fields"() IS 'Prevents authenticated clients from mutating XP, referral, and affiliate ledger projections directly.';


--
-- Name: purchase_extra_meal_credit("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."purchase_extra_meal_credit"("p_subscription_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_subscription public.subscriptions%ROWTYPE;
  v_wallet public.customer_wallets%ROWTYPE;
  v_price NUMERIC(10, 2);
  v_balance_after NUMERIC(10, 2);
  v_transaction_id UUID;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  SELECT *
    INTO v_subscription
  FROM public.subscriptions
  WHERE id = p_subscription_id
    AND user_id = v_user_id
    AND status IN ('active', 'cancelled')
    AND (
      status = 'active'
      OR COALESCE(end_date, CURRENT_DATE - 1) >= CURRENT_DATE
    )
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'SUBSCRIPTION_NOT_FOUND';
  END IF;

  SELECT COALESCE(
    v_subscription.price_per_meal,
    (
      SELECT sp.price_per_meal
      FROM public.subscription_plans sp
      WHERE sp.id = v_subscription.plan_id
         OR (
           sp.tier = v_subscription.tier
           AND sp.billing_interval = COALESCE(
             v_subscription.billing_interval,
             'monthly'
           )
         )
      ORDER BY (sp.id = v_subscription.plan_id) DESC
      LIMIT 1
    ),
    50
  ) INTO v_price;

  IF v_price <= 0 THEN
    RAISE EXCEPTION 'INVALID_MEAL_CREDIT_PRICE';
  END IF;

  SELECT *
    INTO v_wallet
  FROM public.customer_wallets
  WHERE user_id = v_user_id
    AND is_active = TRUE
  FOR UPDATE;

  IF NOT FOUND OR COALESCE(v_wallet.balance, 0) < v_price THEN
    RAISE EXCEPTION 'INSUFFICIENT_WALLET_BALANCE';
  END IF;

  v_balance_after := v_wallet.balance - v_price;

  UPDATE public.customer_wallets
  SET balance = v_balance_after,
      total_debits = COALESCE(total_debits, 0) + v_price,
      updated_at = NOW()
  WHERE id = v_wallet.id;

  UPDATE public.subscriptions
  SET meals_per_month = COALESCE(meals_per_month, 0) + 1,
      updated_at = NOW()
  WHERE id = v_subscription.id;

  INSERT INTO public.wallet_transactions (
    wallet_id,
    user_id,
    type,
    amount,
    balance_after,
    reference_type,
    reference_id,
    description,
    metadata
  ) VALUES (
    v_wallet.id,
    v_user_id,
    'debit',
    v_price,
    v_balance_after,
    'extra_meal_credit',
    v_subscription.id,
    'Extra meal credit purchase',
    jsonb_build_object('subscription_id', v_subscription.id)
  )
  RETURNING id INTO v_transaction_id;

  RETURN jsonb_build_object(
    'success', TRUE,
    'transaction_id', v_transaction_id,
    'amount', v_price,
    'new_balance', v_balance_after,
    'meals_per_month', COALESCE(v_subscription.meals_per_month, 0) + 1
  );
END;
$$;


ALTER FUNCTION "public"."purchase_extra_meal_credit"("p_subscription_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "purchase_extra_meal_credit"("p_subscription_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."purchase_extra_meal_credit"("p_subscription_id" "uuid") IS 'Atomically debits the authenticated customer wallet and increases their subscription meal allowance.';


--
-- Name: quote_delivery_fee("date", "text", "uuid", "text", numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."quote_delivery_fee"("p_scheduled_date" "date", "p_delivery_time_slot" "text", "p_delivery_address_id" "uuid", "p_delivery_type" "text" DEFAULT 'standard'::"text", "p_order_total" numeric DEFAULT 0) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_breakdown JSONB;
  v_quote_id UUID;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;
  IF p_scheduled_date < CURRENT_DATE OR p_scheduled_date > CURRENT_DATE + 90 THEN
    RAISE EXCEPTION 'SCHEDULE_DATE_INVALID';
  END IF;

  v_breakdown := public.calculate_delivery_fee_breakdown(
    v_user_id,
    p_scheduled_date,
    p_delivery_time_slot,
    p_delivery_address_id,
    p_delivery_type,
    p_order_total
  );

  INSERT INTO public.delivery_fee_quotes (
    user_id, scheduled_date, delivery_time_slot, delivery_address_id,
    delivery_type, city, base_fee, surge_fee, total_fee, rule_id,
    rule_name, customer_message, demand_count, pricing_context
  ) VALUES (
    v_user_id,
    p_scheduled_date,
    p_delivery_time_slot,
    p_delivery_address_id,
    p_delivery_type,
    COALESCE(v_breakdown ->> 'city', ''),
    COALESCE((v_breakdown ->> 'base_fee')::NUMERIC, 0),
    COALESCE((v_breakdown ->> 'surge_fee')::NUMERIC, 0),
    COALESCE((v_breakdown ->> 'total_fee')::NUMERIC, 0),
    NULLIF(v_breakdown ->> 'rule_id', '')::UUID,
    NULLIF(v_breakdown ->> 'rule_name', ''),
    NULLIF(v_breakdown ->> 'message', ''),
    COALESCE((v_breakdown ->> 'demand_count')::INTEGER, 0),
    v_breakdown
  )
  RETURNING id INTO v_quote_id;

  RETURN v_breakdown || jsonb_build_object(
    'quote_id', v_quote_id,
    'expires_at', now() + INTERVAL '10 minutes'
  );
END;
$$;


ALTER FUNCTION "public"."quote_delivery_fee"("p_scheduled_date" "date", "p_delivery_time_slot" "text", "p_delivery_address_id" "uuid", "p_delivery_type" "text", "p_order_total" numeric) OWNER TO "postgres";

--
-- Name: reactivate_subscription("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reactivate_subscription"("p_subscription_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sub public.subscriptions%ROWTYPE;
BEGIN
  SELECT * INTO v_sub FROM public.subscriptions
  WHERE id = p_subscription_id FOR UPDATE;

  IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'Subscription not found'); END IF;
  IF auth.uid() IS NULL OR v_sub.user_id <> auth.uid() THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authorized');
  END IF;
  IF v_sub.status NOT IN ('expired', 'cancelled') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Subscription is not eligible for reactivation');
  END IF;

  UPDATE public.subscriptions
  SET status = 'active', active = true, expired_at = NULL,
      start_date = CURRENT_DATE, end_date = CURRENT_DATE + 30,
      next_renewal_date = CURRENT_DATE + 30,
      meals_used_this_month = 0, meals_used_this_week = 0,
      week_start_date = CURRENT_DATE, month_start_date = CURRENT_DATE,
      updated_at = now()
  WHERE id = p_subscription_id;

  UPDATE public.subscription_recovery
  SET recovery_status = 'reactivated', reactivated_at = now(),
      reactivation_tier = v_sub.tier, new_subscription_id = p_subscription_id,
      updated_at = now()
  WHERE user_id = v_sub.user_id
    AND subscription_id = p_subscription_id
    AND recovery_status IN ('pending', 'offer_viewed', 'offer_accepted');

  INSERT INTO public.retention_audit_logs
    (user_id, subscription_id, action_type, action_details, triggered_by, triggered_by_user_id)
  VALUES
    (v_sub.user_id, p_subscription_id, 'subscription_renewed',
     jsonb_build_object('action', 'reactivated'), 'user', auth.uid());

  RETURN jsonb_build_object('success', true, 'message', 'Subscription reactivated successfully');
END;
$$;


ALTER FUNCTION "public"."reactivate_subscription"("p_subscription_id" "uuid") OWNER TO "postgres";

--
-- Name: rebuild_health_daily_metrics_from_wearables("uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."rebuild_health_daily_metrics_from_wearables"("p_user_id" "uuid", "p_metric_date" "date") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_steps integer := 0;
  v_workouts_count integer := 0;
  v_active_calories integer := 0;
  v_resting_heart_rate numeric;
  v_average_heart_rate numeric;
  v_hrv numeric;
  v_sleep_minutes integer;
  v_deep_sleep_minutes integer;
  v_rem_sleep_minutes integer;
  v_respiratory_rate numeric;
  v_spo2 numeric;
  v_skin_temperature numeric;
  v_source text := 'manual';
begin
  if auth.uid() is null or auth.uid() <> p_user_id then
    raise exception 'AUTH_REQUIRED' using errcode = '42501';
  end if;

  with provider_metric as (
    select
      metric_type,
      provider,
      public.wearable_provider_precedence(provider) as precedence,
      max(synced_at) as latest_synced_at,
      case
        when metric_type in ('steps', 'workouts_count', 'active_calories', 'sleep_minutes', 'deep_sleep_minutes', 'rem_sleep_minutes')
          then sum(value)
        else avg(value)
      end as metric_value
    from public.wearable_metric_samples
    where user_id = p_user_id
      and metric_date = p_metric_date
      and deleted_at is null
      and sync_status = 'synced'
    group by metric_type, provider
  ),
  selected_metric as (
    select distinct on (metric_type)
      metric_type,
      provider,
      metric_value
    from provider_metric
    order by metric_type, precedence desc, latest_synced_at desc, provider
  )
  select
    coalesce(max(metric_value) filter (where metric_type = 'steps'), 0)::integer,
    coalesce(max(metric_value) filter (where metric_type = 'workouts_count'), 0)::integer,
    coalesce(max(metric_value) filter (where metric_type = 'active_calories'), 0)::integer,
    max(metric_value) filter (where metric_type = 'resting_heart_rate'),
    max(metric_value) filter (where metric_type = 'average_heart_rate'),
    max(metric_value) filter (where metric_type = 'hrv'),
    max(metric_value) filter (where metric_type = 'sleep_minutes')::integer,
    max(metric_value) filter (where metric_type = 'deep_sleep_minutes')::integer,
    max(metric_value) filter (where metric_type = 'rem_sleep_minutes')::integer,
    max(metric_value) filter (where metric_type = 'respiratory_rate'),
    max(metric_value) filter (where metric_type = 'spo2'),
    max(metric_value) filter (where metric_type = 'skin_temperature'),
    coalesce(string_agg(distinct provider, '+' order by provider), 'manual')
  into
    v_steps,
    v_workouts_count,
    v_active_calories,
    v_resting_heart_rate,
    v_average_heart_rate,
    v_hrv,
    v_sleep_minutes,
    v_deep_sleep_minutes,
    v_rem_sleep_minutes,
    v_respiratory_rate,
    v_spo2,
    v_skin_temperature,
    v_source
  from selected_metric;

  insert into public.health_daily_metrics (
    user_id,
    metric_date,
    steps,
    workouts_count,
    active_calories,
    resting_heart_rate,
    average_heart_rate,
    hrv,
    sleep_minutes,
    deep_sleep_minutes,
    rem_sleep_minutes,
    respiratory_rate,
    spo2,
    skin_temperature,
    source,
    synced_at,
    updated_at
  )
  values (
    p_user_id,
    p_metric_date,
    v_steps,
    v_workouts_count,
    v_active_calories,
    v_resting_heart_rate,
    v_average_heart_rate,
    v_hrv,
    v_sleep_minutes,
    v_deep_sleep_minutes,
    v_rem_sleep_minutes,
    v_respiratory_rate,
    v_spo2,
    v_skin_temperature,
    v_source,
    now(),
    now()
  )
  on conflict (user_id, metric_date)
  do update set
    steps = excluded.steps,
    workouts_count = excluded.workouts_count,
    active_calories = excluded.active_calories,
    resting_heart_rate = excluded.resting_heart_rate,
    average_heart_rate = excluded.average_heart_rate,
    hrv = excluded.hrv,
    sleep_minutes = excluded.sleep_minutes,
    deep_sleep_minutes = excluded.deep_sleep_minutes,
    rem_sleep_minutes = excluded.rem_sleep_minutes,
    respiratory_rate = excluded.respiratory_rate,
    spo2 = excluded.spo2,
    skin_temperature = excluded.skin_temperature,
    source = excluded.source,
    synced_at = excluded.synced_at,
    updated_at = now();
end;
$$;


ALTER FUNCTION "public"."rebuild_health_daily_metrics_from_wearables"("p_user_id" "uuid", "p_metric_date" "date") OWNER TO "postgres";

--
-- Name: rebuild_xp_profile_from_ledger("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."rebuild_xp_profile_from_ledger"("p_user_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_remaining INTEGER;
  v_level INTEGER := 1;
  v_threshold INTEGER := 100;
BEGIN
  SELECT greatest(coalesce(sum(xp_amount), 0), 0)::INTEGER INTO v_remaining
  FROM public.xp_transactions WHERE user_id = p_user_id;

  WHILE v_remaining >= v_threshold LOOP
    v_remaining := v_remaining - v_threshold;
    v_level := v_level + 1;
    v_threshold := greatest(100, v_level * 100);
  END LOOP;

  UPDATE public.profiles SET xp = v_remaining, level = v_level
  WHERE user_id = p_user_id;
END;
$$;


ALTER FUNCTION "public"."rebuild_xp_profile_from_ledger"("p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: record_meal_ranking_audit("uuid", "text", timestamp with time zone, "jsonb", "jsonb", "jsonb", "jsonb", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_meal_ranking_audit"("p_request_id" "uuid", "p_engine_version" "text", "p_generated_at" timestamp with time zone, "p_input_freshness" "jsonb", "p_exclusions" "jsonb", "p_ranked" "jsonb", "p_context" "jsonb", "p_offline" boolean DEFAULT false) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_id UUID;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED' USING ERRCODE = '42501';
  END IF;
  IF p_offline THEN
    RAISE EXCEPTION 'OFFLINE_AUDIT_NOT_ALLOWED' USING ERRCODE = '22023';
  END IF;
  IF p_generated_at > now() + interval '5 minutes' OR p_generated_at < now() - interval '48 hours' THEN
    RAISE EXCEPTION 'INVALID_GENERATED_AT' USING ERRCODE = '22023';
  END IF;
  IF char_length(p_engine_version) NOT BETWEEN 1 AND 80
     OR jsonb_typeof(p_input_freshness) <> 'object'
     OR jsonb_typeof(p_exclusions) <> 'array'
     OR jsonb_typeof(p_ranked) <> 'array'
     OR jsonb_typeof(p_context) <> 'object'
     OR jsonb_array_length(p_exclusions) > 250
     OR jsonb_array_length(p_ranked) > 50
     OR octet_length(p_input_freshness::TEXT) > 8192
     OR octet_length(p_exclusions::TEXT) > 65536
     OR octet_length(p_ranked::TEXT) > 131072
     OR octet_length(p_context::TEXT) > 8192 THEN
    RAISE EXCEPTION 'INVALID_AUDIT_PAYLOAD' USING ERRCODE = '22023';
  END IF;

  INSERT INTO public.meal_ranking_audits (
    user_id, request_id, engine_version, generated_at, input_freshness,
    exclusions, ranked, context, offline
  ) VALUES (
    v_user_id, p_request_id, p_engine_version, p_generated_at, p_input_freshness,
    p_exclusions, p_ranked, p_context, false
  )
  ON CONFLICT (user_id, request_id) DO NOTHING
  RETURNING id INTO v_id;

  IF v_id IS NULL THEN
    SELECT id INTO v_id
    FROM public.meal_ranking_audits
    WHERE user_id = v_user_id AND request_id = p_request_id;
  END IF;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."record_meal_ranking_audit"("p_request_id" "uuid", "p_engine_version" "text", "p_generated_at" timestamp with time zone, "p_input_freshness" "jsonb", "p_exclusions" "jsonb", "p_ranked" "jsonb", "p_context" "jsonb", "p_offline" boolean) OWNER TO "postgres";

--
-- Name: record_notification_event_delivery("uuid", "text", "text", "text", "text", "text", "text", "text", "text", "text", "uuid", "uuid", timestamp with time zone, "text", "text", boolean, "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_notification_event_delivery"("p_user_id" "uuid", "p_event_type" "text", "p_template_key" "text", "p_notification_type" "text", "p_preference_key" "text", "p_channel" "text", "p_status" "text", "p_dedupe_key" "text", "p_quiet_hours_policy" "text" DEFAULT 'respect'::"text", "p_deep_link_type" "text" DEFAULT NULL::"text", "p_notification_id" "uuid" DEFAULT NULL::"uuid", "p_event_id" "uuid" DEFAULT NULL::"uuid", "p_deferred_until" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_suppression_reason" "text" DEFAULT NULL::"text", "p_error_code" "text" DEFAULT NULL::"text", "p_retryable" boolean DEFAULT true, "p_provider_message_id" "text" DEFAULT NULL::"text", "p_analytics_event" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public', 'pg_temp'
    AS $$
declare
  v_status text := lower(trim(coalesce(p_status, 'pending')));
  v_channel text := lower(trim(coalesce(p_channel, '')));
  v_quiet_hours_policy text := lower(trim(coalesce(p_quiet_hours_policy, 'respect')));
  v_error_code text := security.safe_notification_error_code(p_error_code);
  v_row security.notification_event_deliveries%rowtype;
begin
  if coalesce(auth.role(), '') <> 'service_role' then
    raise exception 'Service role required';
  end if;

  if p_user_id is null
     or v_channel not in ('in_app', 'push', 'email', 'whatsapp')
     or v_status not in ('pending', 'deferred', 'suppressed', 'processing', 'delivered', 'failed', 'dead_letter')
     or v_quiet_hours_policy not in ('respect', 'bypass')
     or char_length(coalesce(p_event_type, '')) not between 1 and 120
     or char_length(coalesce(p_template_key, '')) not between 1 and 160
     or char_length(coalesce(p_dedupe_key, '')) not between 1 and 220 then
    raise exception 'Invalid notification delivery event';
  end if;

  insert into security.notification_event_deliveries (
    event_id,
    notification_id,
    user_id,
    event_type,
    template_key,
    notification_type,
    preference_key,
    channel,
    status,
    dedupe_key,
    quiet_hours_policy,
    deep_link_type,
    deferred_until,
    suppressed_at,
    suppression_reason,
    attempt_count,
    last_error_code,
    retryable,
    provider_message_id,
    analytics_event,
    updated_at
  )
  values (
    p_event_id,
    p_notification_id,
    p_user_id,
    left(p_event_type, 120),
    left(p_template_key, 160),
    left(coalesce(p_notification_type, 'general'), 80),
    left(coalesce(p_preference_key, 'system_alerts'), 80),
    v_channel,
    v_status,
    left(p_dedupe_key, 220),
    v_quiet_hours_policy,
    nullif(left(coalesce(p_deep_link_type, ''), 80), ''),
    case when v_status = 'deferred' then p_deferred_until else null end,
    case when v_status = 'suppressed' then now() else null end,
    case when v_status = 'suppressed' then left(coalesce(p_suppression_reason, 'suppressed'), 120) else null end,
    case when v_status in ('processing', 'failed', 'dead_letter') then 1 else 0 end,
    v_error_code,
    coalesce(p_retryable, true),
    nullif(left(coalesce(p_provider_message_id, ''), 250), ''),
    nullif(left(coalesce(p_analytics_event, ''), 120), ''),
    now()
  )
  on conflict (user_id, channel, dedupe_key)
  do update set
    status = excluded.status,
    notification_id = coalesce(excluded.notification_id, security.notification_event_deliveries.notification_id),
    event_id = coalesce(excluded.event_id, security.notification_event_deliveries.event_id),
    deferred_until = excluded.deferred_until,
    suppressed_at = coalesce(excluded.suppressed_at, security.notification_event_deliveries.suppressed_at),
    suppression_reason = excluded.suppression_reason,
    attempt_count = case
      when excluded.status in ('processing', 'failed', 'dead_letter')
        then least(security.notification_event_deliveries.attempt_count + 1, 20)
      else security.notification_event_deliveries.attempt_count
    end,
    last_error_code = excluded.last_error_code,
    retryable = excluded.retryable,
    provider_message_id = coalesce(excluded.provider_message_id, security.notification_event_deliveries.provider_message_id),
    analytics_event = coalesce(excluded.analytics_event, security.notification_event_deliveries.analytics_event),
    updated_at = now()
  returning * into v_row;

  return jsonb_build_object(
    'ok', true,
    'status', v_row.status,
    'attempt_count', v_row.attempt_count,
    'delivery_id', v_row.id
  );
end;
$$;


ALTER FUNCTION "public"."record_notification_event_delivery"("p_user_id" "uuid", "p_event_type" "text", "p_template_key" "text", "p_notification_type" "text", "p_preference_key" "text", "p_channel" "text", "p_status" "text", "p_dedupe_key" "text", "p_quiet_hours_policy" "text", "p_deep_link_type" "text", "p_notification_id" "uuid", "p_event_id" "uuid", "p_deferred_until" timestamp with time zone, "p_suppression_reason" "text", "p_error_code" "text", "p_retryable" boolean, "p_provider_message_id" "text", "p_analytics_event" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "record_notification_event_delivery"("p_user_id" "uuid", "p_event_type" "text", "p_template_key" "text", "p_notification_type" "text", "p_preference_key" "text", "p_channel" "text", "p_status" "text", "p_dedupe_key" "text", "p_quiet_hours_policy" "text", "p_deep_link_type" "text", "p_notification_id" "uuid", "p_event_id" "uuid", "p_deferred_until" timestamp with time zone, "p_suppression_reason" "text", "p_error_code" "text", "p_retryable" boolean, "p_provider_message_id" "text", "p_analytics_event" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."record_notification_event_delivery"("p_user_id" "uuid", "p_event_type" "text", "p_template_key" "text", "p_notification_type" "text", "p_preference_key" "text", "p_channel" "text", "p_status" "text", "p_dedupe_key" "text", "p_quiet_hours_policy" "text", "p_deep_link_type" "text", "p_notification_id" "uuid", "p_event_id" "uuid", "p_deferred_until" timestamp with time zone, "p_suppression_reason" "text", "p_error_code" "text", "p_retryable" boolean, "p_provider_message_id" "text", "p_analytics_event" "text") IS 'Service-role-only Agent 9 delivery receipt recorder with idempotent per-channel dedupe.';


--
-- Name: record_order_meal_consumption("text", "uuid", "uuid", "text", numeric, "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_order_meal_consumption"("p_source_type" "text", "p_source_id" "uuid", "p_source_meal_id" "uuid", "p_status" "text", "p_portion_percent" numeric DEFAULT 100, "p_substitute_meal_id" "uuid" DEFAULT NULL::"uuid", "p_request_id" "uuid" DEFAULT "gen_random_uuid"()) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_actor uuid := auth.uid();
  v_source_type text := lower(coalesce(p_source_type, ''));
  v_status text := lower(coalesce(p_status, ''));
  v_event_type text;
  v_portion numeric(6, 5);
  v_source_snapshot jsonb;
  v_effective_snapshot jsonb;
  v_order public.orders%rowtype;
  v_consumption public.meal_consumptions%rowtype;
  v_existing_result jsonb;
  v_consumption_id uuid;
  v_event_version integer;
  v_log_date date := (now() at time zone 'Asia/Qatar')::date;
  v_old_log_date date;
  v_old_calories integer := 0;
  v_old_protein integer := 0;
  v_old_carbs integer := 0;
  v_old_fat integer := 0;
  v_old_fiber integer := 0;
  v_new_calories integer := 0;
  v_new_protein integer := 0;
  v_new_carbs integer := 0;
  v_new_fat integer := 0;
  v_new_fiber integer := 0;
  v_history_id uuid;
  v_result jsonb;
  v_previous_state jsonb;
  v_current_state jsonb;
  v_semantic_key text;
begin
  if v_actor is null then
    raise exception 'AUTHENTICATION_REQUIRED';
  end if;
  if p_request_id is null then
    raise exception 'REQUEST_ID_REQUIRED';
  end if;
  if v_source_type not in ('order', 'meal_schedule') then
    raise exception 'INVALID_CONSUMPTION_SOURCE';
  end if;
  if v_status not in ('full', 'partial', 'skipped', 'substituted', 'reversed') then
    raise exception 'INVALID_CONSUMPTION_STATUS';
  end if;

  perform 1
  from public.profiles p
  where p.user_id = v_actor
  for update;
  if not found then
    raise exception 'PROFILE_NOT_FOUND';
  end if;

  perform pg_advisory_xact_lock(hashtextextended(v_actor::text || ':' || p_request_id::text, 0));
  perform pg_advisory_xact_lock(
    hashtextextended(v_actor::text || ':' || v_source_type || ':' || p_source_id::text || ':' || p_source_meal_id::text, 0)
  );

  select mce.result_snapshot
  into v_existing_result
  from public.meal_consumption_events mce
  where mce.user_id = v_actor
    and mce.request_id = p_request_id;

  if found then
    return v_existing_result || jsonb_build_object('already_processed', true);
  end if;

  if v_source_type = 'meal_schedule' then
    select coalesce(ms.nutrition_snapshot, public.get_meal_nutrition_snapshot(ms.meal_id))
    into v_source_snapshot
    from public.meal_schedules ms
    where ms.id = p_source_id
      and ms.user_id = v_actor
      and ms.meal_id = p_source_meal_id
      and ms.order_status in ('delivered', 'completed')
    for update of ms;

    if not found then
      raise exception 'DELIVERED_SCHEDULE_NOT_FOUND';
    end if;
  else
    select *
    into v_order
    from public.orders o
    where o.id = p_source_id
      and o.user_id = v_actor
      and o.status::text in ('delivered', 'completed')
    for update;

    if not found then
      raise exception 'DELIVERED_ORDER_NOT_FOUND';
    end if;

    select jsonb_build_object(
      'schema_version', 2,
      'meal_id', p_source_meal_id,
      'order_item_ids', jsonb_agg(oi.id order by oi.id),
      'meal_name', max(coalesce(oi.nutrition_snapshot ->> 'meal_name', oi.meal_name, m.name)),
      'image_url', max(coalesce(oi.nutrition_snapshot ->> 'image_url', m.image_url)),
      'serving_quantity', sum(greatest(coalesce(oi.quantity, 1), 1)),
      'serving_unit', 'meal',
      'calories', sum(coalesce((oi.nutrition_snapshot ->> 'calories')::numeric, m.calories) * greatest(coalesce(oi.quantity, 1), 1)),
      'protein_g', sum(coalesce((oi.nutrition_snapshot ->> 'protein_g')::numeric, m.protein_g, m.protein) * greatest(coalesce(oi.quantity, 1), 1)),
      'carbs_g', sum(coalesce((oi.nutrition_snapshot ->> 'carbs_g')::numeric, m.carbs_g, m.carbs) * greatest(coalesce(oi.quantity, 1), 1)),
      'fat_g', sum(coalesce((oi.nutrition_snapshot ->> 'fat_g')::numeric, m.fat_g, m.fats) * greatest(coalesce(oi.quantity, 1), 1)),
      'fiber_g', sum(coalesce((oi.nutrition_snapshot ->> 'fiber_g')::numeric, m.fiber_g) * greatest(coalesce(oi.quantity, 1), 1)),
      'sugar_g', sum(coalesce((oi.nutrition_snapshot ->> 'sugar_g')::numeric, m.sugar_g) * greatest(coalesce(oi.quantity, 1), 1)),
      'sodium_mg', sum(coalesce((oi.nutrition_snapshot ->> 'sodium_mg')::numeric, m.sodium_mg) * greatest(coalesce(oi.quantity, 1), 1)),
      'captured_at', min(coalesce(oi.nutrition_snapshot ->> 'captured_at', oi.created_at::text)),
      'source_type', 'order',
      'source_record_id', p_source_id,
      'missing_nutrient_codes', (
        select coalesce(jsonb_agg(distinct code), '[]'::jsonb)
        from (
          select jsonb_array_elements_text(coalesce(oi2.nutrition_snapshot -> 'missing_nutrient_codes', '[]'::jsonb)) as code
          from public.order_items oi2
          where oi2.order_id = p_source_id
            and oi2.meal_id = p_source_meal_id
        ) missing_codes
      )
    )
    into v_source_snapshot
    from public.order_items oi
    left join public.meals m on m.id = oi.meal_id
    where oi.order_id = p_source_id
      and oi.meal_id = p_source_meal_id
    having count(*) > 0;

    if v_source_snapshot is null and v_order.meal_id = p_source_meal_id then
      v_source_snapshot := public.get_meal_nutrition_snapshot(v_order.meal_id);
    end if;

    if v_source_snapshot is null then
      raise exception 'MEAL_NOT_IN_ORDER';
    end if;
  end if;

  if v_status = 'full' then
    p_portion_percent := 100;
    p_substitute_meal_id := null;
    v_event_type := 'consumed';
  elsif v_status = 'partial' then
    if p_portion_percent is null or p_portion_percent <= 0 or p_portion_percent >= 100 then
      raise exception 'PARTIAL_PORTION_MUST_BE_BETWEEN_0_AND_100';
    end if;
    p_substitute_meal_id := null;
    v_event_type := 'consumed';
  elsif v_status = 'substituted' then
    if p_substitute_meal_id is null or p_substitute_meal_id = p_source_meal_id then
      raise exception 'SUBSTITUTE_MEAL_REQUIRED';
    end if;
    if p_portion_percent is null or p_portion_percent <= 0 or p_portion_percent > 100 then
      raise exception 'INVALID_PORTION_PERCENT';
    end if;
    v_event_type := 'substituted';
  elsif v_status = 'reversed' then
    p_portion_percent := 0;
    p_substitute_meal_id := null;
    v_event_type := 'reversed';
  else
    p_portion_percent := 0;
    p_substitute_meal_id := null;
    v_event_type := 'skipped';
  end if;

  v_portion := round((p_portion_percent / 100.0)::numeric, 5);

  if v_status = 'substituted' then
    v_effective_snapshot := public.get_meal_nutrition_snapshot(p_substitute_meal_id);
    if v_effective_snapshot is null then
      raise exception 'SUBSTITUTE_MEAL_NOT_FOUND';
    end if;
    v_effective_snapshot := v_effective_snapshot || jsonb_build_object(
      'original_meal_id', p_source_meal_id,
      'substitute_meal_id', p_substitute_meal_id,
      'substitution_source_snapshot', v_source_snapshot
    );
  else
    v_effective_snapshot := v_source_snapshot;
  end if;

  select *
  into v_consumption
  from public.meal_consumptions mc
  where mc.user_id = v_actor
    and mc.source_type = v_source_type
    and mc.source_id = p_source_id
    and mc.source_meal_id = p_source_meal_id
  for update;

  if found then
    if v_consumption.status = v_status
      and v_consumption.portion_percent = p_portion_percent
      and v_consumption.substitute_meal_id is not distinct from p_substitute_meal_id then
      return jsonb_build_object(
        'success', true,
        'already_processed', true,
        'consumption_id', v_consumption.id,
        'event_version', v_consumption.event_version,
        'status', v_consumption.status,
        'portion_percent', v_consumption.portion_percent,
        'portion', round((v_consumption.portion_percent / 100.0)::numeric, 5),
        'nutrition', jsonb_build_object(
          'calories', v_consumption.applied_calories,
          'protein_g', v_consumption.applied_protein_g,
          'carbs_g', v_consumption.applied_carbs_g,
          'fat_g', v_consumption.applied_fat_g,
          'fiber_g', v_consumption.applied_fiber_g
        )
      );
    end if;

    v_consumption_id := v_consumption.id;
    v_event_version := v_consumption.event_version + 1;
    v_old_log_date := v_consumption.log_date;
    v_old_calories := v_consumption.applied_calories;
    v_old_protein := v_consumption.applied_protein_g;
    v_old_carbs := v_consumption.applied_carbs_g;
    v_old_fat := v_consumption.applied_fat_g;
    v_old_fiber := v_consumption.applied_fiber_g;
    v_previous_state := jsonb_build_object(
      'status', v_consumption.status,
      'portion_percent', v_consumption.portion_percent,
      'portion', round((v_consumption.portion_percent / 100.0)::numeric, 5),
      'substitute_meal_id', v_consumption.substitute_meal_id,
      'log_date', v_consumption.log_date
    );
  else
    v_consumption_id := gen_random_uuid();
    v_event_version := 1;
    v_old_log_date := v_log_date;
    v_previous_state := null;
  end if;

  v_semantic_key := concat_ws(':', v_actor::text, v_source_type, p_source_id::text, p_source_meal_id::text, v_event_type, v_event_version::text);

  if p_portion_percent > 0 then
    v_new_calories := round(coalesce((v_effective_snapshot ->> 'calories')::numeric, 0) * v_portion)::integer;
    v_new_protein := round(coalesce((v_effective_snapshot ->> 'protein_g')::numeric, 0) * v_portion)::integer;
    v_new_carbs := round(coalesce((v_effective_snapshot ->> 'carbs_g')::numeric, 0) * v_portion)::integer;
    v_new_fat := round(coalesce((v_effective_snapshot ->> 'fat_g')::numeric, 0) * v_portion)::integer;
    v_new_fiber := round(coalesce((v_effective_snapshot ->> 'fiber_g')::numeric, 0) * v_portion)::integer;
  end if;

  if v_old_calories + v_old_protein + v_old_carbs + v_old_fat + v_old_fiber > 0 then
    update public.progress_logs
    set calories_consumed = greatest(0, coalesce(calories_consumed, 0) - v_old_calories),
        protein_consumed_g = greatest(0, coalesce(protein_consumed_g, 0) - v_old_protein),
        carbs_consumed_g = greatest(0, coalesce(carbs_consumed_g, 0) - v_old_carbs),
        fat_consumed_g = greatest(0, coalesce(fat_consumed_g, 0) - v_old_fat),
        fiber_consumed_g = greatest(0, coalesce(fiber_consumed_g, 0) - v_old_fiber),
        updated_at = now()
    where user_id = v_actor
      and log_date = v_old_log_date;
  end if;

  if v_new_calories + v_new_protein + v_new_carbs + v_new_fat + v_new_fiber > 0 then
    insert into public.progress_logs (
      user_id, log_date, calories_consumed, protein_consumed_g,
      carbs_consumed_g, fat_consumed_g, fiber_consumed_g, created_at, updated_at
    ) values (
      v_actor, v_log_date, v_new_calories, v_new_protein,
      v_new_carbs, v_new_fat, v_new_fiber, now(), now()
    )
    on conflict (user_id, log_date) do update
    set calories_consumed = coalesce(public.progress_logs.calories_consumed, 0) + excluded.calories_consumed,
        protein_consumed_g = coalesce(public.progress_logs.protein_consumed_g, 0) + excluded.protein_consumed_g,
        carbs_consumed_g = coalesce(public.progress_logs.carbs_consumed_g, 0) + excluded.carbs_consumed_g,
        fat_consumed_g = coalesce(public.progress_logs.fat_consumed_g, 0) + excluded.fat_consumed_g,
        fiber_consumed_g = coalesce(public.progress_logs.fiber_consumed_g, 0) + excluded.fiber_consumed_g,
        updated_at = now();
  end if;

  if v_consumption.id is null then
    insert into public.meal_consumptions (
      id, user_id, source_type, source_id, source_meal_id, status,
      portion_percent, substitute_meal_id, nutrition_snapshot, source_snapshot,
      applied_calories, applied_protein_g, applied_carbs_g, applied_fat_g,
      applied_fiber_g, log_date, event_version, semantic_idempotency_key,
      created_at, updated_at
    ) values (
      v_consumption_id, v_actor, v_source_type, p_source_id, p_source_meal_id, v_status,
      p_portion_percent, p_substitute_meal_id, v_effective_snapshot, v_source_snapshot,
      v_new_calories, v_new_protein, v_new_carbs, v_new_fat,
      v_new_fiber, v_log_date, v_event_version, v_semantic_key, now(), now()
    );
  else
    update public.meal_consumptions
    set status = v_status,
        portion_percent = p_portion_percent,
        substitute_meal_id = p_substitute_meal_id,
        nutrition_snapshot = v_effective_snapshot,
        source_snapshot = v_source_snapshot,
        applied_calories = v_new_calories,
        applied_protein_g = v_new_protein,
        applied_carbs_g = v_new_carbs,
        applied_fat_g = v_new_fat,
        applied_fiber_g = v_new_fiber,
        log_date = v_log_date,
        event_version = v_event_version,
        semantic_idempotency_key = v_semantic_key,
        updated_at = now()
    where id = v_consumption_id;
  end if;

  select mh.id
  into v_history_id
  from public.meal_history mh
  where mh.source_consumption_id = v_consumption_id
  for update;

  if v_new_calories + v_new_protein + v_new_carbs + v_new_fat + v_new_fiber > 0 then
    if v_history_id is null then
      insert into public.meal_history (
        user_id, name, calories, protein_g, carbs_g, fat_g, fiber_g, image_url,
        logged_at, source, schedule_id, source_order_id, source_meal_id,
        source_consumption_id
      ) values (
        v_actor,
        coalesce(v_effective_snapshot ->> 'meal_name', 'Meal'),
        v_new_calories,
        v_new_protein,
        v_new_carbs,
        v_new_fat,
        v_new_fiber,
        nullif(v_effective_snapshot ->> 'image_url', ''),
        now(),
        'order_consumption',
        case when v_source_type = 'meal_schedule' then p_source_id else null end,
        case when v_source_type = 'order' then p_source_id else null end,
        p_source_meal_id,
        v_consumption_id
      )
      returning id into v_history_id;
    else
      update public.meal_history
      set name = coalesce(v_effective_snapshot ->> 'meal_name', name),
          calories = v_new_calories,
          protein_g = v_new_protein,
          carbs_g = v_new_carbs,
          fat_g = v_new_fat,
          fiber_g = v_new_fiber,
          image_url = nullif(v_effective_snapshot ->> 'image_url', ''),
          logged_at = now(),
          source = 'order_consumption'
      where id = v_history_id;
    end if;
  elsif v_history_id is not null then
    update public.meal_history set fiber_g = 0 where id = v_history_id;
    delete from public.meal_history where id = v_history_id;
    v_history_id := null;
  end if;

  update public.meal_consumptions
  set meal_history_id = v_history_id
  where id = v_consumption_id;

  if v_source_type = 'meal_schedule' then
    update public.meal_schedules
    set is_completed = v_status in ('full', 'partial', 'substituted'),
        completed_at = case when v_status in ('full', 'partial', 'substituted') then now() else null end,
        updated_at = now()
    where id = p_source_id
      and user_id = v_actor;
  end if;

  update public.profiles p
  set total_meals_logged = counts.meal_count,
      updated_at = now()
  from (
    select count(*)::integer as meal_count
    from public.meal_history mh
    where mh.user_id = v_actor
  ) counts
  where p.user_id = v_actor;

  if v_old_calories + v_old_protein + v_old_carbs + v_old_fat + v_old_fiber = 0
    and v_new_calories + v_new_protein + v_new_carbs + v_new_fat + v_new_fiber > 0 then
    perform public.award_xp(
      v_actor,
      10,
      'Delivered meal logged',
      'delivered_meal_log',
      v_consumption_id::text,
      jsonb_build_object(
        'consumption_id', v_consumption_id,
        'source_type', v_source_type,
        'source_id', p_source_id,
        'source_meal_id', p_source_meal_id
      )
    );
  end if;

  v_current_state := jsonb_build_object(
    'status', v_status,
    'portion_percent', p_portion_percent,
    'portion', v_portion,
    'substitute_meal_id', p_substitute_meal_id,
    'log_date', v_log_date
  );

  v_result := jsonb_build_object(
    'success', true,
    'already_processed', false,
    'consumption_id', v_consumption_id,
    'meal_history_id', v_history_id,
    'event_version', v_event_version,
    'event_type', v_event_type,
    'semantic_idempotency_key', v_semantic_key,
    'status', v_status,
    'portion_percent', p_portion_percent,
    'portion', v_portion,
    'nutrition', jsonb_build_object(
      'calories', v_new_calories,
      'protein_g', v_new_protein,
      'carbs_g', v_new_carbs,
      'fat_g', v_new_fat,
      'fiber_g', v_new_fiber
    )
  );

  insert into public.meal_consumption_events (
    consumption_id, user_id, request_id, event_version, previous_state,
    current_state, nutrition_delta, result_snapshot,
    source_type, source_id, source_meal_id, event_type, semantic_idempotency_key
  ) values (
    v_consumption_id,
    v_actor,
    p_request_id,
    v_event_version,
    v_previous_state,
    v_current_state,
    jsonb_build_object(
      'calories', v_new_calories - v_old_calories,
      'protein_g', v_new_protein - v_old_protein,
      'carbs_g', v_new_carbs - v_old_carbs,
      'fat_g', v_new_fat - v_old_fat,
      'fiber_g', v_new_fiber - v_old_fiber
    ),
    v_result,
    v_source_type,
    p_source_id,
    p_source_meal_id,
    v_event_type,
    v_semantic_key
  );

  update public.notifications
  set status = 'read',
      read_at = coalesce(read_at, now())
  where user_id = v_actor
    and type::text = 'order_delivered'
    and related_entity_id = p_source_id
    and data ->> 'meal_id' = p_source_meal_id::text;

  if v_new_calories + v_new_protein + v_new_carbs + v_new_fat + v_new_fiber > 0 then
    perform public.check_and_award_badges(v_actor);
  end if;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."record_order_meal_consumption"("p_source_type" "text", "p_source_id" "uuid", "p_source_meal_id" "uuid", "p_status" "text", "p_portion_percent" numeric, "p_substitute_meal_id" "uuid", "p_request_id" "uuid") OWNER TO "postgres";

--
-- Name: record_sadad_payment_status("uuid", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_sadad_payment_status"("p_payment_id" "uuid", "p_status" "text", "p_gateway_response" "jsonb") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF p_status NOT IN ('processing', 'failed') THEN
    RAISE EXCEPTION 'PAYMENT_STATUS_INVALID';
  END IF;

  UPDATE public.payments
  SET status = p_status,
      gateway_response = COALESCE(p_gateway_response, '{}'::JSONB),
      failed_at = CASE WHEN p_status = 'failed' THEN NOW() ELSE failed_at END,
      updated_at = NOW()
  WHERE id = p_payment_id
    AND status <> 'completed';

  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."record_sadad_payment_status"("p_payment_id" "uuid", "p_status" "text", "p_gateway_response" "jsonb") OWNER TO "postgres";

