-- Name: reject_friend_request("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reject_friend_request"("p_friendship_id" "uuid", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_user_id);
  RETURN public.reject_friend_request_trusted(p_friendship_id, p_user_id);
END;
$$;


ALTER FUNCTION "public"."reject_friend_request"("p_friendship_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: reject_friend_request_trusted("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reject_friend_request_trusted"("p_friendship_id" "uuid", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  UPDATE friendships
  SET status = 'rejected', updated_at = NOW()
  WHERE id = p_friendship_id
    AND target_id = p_user_id
    AND status = 'pending';

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'No pending request found');
  END IF;

  RETURN jsonb_build_object('success', true, 'message', 'Friend request rejected');
END;
$$;


ALTER FUNCTION "public"."reject_friend_request_trusted"("p_friendship_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

