--
-- Name: remove_friend_trusted("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."remove_friend_trusted"("p_friendship_id" "uuid", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  DELETE FROM friendships
  WHERE id = p_friendship_id
    AND (requester_id = p_user_id OR target_id = p_user_id)
    AND status = 'accepted';

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Friendship not found');
  END IF;

  RETURN jsonb_build_object('success', true, 'message', 'Friend removed');
END;
$$;


