-- Name: FUNCTION "request_coach_withdrawal"("p_request_key" "uuid", "p_amount" numeric, "p_bank_name" "text", "p_iban" "text", "p_account_holder" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

