--
-- Name: request_driver_payout("uuid", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."request_driver_payout"("p_request_key" "uuid", "p_bank_name" "text", "p_account_number" "text", "p_account_name" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_driver_id UUID;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;

  SELECT d.id INTO v_driver_id
  FROM public.drivers d
  WHERE d.user_id = v_actor;

  IF v_driver_id IS NULL THEN
    RAISE EXCEPTION 'DRIVER_NOT_FOUND';
  END IF;

  RETURN public.reserve_driver_payout(
    v_driver_id,
    p_request_key,
    date_trunc('month', CURRENT_DATE)::DATE,
    CURRENT_DATE,
    jsonb_build_object(
      'bankName', trim(p_bank_name),
      'accountNumber', trim(p_account_number),
      'accountName', trim(p_account_name)
    ),
    v_actor
  );
END;
$$;


