--
-- Name: featured_listings; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."featured_listings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "restaurant_id" "uuid" NOT NULL,
    "package_type" "text" NOT NULL,
    "price_paid" numeric NOT NULL,
    "starts_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "ends_at" timestamp with time zone NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "payment_reference" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "featured_listings_package_type_check" CHECK (("package_type" = ANY (ARRAY['weekly'::"text", 'biweekly'::"text", 'monthly'::"text"]))),
    CONSTRAINT "featured_listings_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'active'::"text", 'expired'::"text", 'cancelled'::"text"])))
);


ALTER TABLE "public"."featured_listings" OWNER TO "postgres";

--
-- Name: request_featured_listing("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."request_featured_listing"("p_package_type" "text") RETURNS "public"."featured_listings"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_restaurant_id UUID;
  v_prices JSONB;
  v_price NUMERIC;
  v_duration_days INTEGER;
  v_listing public.featured_listings;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;

  IF p_package_type NOT IN ('weekly', 'biweekly', 'monthly') THEN
    RAISE EXCEPTION 'FEATURED_PACKAGE_INVALID';
  END IF;

  SELECT id
  INTO v_restaurant_id
  FROM public.restaurants
  WHERE owner_id = v_user_id
  ORDER BY created_at
  LIMIT 1;

  IF v_restaurant_id IS NULL THEN
    RAISE EXCEPTION 'RESTAURANT_NOT_FOUND';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.featured_listings
    WHERE restaurant_id = v_restaurant_id
      AND (
        status = 'pending'
        OR (status = 'active' AND ends_at > now())
      )
  ) THEN
    RAISE EXCEPTION 'FEATURED_LISTING_ALREADY_OPEN';
  END IF;

  SELECT value
  INTO v_prices
  FROM public.platform_settings
  WHERE key = 'featured_listing_prices';

  v_price := CASE p_package_type
    WHEN 'weekly' THEN COALESCE((v_prices ->> 'weekly')::NUMERIC, 49)
    WHEN 'biweekly' THEN COALESCE((v_prices ->> 'biweekly')::NUMERIC, 89)
    WHEN 'monthly' THEN COALESCE((v_prices ->> 'monthly')::NUMERIC, 149)
  END;

  v_duration_days := CASE p_package_type
    WHEN 'weekly' THEN 7
    WHEN 'biweekly' THEN 14
    WHEN 'monthly' THEN 30
  END;

  INSERT INTO public.featured_listings (
    restaurant_id,
    package_type,
    price_paid,
    starts_at,
    ends_at,
    status,
    payment_reference
  )
  VALUES (
    v_restaurant_id,
    p_package_type,
    v_price,
    now(),
    now() + make_interval(days => v_duration_days),
    'pending',
    NULL
  )
  RETURNING * INTO v_listing;

  RETURN v_listing;
END;
$$;


ALTER FUNCTION "public"."request_featured_listing"("p_package_type" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "request_featured_listing"("p_package_type" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."request_featured_listing"("p_package_type" "text") IS 'Creates a server-priced pending featured placement request. It never activates a placement or records unverified revenue.';


--
-- Name: request_partner_payout("uuid", "uuid", "date", "date", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."request_partner_payout"("p_restaurant_id" "uuid", "p_request_key" "uuid", "p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date", "p_request_source" "text" DEFAULT 'partner'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_is_admin BOOLEAN;
  v_existing public.partner_payouts%ROWTYPE;
  v_amount NUMERIC(10, 2);
  v_start DATE;
  v_end DATE;
  v_threshold NUMERIC := 50;
  v_bank JSONB;
  v_payout_id UUID;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;

  v_is_admin := public.has_role(v_actor, 'admin');

  IF NOT v_is_admin AND NOT EXISTS (
    SELECT 1
    FROM public.restaurants r
    WHERE r.id = p_restaurant_id
      AND r.owner_id = v_actor
  ) THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  IF p_request_key IS NULL
    OR p_request_source NOT IN ('partner', 'admin')
    OR (NOT v_is_admin AND p_request_source <> 'partner')
    OR (p_period_start IS NOT NULL AND p_period_end IS NOT NULL AND p_period_start > p_period_end) THEN
    RAISE EXCEPTION 'INVALID_PAYOUT_REQUEST';
  END IF;

  SELECT *
  INTO v_existing
  FROM public.partner_payouts
  WHERE request_key = p_request_key;

  IF FOUND THEN
    IF v_existing.restaurant_id <> p_restaurant_id THEN
      RAISE EXCEPTION 'REQUEST_KEY_CONFLICT';
    END IF;

    RETURN jsonb_build_object(
      'success', true,
      'duplicate', true,
      'payout_id', v_existing.id,
      'status', v_existing.status,
      'amount', v_existing.amount
    );
  END IF;

  PERFORM 1
  FROM public.restaurants r
  WHERE r.id = p_restaurant_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'RESTAURANT_NOT_FOUND';
  END IF;

  PERFORM 1
  FROM public.partner_earnings pe
  WHERE pe.restaurant_id = p_restaurant_id
    AND pe.status = 'pending'
    AND pe.payout_id IS NULL
    AND (p_period_start IS NULL OR pe.created_at::DATE >= p_period_start)
    AND (p_period_end IS NULL OR pe.created_at::DATE <= p_period_end)
  FOR UPDATE;

  SELECT
    COALESCE(SUM(pe.net_amount), 0),
    COALESCE(MIN(pe.created_at)::DATE, COALESCE(p_period_start, CURRENT_DATE)),
    COALESCE(MAX(pe.created_at)::DATE, COALESCE(p_period_end, CURRENT_DATE))
  INTO v_amount, v_start, v_end
  FROM public.partner_earnings pe
  WHERE pe.restaurant_id = p_restaurant_id
    AND pe.status = 'pending'
    AND pe.payout_id IS NULL
    AND (p_period_start IS NULL OR pe.created_at::DATE >= p_period_start)
    AND (p_period_end IS NULL OR pe.created_at::DATE <= p_period_end);

  SELECT COALESCE((ps.value ->> 'minimum_partner_payout')::NUMERIC, 50)
  INTO v_threshold
  FROM public.platform_settings ps
  WHERE ps.key = 'partner_settings'
  ORDER BY ps.updated_at DESC
  LIMIT 1;

  v_threshold := COALESCE(v_threshold, 50);

  IF v_amount <= 0 OR (NOT v_is_admin AND v_amount < v_threshold) THEN
    RAISE EXCEPTION 'INSUFFICIENT_AVAILABLE_PARTNER_BALANCE';
  END IF;

  SELECT jsonb_build_object(
    'bank_name', rd.bank_name,
    'bank_account_name', rd.bank_account_name,
    'bank_account_number', rd.bank_account_number,
    'bank_iban', rd.bank_iban,
    'swift_code', rd.swift_code
  )
  INTO v_bank
  FROM public.restaurant_details rd
  WHERE rd.restaurant_id = p_restaurant_id;

  IF v_bank IS NULL OR COALESCE(v_bank ->> 'bank_name', '') = ''
    OR (
      COALESCE(v_bank ->> 'bank_iban', '') = ''
      AND COALESCE(v_bank ->> 'bank_account_number', '') = ''
    ) THEN
    RAISE EXCEPTION 'BANK_DETAILS_REQUIRED';
  END IF;

  INSERT INTO public.partner_payouts (
    restaurant_id,
    amount,
    period_start,
    period_end,
    status,
    payout_method,
    payout_details,
    request_key,
    request_source,
    requested_by
  )
  VALUES (
    p_restaurant_id,
    v_amount,
    COALESCE(p_period_start, v_start),
    COALESCE(p_period_end, v_end),
    'pending',
    'bank_transfer',
    v_bank,
    p_request_key,
    p_request_source,
    v_actor
  )
  RETURNING id INTO v_payout_id;

  UPDATE public.partner_earnings pe
  SET payout_id = v_payout_id,
      status = 'processing'
  WHERE pe.restaurant_id = p_restaurant_id
    AND pe.status = 'pending'
    AND pe.payout_id IS NULL
    AND (p_period_start IS NULL OR pe.created_at::DATE >= p_period_start)
    AND (p_period_end IS NULL OR pe.created_at::DATE <= p_period_end);

  RETURN jsonb_build_object(
    'success', true,
    'duplicate', false,
    'payout_id', v_payout_id,
    'status', 'pending',
    'amount', v_amount
  );
END;
$$;


ALTER FUNCTION "public"."request_partner_payout"("p_restaurant_id" "uuid", "p_request_key" "uuid", "p_period_start" "date", "p_period_end" "date", "p_request_source" "text") OWNER TO "postgres";

--
-- Name: request_subscription_freeze("uuid", "uuid", "date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."request_subscription_freeze"("p_user_id" "uuid", "p_subscription_id" "uuid", "p_freeze_start_date" "date", "p_freeze_end_date" "date") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_subscription public.subscriptions%ROWTYPE;
  v_freeze_days INTEGER;
  v_days_remaining INTEGER;
  v_cycle_start DATE;
  v_cycle_end DATE;
  v_freeze_id UUID;
BEGIN
  IF v_actor IS NULL OR p_user_id IS DISTINCT FROM v_actor THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  IF p_freeze_start_date < CURRENT_DATE + 1
    OR p_freeze_end_date < p_freeze_start_date THEN
    RETURN jsonb_build_object('success', false, 'error', 'Freeze must be scheduled at least 24 hours in advance');
  END IF;

  v_freeze_days := p_freeze_end_date - p_freeze_start_date + 1;
  IF v_freeze_days NOT BETWEEN 1 AND 7 THEN
    RETURN jsonb_build_object('success', false, 'error', 'A freeze can be 1 to 7 days');
  END IF;

  SELECT * INTO v_subscription
  FROM public.subscriptions s
  WHERE s.id = p_subscription_id
    AND s.user_id = v_actor
    AND s.status::TEXT = 'active'
    AND COALESCE(s.active, true) = true
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Active subscription not found');
  END IF;

  v_cycle_start := COALESCE(v_subscription.month_start_date, v_subscription.start_date, CURRENT_DATE);
  v_cycle_end := COALESCE(v_subscription.next_renewal_date, v_subscription.end_date, v_cycle_start + 30);

  IF p_freeze_start_date < v_cycle_start OR p_freeze_end_date > v_cycle_end THEN
    RETURN jsonb_build_object('success', false, 'error', 'Freeze period must be within the current billing cycle');
  END IF;

  v_days_remaining := 7 - COALESCE(v_subscription.freeze_days_used, 0);
  IF v_freeze_days > v_days_remaining THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', format('Only %s freeze days remain this cycle', GREATEST(v_days_remaining, 0))
    );
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.subscription_freezes sf
    WHERE sf.subscription_id = p_subscription_id
      AND sf.status IN ('scheduled', 'active')
      AND daterange(sf.freeze_start_date, sf.freeze_end_date, '[]')
        && daterange(p_freeze_start_date, p_freeze_end_date, '[]')
  ) THEN
    RETURN jsonb_build_object('success', false, 'error', 'Freeze period overlaps an existing freeze');
  END IF;

  INSERT INTO public.subscription_freezes (
    user_id,
    subscription_id,
    freeze_start_date,
    freeze_end_date,
    freeze_days,
    billing_cycle_start,
    billing_cycle_end,
    status
  )
  VALUES (
    v_actor,
    p_subscription_id,
    p_freeze_start_date,
    p_freeze_end_date,
    v_freeze_days,
    v_cycle_start,
    v_cycle_end,
    'scheduled'
  )
  RETURNING id INTO v_freeze_id;

  UPDATE public.subscriptions
  SET freeze_days_used = COALESCE(freeze_days_used, 0) + v_freeze_days,
      next_renewal_date = COALESCE(next_renewal_date, v_cycle_end) + v_freeze_days,
      end_date = COALESCE(end_date, v_cycle_end) + v_freeze_days,
      updated_at = now()
  WHERE id = p_subscription_id;

  RETURN jsonb_build_object(
    'success', true,
    'freeze_id', v_freeze_id,
    'freeze_days', v_freeze_days,
    'freeze_start', p_freeze_start_date,
    'freeze_end', p_freeze_end_date,
    'days_remaining_this_cycle', v_days_remaining - v_freeze_days
  );
END;
$$;


ALTER FUNCTION "public"."request_subscription_freeze"("p_user_id" "uuid", "p_subscription_id" "uuid", "p_freeze_start_date" "date", "p_freeze_end_date" "date") OWNER TO "postgres";

--
-- Name: reschedule_meal("uuid", "date", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reschedule_meal"("p_schedule_id" "uuid", "p_new_date" "date" DEFAULT NULL::"date", "p_new_meal_type" "text" DEFAULT NULL::"text", "p_new_time_slot" "text" DEFAULT NULL::"text") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_schedule public.meal_schedules%ROWTYPE;
  v_updates INTEGER := 0;
BEGIN
  SELECT * INTO v_schedule
  FROM public.meal_schedules
  WHERE id = p_schedule_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Schedule not found');
  END IF;
  IF auth.uid() IS NULL OR v_schedule.user_id <> auth.uid() THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authorized');
  END IF;
  IF v_schedule.order_status NOT IN ('pending', 'confirmed') THEN
    RETURN jsonb_build_object('success', false, 'error', 'This order can no longer be rescheduled');
  END IF;
  IF p_new_date IS NOT NULL AND p_new_date < CURRENT_DATE THEN
    RETURN jsonb_build_object('success', false, 'error', 'New date cannot be in the past');
  END IF;

  UPDATE public.meal_schedules
  SET scheduled_date = COALESCE(p_new_date, scheduled_date),
      meal_type = COALESCE(NULLIF(p_new_meal_type, ''), meal_type),
      delivery_time_slot = COALESCE(NULLIF(p_new_time_slot, ''), delivery_time_slot),
      updated_at = now()
  WHERE id = p_schedule_id
    AND (
      (p_new_date IS NOT NULL AND p_new_date IS DISTINCT FROM scheduled_date)
      OR (NULLIF(p_new_meal_type, '') IS NOT NULL AND p_new_meal_type IS DISTINCT FROM meal_type)
      OR (NULLIF(p_new_time_slot, '') IS NOT NULL AND p_new_time_slot IS DISTINCT FROM delivery_time_slot)
    );
  GET DIAGNOSTICS v_updates = ROW_COUNT;

  IF v_updates = 0 THEN
    RETURN jsonb_build_object('success', false, 'error', 'No changes provided');
  END IF;

  INSERT INTO public.notifications (user_id, type, title, message, status, data)
  VALUES (
    v_schedule.user_id, 'order_update', 'Meal Rescheduled',
    'Your meal schedule has been updated.', 'unread',
    jsonb_build_object('schedule_id', p_schedule_id, 'new_date', p_new_date,
      'new_meal_type', p_new_meal_type, 'new_time_slot', p_new_time_slot)
  );

  RETURN jsonb_build_object('success', true, 'updates', v_updates);
END;
$$;


ALTER FUNCTION "public"."reschedule_meal"("p_schedule_id" "uuid", "p_new_date" "date", "p_new_meal_type" "text", "p_new_time_slot" "text") OWNER TO "postgres";

--
-- Name: reserve_ai_coach_request("uuid", "uuid", integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reserve_ai_coach_request"("p_user_id" "uuid", "p_request_id" "uuid", "p_daily_limit" integer, "p_input_chars" integer DEFAULT 0) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_existing public.ai_coach_request_ledger%ROWTYPE;
  v_current_count integer;
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RAISE EXCEPTION 'SERVICE_ROLE_REQUIRED';
  END IF;
  IF p_user_id IS NULL OR p_request_id IS NULL THEN
    RAISE EXCEPTION 'AI_REQUEST_IDENTITY_REQUIRED';
  END IF;
  IF p_daily_limit NOT BETWEEN 1 AND 100
     OR p_input_chars NOT BETWEEN 0 AND 100000 THEN
    RAISE EXCEPTION 'INVALID_AI_BUDGET_REQUEST';
  END IF;

  PERFORM pg_advisory_xact_lock(
    hashtextextended(p_user_id::text || ':nutrition_coach:' || current_date::text, 0)
  );

  SELECT * INTO v_existing
  FROM public.ai_coach_request_ledger
  WHERE request_id = p_request_id;
  IF FOUND THEN
    IF v_existing.user_id <> p_user_id THEN
      RAISE EXCEPTION 'AI_REQUEST_ID_REUSE';
    END IF;
    RETURN jsonb_build_object(
      'allowed', v_existing.status IN ('reserved', 'completed'),
      'duplicate', true,
      'status', v_existing.status
    );
  END IF;

  SELECT count(*)::integer INTO v_current_count
  FROM public.ai_coach_request_ledger
  WHERE user_id = p_user_id
    AND created_at >= date_trunc('day', clock_timestamp())
    AND status IN ('reserved', 'completed');

  IF v_current_count >= p_daily_limit THEN
    INSERT INTO public.ai_coach_request_ledger (
      request_id, user_id, status, input_chars
    ) VALUES (p_request_id, p_user_id, 'rejected', p_input_chars);
    RETURN jsonb_build_object('allowed', false, 'duplicate', false, 'remaining', 0);
  END IF;

  INSERT INTO public.ai_coach_request_ledger (
    request_id, user_id, status, input_chars
  ) VALUES (p_request_id, p_user_id, 'reserved', p_input_chars);
  RETURN jsonb_build_object(
    'allowed', true,
    'duplicate', false,
    'remaining', p_daily_limit - v_current_count - 1
  );
END;
$$;


ALTER FUNCTION "public"."reserve_ai_coach_request"("p_user_id" "uuid", "p_request_id" "uuid", "p_daily_limit" integer, "p_input_chars" integer) OWNER TO "postgres";

--
-- Name: reserve_driver_payout("uuid", "uuid", "date", "date", "jsonb", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reserve_driver_payout"("p_driver_id" "uuid", "p_request_key" "uuid", "p_period_start" "date", "p_period_end" "date", "p_payout_details" "jsonb", "p_requested_by" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_driver public.drivers%ROWTYPE;
  v_existing public.driver_payouts%ROWTYPE;
  v_threshold NUMERIC := 10;
  v_payout_id UUID;
BEGIN
  SELECT * INTO v_existing
  FROM public.driver_payouts
  WHERE request_key = p_request_key;

  IF FOUND THEN
    IF v_existing.driver_id <> p_driver_id THEN
      RAISE EXCEPTION 'REQUEST_KEY_CONFLICT';
    END IF;

    RETURN jsonb_build_object(
      'success', true,
      'duplicate', true,
      'payout_id', v_existing.id,
      'status', v_existing.status,
      'amount', v_existing.amount
    );
  END IF;

  IF p_request_key IS NULL OR p_period_start > p_period_end THEN
    RAISE EXCEPTION 'INVALID_PAYOUT_REQUEST';
  END IF;

  IF COALESCE(p_payout_details ->> 'bankName', '') = ''
    OR COALESCE(p_payout_details ->> 'accountNumber', '') = ''
    OR COALESCE(p_payout_details ->> 'accountName', '') = '' THEN
    RAISE EXCEPTION 'BANK_DETAILS_REQUIRED';
  END IF;

  SELECT * INTO v_driver
  FROM public.drivers
  WHERE id = p_driver_id
  FOR UPDATE;

  IF NOT FOUND OR v_driver.approval_status::TEXT <> 'approved' OR NOT COALESCE(v_driver.is_active, false) THEN
    RAISE EXCEPTION 'ACTIVE_DRIVER_REQUIRED';
  END IF;

  SELECT COALESCE((ps.value ->> 'minimum_payout_threshold')::NUMERIC, 10)
  INTO v_threshold
  FROM public.platform_settings ps
  WHERE ps.key = 'driver_settings'
  ORDER BY ps.updated_at DESC
  LIMIT 1;

  v_threshold := COALESCE(v_threshold, 10);

  IF COALESCE(v_driver.wallet_balance, 0) < v_threshold THEN
    RAISE EXCEPTION 'MINIMUM_PAYOUT_NOT_REACHED';
  END IF;

  INSERT INTO public.driver_payouts (
    driver_id,
    amount,
    period_start,
    period_end,
    status,
    payout_method,
    payout_details,
    request_key,
    requested_by
  )
  VALUES (
    p_driver_id,
    v_driver.wallet_balance,
    p_period_start,
    p_period_end,
    'pending',
    'bank_transfer',
    p_payout_details,
    p_request_key,
    p_requested_by
  )
  RETURNING id INTO v_payout_id;

  PERFORM set_config('app.driver_finance_authorized', 'true', true);

  UPDATE public.drivers
  SET wallet_balance = 0,
      payout_details = p_payout_details,
      updated_at = now()
  WHERE id = p_driver_id;

  INSERT INTO public.driver_wallet_transactions (
    driver_id,
    type,
    amount,
    balance_after,
    reference_type,
    reference_id,
    description
  )
  VALUES (
    p_driver_id,
    'withdrawal',
    v_driver.wallet_balance,
    0,
    'withdrawal',
    v_payout_id,
    'Driver payout reserved'
  );

  RETURN jsonb_build_object(
    'success', true,
    'duplicate', false,
    'payout_id', v_payout_id,
    'status', 'pending',
    'amount', v_driver.wallet_balance
  );
END;
$$;


ALTER FUNCTION "public"."reserve_driver_payout"("p_driver_id" "uuid", "p_request_key" "uuid", "p_period_start" "date", "p_period_end" "date", "p_payout_details" "jsonb", "p_requested_by" "uuid") OWNER TO "postgres";

--
-- Name: reset_daily_capacity_counts(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reset_daily_capacity_counts"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
    UPDATE public.restaurants
    SET 
        current_day_orders = 0,
        daily_reset_at = NOW()
    WHERE daily_reset_at < date_trunc('day', NOW());
    
    RAISE NOTICE 'Reset daily capacity for % restaurants', 
        (SELECT COUNT(*) FROM public.restaurants WHERE daily_reset_at >= date_trunc('day', NOW()));
END;
$$;


ALTER FUNCTION "public"."reset_daily_capacity_counts"() OWNER TO "postgres";

--
-- Name: reset_weekly_meal_quotas(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reset_weekly_meal_quotas"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_reset_count INTEGER;
BEGIN
  UPDATE public.subscriptions
  SET 
    meals_used_this_week = 0,
    week_start_date = CURRENT_DATE
  WHERE status = 'active'
    AND (
      week_start_date IS NULL 
      OR week_start_date < CURRENT_DATE - INTERVAL '6 days'
    );
  
  GET DIAGNOSTICS v_reset_count = ROW_COUNT;
  
  -- Log the reset
  INSERT INTO public.platform_logs (level, category, message, metadata)
  VALUES (
    'info',
    'subscription',
    format('Weekly meal quotas reset for %s subscriptions', v_reset_count),
    jsonb_build_object('reset_count', v_reset_count, 'reset_date', CURRENT_DATE)
  );
  
  RETURN v_reset_count;
END;
$$;


ALTER FUNCTION "public"."reset_weekly_meal_quotas"() OWNER TO "postgres";

--
-- Name: resolve_weekly_ai_check_in("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."resolve_weekly_ai_check_in"("p_check_in_id" "uuid", "p_decision" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_user_id UUID := (SELECT auth.uid());
  v_check_in public.weekly_ai_check_ins%ROWTYPE;
  v_adjustment public.goal_adjustment_history%ROWTYPE;
  v_goal public.nutrition_goals%ROWTYPE;
  v_now TIMESTAMPTZ := now();
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;
  IF p_decision NOT IN ('apply', 'dismiss') THEN
    RAISE EXCEPTION 'INVALID_WEEKLY_CHECK_IN_DECISION';
  END IF;

  SELECT * INTO v_check_in
  FROM public.weekly_ai_check_ins
  WHERE id = p_check_in_id
    AND user_id = v_user_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'WEEKLY_CHECK_IN_NOT_FOUND';
  END IF;
  IF v_check_in.status <> 'reviewed' THEN
    RETURN jsonb_build_object('status', v_check_in.status, 'already_resolved', true);
  END IF;

  IF p_decision = 'dismiss' THEN
    UPDATE public.weekly_ai_check_ins
    SET status = 'dismissed', resolved_at = v_now, updated_at = v_now
    WHERE id = v_check_in.id;

    UPDATE public.profiles
    SET has_unviewed_adjustment = false
    WHERE user_id = v_user_id;

    RETURN jsonb_build_object('status', 'dismissed', 'already_resolved', false);
  END IF;

  IF v_check_in.adjustment_id IS NULL THEN
    UPDATE public.weekly_ai_check_ins
    SET status = 'applied', resolved_at = v_now, updated_at = v_now
    WHERE id = v_check_in.id;
    RETURN jsonb_build_object('status', 'applied', 'changed', false);
  END IF;

  SELECT * INTO v_adjustment
  FROM public.goal_adjustment_history
  WHERE id = v_check_in.adjustment_id
    AND user_id = v_user_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'ADJUSTMENT_NOT_FOUND';
  END IF;

  SELECT * INTO v_goal
  FROM public.nutrition_goals
  WHERE user_id = v_user_id AND is_active = true
  ORDER BY created_at DESC
  LIMIT 1
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'ACTIVE_NUTRITION_GOAL_NOT_FOUND';
  END IF;

  UPDATE public.nutrition_goals
  SET daily_calorie_target = v_adjustment.new_calories,
      protein_target_g = COALESCE((v_adjustment.new_macros ->> 'protein')::INTEGER, protein_target_g),
      carbs_target_g = COALESCE((v_adjustment.new_macros ->> 'carbs')::INTEGER, carbs_target_g),
      fat_target_g = COALESCE((v_adjustment.new_macros ->> 'fat')::INTEGER, fat_target_g),
      calculation_source = 'weekly_ai_check_in',
      reason = v_adjustment.reason,
      version = COALESCE(version, 1) + 1,
      updated_at = v_now
  WHERE id = v_goal.id;

  UPDATE public.profiles
  SET daily_calorie_target = v_adjustment.new_calories,
      protein_target_g = COALESCE((v_adjustment.new_macros ->> 'protein')::INTEGER, protein_target_g),
      carbs_target_g = COALESCE((v_adjustment.new_macros ->> 'carbs')::INTEGER, carbs_target_g),
      fat_target_g = COALESCE((v_adjustment.new_macros ->> 'fat')::INTEGER, fat_target_g),
      last_goal_adjustment_date = CURRENT_DATE,
      has_unviewed_adjustment = false
  WHERE user_id = v_user_id;

  UPDATE public.goal_adjustment_history
  SET applied = true
  WHERE id = v_adjustment.id;

  INSERT INTO public.nutrition_goal_events (
    user_id, goal_id, event_type, previous_values, new_values, reason
  ) VALUES (
    v_user_id,
    v_goal.id,
    'smart_adjusted',
    jsonb_build_object(
      'daily_calorie_target', v_goal.daily_calorie_target,
      'protein_target_g', v_goal.protein_target_g,
      'carbs_target_g', v_goal.carbs_target_g,
      'fat_target_g', v_goal.fat_target_g
    ),
    v_check_in.proposed_targets,
    v_adjustment.reason
  );

  UPDATE public.weekly_ai_check_ins
  SET status = 'applied', resolved_at = v_now, updated_at = v_now
  WHERE id = v_check_in.id;

  RETURN jsonb_build_object('status', 'applied', 'changed', true);
END;
$$;


ALTER FUNCTION "public"."resolve_weekly_ai_check_in"("p_check_in_id" "uuid", "p_decision" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "resolve_weekly_ai_check_in"("p_check_in_id" "uuid", "p_decision" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."resolve_weekly_ai_check_in"("p_check_in_id" "uuid", "p_decision" "text") IS 'Atomically applies or dismisses a weekly macro recommendation for the authenticated user.';


--
-- Name: resume_subscription("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."resume_subscription"("p_subscription_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
BEGIN
  IF v_actor IS NULL THEN
    RETURN false;
  END IF;

  UPDATE public.subscriptions s
  SET status = 'active',
      active = true,
      resumed_at = now(),
      pause_until = NULL,
      updated_at = now()
  WHERE s.id = p_subscription_id
    AND s.user_id = v_actor
    AND s.status::TEXT = 'pending'
    AND s.freeze_active_id IS NULL
    AND (s.pause_until IS NULL OR s.pause_until <= CURRENT_DATE)
    AND COALESCE(s.end_date, CURRENT_DATE) >= CURRENT_DATE;

  RETURN FOUND;
END;
$$;


ALTER FUNCTION "public"."resume_subscription"("p_subscription_id" "uuid") OWNER TO "postgres";

--
-- Name: retry_failed_payment("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."retry_failed_payment"("p_payment_id" "uuid", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_payment RECORD;
    v_result JSONB;
BEGIN
    SELECT * INTO v_payment
    FROM payments
    WHERE id = p_payment_id AND user_id = p_user_id AND status = 'failed' AND wallet_credited = false;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Payment not found or not in failed state', 'code', 'NOT_FOUND');
    END IF;

    SELECT process_payment_atomic(p_payment_id, p_user_id, v_payment.amount, v_payment.gateway,
        v_payment.gateway_reference, COALESCE(v_payment.description, 'Retry of failed payment')) INTO v_result;

    IF (v_result->>'success')::BOOLEAN THEN
        UPDATE payment_processing_errors
        SET resolved_at = NOW(), resolution_notes = 'Automatically resolved via retry'
        WHERE payment_id = p_payment_id AND resolved_at IS NULL;
    END IF;

    RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."retry_failed_payment"("p_payment_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: retry_verified_payment_fulfillment("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."retry_verified_payment_fulfillment"("p_payment_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_payment public.payments%ROWTYPE;
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role'
    AND NOT public.has_role(v_actor, 'admin') THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;

  SELECT *
    INTO v_payment
  FROM public.payments p
  WHERE p.id = p_payment_id
    AND p.status = 'completed'
    AND p.verified_at IS NOT NULL
    AND p.provider_transaction_id IS NOT NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'VERIFIED_PAYMENT_NOT_FOUND';
  END IF;

  RETURN public.finalize_verified_sadad_payment(
    v_payment.id,
    v_payment.provider_transaction_id,
    COALESCE(v_payment.gateway_response, '{}'::JSONB)
  );
END;
$$;


ALTER FUNCTION "public"."retry_verified_payment_fulfillment"("p_payment_id" "uuid") OWNER TO "postgres";

--
-- Name: reverse_community_challenge_wallet_reward("uuid", "uuid", integer, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reverse_community_challenge_wallet_reward"("p_user_id" "uuid", "p_participant_id" "uuid", "p_completion_version" integer, "p_reason" "text" DEFAULT 'Challenge evidence no longer qualifies'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_settlement public.community_challenge_reward_settlements%ROWTYPE;
  v_wallet public.customer_wallets%ROWTYPE;
  v_debit_amount NUMERIC(10, 2) := 0;
  v_pending_recovery NUMERIC(10, 2) := 0;
  v_reversal_transaction_id UUID;
BEGIN
  PERFORM pg_advisory_xact_lock(
    hashtextextended(
      'challenge-wallet-reversal:' || p_user_id::TEXT || ':' || p_participant_id::TEXT || ':' || p_completion_version::TEXT,
      0
    )
  );

  SELECT * INTO v_settlement
  FROM public.community_challenge_reward_settlements
  WHERE participant_id = p_participant_id
    AND completion_version = p_completion_version
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', true, 'missing_settlement', true);
  END IF;

  IF v_settlement.status = 'reversed' THEN
    RETURN jsonb_build_object(
      'success', true,
      'duplicate', true,
      'debited_amount', v_settlement.reversed_debit_amount,
      'pending_recovery', v_settlement.pending_recovery_amount
    );
  END IF;

  SELECT * INTO v_wallet
  FROM public.customer_wallets
  WHERE user_id = p_user_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'WALLET_NOT_FOUND';
  END IF;

  v_debit_amount := least(coalesce(v_wallet.balance, 0), v_settlement.credited_amount);
  v_pending_recovery := greatest(v_settlement.gross_amount - v_debit_amount, 0);

  UPDATE public.customer_wallets
  SET balance = greatest(coalesce(balance, 0) - v_debit_amount, 0),
      total_debits = coalesce(total_debits, 0) + v_debit_amount,
      reward_adjustment_due = coalesce(reward_adjustment_due, 0) + v_pending_recovery,
      updated_at = now()
  WHERE id = v_wallet.id;

  IF v_debit_amount > 0 THEN
    INSERT INTO public.wallet_transactions (
      wallet_id,
      user_id,
      type,
      amount,
      balance_after,
      reference_type,
      reference_id,
      description,
      metadata,
      idempotency_key
    ) VALUES (
      v_wallet.id,
      p_user_id,
      'debit',
      v_debit_amount,
      greatest(coalesce(v_wallet.balance, 0) - v_debit_amount, 0),
      'community_challenge',
      v_settlement.challenge_id,
      coalesce(p_reason, 'Challenge reward reversed'),
      jsonb_build_object(
        'source_key', v_settlement.source_key,
        'compensates_wallet_transaction_id', v_settlement.wallet_transaction_id,
        'gross_amount', v_settlement.gross_amount,
        'debited_amount', v_debit_amount,
        'pending_recovery', v_pending_recovery
      ),
      'challenge-reversal:' || p_user_id::TEXT || ':' || v_settlement.source_key
    )
    RETURNING id INTO v_reversal_transaction_id;
  END IF;

  UPDATE public.reward_transactions
  SET status = 'expired',
      metadata = coalesce(metadata, '{}'::JSONB) || jsonb_build_object(
        'reversed_at', now(),
        'reversal_transaction_id', v_reversal_transaction_id,
        'pending_recovery', v_pending_recovery
      )
  WHERE id = v_settlement.reward_transaction_id;

  UPDATE public.community_challenge_reward_settlements
  SET status = 'reversed',
      reversed_debit_amount = v_debit_amount,
      pending_recovery_amount = v_pending_recovery,
      wallet_reversal_transaction_id = v_reversal_transaction_id,
      reversed_at = now(),
      metadata = metadata || jsonb_build_object('reversal_reason', p_reason)
  WHERE id = v_settlement.id;

  UPDATE public.challenge_participants
  SET reward_wallet_pending_recovery = v_pending_recovery,
      reward_wallet_reversal_transaction_id = v_reversal_transaction_id,
      reward_wallet_reversed_at = now(),
      updated_at = now()
  WHERE id = p_participant_id;

  RETURN jsonb_build_object(
    'success', true,
    'duplicate', false,
    'debited_amount', v_debit_amount,
    'pending_recovery', v_pending_recovery,
    'wallet_reversal_transaction_id', v_reversal_transaction_id
  );
END;
$$;


ALTER FUNCTION "public"."reverse_community_challenge_wallet_reward"("p_user_id" "uuid", "p_participant_id" "uuid", "p_completion_version" integer, "p_reason" "text") OWNER TO "postgres";

--
-- Name: reverse_deleted_meal_fiber(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reverse_deleted_meal_fiber"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  UPDATE public.progress_logs
  SET fiber_consumed_g = GREATEST(0, COALESCE(fiber_consumed_g, 0) - COALESCE(OLD.fiber_g, 0)),
      updated_at = NOW()
  WHERE user_id = OLD.user_id
    AND log_date = (COALESCE(OLD.logged_at, OLD.created_at, NOW()) AT TIME ZONE 'Asia/Qatar')::DATE;
  RETURN OLD;
END;
$$;


ALTER FUNCTION "public"."reverse_deleted_meal_fiber"() OWNER TO "postgres";

--
-- Name: revoke_wearable_provider("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."revoke_wearable_provider"("p_provider" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_dates date[];
  v_metric_date date;
  v_deleted integer := 0;
begin
  if v_user_id is null then
    raise exception 'AUTH_REQUIRED' using errcode = '42501';
  end if;

  select coalesce(array_agg(distinct metric_date), '{}')
  into v_dates
  from public.wearable_metric_samples
  where user_id = v_user_id
    and provider = p_provider
    and deleted_at is null;

  update public.wearable_metric_samples
  set deleted_at = now(),
      sync_status = 'revoked',
      updated_at = now()
  where user_id = v_user_id
    and provider = p_provider
    and deleted_at is null;

  get diagnostics v_deleted = row_count;

  perform public.upsert_wearable_sync_state(
    p_provider,
    'revoked',
    jsonb_build_object('revokedAt', now()),
    null
  );

  for v_metric_date in select unnest(v_dates)
  loop
    perform public.rebuild_health_daily_metrics_from_wearables(v_user_id, v_metric_date);
  end loop;

  return jsonb_build_object('ok', true, 'revoked_samples', v_deleted);
end;
$$;


ALTER FUNCTION "public"."revoke_wearable_provider"("p_provider" "text") OWNER TO "postgres";

--
-- Name: route_meal_schedule_branch("uuid", "uuid", "uuid", "date", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."route_meal_schedule_branch"("p_restaurant_id" "uuid", "p_meal_id" "uuid", "p_delivery_address_id" "uuid", "p_scheduled_date" "date", "p_delivery_time_slot" "text", "p_meal_type" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_address public.user_addresses%ROWTYPE;
  v_selected RECORD;
  v_candidates JSONB := '[]'::JSONB;
  v_has_branches BOOLEAN := FALSE;
BEGIN
  IF p_restaurant_id IS NULL THEN
    RETURN jsonb_build_object(
      'status', 'manual_review',
      'branch_id', NULL,
      'reason', 'restaurant_missing',
      'candidates', '[]'::JSONB
    );
  END IF;

  IF p_delivery_address_id IS NOT NULL THEN
    SELECT *
      INTO v_address
    FROM public.user_addresses ua
    WHERE ua.id = p_delivery_address_id
      AND (v_user_id IS NULL OR ua.user_id = v_user_id);
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM public.restaurant_branches rb
    WHERE rb.restaurant_id = p_restaurant_id
      AND COALESCE(rb.is_active, TRUE) = TRUE
  ) INTO v_has_branches;

  IF NOT v_has_branches THEN
    RETURN jsonb_build_object(
      'status', 'single_kitchen',
      'branch_id', NULL,
      'reason', 'restaurant_has_no_active_branches',
      'candidates', '[]'::JSONB
    );
  END IF;

  WITH branch_load AS (
    SELECT
      rb.id,
      rb.name,
      rb.address,
      rb.latitude,
      rb.longitude,
      rb.is_accepting_orders,
      rb.max_orders_per_slot,
      rb.service_radius_km,
      rb.avg_prep_time_minutes,
      rb.routing_priority,
      public.haversine_km(
        v_address.latitude::NUMERIC,
        v_address.longitude::NUMERIC,
        rb.latitude::NUMERIC,
        rb.longitude::NUMERIC
      ) AS distance_km,
      COUNT(ms.id)::INTEGER AS slot_load
    FROM public.restaurant_branches rb
    LEFT JOIN public.meal_schedules ms
      ON ms.restaurant_branch_id = rb.id
     AND ms.scheduled_date = p_scheduled_date
     AND COALESCE(ms.delivery_time_slot, '') = COALESCE(p_delivery_time_slot, '')
     AND COALESCE(ms.order_status, 'pending') NOT IN ('cancelled', 'rejected')
    WHERE rb.restaurant_id = p_restaurant_id
      AND COALESCE(rb.is_active, TRUE) = TRUE
    GROUP BY rb.id
  ),
  scored AS (
    SELECT
      bl.*,
      GREATEST(bl.max_orders_per_slot - bl.slot_load, 0) AS remaining_capacity,
      (
        COALESCE(bl.routing_priority, 0) * 10
        - COALESCE(bl.distance_km, 6) * 2
        - (bl.slot_load::NUMERIC / GREATEST(bl.max_orders_per_slot, 1)) * 25
        - COALESCE(bl.avg_prep_time_minutes, 20) * 0.05
      )::NUMERIC(12, 4) AS route_score,
      (
        COALESCE(bl.is_accepting_orders, TRUE) = TRUE
        AND bl.slot_load < bl.max_orders_per_slot
        AND (
          bl.distance_km IS NULL
          OR bl.distance_km <= bl.service_radius_km
        )
      ) AS eligible
    FROM branch_load bl
  )
  SELECT jsonb_agg(
    jsonb_build_object(
      'branch_id', id,
      'name', name,
      'eligible', eligible,
      'score', route_score,
      'distance_km', distance_km,
      'slot_load', slot_load,
      'max_orders_per_slot', max_orders_per_slot,
      'remaining_capacity', remaining_capacity,
      'service_radius_km', service_radius_km,
      'is_accepting_orders', is_accepting_orders,
      'avg_prep_time_minutes', avg_prep_time_minutes
    )
    ORDER BY eligible DESC, route_score DESC, distance_km ASC NULLS LAST, name ASC
  )
    INTO v_candidates
  FROM scored;

  WITH branch_load AS (
    SELECT
      rb.id,
      rb.name,
      rb.latitude,
      rb.longitude,
      rb.is_accepting_orders,
      rb.max_orders_per_slot,
      rb.service_radius_km,
      rb.avg_prep_time_minutes,
      rb.routing_priority,
      public.haversine_km(
        v_address.latitude::NUMERIC,
        v_address.longitude::NUMERIC,
        rb.latitude::NUMERIC,
        rb.longitude::NUMERIC
      ) AS distance_km,
      COUNT(ms.id)::INTEGER AS slot_load
    FROM public.restaurant_branches rb
    LEFT JOIN public.meal_schedules ms
      ON ms.restaurant_branch_id = rb.id
     AND ms.scheduled_date = p_scheduled_date
     AND COALESCE(ms.delivery_time_slot, '') = COALESCE(p_delivery_time_slot, '')
     AND COALESCE(ms.order_status, 'pending') NOT IN ('cancelled', 'rejected')
    WHERE rb.restaurant_id = p_restaurant_id
      AND COALESCE(rb.is_active, TRUE) = TRUE
    GROUP BY rb.id
  ),
  scored AS (
    SELECT
      bl.*,
      GREATEST(bl.max_orders_per_slot - bl.slot_load, 0) AS remaining_capacity,
      (
        COALESCE(bl.routing_priority, 0) * 10
        - COALESCE(bl.distance_km, 6) * 2
        - (bl.slot_load::NUMERIC / GREATEST(bl.max_orders_per_slot, 1)) * 25
        - COALESCE(bl.avg_prep_time_minutes, 20) * 0.05
      )::NUMERIC(12, 4) AS route_score,
      (
        COALESCE(bl.is_accepting_orders, TRUE) = TRUE
        AND bl.slot_load < bl.max_orders_per_slot
        AND (
          bl.distance_km IS NULL
          OR bl.distance_km <= bl.service_radius_km
        )
      ) AS eligible
    FROM branch_load bl
  )
  SELECT *
    INTO v_selected
  FROM scored
  WHERE eligible = TRUE
  ORDER BY route_score DESC, distance_km ASC NULLS LAST, name ASC
  LIMIT 1;

  IF FOUND THEN
    RETURN jsonb_build_object(
      'status', 'routed',
      'branch_id', v_selected.id,
      'branch_name', v_selected.name,
      'score', v_selected.route_score,
      'reason', CASE
        WHEN v_selected.distance_km IS NULL THEN 'best_capacity_no_coordinates'
        ELSE 'best_distance_capacity_score'
      END,
      'distance_km', v_selected.distance_km,
      'slot_load', v_selected.slot_load,
      'remaining_capacity', v_selected.remaining_capacity,
      'meal_id', p_meal_id,
      'meal_type', p_meal_type,
      'candidates', COALESCE(v_candidates, '[]'::JSONB),
      'routed_at', now()
    );
  END IF;

  RETURN jsonb_build_object(
    'status', 'manual_review',
    'branch_id', NULL,
    'reason', 'no_branch_with_capacity_or_service_radius',
    'meal_id', p_meal_id,
    'meal_type', p_meal_type,
    'candidates', COALESCE(v_candidates, '[]'::JSONB),
    'routed_at', now()
  );
END;
$$;


ALTER FUNCTION "public"."route_meal_schedule_branch"("p_restaurant_id" "uuid", "p_meal_id" "uuid", "p_delivery_address_id" "uuid", "p_scheduled_date" "date", "p_delivery_time_slot" "text", "p_meal_type" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "route_meal_schedule_branch"("p_restaurant_id" "uuid", "p_meal_id" "uuid", "p_delivery_address_id" "uuid", "p_scheduled_date" "date", "p_delivery_time_slot" "text", "p_meal_type" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."route_meal_schedule_branch"("p_restaurant_id" "uuid", "p_meal_id" "uuid", "p_delivery_address_id" "uuid", "p_scheduled_date" "date", "p_delivery_time_slot" "text", "p_meal_type" "text") IS 'Routes a meal schedule to the best restaurant branch using distance, slot capacity, branch availability, load, and routing priority.';


--
-- Name: save_meal_menu_offerings("uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."save_meal_menu_offerings"("p_meal_id" "uuid", "p_offerings" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $_$
DECLARE
  v_user_id UUID := auth.uid();
  v_count INTEGER;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'AUTHENTICATION_REQUIRED'; END IF;
  IF jsonb_typeof(p_offerings) <> 'array' OR jsonb_array_length(p_offerings) > 4 THEN
    RAISE EXCEPTION 'MENU_OFFERINGS_INVALID';
  END IF;
  IF NOT EXISTS (
    SELECT 1
    FROM public.meals m
    JOIN public.restaurants r ON r.id = m.restaurant_id
    WHERE m.id = p_meal_id AND r.owner_id = v_user_id
  ) THEN
    RAISE EXCEPTION 'MEAL_NOT_OWNED';
  END IF;

  SELECT count(DISTINCT lower(entry ->> 'meal_type'))
  INTO v_count
  FROM jsonb_array_elements(p_offerings) entry;
  IF v_count <> jsonb_array_length(p_offerings) THEN
    RAISE EXCEPTION 'MENU_OFFERINGS_DUPLICATE';
  END IF;

  IF EXISTS (
    SELECT 1 FROM jsonb_array_elements(p_offerings) entry
    WHERE lower(coalesce(entry ->> 'meal_type', '')) NOT IN ('breakfast', 'lunch', 'dinner', 'snack')
      OR coalesce(entry ->> 'price', '') !~ '^\d+(\.\d{1,2})?$'
      OR (entry ->> 'price')::NUMERIC NOT BETWEEN 0 AND 10000
  ) THEN
    RAISE EXCEPTION 'MENU_OFFERINGS_INVALID';
  END IF;

  DELETE FROM public.meal_menu_offerings WHERE meal_id = p_meal_id;
  INSERT INTO public.meal_menu_offerings (meal_id, meal_type, price, is_available)
  SELECT
    p_meal_id,
    lower(entry ->> 'meal_type'),
    round((entry ->> 'price')::NUMERIC, 2),
    coalesce((entry ->> 'is_available')::BOOLEAN, true)
  FROM jsonb_array_elements(p_offerings) entry;

  RETURN jsonb_build_object('success', true, 'count', jsonb_array_length(p_offerings));
END;
$_$;


ALTER FUNCTION "public"."save_meal_menu_offerings"("p_meal_id" "uuid", "p_offerings" "jsonb") OWNER TO "postgres";

--
-- Name: schedule_meals_atomic("uuid", "jsonb", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."schedule_meals_atomic"("p_subscription_id" "uuid", "p_items" "jsonb", "p_request_batch_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_item JSONB;
  v_addon_item JSONB;
  v_meal public.meals%ROWTYPE;
  v_addon public.meal_addons%ROWTYPE;
  v_schedule_id UUID;
  v_schedule_ids UUID[] := ARRAY[]::UUID[];
  v_item_index INTEGER := 0;
  v_item_count INTEGER;
  v_meal_type TEXT;
  v_scheduled_date DATE;
  v_delivery_address_id UUID;
  v_delivery_time_slot TEXT;
  v_schedule_source TEXT;
  v_coach_program_id UUID;
  v_program_meal_id UUID;
  v_coach_suggested_meal_id UUID;
  v_addon_id UUID;
  v_addon_quantity INTEGER;
  v_addon_count INTEGER;
  v_addons JSONB;
  v_addons_total NUMERIC(10, 2);
  v_existing_ids UUID[];
  v_routing JSONB;
  v_restaurant_branch_id UUID;
  v_customization_data JSONB;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;
  IF p_request_batch_id IS NULL THEN
    RAISE EXCEPTION 'SCHEDULE_REQUEST_ID_REQUIRED';
  END IF;
  IF jsonb_typeof(p_items) <> 'array' THEN
    RAISE EXCEPTION 'SCHEDULE_ITEMS_INVALID';
  END IF;

  v_item_count := jsonb_array_length(p_items);
  IF v_item_count < 1 OR v_item_count > 14 THEN
    RAISE EXCEPTION 'SCHEDULE_ITEM_COUNT_INVALID';
  END IF;

  PERFORM pg_advisory_xact_lock(
    hashtextextended(v_user_id::TEXT || ':' || p_request_batch_id::TEXT, 0)
  );

  SELECT ARRAY_AGG(ms.id ORDER BY ms.request_item_index)
    INTO v_existing_ids
  FROM public.meal_schedules ms
  WHERE ms.user_id = v_user_id
    AND ms.request_batch_id = p_request_batch_id;

  IF COALESCE(array_length(v_existing_ids, 1), 0) > 0 THEN
    RETURN jsonb_build_object(
      'success', TRUE,
      'already_processed', TRUE,
      'schedule_ids', to_jsonb(v_existing_ids)
    );
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.subscriptions s
    WHERE s.id = p_subscription_id
      AND s.user_id = v_user_id
      AND s.status IN ('active', 'cancelled')
      AND (
        s.status = 'active'
        OR COALESCE(s.end_date, CURRENT_DATE - 1) >= CURRENT_DATE
      )
  ) THEN
    RAISE EXCEPTION 'SUBSCRIPTION_NOT_FOUND';
  END IF;

  FOR v_item IN SELECT value FROM jsonb_array_elements(p_items)
  LOOP
    v_item_index := v_item_index + 1;
    IF jsonb_typeof(v_item) <> 'object' THEN
      RAISE EXCEPTION 'SCHEDULE_ITEM_INVALID';
    END IF;
    v_meal_type := LOWER(COALESCE(v_item ->> 'meal_type', ''));
    v_scheduled_date := (v_item ->> 'scheduled_date')::DATE;
    v_delivery_address_id := NULLIF(v_item ->> 'delivery_address_id', '')::UUID;
    v_delivery_time_slot := NULLIF(v_item ->> 'delivery_time_slot', '');
    v_schedule_source := COALESCE(v_item ->> 'schedule_source', 'customer');
    v_coach_program_id := NULLIF(v_item ->> 'coach_program_id', '')::UUID;
    v_program_meal_id := NULLIF(v_item ->> 'program_meal_id', '')::UUID;
    v_coach_suggested_meal_id := NULLIF(v_item ->> 'coach_suggested_meal_id', '')::UUID;
    v_customization_data := COALESCE(v_item -> 'customization_data', '{}'::JSONB);

    IF v_meal_type NOT IN ('breakfast', 'lunch', 'dinner', 'snack') THEN
      RAISE EXCEPTION 'MEAL_TYPE_INVALID';
    END IF;
    IF v_scheduled_date < CURRENT_DATE THEN
      RAISE EXCEPTION 'SCHEDULE_DATE_INVALID';
    END IF;
    IF LENGTH(COALESCE(v_delivery_time_slot, '')) > 100
      OR LENGTH(COALESCE(v_item ->> 'restaurant_note', '')) > 1000
      OR OCTET_LENGTH(v_customization_data::TEXT) > 16384 THEN
      RAISE EXCEPTION 'SCHEDULE_DETAILS_TOO_LARGE';
    END IF;

    SELECT *
      INTO v_meal
    FROM public.meals m
    WHERE m.id = (v_item ->> 'meal_id')::UUID
      AND COALESCE(m.is_available, FALSE) = TRUE
      AND m.deleted_at IS NULL
      AND (m.approval_status IS NULL OR m.approval_status = 'approved')
    FOR SHARE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'MEAL_NOT_AVAILABLE';
    END IF;

    IF v_delivery_address_id IS NOT NULL
      AND NOT EXISTS (
        SELECT 1
        FROM public.user_addresses ua
        WHERE ua.id = v_delivery_address_id
          AND ua.user_id = v_user_id
      ) THEN
      RAISE EXCEPTION 'DELIVERY_ADDRESS_NOT_FOUND';
    END IF;

    IF v_schedule_source NOT IN ('customer', 'coach_program', 'coach_replacement') THEN
      RAISE EXCEPTION 'SCHEDULE_SOURCE_INVALID';
    END IF;

    IF v_schedule_source <> 'customer' THEN
      IF NOT EXISTS (
        SELECT 1
        FROM public.coach_programs cp
        JOIN public.program_meals pm
          ON pm.program_id = cp.id
        WHERE cp.id = v_coach_program_id
          AND cp.client_id = v_user_id
          AND cp.status = 'active'
          AND pm.id = v_program_meal_id
          AND pm.assigned_date = v_scheduled_date
          AND pm.meal_type = v_meal_type
          AND pm.meal_id = v_coach_suggested_meal_id
      ) THEN
        RAISE EXCEPTION 'COACH_MEAL_CONTEXT_INVALID';
      END IF;
    ELSE
      v_coach_program_id := NULL;
      v_program_meal_id := NULL;
      v_coach_suggested_meal_id := NULL;
    END IF;

    IF NOT public.increment_monthly_meal_usage(p_subscription_id) THEN
      RAISE EXCEPTION 'MEAL_QUOTA_EXHAUSTED';
    END IF;
    IF v_meal_type = 'snack'
      AND NOT public.increment_snack_usage(p_subscription_id) THEN
      RAISE EXCEPTION 'SNACK_QUOTA_EXHAUSTED';
    END IF;

    v_schedule_id := gen_random_uuid();
    v_addons_total := 0;
    v_routing := public.route_meal_schedule_branch(
      v_meal.restaurant_id,
      v_meal.id,
      v_delivery_address_id,
      v_scheduled_date,
      v_delivery_time_slot,
      v_meal_type
    );
    v_restaurant_branch_id := NULLIF(v_routing ->> 'branch_id', '')::UUID;

    IF v_item ? 'addons'
      AND jsonb_typeof(v_item -> 'addons') <> 'array' THEN
      RAISE EXCEPTION 'SCHEDULE_ADDONS_INVALID';
    END IF;
    v_addons := CASE
      WHEN jsonb_typeof(v_item -> 'addons') = 'array' THEN v_item -> 'addons'
      ELSE '[]'::JSONB
    END;
    v_addon_count := jsonb_array_length(v_addons);
    IF v_addon_count > 20 THEN
      RAISE EXCEPTION 'SCHEDULE_ADDONS_INVALID';
    END IF;

    FOR v_addon_item IN
      SELECT jsonb_build_object(
        'addon_id', source.addon_id,
        'quantity', SUM(source.quantity)
      )
      FROM (
        SELECT
          (entry ->> 'addon_id')::UUID AS addon_id,
          (entry ->> 'quantity')::INTEGER AS quantity
        FROM jsonb_array_elements(v_addons) entry
      ) source
      GROUP BY source.addon_id
    LOOP
      v_addon_id := (v_addon_item ->> 'addon_id')::UUID;
      v_addon_quantity := (v_addon_item ->> 'quantity')::INTEGER;

      IF v_addon_quantity < 1 OR v_addon_quantity > 20 THEN
        RAISE EXCEPTION 'SCHEDULE_ADDON_QUANTITY_INVALID';
      END IF;

      SELECT *
        INTO v_addon
      FROM public.meal_addons ma
      WHERE ma.id = v_addon_id
        AND ma.meal_id = v_meal.id
        AND ma.is_available = TRUE
      FOR SHARE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'MEAL_ADDON_NOT_AVAILABLE';
      END IF;

      v_addons_total := v_addons_total
        + ROUND(v_addon.price::NUMERIC * v_addon_quantity, 2);
    END LOOP;

    INSERT INTO public.meal_schedules (
      id,
      user_id,
      meal_id,
      restaurant_id,
      restaurant_branch_id,
      scheduled_date,
      meal_type,
      is_completed,
      order_status,
      delivery_address_id,
      delivery_time_slot,
      customization_data,
      restaurant_note,
      schedule_source,
      coach_program_id,
      program_meal_id,
      coach_suggested_meal_id,
      coach_replacement_status,
      coach_replacement_delta,
      addons_total,
      routing_metadata,
      request_batch_id,
      request_item_index
    ) VALUES (
      v_schedule_id,
      v_user_id,
      v_meal.id,
      v_meal.restaurant_id,
      v_restaurant_branch_id,
      v_scheduled_date,
      v_meal_type,
      FALSE,
      'pending',
      v_delivery_address_id,
      v_delivery_time_slot,
      v_customization_data,
      NULLIF(TRIM(v_item ->> 'restaurant_note'), ''),
      v_schedule_source,
      v_coach_program_id,
      v_program_meal_id,
      v_coach_suggested_meal_id,
      CASE
        WHEN v_schedule_source = 'customer' THEN NULL
        ELSE NULLIF(v_item ->> 'coach_replacement_status', '')
      END,
      CASE
        WHEN v_schedule_source = 'customer' THEN NULL
        ELSE v_item -> 'coach_replacement_delta'
      END,
      v_addons_total,
      COALESCE(v_routing, '{}'::JSONB),
      p_request_batch_id,
      v_item_index
    );

    IF v_addons_total > 0 THEN
      PERFORM public.debit_wallet(
        v_user_id,
        v_addons_total,
        'meal_addons',
        v_schedule_id,
        'Meal add-ons',
        jsonb_build_object('meal_id', v_meal.id)
      );

    END IF;

    IF v_addon_count > 0 THEN
      INSERT INTO public.schedule_addons (
        schedule_id,
        addon_id,
        quantity,
        unit_price
      )
      SELECT
        v_schedule_id,
        source.addon_id,
        source.quantity,
        ma.price
      FROM (
        SELECT
          (entry ->> 'addon_id')::UUID AS addon_id,
          SUM((entry ->> 'quantity')::INTEGER)::INTEGER AS quantity
        FROM jsonb_array_elements(v_addons) entry
        GROUP BY (entry ->> 'addon_id')::UUID
      ) source
      JOIN public.meal_addons ma ON ma.id = source.addon_id;
    END IF;

    v_schedule_ids := array_append(v_schedule_ids, v_schedule_id);
  END LOOP;

  RETURN jsonb_build_object(
    'success', TRUE,
    'already_processed', FALSE,
    'schedule_ids', to_jsonb(v_schedule_ids)
  );
END;
$$;


ALTER FUNCTION "public"."schedule_meals_atomic"("p_subscription_id" "uuid", "p_items" "jsonb", "p_request_batch_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "schedule_meals_atomic"("p_subscription_id" "uuid", "p_items" "jsonb", "p_request_batch_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."schedule_meals_atomic"("p_subscription_id" "uuid", "p_items" "jsonb", "p_request_batch_id" "uuid") IS 'Atomically validates and schedules one or more customer meals, consumes quotas, and charges server-priced add-ons.';


--
-- Name: schedule_webhook("text", "text", "jsonb", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."schedule_webhook"("p_webhook_url" "text", "p_event_type" "text", "p_payload" "jsonb", "p_headers" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_id UUID;
BEGIN
    INSERT INTO public.webhook_delivery_queue (
        webhook_url,
        event_type,
        payload,
        headers,
        next_retry_at
    ) VALUES (
        p_webhook_url,
        p_event_type,
        p_payload,
        p_headers,
        NOW() -- First attempt immediately
    )
    RETURNING id INTO v_id;
    
    RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."schedule_webhook"("p_webhook_url" "text", "p_event_type" "text", "p_payload" "jsonb", "p_headers" "jsonb") OWNER TO "postgres";

--
-- Name: search_nutrition_knowledge("text", "date", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."search_nutrition_knowledge"("p_query" "text", "p_as_of" "date" DEFAULT CURRENT_DATE, "p_limit" integer DEFAULT 5) RETURNS TABLE("chunk_id" "uuid", "document_id" "uuid", "title" "text", "publisher" "text", "source_url" "text", "version" "text", "effective_from" "date", "heading" "text", "content" "text", "rank" real)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  WITH query AS (
    SELECT websearch_to_tsquery('english', LEFT(COALESCE(p_query, ''), 500)) AS value
  )
  SELECT
    chunk.id,
    document.id,
    document.title,
    document.publisher,
    document.source_url,
    document.version,
    document.effective_from,
    chunk.heading,
    chunk.content,
    ts_rank_cd(chunk.search_vector, query.value)::REAL
  FROM public.knowledge_chunks chunk
  JOIN public.knowledge_documents document ON document.id = chunk.document_id
  CROSS JOIN query
  WHERE document.status = 'published'
    AND document.effective_from <= p_as_of
    AND (document.effective_to IS NULL OR document.effective_to >= p_as_of)
    AND chunk.search_vector @@ query.value
  ORDER BY ts_rank_cd(chunk.search_vector, query.value) DESC, document.effective_from DESC
  LIMIT LEAST(GREATEST(COALESCE(p_limit, 5), 1), 10);
$$;


ALTER FUNCTION "public"."search_nutrition_knowledge"("p_query" "text", "p_as_of" "date", "p_limit" integer) OWNER TO "postgres";

--
-- Name: select_nearest_branch("uuid", numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."select_nearest_branch"("p_restaurant_id" "uuid", "p_customer_lat" numeric, "p_customer_lng" numeric) RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_branch_id UUID;
  v_min_distance NUMERIC := 999999;
  v_branch RECORD;
BEGIN
  -- Find the nearest active branch for the restaurant
  FOR v_branch IN 
    SELECT id, latitude, longitude 
    FROM restaurant_branches 
    WHERE restaurant_id = p_restaurant_id 
      AND is_active = true
  LOOP
    DECLARE
      v_distance NUMERIC;
    BEGIN
      -- Calculate distance using Haversine formula
      v_distance := (
        6371 * acos(
          cos(radians(p_customer_lat)) * 
          cos(radians(v_branch.latitude)) * 
          cos(radians(v_branch.longitude) - radians(p_customer_lng)) + 
          sin(radians(p_customer_lat)) * 
          sin(radians(v_branch.latitude))
        )
      );
      
      IF v_distance < v_min_distance THEN
        v_min_distance := v_distance;
        v_branch_id := v_branch.id;
      END IF;
    END;
  END LOOP;
  
  RETURN v_branch_id;
END;
$$;


ALTER FUNCTION "public"."select_nearest_branch"("p_restaurant_id" "uuid", "p_customer_lat" numeric, "p_customer_lng" numeric) OWNER TO "postgres";

--
-- Name: select_nearest_branch_for_meal("uuid", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."select_nearest_branch_for_meal"("p_meal_id" "uuid", "p_user_id" "uuid", "p_delivery_address_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_restaurant_id UUID;
  v_nearest_branch_id UUID;
  v_user_lat DECIMAL(10, 8);
  v_user_lon DECIMAL(11, 8);
  v_branch_lat DECIMAL(10, 8);
  v_branch_lon DECIMAL(11, 8);
  v_min_distance NUMERIC := NULL;
  v_current_distance NUMERIC;
  v_branch RECORD;
BEGIN
  -- Get restaurant ID from meal
  SELECT restaurant_id INTO v_restaurant_id
  FROM public.meals
  WHERE id = p_meal_id;

  IF v_restaurant_id IS NULL THEN
    RAISE EXCEPTION 'Meal not found or has no restaurant';
  END IF;

  -- Get user address coordinates
  IF p_delivery_address_id IS NOT NULL THEN
    SELECT latitude, longitude INTO v_user_lat, v_user_lon
    FROM public.user_addresses
    WHERE id = p_delivery_address_id AND user_id = p_user_id;
  END IF;

  -- If no address ID provided, try to get default address
  IF (v_user_lat IS NULL OR v_user_lon IS NULL) AND p_delivery_address_id IS NULL THEN
    SELECT latitude, longitude INTO v_user_lat, v_user_lon
    FROM public.user_addresses
    WHERE user_id = p_user_id AND is_default = true
    LIMIT 1;
  END IF;

  -- If still no coordinates, return NULL (no branch selected)
  IF v_user_lat IS NULL OR v_user_lon IS NULL THEN
    RETURN NULL;
  END IF;

  -- Find nearest branch for this restaurant
  FOR v_branch IN 
    SELECT id, latitude, longitude
    FROM public.restaurant_branches
    WHERE restaurant_id = v_restaurant_id
      AND is_active = true
      AND latitude IS NOT NULL
      AND longitude IS NOT NULL
  LOOP
    -- Calculate distance using Haversine formula
    v_current_distance := (
      6371 * acos(
        cos(radians(v_user_lat)) * cos(radians(v_branch.latitude)) * 
        cos(radians(v_branch.longitude) - radians(v_user_lon)) + 
        sin(radians(v_user_lat)) * sin(radians(v_branch.latitude))
      )
    );

    IF v_min_distance IS NULL OR v_current_distance < v_min_distance THEN
      v_min_distance := v_current_distance;
      v_nearest_branch_id := v_branch.id;
    END IF;
  END LOOP;

  RETURN v_nearest_branch_id;
END;
$$;


ALTER FUNCTION "public"."select_nearest_branch_for_meal"("p_meal_id" "uuid", "p_user_id" "uuid", "p_delivery_address_id" "uuid") OWNER TO "postgres";

--
-- Name: send_announcement_notification("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."send_announcement_notification"("p_announcement_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_announcement RECORD;
  v_user RECORD;
  v_count INTEGER := 0;
  v_notification_type public.notification_type;
BEGIN
  SELECT *
  INTO v_announcement
  FROM public.announcements
  WHERE id = p_announcement_id;

  IF NOT FOUND THEN
    RETURN 0;
  END IF;

  -- Map announcement severity to existing notification types.
  v_notification_type := CASE v_announcement.type
    WHEN 'warning' THEN 'subscription_alert'::public.notification_type
    WHEN 'success' THEN 'order_update'::public.notification_type
    WHEN 'error' THEN 'subscription_alert'::public.notification_type
    ELSE 'general'::public.notification_type
  END;

  FOR v_user IN
    SELECT u.id
    FROM auth.users u
    WHERE
      CASE v_announcement.target_audience
        WHEN 'all' THEN true
        WHEN 'users' THEN EXISTS (
          SELECT 1
          FROM public.profiles p
          WHERE p.user_id = u.id
        )
        WHEN 'customers' THEN EXISTS (
          SELECT 1
          FROM public.profiles p
          WHERE p.user_id = u.id
        )
        WHEN 'partners' THEN EXISTS (
          SELECT 1
          FROM public.restaurants r
          WHERE r.owner_id = u.id
        )
        WHEN 'admins' THEN public.has_role(u.id, 'admin'::public.app_role)
        ELSE true
      END
      AND NOT EXISTS (
        SELECT 1
        FROM public.notifications n
        WHERE n.user_id = u.id
          AND n.related_entity_type = 'announcement'
          AND n.related_entity_id = p_announcement_id
      )
  LOOP
    INSERT INTO public.notifications (
      user_id,
      type,
      title,
      message,
      status,
      data,
      related_entity_type,
      related_entity_id
    )
    VALUES (
      v_user.id,
      v_notification_type,
      v_announcement.title,
      v_announcement.message,
      'unread'::public.notification_status,
      jsonb_build_object(
        'announcement_id', v_announcement.id,
        'announcement_type', v_announcement.type,
        'target_audience', v_announcement.target_audience
      ),
      'announcement',
      v_announcement.id
    );

    v_count := v_count + 1;
  END LOOP;

  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."send_announcement_notification"("p_announcement_id" "uuid") OWNER TO "postgres";

--
-- Name: send_announcement_notification_secure("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."send_announcement_notification_secure"("p_announcement_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin') THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;

  RETURN public.send_announcement_notification(p_announcement_id);
END;
$$;


