-- Name: send_friend_request("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."send_friend_request"("p_requester_id" "uuid", "p_target_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_requester_id);
  RETURN public.send_friend_request_trusted(p_requester_id, p_target_id);
END;
$$;


ALTER FUNCTION "public"."send_friend_request"("p_requester_id" "uuid", "p_target_id" "uuid") OWNER TO "postgres";

--
-- Name: send_friend_request_trusted("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."send_friend_request_trusted"("p_requester_id" "uuid", "p_target_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_existing public.friendships%ROWTYPE;
  v_new_id UUID;
  v_requester_name TEXT;
BEGIN
  IF auth.uid() IS NULL OR auth.uid() <> p_requester_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authorized');
  END IF;
  IF p_requester_id = p_target_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'You cannot add yourself');
  END IF;
  IF NOT EXISTS (SELECT 1 FROM public.profiles WHERE user_id = p_target_id) THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  SELECT * INTO v_existing
  FROM public.friendships
  WHERE (requester_id = p_requester_id AND target_id = p_target_id)
     OR (requester_id = p_target_id AND target_id = p_requester_id)
  LIMIT 1
  FOR UPDATE;

  IF FOUND AND v_existing.status = 'accepted' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Already friends');
  ELSIF FOUND AND v_existing.status = 'pending' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Friend request already sent');
  ELSIF FOUND THEN
    UPDATE public.friendships
    SET requester_id = p_requester_id,
        target_id = p_target_id,
        status = 'pending',
        updated_at = now()
    WHERE id = v_existing.id
    RETURNING id INTO v_new_id;
  ELSE
    INSERT INTO public.friendships (requester_id, target_id, status)
    VALUES (p_requester_id, p_target_id, 'pending')
    RETURNING id INTO v_new_id;
  END IF;

  SELECT COALESCE(full_name, 'Someone') INTO v_requester_name
  FROM public.profiles WHERE user_id = p_requester_id;

  INSERT INTO public.notifications (user_id, type, title, message, status, data)
  VALUES (
    p_target_id, 'general', 'New Friend Request',
    v_requester_name || ' wants to be friends!', 'unread',
    jsonb_build_object('friendship_id', v_new_id, 'requester_id', p_requester_id)
  );

  RETURN jsonb_build_object('success', true, 'id', v_new_id, 'message', 'Friend request sent');
END;
$$;


ALTER FUNCTION "public"."send_friend_request_trusted"("p_requester_id" "uuid", "p_target_id" "uuid") OWNER TO "postgres";

--
-- Name: send_whatsapp_notification("text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."send_whatsapp_notification"("p_phone" "text", "p_message" "text", "p_template" "text" DEFAULT 'custom'::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_instance_id TEXT;
  v_api_token TEXT;
  v_api_url TEXT;
BEGIN
  -- Get Ultramsg credentials from environment (set via Supabase secrets)
  -- In production, these should be stored as encrypted secrets
  v_instance_id := current_setting('app.ultramsg_instance_id', true);
  v_api_token := current_setting('app.ultramsg_api_token', true);
  
  -- Skip if credentials not configured
  IF v_instance_id IS NULL OR v_api_token IS NULL THEN
    RAISE NOTICE 'WhatsApp credentials not configured, skipping notification';
    RETURN;
  END IF;
  
  -- Construct API URL
  v_api_url := format(
    'https://api.ultramsg.com/%s/messages/chat',
    v_instance_id
  );
  
  -- Note: Actual HTTP call would be made via Supabase Edge Function
  -- This function serves as a trigger handler that queues the notification
  
  -- Insert into notification queue for async processing
  INSERT INTO notification_queue (
    phone,
    message,
    template,
    status,
    created_at
  ) VALUES (
    p_phone,
    p_message,
    p_template,
    'pending',
    NOW()
  );
  
EXCEPTION WHEN OTHERS THEN
  RAISE NOTICE 'Error queueing WhatsApp notification: %', SQLERRM;
END;
$$;


ALTER FUNCTION "public"."send_whatsapp_notification"("p_phone" "text", "p_message" "text", "p_template" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "send_whatsapp_notification"("p_phone" "text", "p_message" "text", "p_template" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."send_whatsapp_notification"("p_phone" "text", "p_message" "text", "p_template" "text") IS 'Queues WhatsApp notifications. Requires Ultramsg credentials to be set via:
ALTER SYSTEM SET app.ultramsg_instance_id = ''your_instance_id'';
ALTER SYSTEM SET app.ultramsg_api_token = ''your_api_token'';
Or via Supabase Vault/Edge Function in production.';


--
-- Name: set_ai_coach_consent(boolean, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."set_ai_coach_consent"("p_granted" boolean, "p_policy_version" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_actor uuid := auth.uid();
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;
  IF p_policy_version <> '2026-07-health-ai-v1' THEN
    RAISE EXCEPTION 'INVALID_AI_CONSENT_VERSION';
  END IF;

  INSERT INTO public.ai_data_consents (
    user_id, purpose, status, policy_version, granted_at, revoked_at, updated_at
  ) VALUES (
    v_actor,
    'nutrition_coaching',
    CASE WHEN p_granted THEN 'granted' ELSE 'revoked' END,
    p_policy_version,
    CASE WHEN p_granted THEN clock_timestamp() ELSE NULL END,
    CASE WHEN p_granted THEN NULL ELSE clock_timestamp() END,
    clock_timestamp()
  )
  ON CONFLICT (user_id, purpose) DO UPDATE
  SET status = EXCLUDED.status,
      policy_version = EXCLUDED.policy_version,
      granted_at = CASE
        WHEN EXCLUDED.status = 'granted' THEN clock_timestamp()
        ELSE public.ai_data_consents.granted_at
      END,
      revoked_at = CASE
        WHEN EXCLUDED.status = 'revoked' THEN clock_timestamp()
        ELSE NULL
      END,
      updated_at = clock_timestamp();

  INSERT INTO public.ai_coach_consent_events (user_id, granted, policy_version)
  VALUES (v_actor, p_granted, p_policy_version);
END;
$$;


ALTER FUNCTION "public"."set_ai_coach_consent"("p_granted" boolean, "p_policy_version" "text") OWNER TO "postgres";

