-- Name: set_delivery_job_restaurant_id(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."set_delivery_job_restaurant_id"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.restaurant_id IS NULL AND NEW.schedule_id IS NOT NULL THEN
    SELECT m.restaurant_id INTO NEW.restaurant_id
    FROM meal_schedules ms
    JOIN meals m ON ms.meal_id = m.id
    WHERE ms.id = NEW.schedule_id
    LIMIT 1;
  END IF;
  RETURN NEW;
END;
$$;


