--
-- Name: set_order_item_nutrition_snapshot(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."set_order_item_nutrition_snapshot"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_snapshot jsonb;
begin
  if tg_op = 'insert' then
    v_snapshot := public.get_meal_nutrition_snapshot(new.meal_id);
  elsif new.meal_id is distinct from old.meal_id
     or new.quantity is distinct from old.quantity then
    v_snapshot := public.get_meal_nutrition_snapshot(new.meal_id);
  else
    new.nutrition_snapshot := old.nutrition_snapshot;
    return new;
  end if;

  if v_snapshot is null then
    new.nutrition_snapshot := null;
  else
    new.nutrition_snapshot := v_snapshot || jsonb_build_object(
      'order_item_id', new.id,
      'serving_quantity', greatest(coalesce(new.quantity, 1), 1),
      'serving_unit', 'meal',
      'source_type', 'order_item',
      'source_record_id', new.id
    );
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."set_order_item_nutrition_snapshot"() OWNER TO "postgres";

--
-- Name: set_own_health_tracking_goals(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."set_own_health_tracking_goals"("p_water_goal_ml" integer DEFAULT NULL::integer, "p_step_goal" integer DEFAULT NULL::integer) RETURNS TABLE("water_goal_ml" integer, "step_goal" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_defaults RECORD;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'UNAUTHENTICATED';
  END IF;

  SELECT * INTO v_defaults FROM public.get_own_health_tracking_goals();

  IF p_water_goal_ml IS NOT NULL AND p_water_goal_ml NOT BETWEEN 1000 AND 10000 THEN
    RAISE EXCEPTION 'INVALID_WATER_GOAL';
  END IF;
  IF p_step_goal IS NOT NULL AND p_step_goal NOT BETWEEN 1000 AND 100000 THEN
    RAISE EXCEPTION 'INVALID_STEP_GOAL';
  END IF;

  INSERT INTO public.user_health_tracking_goals (
    user_id, water_goal_ml, step_goal, updated_at
  ) VALUES (
    v_actor,
    COALESCE(p_water_goal_ml, v_defaults.water_goal_ml),
    COALESCE(p_step_goal, v_defaults.step_goal),
    NOW()
  )
  ON CONFLICT (user_id) DO UPDATE
  SET water_goal_ml = COALESCE(p_water_goal_ml, public.user_health_tracking_goals.water_goal_ml),
      step_goal = COALESCE(p_step_goal, public.user_health_tracking_goals.step_goal),
      updated_at = NOW();

  RETURN QUERY
  SELECT goals.water_goal_ml, goals.step_goal
  FROM public.user_health_tracking_goals goals
  WHERE goals.user_id = v_actor;
END;
$$;


ALTER FUNCTION "public"."set_own_health_tracking_goals"("p_water_goal_ml" integer, "p_step_goal" integer) OWNER TO "postgres";

