--
-- Name: settle_coach_earnings("uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."settle_coach_earnings"("p_earning_ids" "uuid"[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_admin_id UUID := auth.uid();
  v_updated_count INTEGER;
  v_released_amount NUMERIC(12, 2);
BEGIN
  IF v_admin_id IS NULL OR NOT COALESCE(public.has_role(v_admin_id, 'admin'), FALSE) THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;
  IF COALESCE(array_length(p_earning_ids, 1), 0) < 1
    OR array_length(p_earning_ids, 1) > 200 THEN
    RAISE EXCEPTION 'INVALID_EARNING_BATCH';
  END IF;

  WITH updated AS (
    UPDATE public.coach_earnings ce
    SET status = 'settled',
        settled_at = NOW()
    WHERE ce.id = ANY(p_earning_ids)
      AND ce.status = 'pending'
    RETURNING ce.net_amount
  )
  SELECT COUNT(*)::INTEGER, COALESCE(SUM(net_amount), 0)
  INTO v_updated_count, v_released_amount
  FROM updated;

  IF v_updated_count = 0 THEN
    RAISE EXCEPTION 'NO_PENDING_EARNINGS';
  END IF;

  RETURN jsonb_build_object(
    'success', TRUE,
    'released_count', v_updated_count,
    'released_amount', v_released_amount
  );
END;
$$;


ALTER FUNCTION "public"."settle_coach_earnings"("p_earning_ids" "uuid"[]) OWNER TO "postgres";

--
-- Name: settle_ended_community_challenges(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."settle_ended_community_challenges"("p_limit" integer DEFAULT 250) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_participant RECORD;
  v_result JSONB;
  v_results JSONB := '[]'::JSONB;
  v_count INTEGER := 0;
  v_qatar_today DATE := (now() AT TIME ZONE 'Asia/Qatar')::DATE;
BEGIN
  FOR v_participant IN
    SELECT cp.user_id, cp.challenge_id
    FROM public.challenge_participants cp
    JOIN public.community_challenges cc ON cc.id = cp.challenge_id
    WHERE cc.end_date < v_qatar_today
      AND cp.reward_settlement_finalized_at IS NULL
    ORDER BY cc.end_date, cp.joined_at
    LIMIT greatest(least(coalesce(p_limit, 250), 1000), 1)
    FOR UPDATE OF cp SKIP LOCKED
  LOOP
    v_result := public.apply_community_challenge_progress(
      v_participant.user_id,
      v_participant.challenge_id
    );
    v_results := v_results || jsonb_build_array(
      jsonb_build_object(
        'user_id', v_participant.user_id,
        'challenge_id', v_participant.challenge_id,
        'result', v_result
      )
    );
    v_count := v_count + 1;
  END LOOP;

  RETURN jsonb_build_object('success', true, 'processed', v_count, 'results', v_results);
END;
$$;


ALTER FUNCTION "public"."settle_ended_community_challenges"("p_limit" integer) OWNER TO "postgres";

