-- Name: submit_meal_review("uuid", "uuid", integer, "text", "text", "text"[], boolean, "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."submit_meal_review"("p_meal_id" "uuid", "p_user_id" "uuid", "p_rating" integer, "p_title" "text" DEFAULT NULL::"text", "p_review_text" "text" DEFAULT NULL::"text", "p_photo_urls" "text"[] DEFAULT '{}'::"text"[], "p_would_recommend" boolean DEFAULT NULL::boolean, "p_tags" "text"[] DEFAULT '{}'::"text"[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  PERFORM public.assert_self_or_admin(p_user_id);
  RETURN public.submit_meal_review_trusted(p_meal_id, p_user_id, p_rating, p_title, p_review_text, p_photo_urls, p_would_recommend, p_tags);
END;
$$;


ALTER FUNCTION "public"."submit_meal_review"("p_meal_id" "uuid", "p_user_id" "uuid", "p_rating" integer, "p_title" "text", "p_review_text" "text", "p_photo_urls" "text"[], "p_would_recommend" boolean, "p_tags" "text"[]) OWNER TO "postgres";

--
-- Name: submit_meal_review_trusted("uuid", "uuid", integer, "text", "text", "text"[], boolean, "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."submit_meal_review_trusted"("p_meal_id" "uuid", "p_user_id" "uuid", "p_rating" integer, "p_title" "text" DEFAULT NULL::"text", "p_review_text" "text" DEFAULT NULL::"text", "p_photo_urls" "text"[] DEFAULT '{}'::"text"[], "p_would_recommend" boolean DEFAULT NULL::boolean, "p_tags" "text"[] DEFAULT '{}'::"text"[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_restaurant_id UUID;
    v_order_id UUID;
    v_is_verified BOOLEAN;
    v_review_id UUID;
    v_result JSONB;
BEGIN
    -- Get meal's restaurant
    SELECT restaurant_id INTO v_restaurant_id
    FROM meals
    WHERE id = p_meal_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Meal not found',
            'code', 'MEAL_NOT_FOUND'
        );
    END IF;
    
    -- Check if user has ordered this meal (verified purchase)
    SELECT o.id INTO v_order_id
    FROM orders o
    JOIN order_items oi ON o.id = oi.order_id
    WHERE o.user_id = p_user_id
    AND oi.meal_id = p_meal_id
    AND o.status IN ('delivered', 'completed')
    ORDER BY o.created_at DESC
    LIMIT 1;
    
    v_is_verified := v_order_id IS NOT NULL;
    
    -- Check if user already reviewed this meal
    IF EXISTS (
        SELECT 1 FROM meal_reviews 
        WHERE meal_id = p_meal_id AND user_id = p_user_id
    ) THEN
        -- Update existing review
        UPDATE meal_reviews
        SET 
            rating = p_rating,
            title = p_title,
            review_text = p_review_text,
            photo_urls = p_photo_urls,
            would_recommend = p_would_recommend,
            tags = p_tags,
            is_verified_purchase = v_is_verified,
            order_id = v_order_id,
            updated_at = NOW()
        WHERE meal_id = p_meal_id AND user_id = p_user_id
        RETURNING id INTO v_review_id;
        
        v_result := jsonb_build_object(
            'success', true,
            'action', 'updated',
            'review_id', v_review_id,
            'is_verified', v_is_verified
        );
    ELSE
        -- Insert new review
        INSERT INTO meal_reviews (
            meal_id,
            user_id,
            restaurant_id,
            order_id,
            rating,
            title,
            review_text,
            photo_urls,
            is_verified_purchase,
            would_recommend,
            tags
        ) VALUES (
            p_meal_id,
            p_user_id,
            v_restaurant_id,
            v_order_id,
            p_rating,
            p_title,
            p_review_text,
            p_photo_urls,
            v_is_verified,
            p_would_recommend,
            p_tags
        )
        RETURNING id INTO v_review_id;
        
        v_result := jsonb_build_object(
            'success', true,
            'action', 'created',
            'review_id', v_review_id,
            'is_verified', v_is_verified
        );
    END IF;
    
    RETURN v_result;
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM,
        'code', SQLSTATE
    );
END;
$$;


ALTER FUNCTION "public"."submit_meal_review_trusted"("p_meal_id" "uuid", "p_user_id" "uuid", "p_rating" integer, "p_title" "text", "p_review_text" "text", "p_photo_urls" "text"[], "p_would_recommend" boolean, "p_tags" "text"[]) OWNER TO "postgres";

