-- Name: FUNCTION "submit_meal_review_trusted"("p_meal_id" "uuid", "p_user_id" "uuid", "p_rating" integer, "p_title" "text", "p_review_text" "text", "p_photo_urls" "text"[], "p_would_recommend" boolean, "p_tags" "text"[]); Type: COMMENT; Schema: public; Owner: postgres
