--
-- Name: submit_skip_reason_trusted("uuid", "uuid", "uuid", character varying, "text", "date", character varying, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."submit_skip_reason_trusted"("p_user_id" "uuid", "p_meal_id" "uuid", "p_schedule_id" "uuid", "p_reason_type" character varying, "p_details" "text" DEFAULT NULL::"text", "p_scheduled_date" "date" DEFAULT NULL::"date", "p_meal_type" character varying DEFAULT NULL::character varying, "p_ai_confidence_score" numeric DEFAULT NULL::numeric) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_skip_id UUID;
BEGIN
    INSERT INTO meal_skip_reasons (
        user_id,
        meal_id,
        schedule_id,
        reason_type,
        details,
        scheduled_date,
        meal_type,
        ai_confidence_score
    ) VALUES (
        p_user_id,
        p_meal_id,
        p_schedule_id,
        p_reason_type,
        p_details,
        p_scheduled_date,
        p_meal_type,
        p_ai_confidence_score
    )
    ON CONFLICT (schedule_id) DO UPDATE SET
        reason_type = EXCLUDED.reason_type,
        details = EXCLUDED.details,
        ai_confidence_score = EXCLUDED.ai_confidence_score,
        created_at = NOW()
    RETURNING id INTO v_skip_id;

    RETURN jsonb_build_object(
        'success', true,
        'skip_id', v_skip_id,
        'message', 'Skip reason recorded'
    );
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM
    );
END;
$$;


