--
-- Name: sync_delivery_status_bidirectional(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_delivery_status_bidirectional"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_target_status TEXT;
BEGIN
    IF TG_TABLE_NAME = 'delivery_jobs' THEN
        -- Sync delivery_jobs → meal_schedules (with mapping)
        IF NEW.status IS DISTINCT FROM OLD.status AND NEW.schedule_id IS NOT NULL THEN
            
            -- Map delivery_jobs status to meal_schedules order_status
            v_target_status := CASE NEW.status
                WHEN 'assigned' THEN 'ready'
                WHEN 'accepted' THEN 'ready'
                WHEN 'picked_up' THEN 'out_for_delivery'
                WHEN 'in_transit' THEN 'out_for_delivery'
                WHEN 'delivered' THEN 'delivered'
                WHEN 'completed' THEN 'completed'
                WHEN 'failed' THEN 'ready'
                WHEN 'cancelled' THEN 'cancelled'
                ELSE NEW.status
            END;
            
            UPDATE public.meal_schedules
            SET order_status = v_target_status,
                updated_at = NOW()
            WHERE id = NEW.schedule_id
              AND order_status != v_target_status;
        END IF;
        
    ELSIF TG_TABLE_NAME = 'meal_schedules' THEN
        -- Sync meal_schedules → delivery_jobs (ONLY for compatible statuses)
        IF NEW.order_status IS DISTINCT FROM OLD.order_status THEN
            
            -- Only sync if the meal_schedules status is compatible with delivery_jobs
            -- Valid delivery_jobs statuses: pending, assigned, accepted, picked_up, 
            -- in_transit, delivered, completed, failed, cancelled
            -- INVALID: confirmed, preparing, ready, out_for_delivery
            IF NEW.order_status IN ('pending', 'assigned', 'accepted', 'picked_up', 
                                     'in_transit', 'delivered', 'completed', 'failed', 'cancelled') THEN
                
                UPDATE public.delivery_jobs
                SET status = NEW.order_status,
                    updated_at = NOW()
                WHERE schedule_id = NEW.id
                  AND status != NEW.order_status;
            END IF;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_delivery_status_bidirectional"() OWNER TO "postgres";

--
-- Name: sync_delivery_status_to_order(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_delivery_status_to_order"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.order_id IS NULL THEN
    RETURN NEW;
  END IF;

  UPDATE public.orders o
  SET driver_id = NEW.driver_id,
      status = CASE NEW.status
        WHEN 'assigned' THEN 'confirmed'::public.order_status
        WHEN 'accepted' THEN 'confirmed'::public.order_status
        WHEN 'picked_up' THEN 'picked_up'::public.order_status
        WHEN 'in_transit' THEN 'out_for_delivery'::public.order_status
        WHEN 'delivered' THEN 'delivered'::public.order_status
        WHEN 'completed' THEN 'completed'::public.order_status
        WHEN 'cancelled' THEN 'cancelled'::public.order_status
        ELSE o.status
      END,
      delivered_at = CASE
        WHEN NEW.status IN ('delivered', 'completed')
          THEN COALESCE(o.delivered_at, NEW.delivered_at, NOW())
        ELSE o.delivered_at
      END,
      updated_at = NOW()
  WHERE o.id = NEW.order_id;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_delivery_status_to_order"() OWNER TO "postgres";

--
-- Name: sync_delivery_status_to_schedule(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_delivery_status_to_schedule"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_schedule_status TEXT;
  v_target_status TEXT;
  v_role TEXT := 'system';
BEGIN
  IF NEW.schedule_id IS NULL THEN
    RETURN NEW;
  END IF;

  v_target_status := CASE NEW.status
    WHEN 'picked_up' THEN 'out_for_delivery'
    WHEN 'in_transit' THEN 'out_for_delivery'
    WHEN 'delivered' THEN 'delivered'
    WHEN 'completed' THEN 'completed'
    ELSE NULL
  END;

  IF v_target_status IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT order_status INTO v_schedule_status
  FROM public.meal_schedules
  WHERE id = NEW.schedule_id
  FOR UPDATE;

  IF NOT FOUND OR v_schedule_status = v_target_status THEN
    RETURN NEW;
  END IF;

  IF NOT v_target_status = ANY(public.get_valid_next_statuses(v_schedule_status)) THEN
    RAISE EXCEPTION 'Delivery status % cannot move order % from % to %',
      NEW.status, NEW.schedule_id, v_schedule_status, v_target_status;
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.drivers d
    WHERE d.id = NEW.driver_id AND d.user_id = auth.uid()
  ) THEN
    v_role := 'driver';
  END IF;

  PERFORM set_config('app.current_user_role', v_role, true);

  UPDATE public.meal_schedules
  SET order_status = v_target_status,
      updated_at = now()
  WHERE id = NEW.schedule_id;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_delivery_status_to_schedule"() OWNER TO "postgres";

--
-- Name: FUNCTION "sync_delivery_status_to_schedule"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."sync_delivery_status_to_schedule"() IS 'Syncs delivery_jobs status to meal_schedules.order_status on INSERT and status UPDATE';


--
-- Name: sync_delivery_to_order(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_delivery_to_order"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Sync delivery status to order
  IF NEW.status = 'claimed' THEN
    UPDATE public.orders 
    SET driver_id = NEW.driver_id,
        status = 'driver_assigned',
        updated_at = now()
    WHERE id = NEW.order_id;
  ELSIF NEW.status = 'picked_up' THEN
    UPDATE public.orders 
    SET status = 'picked_up',
        updated_at = now()
    WHERE id = NEW.order_id;
  ELSIF NEW.status = 'on_the_way' THEN
    UPDATE public.orders 
    SET status = 'out_for_delivery',
        updated_at = now()
    WHERE id = NEW.order_id;
  ELSIF NEW.status = 'delivered' THEN
    UPDATE public.orders 
    SET status = 'delivered',
        delivered_at = now(),
        updated_at = now()
    WHERE id = NEW.order_id;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_delivery_to_order"() OWNER TO "postgres";

--
-- Name: sync_delivery_to_schedule(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_delivery_to_schedule"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.status = 'delivered' AND OLD.status != 'delivered' THEN
    -- Update meal schedule status
    UPDATE meal_schedules 
    SET order_status = 'delivered',
        updated_at = NOW()
    WHERE id = NEW.schedule_id;
    
    -- Update driver stats
    UPDATE drivers 
    SET total_deliveries = total_deliveries + 1,
        total_earnings = total_earnings + NEW.driver_earnings,
        updated_at = NOW()
    WHERE id = NEW.driver_id;
  END IF;
  
  -- Also handle completed status (for direct completion)
  IF NEW.status = 'completed' AND OLD.status != 'completed' AND OLD.status != 'delivered' THEN
    -- Update meal schedule status
    UPDATE meal_schedules 
    SET order_status = 'completed',
        updated_at = NOW()
    WHERE id = NEW.schedule_id;
    
    -- Update driver stats
    UPDATE drivers 
    SET total_deliveries = total_deliveries + 1,
        total_earnings = total_earnings + NEW.driver_earnings,
        updated_at = NOW()
    WHERE id = NEW.driver_id;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_delivery_to_schedule"() OWNER TO "postgres";

--
-- Name: FUNCTION "sync_delivery_to_schedule"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."sync_delivery_to_schedule"() IS 'Syncs delivery completion to meal_schedules and updates driver stats';


--
-- Name: sync_driver_current_job(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_driver_current_job"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF OLD.driver_id IS DISTINCT FROM NEW.driver_id AND OLD.driver_id IS NOT NULL THEN
    UPDATE public.drivers
    SET current_job_id = NULL,
        updated_at = now()
    WHERE id = OLD.driver_id
      AND current_job_id = OLD.id;
  END IF;

  IF NEW.driver_id IS NOT NULL
     AND NEW.status IN ('assigned', 'accepted', 'picked_up', 'in_transit') THEN
    UPDATE public.drivers
    SET current_job_id = NEW.id,
        updated_at = now()
    WHERE id = NEW.driver_id;
  ELSIF NEW.driver_id IS NOT NULL
        AND NEW.status IN ('delivered', 'completed', 'failed', 'cancelled') THEN
    UPDATE public.drivers
    SET current_job_id = NULL,
        updated_at = now()
    WHERE id = NEW.driver_id
      AND current_job_id = NEW.id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_driver_current_job"() OWNER TO "postgres";

--
-- Name: sync_meal_addon_to_library(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_meal_addon_to_library"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- If restaurant_addon_id is provided, copy data from library
  IF NEW.restaurant_addon_id IS NOT NULL THEN
    SELECT 
      name, description, price, category, is_available
    INTO 
      NEW.name, NEW.description, NEW.price, NEW.category, NEW.is_available
    FROM restaurant_addons
    WHERE id = NEW.restaurant_addon_id;
    
    -- Increment usage count
    UPDATE restaurant_addons 
    SET usage_count = usage_count + 1 
    WHERE id = NEW.restaurant_addon_id;
  END IF;
  
  RETURN NEW;
END;
$$;


