--
-- Name: sync_schedule_status_to_delivery(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_schedule_status_to_delivery"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
    -- Only sync if order_status changed and there's a related delivery_job
    IF NEW.order_status IS DISTINCT FROM OLD.order_status THEN
        UPDATE public.delivery_jobs
        SET 
            status = NEW.order_status,
            updated_at = NOW()
        WHERE schedule_id = NEW.id
          AND status != NEW.order_status;
          
        RAISE NOTICE 'Synced meal_schedule status % to delivery_jobs for schedule %', NEW.order_status, NEW.id;
    END IF;
    
    RETURN NEW;
END;
$$;


