--
-- Name: transition_affiliate_payout("uuid", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."transition_affiliate_payout"("p_payout_id" "uuid", "p_action" "text", "p_notes" "text" DEFAULT NULL::"text", "p_transfer_reference" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_admin_id UUID := auth.uid();
  v_action TEXT := LOWER(BTRIM(COALESCE(p_action, '')));
  v_payout public.affiliate_payouts%ROWTYPE;
  v_new_status TEXT;
BEGIN
  IF v_admin_id IS NULL OR NOT COALESCE(public.has_role(v_admin_id, 'admin'), FALSE) THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;
  IF COALESCE(LENGTH(p_notes), 0) > 1000
    OR COALESCE(LENGTH(p_transfer_reference), 0) > 160 THEN
    RAISE EXCEPTION 'INVALID_PAYOUT_METADATA';
  END IF;

  SELECT *
  INTO v_payout
  FROM public.affiliate_payouts ap
  WHERE ap.id = p_payout_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'PAYOUT_NOT_FOUND';
  END IF;

  IF v_action = 'approve' AND v_payout.status = 'pending' THEN
    v_new_status := 'processing';
    UPDATE public.affiliate_payouts
    SET status = v_new_status,
        approved_at = NOW(),
        processed_by = v_admin_id,
        notes = NULLIF(BTRIM(p_notes), '')
    WHERE id = v_payout.id;
  ELSIF v_action = 'reject' AND v_payout.status IN ('pending', 'processing') THEN
    v_new_status := 'rejected';
    UPDATE public.profiles
    SET affiliate_balance = COALESCE(affiliate_balance, 0) + v_payout.amount,
        updated_at = NOW()
    WHERE user_id = v_payout.user_id;

    UPDATE public.affiliate_payouts
    SET status = v_new_status,
        processed_at = NOW(),
        processed_by = v_admin_id,
        notes = NULLIF(BTRIM(p_notes), '')
    WHERE id = v_payout.id;
  ELSIF v_action = 'complete' AND v_payout.status = 'processing' THEN
    IF NULLIF(BTRIM(p_transfer_reference), '') IS NULL THEN
      RAISE EXCEPTION 'TRANSFER_REFERENCE_REQUIRED';
    END IF;
    v_new_status := 'completed';
    UPDATE public.affiliate_payouts
    SET status = v_new_status,
        processed_at = NOW(),
        processed_by = v_admin_id,
        payout_reference = BTRIM(p_transfer_reference),
        notes = COALESCE(NULLIF(BTRIM(p_notes), ''), notes)
    WHERE id = v_payout.id;
  ELSE
    RAISE EXCEPTION 'INVALID_PAYOUT_TRANSITION_%_TO_%', v_payout.status, v_action;
  END IF;

  INSERT INTO public.notifications (user_id, type, title, message, status, data)
  VALUES (
    v_payout.user_id,
    'general',
    CASE v_new_status
      WHEN 'processing' THEN 'Payout approved'
      WHEN 'completed' THEN 'Payout transferred'
      ELSE 'Payout request rejected'
    END,
    CASE v_new_status
      WHEN 'processing' THEN 'Your affiliate payout was approved and is awaiting transfer.'
      WHEN 'completed' THEN 'Your affiliate payout transfer has been completed.'
      ELSE 'Your affiliate payout was rejected and the reserved balance was returned.'
    END,
    'unread',
    jsonb_build_object('payout_id', v_payout.id, 'status', v_new_status, 'amount', v_payout.amount)
  );

  RETURN jsonb_build_object('success', TRUE, 'payout_id', v_payout.id, 'status', v_new_status);
END;
$$;


ALTER FUNCTION "public"."transition_affiliate_payout"("p_payout_id" "uuid", "p_action" "text", "p_notes" "text", "p_transfer_reference" "text") OWNER TO "postgres";

--
-- Name: transition_coach_withdrawal("uuid", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."transition_coach_withdrawal"("p_withdrawal_id" "uuid", "p_action" "text", "p_notes" "text" DEFAULT NULL::"text", "p_transfer_reference" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_admin_id UUID := auth.uid();
  v_action TEXT := LOWER(BTRIM(COALESCE(p_action, '')));
  v_request public.coach_withdrawal_requests%ROWTYPE;
  v_new_status TEXT;
BEGIN
  IF v_admin_id IS NULL OR NOT COALESCE(public.has_role(v_admin_id, 'admin'), FALSE) THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;
  IF COALESCE(LENGTH(p_notes), 0) > 1000
    OR COALESCE(LENGTH(p_transfer_reference), 0) > 160 THEN
    RAISE EXCEPTION 'INVALID_WITHDRAWAL_METADATA';
  END IF;

  SELECT *
  INTO v_request
  FROM public.coach_withdrawal_requests cwr
  WHERE cwr.id = p_withdrawal_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'WITHDRAWAL_NOT_FOUND';
  END IF;

  IF v_action = 'approve' AND v_request.status = 'pending' THEN
    v_new_status := 'approved';
    UPDATE public.coach_withdrawal_requests
    SET status = v_new_status,
        approved_at = NOW(),
        processed_by = v_admin_id,
        admin_notes = NULLIF(BTRIM(p_notes), '')
    WHERE id = v_request.id;
  ELSIF v_action = 'reject' AND v_request.status IN ('pending', 'approved') THEN
    v_new_status := 'rejected';
    UPDATE public.coach_withdrawal_requests
    SET status = v_new_status,
        processed_at = NOW(),
        processed_by = v_admin_id,
        admin_notes = NULLIF(BTRIM(p_notes), '')
    WHERE id = v_request.id;
  ELSIF v_action = 'process' AND v_request.status = 'approved' THEN
    IF NULLIF(BTRIM(p_transfer_reference), '') IS NULL THEN
      RAISE EXCEPTION 'TRANSFER_REFERENCE_REQUIRED';
    END IF;
    v_new_status := 'processed';
    UPDATE public.coach_withdrawal_requests
    SET status = v_new_status,
        processed_at = NOW(),
        processed_by = v_admin_id,
        transfer_reference = BTRIM(p_transfer_reference),
        admin_notes = COALESCE(NULLIF(BTRIM(p_notes), ''), admin_notes)
    WHERE id = v_request.id;
  ELSE
    RAISE EXCEPTION 'INVALID_WITHDRAWAL_TRANSITION_%_TO_%', v_request.status, v_action;
  END IF;

  INSERT INTO public.notifications (user_id, type, title, message, status, data)
  VALUES (
    v_request.coach_id,
    'coach_withdrawal',
    CASE v_new_status
      WHEN 'approved' THEN 'Withdrawal approved'
      WHEN 'processed' THEN 'Withdrawal transferred'
      ELSE 'Withdrawal rejected'
    END,
    CASE v_new_status
      WHEN 'approved' THEN 'Your withdrawal was approved and is awaiting bank transfer.'
      WHEN 'processed' THEN 'Your withdrawal transfer has been completed.'
      ELSE 'Your withdrawal was rejected. The reserved amount is available again.'
    END,
    'unread',
    jsonb_build_object('withdrawal_id', v_request.id, 'status', v_new_status, 'amount', v_request.amount)
  );

  RETURN jsonb_build_object('success', TRUE, 'withdrawal_id', v_request.id, 'status', v_new_status);
END;
$$;


ALTER FUNCTION "public"."transition_coach_withdrawal"("p_withdrawal_id" "uuid", "p_action" "text", "p_notes" "text", "p_transfer_reference" "text") OWNER TO "postgres";

--
-- Name: transition_driver_payout("uuid", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."transition_driver_payout"("p_payout_id" "uuid", "p_action" "text", "p_payment_reference" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_payout public.driver_payouts%ROWTYPE;
  v_new_status TEXT;
  v_balance NUMERIC(10, 2);
BEGIN
  IF v_actor IS NULL OR NOT (
    public.has_role(v_actor, 'admin')
    OR public.is_active_fleet_operator(v_actor)
  ) THEN
    RAISE EXCEPTION 'FLEET_OPERATOR_REQUIRED';
  END IF;

  SELECT * INTO v_payout
  FROM public.driver_payouts
  WHERE id = p_payout_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'PAYOUT_NOT_FOUND';
  END IF;

  v_new_status := CASE p_action
    WHEN 'start' THEN 'processing'
    WHEN 'pay' THEN 'paid'
    WHEN 'reject' THEN 'failed'
    ELSE NULL
  END;

  IF v_new_status IS NULL
    OR (p_action = 'start' AND v_payout.status <> 'pending')
    OR (p_action IN ('pay', 'reject') AND v_payout.status NOT IN ('pending', 'processing')) THEN
    RAISE EXCEPTION 'INVALID_PAYOUT_TRANSITION';
  END IF;

  IF p_action = 'pay' AND length(trim(COALESCE(p_payment_reference, ''))) < 3 THEN
    RAISE EXCEPTION 'PAYMENT_REFERENCE_REQUIRED';
  END IF;

  UPDATE public.driver_payouts
  SET status = v_new_status,
      payment_reference = CASE WHEN p_action = 'pay' THEN trim(p_payment_reference) ELSE payment_reference END,
      rejection_reason = CASE WHEN p_action = 'reject' THEN NULLIF(trim(p_notes), '') ELSE NULL END,
      processed_at = CASE WHEN p_action IN ('pay', 'reject') THEN now() ELSE processed_at END,
      processed_by = v_actor,
      updated_at = now()
  WHERE id = v_payout.id;

  IF p_action = 'reject' THEN
    PERFORM 1 FROM public.drivers WHERE id = v_payout.driver_id FOR UPDATE;
    PERFORM set_config('app.driver_finance_authorized', 'true', true);

    UPDATE public.drivers
    SET wallet_balance = COALESCE(wallet_balance, 0) + v_payout.amount,
        updated_at = now()
    WHERE id = v_payout.driver_id
    RETURNING wallet_balance INTO v_balance;

    INSERT INTO public.driver_wallet_transactions (
      driver_id,
      type,
      amount,
      balance_after,
      reference_type,
      reference_id,
      description
    )
    VALUES (
      v_payout.driver_id,
      'adjustment',
      v_payout.amount,
      v_balance,
      'withdrawal',
      v_payout.id,
      'Rejected payout returned to driver balance'
    );
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'payout_id', v_payout.id,
    'status', v_new_status,
    'amount', v_payout.amount
  );
END;
$$;


ALTER FUNCTION "public"."transition_driver_payout"("p_payout_id" "uuid", "p_action" "text", "p_payment_reference" "text", "p_notes" "text") OWNER TO "postgres";

--
-- Name: transition_legacy_partner_payout("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."transition_legacy_partner_payout"("p_payout_id" "uuid", "p_action" "text", "p_reference_number" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_payout public.payouts%ROWTYPE;
  v_status TEXT;
BEGIN
  IF v_actor IS NULL OR NOT public.has_role(v_actor, 'admin') THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;

  SELECT * INTO v_payout
  FROM public.payouts
  WHERE id = p_payout_id
  FOR UPDATE;

  IF NOT FOUND OR v_payout.status <> 'pending' THEN
    RAISE EXCEPTION 'INVALID_LEGACY_PAYOUT_TRANSITION';
  END IF;

  v_status := CASE p_action WHEN 'process' THEN 'processed' WHEN 'reject' THEN 'rejected' END;
  IF v_status IS NULL THEN
    RAISE EXCEPTION 'INVALID_LEGACY_PAYOUT_ACTION';
  END IF;

  IF p_action = 'process' AND length(trim(COALESCE(p_reference_number, ''))) < 3 THEN
    RAISE EXCEPTION 'TRANSFER_REFERENCE_REQUIRED';
  END IF;

  UPDATE public.payouts
  SET status = v_status,
      processed_at = CASE WHEN v_status = 'processed' THEN now() ELSE processed_at END,
      transfer_reference = CASE WHEN v_status = 'processed' THEN trim(p_reference_number) ELSE transfer_reference END,
      processed_by = v_actor,
      updated_at = now()
  WHERE id = v_payout.id;

  RETURN jsonb_build_object('success', true, 'payout_id', v_payout.id, 'status', v_status);
END;
$$;


ALTER FUNCTION "public"."transition_legacy_partner_payout"("p_payout_id" "uuid", "p_action" "text", "p_reference_number" "text") OWNER TO "postgres";

--
-- Name: transition_partner_payout("uuid", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."transition_partner_payout"("p_payout_id" "uuid", "p_action" "text", "p_reference_number" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_payout public.partner_payouts%ROWTYPE;
  v_new_status TEXT;
BEGIN
  IF v_actor IS NULL OR NOT public.has_role(v_actor, 'admin') THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;

  SELECT *
  INTO v_payout
  FROM public.partner_payouts
  WHERE id = p_payout_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'PAYOUT_NOT_FOUND';
  END IF;

  v_new_status := CASE p_action
    WHEN 'start' THEN 'processing'
    WHEN 'complete' THEN 'completed'
    WHEN 'reject' THEN 'failed'
    ELSE NULL
  END;

  IF v_new_status IS NULL
    OR (p_action = 'start' AND v_payout.status <> 'pending')
    OR (p_action IN ('complete', 'reject') AND v_payout.status NOT IN ('pending', 'processing')) THEN
    RAISE EXCEPTION 'INVALID_PAYOUT_TRANSITION';
  END IF;

  IF p_action = 'complete' AND length(trim(COALESCE(p_reference_number, ''))) < 3 THEN
    RAISE EXCEPTION 'TRANSFER_REFERENCE_REQUIRED';
  END IF;

  UPDATE public.partner_payouts
  SET status = v_new_status,
      reference_number = CASE
        WHEN p_action = 'complete' THEN trim(p_reference_number)
        ELSE reference_number
      END,
      processed_at = CASE WHEN p_action IN ('complete', 'reject') THEN now() ELSE processed_at END,
      processed_by = v_actor,
      rejection_reason = CASE WHEN p_action = 'reject' THEN NULLIF(trim(p_notes), '') ELSE NULL END,
      updated_at = now()
  WHERE id = v_payout.id;

  IF p_action = 'complete' THEN
    UPDATE public.partner_earnings
    SET status = 'paid'
    WHERE payout_id = v_payout.id;
  ELSIF p_action = 'reject' THEN
    UPDATE public.partner_earnings
    SET status = 'pending',
        payout_id = NULL
    WHERE payout_id = v_payout.id;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'payout_id', v_payout.id,
    'status', v_new_status,
    'amount', v_payout.amount
  );
END;
$$;


ALTER FUNCTION "public"."transition_partner_payout"("p_payout_id" "uuid", "p_action" "text", "p_reference_number" "text", "p_notes" "text") OWNER TO "postgres";

--
-- Name: transition_recovery_booking("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."transition_recovery_booking"("p_booking_id" "uuid", "p_status" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_booking public.recovery_bookings%ROWTYPE;
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role'
    AND NOT public.has_role(v_actor, 'admin') THEN
    RAISE EXCEPTION 'ADMIN_REQUIRED';
  END IF;

  IF p_status NOT IN ('completed', 'no_show') THEN
    RAISE EXCEPTION 'RECOVERY_BOOKING_STATUS_INVALID';
  END IF;

  SELECT *
    INTO v_booking
  FROM public.recovery_bookings rb
  WHERE rb.id = p_booking_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'RECOVERY_BOOKING_NOT_FOUND';
  END IF;

  IF v_booking.status = p_status THEN
    RETURN jsonb_build_object(
      'success', TRUE,
      'already_processed', TRUE,
      'booking_id', v_booking.id,
      'status', v_booking.status
    );
  END IF;

  IF v_booking.status <> 'booked' THEN
    RAISE EXCEPTION 'RECOVERY_BOOKING_TRANSITION_INVALID';
  END IF;

  UPDATE public.recovery_bookings
  SET status = p_status
  WHERE id = v_booking.id;

  RETURN jsonb_build_object(
    'success', TRUE,
    'already_processed', FALSE,
    'booking_id', v_booking.id,
    'status', p_status
  );
END;
$$;


ALTER FUNCTION "public"."transition_recovery_booking"("p_booking_id" "uuid", "p_status" "text") OWNER TO "postgres";

--
-- Name: trg_check_order_capacity(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trg_check_order_capacity"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_meal_restaurant_id UUID;
    v_capacity_check RECORD;
BEGIN
    -- Get restaurant ID from meal
    SELECT restaurant_id INTO v_meal_restaurant_id
    FROM public.meals
    WHERE id = NEW.meal_id;
    
    IF v_meal_restaurant_id IS NULL THEN
        RAISE EXCEPTION 'Meal not found or has no restaurant';
    END IF;
    
    -- Check capacity
    SELECT * INTO v_capacity_check
    FROM check_restaurant_capacity(v_meal_restaurant_id);
    
    IF NOT v_capacity_check.can_accept THEN
        RAISE EXCEPTION 'Restaurant has reached daily capacity: %', v_capacity_check.message;
    END IF;
    
    -- Increment count
    PERFORM increment_restaurant_order_count(v_meal_restaurant_id);
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trg_check_order_capacity"() OWNER TO "postgres";

--
-- Name: trigger_auto_group_delivery(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trigger_auto_group_delivery"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_grouped_schedules UUID[];
BEGIN
  -- Only process if delivery_group_id is not already set
  IF NEW.delivery_group_id IS NULL THEN
    -- Try to group this new schedule with existing pending schedules
    v_grouped_schedules := public.auto_group_deliveries(
      NEW.user_id,
      NEW.scheduled_date
    );
  END IF;
  
  RETURN NEW;
END;
$$;


