--
-- Name: trigger_calculate_driver_earnings(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trigger_calculate_driver_earnings"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Only recalculate if delivery_fee or tip changed
  IF TG_OP = 'INSERT' OR 
     (TG_OP = 'UPDATE' AND (
       NEW.delivery_fee IS DISTINCT FROM OLD.delivery_fee OR
       NEW.tip_amount IS DISTINCT FROM OLD.tip_amount
     )) THEN
    
    NEW.driver_earnings := calculate_driver_earnings(
      COALESCE(NEW.delivery_fee, 0),
      COALESCE(NEW.tip_amount, 0),
      NULL, -- city - could be enhanced with location lookup
      NEW.restaurant_id,
      NULL, -- distance - could be calculated from coordinates
      NEW.created_at
    );
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trigger_calculate_driver_earnings"() OWNER TO "postgres";

--
-- Name: trigger_push_notification(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trigger_push_notification"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Insert into the push notification queue for async processing
  -- The edge function will pick this up and send via FCM using its own env vars
  INSERT INTO public.push_notification_queue (
    notification_id,
    user_id,
    title,
    message,
    type,
    data,
    status
  ) VALUES (
    NEW.id,
    NEW.user_id,
    NEW.title,
    NEW.message,
    COALESCE(NEW.type::text, 'general'),
    COALESCE(NEW.data, '{}'::jsonb),
    'pending'
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trigger_push_notification"() OWNER TO "postgres";

--
-- Name: trigger_sync_community_challenges(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."trigger_sync_community_challenges"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_user_id := coalesce(
      nullif(to_jsonb(OLD)->>'user_id', '')::uuid,
      nullif(to_jsonb(OLD)->>'client_id', '')::uuid,
      nullif(to_jsonb(OLD)->>'referrer_id', '')::uuid
    );
  ELSE
    v_user_id := coalesce(
      nullif(to_jsonb(NEW)->>'user_id', '')::uuid,
      nullif(to_jsonb(NEW)->>'client_id', '')::uuid,
      nullif(to_jsonb(NEW)->>'referrer_id', '')::uuid
    );
  END IF;

  IF v_user_id IS NOT NULL THEN
    PERFORM public.sync_community_challenge_progress_for_user(v_user_id);
  END IF;

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."trigger_sync_community_challenges"() OWNER TO "postgres";

