COMMENT ON FUNCTION "public"."update_restaurant_branch_routing"("p_branch_id" "uuid", "p_is_accepting_orders" boolean, "p_max_orders_per_slot" integer, "p_service_radius_km" numeric, "p_avg_prep_time_minutes" integer, "p_routing_priority" integer, "p_routing_notes" "text") IS 'Safely updates operational routing controls for a restaurant branch owned by the current partner or by an admin.';


--
-- Name: update_restaurant_capacity("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."update_restaurant_capacity"("p_restaurant_id" "uuid", "p_max_meals_per_day" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF p_max_meals_per_day < 10 OR p_max_meals_per_day > 1000 THEN
    RAISE EXCEPTION 'INVALID_RESTAURANT_CAPACITY';
  END IF;
  IF auth.role() <> 'service_role'
     AND NOT public.has_role(auth.uid(), 'admin'::public.app_role)
     AND NOT public.is_restaurant_operator(p_restaurant_id, auth.uid()) THEN
    RAISE EXCEPTION 'RESTAURANT_OPERATOR_REQUIRED';
  END IF;
  UPDATE public.restaurants SET max_meals_per_day = p_max_meals_per_day WHERE id = p_restaurant_id;
END;
$$;


