--
-- Name: upgrade_subscription("uuid", character varying, character varying); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upgrade_subscription"("p_subscription_id" "uuid", "p_new_tier" character varying, "p_new_billing_interval" character varying DEFAULT NULL::character varying) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_current_sub RECORD;
    v_new_plan RECORD;
    v_prorated_credit DECIMAL(10,2);
    v_new_price DECIMAL(10,2);
    v_renewal_date DATE;
BEGIN
    SELECT * INTO v_current_sub
    FROM subscriptions
    WHERE id = p_subscription_id
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Subscription not found',
            'code', 'NOT_FOUND'
        );
    END IF;

    IF p_new_billing_interval IS NULL THEN
        p_new_billing_interval := COALESCE(v_current_sub.billing_interval, 'monthly');
    END IF;

    SELECT * INTO v_new_plan
    FROM subscription_plans
    WHERE tier = p_new_tier
    AND billing_interval = p_new_billing_interval
    AND is_active = true;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Target plan not found',
            'code', 'PLAN_NOT_FOUND'
        );
    END IF;

    v_prorated_credit := 0;
    v_renewal_date := COALESCE(v_current_sub.next_renewal_date, v_current_sub.end_date);
    IF v_renewal_date IS NOT NULL AND v_renewal_date > CURRENT_DATE THEN
        v_prorated_credit := COALESCE(v_current_sub.price, 0) *
            (v_renewal_date - CURRENT_DATE)::INTEGER / 30.0;
    END IF;

    v_new_price := GREATEST(0, v_new_plan.price_qar - v_prorated_credit);

    UPDATE subscriptions
    SET tier = p_new_tier,
        plan = p_new_tier,
        billing_interval = p_new_billing_interval,
        price = v_new_plan.price_qar,
        annual_discount_percent = v_new_plan.discount_percent,
        meals_per_month = v_new_plan.meals_per_month,
        prorated_credit = v_prorated_credit
    WHERE id = p_subscription_id;

    RETURN jsonb_build_object(
        'success', true,
        'prorated_credit', v_prorated_credit,
        'amount_due', v_new_price,
        'new_tier', p_new_tier,
        'new_billing_interval', p_new_billing_interval
    );
END;
$$;


ALTER FUNCTION "public"."upgrade_subscription"("p_subscription_id" "uuid", "p_new_tier" character varying, "p_new_billing_interval" character varying) OWNER TO "postgres";

--
-- Name: upgrade_subscription_with_wallet("uuid", "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upgrade_subscription_with_wallet"("p_user_id" "uuid", "p_subscription_id" "uuid", "p_plan_id" "uuid", "p_promo_code" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_subscription public.subscriptions%ROWTYPE;
  v_plan public.subscription_plans%ROWTYPE;
  v_promotion public.promotions%ROWTYPE;
  v_payment_id UUID := gen_random_uuid();
  v_wallet_transaction_id UUID;
  v_period_days INTEGER;
  v_remaining_days INTEGER;
  v_prorated_credit NUMERIC(10, 2) := 0;
  v_amount_before_discount NUMERIC(10, 2);
  v_discount NUMERIC(10, 2) := 0;
  v_amount_due NUMERIC(10, 2);
  v_user_promo_uses INTEGER := 0;
  v_period_end DATE;
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RAISE EXCEPTION 'SERVICE_ROLE_REQUIRED';
  END IF;

  SELECT *
    INTO v_subscription
  FROM public.subscriptions s
  WHERE s.id = p_subscription_id
    AND s.user_id = p_user_id
    AND s.status IN ('active', 'cancelled')
    AND (
      s.status = 'active'
      OR COALESCE(s.end_date, CURRENT_DATE - 1) >= CURRENT_DATE
    )
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'SUBSCRIPTION_NOT_FOUND';
  END IF;

  SELECT *
    INTO v_plan
  FROM public.subscription_plans sp
  WHERE sp.id = p_plan_id
    AND sp.is_active = TRUE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'PAYMENT_PLAN_NOT_FOUND';
  END IF;

  IF v_subscription.plan_id = v_plan.id
    OR (
      v_subscription.plan_id IS NULL
      AND v_subscription.tier = v_plan.tier
      AND COALESCE(v_subscription.billing_interval, 'monthly') = v_plan.billing_interval
    ) THEN
    RAISE EXCEPTION 'SUBSCRIPTION_PLAN_UNCHANGED';
  END IF;

  IF v_subscription.end_date IS NOT NULL
    AND v_subscription.start_date IS NOT NULL
    AND v_subscription.end_date::DATE > CURRENT_DATE THEN
    v_period_days := GREATEST(
      1,
      v_subscription.end_date::DATE - v_subscription.start_date::DATE
    );
    v_remaining_days := GREATEST(
      0,
      v_subscription.end_date::DATE - CURRENT_DATE
    );
    v_prorated_credit := ROUND(
      COALESCE(v_subscription.price, 0)::NUMERIC
        * v_remaining_days::NUMERIC
        / v_period_days::NUMERIC,
      2
    );
  END IF;

  v_amount_before_discount := ROUND(
    GREATEST(0, v_plan.price_qar::NUMERIC - v_prorated_credit),
    2
  );

  IF NULLIF(TRIM(p_promo_code), '') IS NOT NULL THEN
    SELECT *
      INTO v_promotion
    FROM public.promotions p
    WHERE UPPER(p.code) = UPPER(TRIM(p_promo_code))
      AND p.is_active = TRUE
      AND p.valid_from <= NOW()
      AND (p.valid_until IS NULL OR p.valid_until > NOW())
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'PROMOTION_INVALID';
    END IF;

    IF v_promotion.max_uses IS NOT NULL
      AND COALESCE(v_promotion.uses_count, 0) >= v_promotion.max_uses THEN
      RAISE EXCEPTION 'PROMOTION_LIMIT_REACHED';
    END IF;

    IF v_plan.price_qar < COALESCE(v_promotion.min_order_amount, 0) THEN
      RAISE EXCEPTION 'PROMOTION_MINIMUM_NOT_MET';
    END IF;

    SELECT COUNT(*)::INTEGER
      INTO v_user_promo_uses
    FROM public.promotion_usage pu
    WHERE pu.promotion_id = v_promotion.id
      AND pu.user_id = p_user_id;

    IF v_user_promo_uses >= COALESCE(v_promotion.max_uses_per_user, 1) THEN
      RAISE EXCEPTION 'PROMOTION_USER_LIMIT_REACHED';
    END IF;

    IF v_promotion.discount_type::TEXT = 'percentage' THEN
      v_discount := ROUND(
        v_plan.price_qar::NUMERIC * v_promotion.discount_value::NUMERIC / 100,
        2
      );
      IF v_promotion.max_discount_amount IS NOT NULL THEN
        v_discount := LEAST(v_discount, v_promotion.max_discount_amount::NUMERIC);
      END IF;
    ELSE
      v_discount := LEAST(
        v_plan.price_qar::NUMERIC,
        v_promotion.discount_value::NUMERIC
      );
    END IF;
  END IF;

  v_amount_due := ROUND(
    GREATEST(0, v_amount_before_discount - v_discount),
    2
  );

  IF v_amount_due > 0 THEN
    v_wallet_transaction_id := public.debit_wallet(
      p_user_id,
      v_amount_due,
      'subscription_upgrade',
      v_payment_id,
      'Subscription change to ' || v_plan.tier,
      jsonb_build_object(
        'subscription_id', p_subscription_id,
        'plan_id', v_plan.id,
        'prorated_credit', v_prorated_credit,
        'discount', v_discount
      )
    );
  END IF;

  v_period_end := CASE
    WHEN v_plan.billing_interval = 'annual'
      THEN CURRENT_DATE + INTERVAL '1 year'
    ELSE CURRENT_DATE + INTERVAL '1 month'
  END;

  INSERT INTO public.payments (
    id,
    user_id,
    payment_type,
    amount,
    currency,
    status,
    payment_method,
    gateway,
    gateway_reference,
    provider_transaction_id,
    wallet_transaction_id,
    description,
    metadata,
    idempotency_key,
    fulfillment_status,
    verified_at,
    completed_at,
    processed_at,
    created_at,
    updated_at
  ) VALUES (
    v_payment_id,
    p_user_id,
    'subscription',
    v_amount_due,
    'QAR',
    'completed',
    'wallet',
    'wallet',
    v_payment_id::TEXT,
    v_wallet_transaction_id::TEXT,
    v_wallet_transaction_id,
    'Subscription change to ' || v_plan.tier,
    jsonb_build_object(
      'mode', 'upgrade',
      'subscription_id', p_subscription_id,
      'plan_id', v_plan.id,
      'price_qar', v_plan.price_qar,
      'prorated_credit', v_prorated_credit,
      'discount', v_discount,
      'promotion_id', v_promotion.id
    ),
    gen_random_uuid(),
    'completed',
    NOW(),
    NOW(),
    NOW(),
    NOW(),
    NOW()
  );

  UPDATE public.subscriptions
  SET plan_id = v_plan.id,
      payment_id = v_payment_id,
      plan = v_plan.tier,
      plan_type = v_plan.tier,
      tier = v_plan.tier,
      status = 'active',
      active = TRUE,
      billing_interval = v_plan.billing_interval,
      price = v_plan.price_qar,
      price_per_meal = v_plan.price_per_meal,
      start_date = CURRENT_DATE,
      end_date = v_period_end,
      next_renewal_date = v_period_end,
      annual_renewal_date = CASE
        WHEN v_plan.billing_interval = 'annual' THEN v_period_end
        ELSE NULL
      END,
      meals_per_month = v_plan.meals_per_month,
      meals_used_this_month = 0,
      month_start_date = DATE_TRUNC('month', CURRENT_DATE)::DATE,
      meals_per_week = COALESCE(v_plan.meals_per_week, 0),
      meals_used_this_week = 0,
      week_start_date = DATE_TRUNC('week', CURRENT_DATE)::DATE,
      snacks_per_month = COALESCE(v_plan.snacks_per_month, 0),
      snacks_used_this_month = 0,
      annual_discount_percent = COALESCE(v_plan.discount_percent, 0),
      prorated_credit = v_prorated_credit,
      updated_at = NOW()
  WHERE id = v_subscription.id;

  IF v_promotion.id IS NOT NULL THEN
    INSERT INTO public.promotion_usage (
      promotion_id,
      user_id,
      discount_applied
    ) VALUES (
      v_promotion.id,
      p_user_id,
      v_discount
    );
  END IF;

  RETURN jsonb_build_object(
    'success', TRUE,
    'payment_id', v_payment_id,
    'subscription_id', v_subscription.id,
    'plan_id', v_plan.id,
    'prorated_credit', v_prorated_credit,
    'discount', v_discount,
    'amount_due', v_amount_due,
    'new_tier', v_plan.tier,
    'new_billing_interval', v_plan.billing_interval
  );
END;
$$;


ALTER FUNCTION "public"."upgrade_subscription_with_wallet"("p_user_id" "uuid", "p_subscription_id" "uuid", "p_plan_id" "uuid", "p_promo_code" "text") OWNER TO "postgres";

--
-- Name: FUNCTION "upgrade_subscription_with_wallet"("p_user_id" "uuid", "p_subscription_id" "uuid", "p_plan_id" "uuid", "p_promo_code" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."upgrade_subscription_with_wallet"("p_user_id" "uuid", "p_subscription_id" "uuid", "p_plan_id" "uuid", "p_promo_code" "text") IS 'Service-only atomic wallet charge, promotion redemption, payment audit, and subscription plan change.';


--
-- Name: upsert_google_fit_server_credentials("uuid", "text", "text", bigint, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_google_fit_server_credentials"("p_user_id" "uuid", "p_access_token" "text", "p_refresh_token" "text", "p_expires_at" bigint, "p_scope" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public', 'extensions', 'pg_temp'
    AS $$
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RAISE EXCEPTION 'Service role required';
  END IF;

  IF p_access_token IS NULL
     OR char_length(p_access_token) < 16
     OR p_expires_at <= extract(epoch FROM clock_timestamp())::BIGINT THEN
    RAISE EXCEPTION 'Invalid OAuth credential payload';
  END IF;

  INSERT INTO public.user_integrations (
    user_id,
    provider,
    access_token,
    refresh_token,
    access_token_encrypted,
    refresh_token_encrypted,
    expires_at,
    scope,
    created_at,
    updated_at
  ) VALUES (
    p_user_id,
    'google_fit',
    NULL,
    NULL,
    security.encrypt_oauth_token(p_access_token),
    CASE
      WHEN p_refresh_token IS NOT NULL
        THEN security.encrypt_oauth_token(p_refresh_token)
      ELSE NULL
    END,
    p_expires_at,
    p_scope,
    clock_timestamp(),
    clock_timestamp()
  )
  ON CONFLICT (user_id, provider) DO UPDATE
  SET access_token = NULL,
      refresh_token = NULL,
      access_token_encrypted = EXCLUDED.access_token_encrypted,
      refresh_token_encrypted = COALESCE(
        EXCLUDED.refresh_token_encrypted,
        public.user_integrations.refresh_token_encrypted
      ),
      expires_at = EXCLUDED.expires_at,
      scope = COALESCE(EXCLUDED.scope, public.user_integrations.scope),
      updated_at = clock_timestamp();
END;
$$;


ALTER FUNCTION "public"."upsert_google_fit_server_credentials"("p_user_id" "uuid", "p_access_token" "text", "p_refresh_token" "text", "p_expires_at" bigint, "p_scope" "text") OWNER TO "postgres";

--
-- Name: health_context_entries; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."health_context_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" NOT NULL,
    "entry_date" "date" NOT NULL,
    "mood" smallint,
    "stress" smallint,
    "appetite" smallint,
    "energy" smallint,
    "digestive_symptoms" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "symptom_severity" smallint,
    "cycle_phase" "text",
    "bleeding_flow" "text",
    "note" "text",
    "created_at" timestamp with time zone DEFAULT "clock_timestamp"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "clock_timestamp"() NOT NULL,
    CONSTRAINT "health_context_digestive_symptoms_allowed" CHECK ((("cardinality"("digestive_symptoms") <= 6) AND ("digestive_symptoms" <@ ARRAY['bloating'::"text", 'reflux'::"text", 'constipation'::"text", 'diarrhea'::"text", 'nausea'::"text", 'discomfort'::"text"]))),
    CONSTRAINT "health_context_entries_appetite_check" CHECK ((("appetite" >= 1) AND ("appetite" <= 5))),
    CONSTRAINT "health_context_entries_bleeding_flow_check" CHECK ((("bleeding_flow" IS NULL) OR ("bleeding_flow" = ANY (ARRAY['none'::"text", 'spotting'::"text", 'light'::"text", 'medium'::"text", 'heavy'::"text"])))),
    CONSTRAINT "health_context_entries_cycle_phase_check" CHECK ((("cycle_phase" IS NULL) OR ("cycle_phase" = ANY (ARRAY['menstrual'::"text", 'follicular'::"text", 'ovulatory'::"text", 'luteal'::"text"])))),
    CONSTRAINT "health_context_entries_energy_check" CHECK ((("energy" >= 1) AND ("energy" <= 5))),
    CONSTRAINT "health_context_entries_mood_check" CHECK ((("mood" >= 1) AND ("mood" <= 5))),
    CONSTRAINT "health_context_entries_note_check" CHECK ((("note" IS NULL) OR ("char_length"("note") <= 800))),
    CONSTRAINT "health_context_entries_stress_check" CHECK ((("stress" >= 1) AND ("stress" <= 5))),
    CONSTRAINT "health_context_entries_symptom_severity_check" CHECK ((("symptom_severity" >= 0) AND ("symptom_severity" <= 4))),
    CONSTRAINT "health_context_entry_has_value" CHECK ((("mood" IS NOT NULL) OR ("stress" IS NOT NULL) OR ("appetite" IS NOT NULL) OR ("energy" IS NOT NULL) OR ("cardinality"("digestive_symptoms") > 0) OR ("symptom_severity" IS NOT NULL) OR ("cycle_phase" IS NOT NULL) OR ("bleeding_flow" IS NOT NULL) OR (NULLIF(TRIM(BOTH FROM "note"), ''::"text") IS NOT NULL)))
);

ALTER TABLE ONLY "public"."health_context_entries" FORCE ROW LEVEL SECURITY;


ALTER TABLE "public"."health_context_entries" OWNER TO "postgres";

--
-- Name: TABLE "health_context_entries"; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON TABLE "public"."health_context_entries" IS 'Private user-entered health context. It is never a diagnosis, fertility prediction, or social dataset.';


--
-- Name: upsert_health_context_entry("date", smallint, smallint, smallint, smallint, "text"[], smallint, "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_health_context_entry"("p_entry_date" "date", "p_mood" smallint DEFAULT NULL::smallint, "p_stress" smallint DEFAULT NULL::smallint, "p_appetite" smallint DEFAULT NULL::smallint, "p_energy" smallint DEFAULT NULL::smallint, "p_digestive_symptoms" "text"[] DEFAULT '{}'::"text"[], "p_symptom_severity" smallint DEFAULT NULL::smallint, "p_cycle_phase" "text" DEFAULT NULL::"text", "p_bleeding_flow" "text" DEFAULT NULL::"text", "p_note" "text" DEFAULT NULL::"text") RETURNS "public"."health_context_entries"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_preferences public.health_context_preferences%ROWTYPE;
  v_entry public.health_context_entries%ROWTYPE;
BEGIN
  IF v_actor IS NULL THEN RAISE EXCEPTION 'AUTHENTICATION_REQUIRED'; END IF;
  IF NOT public.health_context_feature_enabled() THEN RAISE EXCEPTION 'HEALTH_CONTEXT_DISABLED'; END IF;
  IF p_entry_date IS NULL OR p_entry_date > CURRENT_DATE + 1 OR p_entry_date < CURRENT_DATE - 730 THEN
    RAISE EXCEPTION 'INVALID_HEALTH_CONTEXT_DATE';
  END IF;

  SELECT * INTO v_preferences
  FROM public.health_context_preferences
  WHERE user_id = v_actor;
  IF NOT FOUND OR NOT v_preferences.journal_enabled THEN
    RAISE EXCEPTION 'HEALTH_CONTEXT_OPT_IN_REQUIRED';
  END IF;
  IF (p_cycle_phase IS NOT NULL OR p_bleeding_flow IS NOT NULL)
     AND NOT v_preferences.cycle_tracking_enabled THEN
    RAISE EXCEPTION 'CYCLE_CONTEXT_OPT_IN_REQUIRED';
  END IF;

  INSERT INTO public.health_context_entries (
    user_id, entry_date, mood, stress, appetite, energy, digestive_symptoms,
    symptom_severity, cycle_phase, bleeding_flow, note, updated_at
  ) VALUES (
    v_actor,
    p_entry_date,
    CASE WHEN v_preferences.mood_enabled THEN p_mood ELSE NULL END,
    CASE WHEN v_preferences.stress_enabled THEN p_stress ELSE NULL END,
    CASE WHEN v_preferences.appetite_enabled THEN p_appetite ELSE NULL END,
    CASE WHEN v_preferences.energy_enabled THEN p_energy ELSE NULL END,
    CASE WHEN v_preferences.digestive_enabled THEN COALESCE(p_digestive_symptoms, '{}'::TEXT[]) ELSE '{}'::TEXT[] END,
    CASE WHEN v_preferences.digestive_enabled THEN p_symptom_severity ELSE NULL END,
    CASE WHEN v_preferences.cycle_tracking_enabled THEN p_cycle_phase ELSE NULL END,
    CASE WHEN v_preferences.cycle_tracking_enabled THEN p_bleeding_flow ELSE NULL END,
    CASE WHEN v_preferences.note_enabled THEN NULLIF(trim(p_note), '') ELSE NULL END,
    clock_timestamp()
  )
  ON CONFLICT (user_id, entry_date) DO UPDATE SET
    mood = EXCLUDED.mood,
    stress = EXCLUDED.stress,
    appetite = EXCLUDED.appetite,
    energy = EXCLUDED.energy,
    digestive_symptoms = EXCLUDED.digestive_symptoms,
    symptom_severity = EXCLUDED.symptom_severity,
    cycle_phase = EXCLUDED.cycle_phase,
    bleeding_flow = EXCLUDED.bleeding_flow,
    note = EXCLUDED.note,
    updated_at = clock_timestamp()
  RETURNING * INTO v_entry;

  RETURN v_entry;
END;
$$;


ALTER FUNCTION "public"."upsert_health_context_entry"("p_entry_date" "date", "p_mood" smallint, "p_stress" smallint, "p_appetite" smallint, "p_energy" smallint, "p_digestive_symptoms" "text"[], "p_symptom_severity" smallint, "p_cycle_phase" "text", "p_bleeding_flow" "text", "p_note" "text") OWNER TO "postgres";

--
-- Name: upsert_my_adherence_goal("text", integer, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_my_adherence_goal"("p_metric" "text", "p_frequency_per_week" integer, "p_target_value" numeric) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_user_id UUID := auth.uid();
  v_goal_id UUID;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'AUTHENTICATION_REQUIRED'; END IF;
  IF p_metric NOT IN ('meal_logging', 'activity', 'water') THEN
    RAISE EXCEPTION 'INVALID_ADHERENCE_METRIC';
  END IF;
  IF p_frequency_per_week NOT BETWEEN 1 AND 7 THEN
    RAISE EXCEPTION 'INVALID_WEEKLY_FREQUENCY';
  END IF;
  IF p_target_value IS NULL OR p_target_value <= 0 THEN
    RAISE EXCEPTION 'INVALID_TARGET_VALUE';
  END IF;

  INSERT INTO public.adherence_goals (
    user_id, metric, frequency_per_week, target_value, is_active, updated_at
  ) VALUES (
    v_user_id, p_metric, p_frequency_per_week, p_target_value, TRUE, now()
  )
  ON CONFLICT (user_id, metric) DO UPDATE SET
    frequency_per_week = EXCLUDED.frequency_per_week,
    target_value = EXCLUDED.target_value,
    is_active = TRUE,
    updated_at = now()
  RETURNING id INTO v_goal_id;

  RETURN v_goal_id;
END;
$$;


ALTER FUNCTION "public"."upsert_my_adherence_goal"("p_metric" "text", "p_frequency_per_week" integer, "p_target_value" numeric) OWNER TO "postgres";

--
-- Name: upsert_wearable_sync_state("text", "text", "jsonb", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_wearable_sync_state"("p_provider" "text", "p_status" "text", "p_cursor" "jsonb" DEFAULT '{}'::"jsonb", "p_error_message" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_user_id uuid := auth.uid();
begin
  if v_user_id is null then
    raise exception 'AUTH_REQUIRED' using errcode = '42501';
  end if;

  insert into public.wearable_sync_sources (
    user_id,
    provider,
    status,
    sync_cursor,
    source_precedence,
    last_success_at,
    last_error_at,
    last_error_message,
    updated_at
  )
  values (
    v_user_id,
    p_provider,
    p_status,
    coalesce(p_cursor, '{}'::jsonb),
    public.wearable_provider_precedence(p_provider),
    case when p_status = 'synced' then now() else null end,
    case when p_status = 'error' then now() else null end,
    p_error_message,
    now()
  )
  on conflict (user_id, provider)
  do update set
    status = excluded.status,
    sync_cursor = excluded.sync_cursor,
    source_precedence = excluded.source_precedence,
    last_success_at = coalesce(excluded.last_success_at, public.wearable_sync_sources.last_success_at),
    last_error_at = coalesce(excluded.last_error_at, public.wearable_sync_sources.last_error_at),
    last_error_message = excluded.last_error_message,
    revoked_at = case when excluded.status = 'revoked' then now() else public.wearable_sync_sources.revoked_at end,
    updated_at = now();
end;
$$;


ALTER FUNCTION "public"."upsert_wearable_sync_state"("p_provider" "text", "p_status" "text", "p_cursor" "jsonb", "p_error_message" "text") OWNER TO "postgres";

--
-- Name: use_rollover_credit_if_available("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."use_rollover_credit_if_available"("p_subscription_id" "uuid", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_is_service BOOLEAN := COALESCE(auth.role(), '') = 'service_role';
  v_subscription public.subscriptions%ROWTYPE;
  v_rollover public.subscription_rollovers%ROWTYPE;
  v_remaining INTEGER;
  v_total_remaining INTEGER;
BEGIN
  IF NOT v_is_service AND (
    v_actor IS NULL
    OR p_user_id IS DISTINCT FROM v_actor
  ) THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  PERFORM pg_advisory_xact_lock(
    hashtextextended(p_subscription_id::TEXT, 0)
  );

  SELECT *
    INTO v_subscription
  FROM public.subscriptions s
  WHERE s.id = p_subscription_id
    AND s.user_id = p_user_id
    AND s.status IN ('active', 'cancelled')
    AND COALESCE(s.end_date, CURRENT_DATE) >= CURRENT_DATE
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'ACTIVE_SUBSCRIPTION_NOT_FOUND';
  END IF;

  SELECT *
    INTO v_rollover
  FROM public.subscription_rollovers sr
  WHERE sr.user_id = p_user_id
    AND sr.subscription_id = p_subscription_id
    AND sr.status = 'active'
    AND sr.is_consumed = FALSE
    AND sr.expiry_date >= CURRENT_DATE
    AND sr.rollover_credits > 0
  ORDER BY sr.expiry_date ASC, sr.created_at ASC
  LIMIT 1
  FOR UPDATE;

  IF NOT FOUND THEN
    UPDATE public.subscriptions
    SET rollover_credits = 0,
        updated_at = NOW()
    WHERE id = p_subscription_id
      AND user_id = p_user_id;

    RETURN jsonb_build_object(
      'used_rollover', FALSE,
      'rollover_remaining', 0
    );
  END IF;

  v_remaining := v_rollover.rollover_credits - 1;

  UPDATE public.subscription_rollovers
  SET rollover_credits = GREATEST(0, v_remaining),
      status = CASE WHEN v_remaining <= 0 THEN 'consumed' ELSE 'active' END,
      is_consumed = v_remaining <= 0,
      consumed_at = CASE
        WHEN v_remaining <= 0 THEN COALESCE(consumed_at, NOW())
        ELSE NULL
      END,
      updated_at = NOW()
  WHERE id = v_rollover.id;

  SELECT COALESCE(SUM(sr.rollover_credits), 0)::INTEGER
    INTO v_total_remaining
  FROM public.subscription_rollovers sr
  WHERE sr.user_id = p_user_id
    AND sr.subscription_id = p_subscription_id
    AND sr.status = 'active'
    AND sr.is_consumed = FALSE
    AND sr.expiry_date >= CURRENT_DATE;

  UPDATE public.subscriptions
  SET rollover_credits = v_total_remaining,
      updated_at = NOW()
  WHERE id = p_subscription_id
    AND user_id = p_user_id;

  RETURN jsonb_build_object(
    'used_rollover', TRUE,
    'rollover_remaining', v_total_remaining,
    'rollover_id', v_rollover.id
  );
END;
$$;


ALTER FUNCTION "public"."use_rollover_credit_if_available"("p_subscription_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "use_rollover_credit_if_available"("p_subscription_id" "uuid", "p_user_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."use_rollover_credit_if_available"("p_subscription_id" "uuid", "p_user_id" "uuid") IS 'Deducts 1 rollover credit from the soonest-expiring active rollover record. Called when a meal is scheduled.';


--
-- Name: validate_delivery_job_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."validate_delivery_job_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_is_service BOOLEAN := false;
  v_is_admin BOOLEAN := false;
  v_is_fleet BOOLEAN := false;
  v_is_driver BOOLEAN := false;
  v_is_customer BOOLEAN := false;
  v_is_partner BOOLEAN := false;
  v_actor_role TEXT;
  v_status_changed BOOLEAN := false;
  v_driver_changed BOOLEAN := false;
  v_link_changed BOOLEAN := false;
  v_valid_transition BOOLEAN := false;
BEGIN
  v_is_service :=
    COALESCE(current_setting('request.jwt.claim.role', true), '') = 'service_role'
    OR (v_actor IS NULL AND session_user IN ('postgres', 'supabase_admin'));

  IF TG_OP = 'INSERT' THEN
    v_status_changed := true;
    v_driver_changed := NEW.driver_id IS NOT NULL;
  ELSE
    v_status_changed := OLD.status IS DISTINCT FROM NEW.status;
    v_driver_changed := OLD.driver_id IS DISTINCT FROM NEW.driver_id;
    v_link_changed := OLD.schedule_id IS DISTINCT FROM NEW.schedule_id
      OR OLD.restaurant_id IS DISTINCT FROM NEW.restaurant_id;
  END IF;

  IF NOT v_status_changed AND NOT v_driver_changed AND NOT v_link_changed THEN
    RETURN NEW;
  END IF;

  IF v_actor IS NOT NULL THEN
    v_is_admin := public.has_role(v_actor, 'admin');
    v_is_fleet := public.is_active_fleet_operator(v_actor);
    v_is_driver := EXISTS (
      SELECT 1
      FROM public.drivers d
      WHERE d.user_id = v_actor
        AND d.id = COALESCE(NEW.driver_id, CASE WHEN TG_OP = 'UPDATE' THEN OLD.driver_id END)
    );
    v_is_customer := EXISTS (
      SELECT 1
      FROM public.meal_schedules ms
      WHERE ms.id = NEW.schedule_id
        AND ms.user_id = v_actor
    );
    v_is_partner := EXISTS (
      SELECT 1
      FROM public.restaurants r
      WHERE r.id = NEW.restaurant_id
        AND public.is_restaurant_operator(r.id, v_actor)
    ) OR EXISTS (
      SELECT 1
      FROM public.meal_schedules ms
      JOIN public.meals m ON m.id = ms.meal_id
      JOIN public.restaurants r ON r.id = m.restaurant_id
      WHERE ms.id = NEW.schedule_id
        AND public.is_restaurant_operator(r.id, v_actor)
    );
  END IF;

  IF TG_OP = 'INSERT' THEN
    IF NEW.status IS NULL THEN
      NEW.status := 'pending';
    END IF;

    IF NOT (
      v_is_service OR v_is_admin OR v_is_fleet
      OR ((v_is_customer OR v_is_partner) AND NEW.status = 'pending' AND NEW.driver_id IS NULL)
    ) THEN
      RAISE EXCEPTION 'You are not allowed to create this delivery job';
    END IF;

    v_actor_role := CASE
      WHEN v_is_service THEN 'system'
      WHEN v_is_admin THEN 'admin'
      WHEN v_is_fleet THEN 'fleet'
      WHEN v_is_partner THEN 'partner'
      ELSE 'customer'
    END;
  ELSE
    IF v_status_changed THEN
      v_valid_transition := CASE OLD.status
        WHEN 'pending' THEN NEW.status IN ('assigned', 'cancelled')
        WHEN 'assigned' THEN NEW.status IN ('accepted', 'pending', 'picked_up', 'failed', 'cancelled')
        WHEN 'accepted' THEN NEW.status IN ('picked_up', 'failed', 'cancelled')
        WHEN 'picked_up' THEN NEW.status IN ('in_transit', 'delivered', 'failed', 'cancelled')
        WHEN 'in_transit' THEN NEW.status IN ('delivered', 'failed', 'cancelled')
        WHEN 'delivered' THEN NEW.status = 'completed'
        ELSE false
      END;

      IF NOT v_valid_transition THEN
        RAISE EXCEPTION 'Invalid delivery status transition from % to %', OLD.status, NEW.status;
      END IF;
    END IF;

    IF v_is_service THEN
      v_actor_role := 'system';
    ELSIF v_is_admin THEN
      v_actor_role := 'admin';
    ELSIF v_is_fleet THEN
      v_actor_role := 'fleet';
    ELSIF v_is_driver AND (
      (OLD.status = 'pending' AND NEW.status = 'assigned'
        AND COALESCE(current_setting('app.delivery_claim_authorized', true), '') = 'true')
      OR (OLD.status = 'assigned' AND NEW.status IN ('accepted', 'pending', 'picked_up', 'failed'))
      OR (OLD.status = 'accepted' AND NEW.status IN ('picked_up', 'failed'))
      OR (OLD.status = 'picked_up' AND NEW.status IN ('in_transit', 'delivered', 'failed'))
      OR (OLD.status = 'in_transit' AND NEW.status IN ('delivered', 'failed'))
    ) THEN
      v_actor_role := 'driver';
    ELSIF v_is_partner AND (
      (OLD.status IN ('pending', 'assigned', 'accepted') AND NEW.status = 'cancelled')
      OR (OLD.status IN ('assigned', 'accepted') AND NEW.status = 'picked_up')
    ) THEN
      v_actor_role := 'partner';
    ELSIF v_is_customer
      AND OLD.status IN ('pending', 'assigned')
      AND NEW.status = 'cancelled' THEN
      v_actor_role := 'customer';
    ELSE
      RAISE EXCEPTION 'You are not allowed to perform this delivery change';
    END IF;

    IF v_driver_changed AND NOT (
      v_is_service OR v_is_admin OR v_is_fleet
      OR (v_actor_role = 'driver' AND (
        (OLD.status = 'pending' AND NEW.status = 'assigned')
        OR (OLD.status = 'assigned' AND NEW.status = 'pending' AND NEW.driver_id IS NULL)
      ))
    ) THEN
      RAISE EXCEPTION 'Only fleet operators can reassign a delivery';
    END IF;

    IF v_link_changed AND NOT (v_is_service OR v_is_admin OR v_is_fleet) THEN
      RAISE EXCEPTION 'Only fleet operators can relink a delivery';
    END IF;
  END IF;

  IF NEW.status = 'assigned' THEN
    NEW.assigned_at := COALESCE(NEW.assigned_at, now());
  ELSIF NEW.status = 'accepted' THEN
    NEW.accepted_at := COALESCE(NEW.accepted_at, now());
  ELSIF NEW.status = 'picked_up' THEN
    NEW.picked_up_at := COALESCE(NEW.picked_up_at, now());
  ELSIF NEW.status = 'delivered' THEN
    NEW.delivered_at := COALESCE(NEW.delivered_at, now());
  ELSIF NEW.status = 'failed' THEN
    NEW.failed_at := COALESCE(NEW.failed_at, now());
  END IF;

  IF TG_OP = 'UPDATE' AND v_status_changed THEN
    INSERT INTO public.delivery_job_status_history (
      delivery_job_id, previous_status, new_status, changed_by, changed_by_role
    ) VALUES (
      NEW.id, OLD.status, NEW.status, v_actor, v_actor_role
    );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_delivery_job_change"() OWNER TO "postgres";

--
-- Name: validate_delivery_job_source(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."validate_delivery_job_source"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_is_service BOOLEAN :=
    COALESCE(auth.role(), '') = 'service_role'
    OR session_user IN ('postgres', 'supabase_admin');
  v_is_fleet BOOLEAN := public.is_active_fleet_operator(v_actor);
  v_is_admin BOOLEAN := public.has_role(v_actor, 'admin');
  v_order_restaurant_id UUID;
BEGIN
  IF num_nonnulls(NEW.schedule_id, NEW.order_id) <> 1 THEN
    RAISE EXCEPTION 'DELIVERY_JOB_REQUIRES_EXACTLY_ONE_SOURCE';
  END IF;

  IF NEW.order_id IS NOT NULL THEN
    SELECT o.restaurant_id
      INTO v_order_restaurant_id
    FROM public.orders o
    WHERE o.id = NEW.order_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'DELIVERY_ORDER_NOT_FOUND';
    END IF;

    IF NEW.restaurant_id IS NULL THEN
      NEW.restaurant_id := v_order_restaurant_id;
    ELSIF NEW.restaurant_id IS DISTINCT FROM v_order_restaurant_id THEN
      RAISE EXCEPTION 'DELIVERY_ORDER_RESTAURANT_MISMATCH';
    END IF;
  END IF;

  IF TG_OP = 'INSERT' AND NEW.order_id IS NOT NULL
    AND NOT (v_is_service OR v_is_admin OR v_is_fleet) THEN
    RAISE EXCEPTION 'ONLY_FLEET_CAN_CREATE_ORDER_DELIVERY';
  END IF;

  IF TG_OP = 'UPDATE'
    AND (
      NEW.order_id IS DISTINCT FROM OLD.order_id
      OR NEW.schedule_id IS DISTINCT FROM OLD.schedule_id
    )
    AND NOT (v_is_service OR v_is_admin OR v_is_fleet) THEN
    RAISE EXCEPTION 'ONLY_FLEET_CAN_RELINK_DELIVERY';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_delivery_job_source"() OWNER TO "postgres";

--
-- Name: validate_delivery_status_transition(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."validate_delivery_status_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$ BEGIN IF OLD.status IS DISTINCT FROM NEW.status THEN IF OLD.status IN ('completed', 'cancelled') THEN RAISE EXCEPTION 'Cannot transition from %', OLD.status; END IF; END IF; RETURN NEW; END; $$;


ALTER FUNCTION "public"."validate_delivery_status_transition"() OWNER TO "postgres";

--
-- Name: validate_order_status_transition(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."validate_order_status_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_actor_role TEXT;
BEGIN
  IF OLD.order_status IS NOT DISTINCT FROM NEW.order_status THEN
    RETURN NEW;
  END IF;

  IF NOT NEW.order_status = ANY(public.get_valid_next_statuses(OLD.order_status)) THEN
    RAISE EXCEPTION 'Invalid order status transition from % to %',
      OLD.order_status, NEW.order_status;
  END IF;

  v_actor_role := NULLIF(current_setting('app.current_user_role', true), '');
  IF v_actor_role IS NULL THEN
    IF COALESCE(current_setting('request.jwt.claim.role', true), '') = 'service_role'
       OR (v_actor IS NULL AND session_user IN ('postgres', 'supabase_admin')) THEN
      v_actor_role := 'system';
    ELSIF public.has_role(v_actor, 'admin') THEN
      v_actor_role := 'admin';
    ELSIF EXISTS (
      SELECT 1 FROM public.drivers d
      WHERE d.user_id = v_actor
    ) THEN
      v_actor_role := 'driver';
    ELSIF EXISTS (
      SELECT 1
      FROM public.restaurants r
      WHERE public.is_restaurant_operator(r.id, v_actor)
    ) THEN
      v_actor_role := 'partner';
    ELSE
      v_actor_role := 'customer';
    END IF;
  END IF;

  INSERT INTO public.order_status_history (
    order_id, previous_status, new_status, changed_by, changed_by_role, changed_at
  ) VALUES (
    NEW.id, OLD.order_status, NEW.order_status, v_actor, v_actor_role, now()
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_order_status_transition"() OWNER TO "postgres";

--
-- Name: FUNCTION "validate_order_status_transition"(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."validate_order_status_transition"() IS 'Validates order status transitions and logs changes to order_status_history';


--
-- Name: verify_notification_worker_secret("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."verify_notification_worker_secret"("p_candidate" "text") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'security', 'vault', 'extensions', 'pg_temp'
    AS $$
DECLARE
  v_expected TEXT;
BEGIN
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RETURN false;
  END IF;

  SELECT decrypted_secret INTO v_expected
  FROM vault.decrypted_secrets
  WHERE name = 'notification_worker_secret'
  ORDER BY created_at DESC
  LIMIT 1;

  RETURN v_expected IS NOT NULL
    AND p_candidate IS NOT NULL
    AND char_length(p_candidate) BETWEEN 32 AND 256
    AND extensions.digest(v_expected, 'sha256') = extensions.digest(p_candidate, 'sha256');
END;
$$;


ALTER FUNCTION "public"."verify_notification_worker_secret"("p_candidate" "text") OWNER TO "postgres";

--
-- Name: verify_pickup_by_code("text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."verify_pickup_by_code"("p_verification_code" "text", "p_driver_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $_$
DECLARE
  v_actor UUID := auth.uid();
  v_job public.delivery_jobs%ROWTYPE;
  v_hash TEXT;
  v_attempts INTEGER;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;

  IF p_driver_id IS NULL OR p_verification_code !~ '^[0-9]{6}$' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid verification code');
  END IF;

  SELECT dj.*
  INTO v_job
  FROM public.delivery_jobs dj
  JOIN public.drivers d ON d.id = dj.driver_id
  WHERE d.id = p_driver_id
    AND d.user_id = v_actor
    AND dj.status IN ('assigned', 'accepted')
  ORDER BY (d.current_job_id = dj.id) DESC, dj.assigned_at DESC NULLS LAST, dj.created_at DESC
  LIMIT 1
  FOR UPDATE OF dj;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'No assigned delivery is ready for verification');
  END IF;

  IF COALESCE(v_job.is_verification_locked, false) THEN
    RETURN jsonb_build_object('success', false, 'error', 'Verification is locked. Ask the restaurant for a new code.');
  END IF;

  IF v_job.verification_expires_at IS NOT NULL AND v_job.verification_expires_at <= now() THEN
    RETURN jsonb_build_object('success', false, 'error', 'Verification code has expired');
  END IF;

  v_hash := encode(sha256(convert_to(p_verification_code, 'UTF8')), 'hex');

  IF NOT (
    v_job.verification_code_hash = v_hash
    OR v_job.pickup_verification_code = p_verification_code
  ) THEN
    v_attempts := COALESCE(v_job.verification_attempts, 0) + 1;

    UPDATE public.delivery_jobs
    SET verification_attempts = v_attempts,
        is_verification_locked = v_attempts >= 5,
        updated_at = now()
    WHERE id = v_job.id;

    RETURN jsonb_build_object(
      'success', false,
      'error', CASE
        WHEN v_attempts >= 5 THEN 'Verification is locked. Ask the restaurant for a new code.'
        ELSE 'Invalid verification code'
      END,
      'remaining_attempts', GREATEST(0, 5 - v_attempts)
    );
  END IF;

  UPDATE public.delivery_jobs
  SET status = 'picked_up',
      picked_up_at = COALESCE(picked_up_at, now()),
      qr_scanned_at = NULL,
      handover_method = 'manual',
      verification_attempts = 0,
      is_verification_locked = false,
      verification_code_hash = NULL,
      pickup_verification_code = NULL,
      verification_expires_at = NULL,
      updated_at = now()
  WHERE id = v_job.id;

  RETURN jsonb_build_object(
    'success', true,
    'message', 'Pickup verified successfully',
    'job_id', v_job.id,
    'status', 'picked_up'
  );
END;
$_$;


ALTER FUNCTION "public"."verify_pickup_by_code"("p_verification_code" "text", "p_driver_id" "uuid") OWNER TO "postgres";

--
-- Name: FUNCTION "verify_pickup_by_code"("p_verification_code" "text", "p_driver_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."verify_pickup_by_code"("p_verification_code" "text", "p_driver_id" "uuid") IS 'Verify driver pickup using 6-digit code';


--
-- Name: verify_pickup_by_qr("uuid", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."verify_pickup_by_qr"("p_delivery_id" "uuid", "p_qr_code" "text", "p_driver_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_actor UUID := auth.uid();
  v_job public.delivery_jobs%ROWTYPE;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'AUTHENTICATION_REQUIRED';
  END IF;

  IF p_delivery_id IS NULL OR p_driver_id IS NULL OR p_qr_code IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Delivery and QR code are required');
  END IF;

  SELECT dj.*
  INTO v_job
  FROM public.delivery_jobs dj
  JOIN public.drivers d ON d.id = dj.driver_id
  WHERE dj.id = p_delivery_id
    AND dj.driver_id = p_driver_id
    AND d.user_id = v_actor
    AND dj.status IN ('assigned', 'accepted')
  FOR UPDATE OF dj;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Delivery is not assigned to this driver');
  END IF;

  IF p_qr_code <> v_job.id::TEXT THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid QR code');
  END IF;

  UPDATE public.delivery_jobs
  SET status = 'picked_up',
      picked_up_at = COALESCE(picked_up_at, now()),
      qr_scanned_at = now(),
      handover_method = 'qr',
      verification_attempts = 0,
      is_verification_locked = false,
      verification_code_hash = NULL,
      pickup_verification_code = NULL,
      verification_expires_at = NULL,
      updated_at = now()
  WHERE id = v_job.id;

  RETURN jsonb_build_object(
    'success', true,
    'message', 'Pickup verified successfully',
    'job_id', v_job.id,
    'status', 'picked_up'
  );
END;
$$;


ALTER FUNCTION "public"."verify_pickup_by_qr"("p_delivery_id" "uuid", "p_qr_code" "text", "p_driver_id" "uuid") OWNER TO "postgres";

--
-- Name: wearable_provider_precedence("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."wearable_provider_precedence"("p_provider" "text") RETURNS integer
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  select case p_provider
    when 'body_scale' then 100
    when 'apple_health' then 90
    when 'google_fit' then 80
    when 'sporthub' then 70
    when 'file_import' then 50
    when 'nutrio_activity' then 30
    when 'manual' then 20
    else 0
  end
$$;


