--
-- Name: check_rate_limit("uuid", integer, integer); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE OR REPLACE FUNCTION "security"."check_rate_limit"("p_partner_id" "uuid", "p_rate_limit" integer, "p_window_minutes" integer DEFAULT 60) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public', 'pg_temp'
    AS $$
DECLARE
    v_current_count INTEGER;
    v_window_start TIMESTAMP WITH TIME ZONE;
BEGIN
    -- Calculate window start
    v_window_start := date_trunc('hour', now()) 
        + INTERVAL '1 hour' * (EXTRACT(MINUTE FROM now())::int / p_window_minutes);
    
    -- Get or create rate limit record
    INSERT INTO security.api_rate_limits (partner_id, request_count, window_start)
    VALUES (p_partner_id, 1, v_window_start)
    ON CONFLICT (partner_id, window_start)
    DO UPDATE SET request_count = security.api_rate_limits.request_count + 1
    RETURNING request_count INTO v_current_count;
    
    -- Return true if under limit
    RETURN v_current_count <= p_rate_limit;
END;
$$;


ALTER FUNCTION "security"."check_rate_limit"("p_partner_id" "uuid", "p_rate_limit" integer, "p_window_minutes" integer) OWNER TO "postgres";

--
-- Name: decrypt_oauth_token("bytea"); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE OR REPLACE FUNCTION "security"."decrypt_oauth_token"("p_value" "bytea") RETURNS "text"
    LANGUAGE "sql" STRICT SECURITY DEFINER
    SET "search_path" TO 'security', 'extensions', 'public', 'pg_temp'
