-- Name: log_failed_auth("text", "text"); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE OR REPLACE FUNCTION "security"."log_failed_auth"("p_email" "text", "p_failure_reason" "text" DEFAULT 'invalid_credentials'::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public', 'pg_temp'
    AS $$
BEGIN
    INSERT INTO security.failed_auth_attempts (
        email,
        ip_address,
        failure_reason,
        user_agent
    ) VALUES (
        p_email,
        inet_client_addr(),
        p_failure_reason,
        current_setting('app.current_user_agent', true)
    );
EXCEPTION WHEN OTHERS THEN
    -- Silently fail if settings not available
    NULL;
END;
$$;


