--
-- Name: notification_next_allowed_at("uuid", timestamp with time zone); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE OR REPLACE FUNCTION "security"."notification_next_allowed_at"("p_user_id" "uuid", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS timestamp with time zone
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_catalog', 'pg_temp'
    AS $$
DECLARE
  v_enabled BOOLEAN;
  v_start TIME;
  v_end TIME;
  v_timezone TEXT;
  v_local_now TIMESTAMP;
  v_local_time TIME;
  v_next_local TIMESTAMP;
  v_in_quiet BOOLEAN := false;
BEGIN
  SELECT
    quiet_hours_enabled,
    quiet_hours_start,
    quiet_hours_end,
    timezone
  INTO v_enabled, v_start, v_end, v_timezone
  FROM public.notification_preferences
  WHERE user_id = p_user_id;

  IF NOT FOUND OR NOT COALESCE(v_enabled, false) OR v_start IS NULL
     OR v_end IS NULL OR v_start = v_end THEN
    RETURN p_now;
  END IF;

  IF NOT EXISTS (SELECT 1 FROM pg_timezone_names WHERE name = v_timezone) THEN
    v_timezone := 'Asia/Qatar';
  END IF;

  v_local_now := p_now AT TIME ZONE v_timezone;
  v_local_time := v_local_now::TIME;

  IF v_start < v_end THEN
    v_in_quiet := v_local_time >= v_start AND v_local_time < v_end;
    v_next_local := date_trunc('day', v_local_now) + v_end;
  ELSE
    v_in_quiet := v_local_time >= v_start OR v_local_time < v_end;
    v_next_local := CASE
      WHEN v_local_time >= v_start
        THEN date_trunc('day', v_local_now) + interval '1 day' + v_end
      ELSE date_trunc('day', v_local_now) + v_end
    END;
  END IF;

  IF NOT v_in_quiet THEN
    RETURN p_now;
  END IF;

  RETURN v_next_local AT TIME ZONE v_timezone;
END;
$$;


ALTER FUNCTION "security"."notification_next_allowed_at"("p_user_id" "uuid", "p_now" timestamp with time zone) OWNER TO "postgres";

--
-- Name: notification_preference_enabled("uuid", "text", "text"); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE OR REPLACE FUNCTION "security"."notification_preference_enabled"("p_user_id" "uuid", "p_preference_key" "text", "p_channel" "text") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_preferences public.notification_preferences%ROWTYPE;
  v_category_enabled BOOLEAN := true;
BEGIN
  SELECT * INTO v_preferences
  FROM public.notification_preferences
  WHERE user_id = p_user_id;

  IF FOUND THEN
    v_category_enabled := CASE p_preference_key
      WHEN 'meal_reminders' THEN COALESCE(v_preferences.meal_reminders, true)
      WHEN 'order_updates' THEN COALESCE(v_preferences.order_updates, true)
      WHEN 'delivery_updates' THEN COALESCE(v_preferences.delivery_updates, true)
      WHEN 'health_insights' THEN COALESCE(v_preferences.health_insights, true)
      WHEN 'plan_updates' THEN COALESCE(v_preferences.plan_updates, true)
      WHEN 'subscription_updates' THEN COALESCE(v_preferences.subscription_updates, true)
      WHEN 'achievements' THEN COALESCE(v_preferences.achievements, true)
      WHEN 'weekly_summary' THEN COALESCE(v_preferences.weekly_summary, true)
      WHEN 'support' THEN COALESCE(v_preferences.support, true)
      ELSE COALESCE(v_preferences.system_alerts, true)
    END;

    IF p_channel = 'push' THEN
      v_category_enabled := v_category_enabled
        AND COALESCE(v_preferences.push_notifications, true);
    END IF;
  END IF;

  RETURN v_category_enabled;
END;
$$;


ALTER FUNCTION "security"."notification_preference_enabled"("p_user_id" "uuid", "p_preference_key" "text", "p_channel" "text") OWNER TO "postgres";

--
-- Name: safe_notification_error_code("text"); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE OR REPLACE FUNCTION "security"."safe_notification_error_code"("p_value" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'pg_catalog'
    AS $$
  select nullif(left(regexp_replace(lower(coalesce(p_value, '')), '[^a-z0-9_.-]', '', 'g'), 120), '')
$$;


ALTER FUNCTION "security"."safe_notification_error_code"("p_value" "text") OWNER TO "postgres";

--
-- Name: should_block_ip("inet"); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE OR REPLACE FUNCTION "security"."should_block_ip"("p_ip_address" "inet") RETURNS boolean
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'security', 'public', 'pg_temp'
    AS $$
DECLARE
    v_recent_failures INTEGER;
BEGIN
    SELECT COUNT(*) INTO v_recent_failures
    FROM security.failed_auth_attempts
    WHERE ip_address = p_ip_address
    AND attempted_at > now() - INTERVAL '15 minutes';
    
    RETURN v_recent_failures >= 5;
END;
$$;


ALTER FUNCTION "security"."should_block_ip"("p_ip_address" "inet") OWNER TO "postgres";

--
-- Name: verify_api_secret("text", "text"); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE OR REPLACE FUNCTION "security"."verify_api_secret"("plain_secret" "text", "stored_hash" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public', 'pg_temp'
    AS $$
BEGIN
    RETURN stored_hash = crypt(plain_secret, stored_hash);
END;
$$;


ALTER FUNCTION "security"."verify_api_secret"("plain_secret" "text", "stored_hash" "text") OWNER TO "postgres";

