CREATE TABLE IF NOT EXISTS "audit"."log" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "table_schema" "text" NOT NULL,
    "table_name" "text" NOT NULL,
    "record_id" "uuid" NOT NULL,
    "action" "text" NOT NULL,
    "action_timestamp" timestamp with time zone DEFAULT "now"() NOT NULL,
    "old_data" "jsonb",
    "new_data" "jsonb",
    "changed_fields" "text"[],
    "changed_by" "uuid",
    "user_role" "text",
    "session_id" "text",
    "ip_address" "inet",
    "user_agent" "text",
    "request_id" "text",
    "application" "text" DEFAULT 'unknown'::"text",
    "api_endpoint" "text",
    CONSTRAINT "log_action_check" CHECK (("action" = ANY (ARRAY['INSERT'::"text", 'UPDATE'::"text", 'DELETE'::"text", 'TRUNCATE'::"text"])))
);


