--
-- Name: audit_summary_view; Type: VIEW; Schema: audit; Owner: postgres
--

CREATE OR REPLACE VIEW "audit"."audit_summary_view" AS
 SELECT "date_trunc"('day'::"text", "action_timestamp") AS "day",
    "table_name",
    "action",
    "count"(*) AS "action_count"
   FROM "audit"."log"
  WHERE ("action_timestamp" > ("now"() - '30 days'::interval))
  GROUP BY ("date_trunc"('day'::"text", "action_timestamp")), "table_name", "action"
  ORDER BY ("date_trunc"('day'::"text", "action_timestamp")) DESC, ("count"(*)) DESC;


ALTER VIEW "audit"."audit_summary_view" OWNER TO "postgres";

