--
-- Name: partner_audit_view; Type: VIEW; Schema: audit; Owner: postgres
--

CREATE OR REPLACE VIEW "audit"."partner_audit_view" AS
 SELECT "id",
    "table_schema",
    "table_name",
    "record_id",
    "action",
    "action_timestamp",
    "old_data",
    "new_data",
    "changed_fields",
    "changed_by",
    "user_role",
    "session_id",
    "ip_address",
    "user_agent",
    "request_id",
    "application",
    "api_endpoint"
   FROM "audit"."log" "al"
  WHERE (("changed_by" = "auth"."uid"()) OR (("table_name" = 'restaurants'::"text") AND ("record_id" IN ( SELECT "restaurants"."id"
           FROM "public"."restaurants"
          WHERE ("restaurants"."owner_id" = "auth"."uid"())))) OR (("table_name" = 'restaurant_details'::"text") AND ("record_id" IN ( SELECT "restaurant_details"."id"
           FROM "public"."restaurant_details"
          WHERE ("restaurant_details"."restaurant_id" IN ( SELECT "restaurants"."id"
                   FROM "public"."restaurants"
                  WHERE ("restaurants"."owner_id" = "auth"."uid"())))))) OR "public"."has_role"("auth"."uid"(), 'admin'::"public"."app_role"));


