--
-- Name: analytics_daily_stats; Type: MATERIALIZED VIEW; Schema: public; Owner: postgres
--

CREATE MATERIALIZED VIEW "public"."analytics_daily_stats" AS
 SELECT "date_trunc"('day'::"text", "created_at") AS "date",
    "count"(DISTINCT "user_id") AS "active_users",
    "count"(*) AS "total_orders",
    (0)::numeric AS "total_revenue",
    (0)::numeric AS "avg_order_value"
   FROM "public"."orders"
  WHERE ("status" <> ALL (ARRAY['cancelled'::"text", 'refunded'::"text"]))
  GROUP BY ("date_trunc"('day'::"text", "created_at"))
  ORDER BY ("date_trunc"('day'::"text", "created_at")) DESC
  WITH NO DATA;


ALTER MATERIALIZED VIEW "public"."analytics_daily_stats" OWNER TO "postgres";

