    CONSTRAINT "profiles_current_weight_kg_check" CHECK ((("current_weight_kg" > (0)::numeric) AND ("current_weight_kg" < (500)::numeric))),
    CONSTRAINT "profiles_height_cm_check" CHECK ((("height_cm" > (0)::numeric) AND ("height_cm" < (300)::numeric))),
