--
-- Name: challenge_leaderboard; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."challenge_leaderboard" WITH ("security_invoker"='true') AS
 SELECT "cp"."challenge_id",
    "cp"."user_id",
    "p"."full_name" AS "user_name",
    "p"."avatar_url",
    "cp"."current_progress",
    "cc"."target_value",
    "round"(((("cp"."current_progress")::numeric / (NULLIF("cc"."target_value", 0))::numeric) * (100)::numeric), 1) AS "progress_percent",
    "cp"."completed_at",
    "rank"() OVER (PARTITION BY "cp"."challenge_id" ORDER BY "cp"."current_progress" DESC, "cp"."completed_at") AS "rank"
   FROM (("public"."challenge_participants" "cp"
     JOIN "public"."community_challenges" "cc" ON (("cp"."challenge_id" = "cc"."id")))
     LEFT JOIN "public"."profiles" "p" ON (("cp"."user_id" = "p"."user_id")))
  WHERE ("cc"."is_active" = true);


ALTER VIEW "public"."challenge_leaderboard" OWNER TO "postgres";

