--
-- Name: coach_rating_summary; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."coach_rating_summary" WITH ("security_invoker"='true') AS
 SELECT "coach_id",
    "round"("avg"("rating"), 1) AS "average_rating",
    "count"(*) AS "total_reviews",
    "count"(*) FILTER (WHERE ("rating" = 5)) AS "five_star",
    "count"(*) FILTER (WHERE ("rating" = 4)) AS "four_star",
    "count"(*) FILTER (WHERE ("rating" = 3)) AS "three_star",
    "count"(*) FILTER (WHERE ("rating" = 2)) AS "two_star",
    "count"(*) FILTER (WHERE ("rating" = 1)) AS "one_star"
   FROM "public"."coach_reviews"
  GROUP BY "coach_id";


ALTER VIEW "public"."coach_rating_summary" OWNER TO "postgres";

