    CONSTRAINT "delivery_surge_rules_multiplier_check" CHECK ((("multiplier" >= (1)::numeric) AND ("multiplier" <= (5)::numeric))),
    CONSTRAINT "delivery_surge_rules_name_check" CHECK ((("char_length"("name") >= 2) AND ("char_length"("name") <= 80))),
    CONSTRAINT "delivery_surge_rules_priority_check" CHECK ((("priority" >= 0) AND ("priority" <= 10000))),
