--
-- Name: nps_responses; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."nps_responses" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" NOT NULL,
    "order_id" "uuid",
    "meal_schedule_id" "uuid",
    "score" integer NOT NULL,
    "feedback_text" "text",
    "category" "text" GENERATED ALWAYS AS (
CASE
    WHEN ("score" >= 9) THEN 'promoter'::"text"
    WHEN ("score" >= 7) THEN 'passive'::"text"
    ELSE 'detractor'::"text"
END) STORED,
    "survey_trigger" "text",
    "responded_at" timestamp with time zone DEFAULT "now"(),
    "follow_up_sent" boolean DEFAULT false,
    "follow_up_sent_at" timestamp with time zone,
    "follow_up_response" "text",
    "admin_notes" "text",
    "is_featured" boolean DEFAULT false,
    "featured_at" timestamp with time zone,
    "metadata" "jsonb" DEFAULT '{}'::"jsonb",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "nps_responses_score_check" CHECK ((("score" >= 0) AND ("score" <= 10))),
    CONSTRAINT "nps_responses_survey_trigger_check" CHECK (("survey_trigger" = ANY (ARRAY['post_delivery'::"text", 'post_order'::"text", 'periodic'::"text", 'manual'::"text", 'app_prompt'::"text"])))
);


ALTER TABLE "public"."nps_responses" OWNER TO "postgres";

