    CONSTRAINT "outdoor_activity_route_points_latitude_check" CHECK ((("latitude" >= ('-90'::integer)::double precision) AND ("latitude" <= (90)::double precision))),
    CONSTRAINT "outdoor_activity_route_points_longitude_check" CHECK ((("longitude" >= ('-180'::integer)::double precision) AND ("longitude" <= (180)::double precision))),
    CONSTRAINT "outdoor_activity_route_points_sequence_number_check" CHECK (("sequence_number" >= 0)),
    CONSTRAINT "outdoor_activity_route_points_speed_mps_check" CHECK ((("speed_mps" IS NULL) OR ("speed_mps" >= (0)::numeric)))
);


