--
-- Name: outdoor_activity_sessions; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."outdoor_activity_sessions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" NOT NULL,
    "workout_session_id" "uuid" NOT NULL,
    "local_session_id" "text" NOT NULL,
    "source" "text" NOT NULL,
    "source_fingerprint" "text" NOT NULL,
    "activity_type" "text" NOT NULL,
    "started_at" timestamp with time zone NOT NULL,
    "ended_at" timestamp with time zone NOT NULL,
    "duration_seconds" integer NOT NULL,
    "moving_seconds" integer NOT NULL,
    "distance_m" numeric(12,2) DEFAULT 0 NOT NULL,
    "elevation_gain_m" numeric(10,2) DEFAULT 0 NOT NULL,
    "average_pace_seconds_per_km" numeric(10,2),
    "calories_burned" integer DEFAULT 0 NOT NULL,
    "calorie_source" "text" NOT NULL,
    "average_heart_rate" integer,
    "max_heart_rate" integer,
    "heart_rate_zones" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "route_visibility" "text" DEFAULT 'private'::"text" NOT NULL,
    "auto_pause_enabled" boolean DEFAULT true NOT NULL,
    "import_format" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "outdoor_activity_sessions_activity_type_check" CHECK (("activity_type" = ANY (ARRAY['walking'::"text", 'running'::"text", 'cycling'::"text"]))),
    CONSTRAINT "outdoor_activity_sessions_average_heart_rate_check" CHECK ((("average_heart_rate" >= 25) AND ("average_heart_rate" <= 260))),
    CONSTRAINT "outdoor_activity_sessions_calorie_source_check" CHECK (("calorie_source" = ANY (ARRAY['gps_met_estimate'::"text", 'heart_rate_estimate'::"text", 'device_sync'::"text", 'imported_file'::"text"]))),
    CONSTRAINT "outdoor_activity_sessions_calories_burned_check" CHECK ((("calories_burned" >= 0) AND ("calories_burned" <= 50000))),
    CONSTRAINT "outdoor_activity_sessions_check" CHECK ((("moving_seconds" >= 0) AND ("moving_seconds" <= "duration_seconds"))),
    CONSTRAINT "outdoor_activity_sessions_check1" CHECK (("ended_at" >= "started_at")),
    CONSTRAINT "outdoor_activity_sessions_distance_m_check" CHECK ((("distance_m" >= (0)::numeric) AND ("distance_m" <= (1000000)::numeric))),
    CONSTRAINT "outdoor_activity_sessions_duration_seconds_check" CHECK ((("duration_seconds" > 0) AND ("duration_seconds" <= 604800))),
    CONSTRAINT "outdoor_activity_sessions_elevation_gain_m_check" CHECK ((("elevation_gain_m" >= (0)::numeric) AND ("elevation_gain_m" <= (50000)::numeric))),
    CONSTRAINT "outdoor_activity_sessions_import_format_check" CHECK (("import_format" = ANY (ARRAY['gpx'::"text", 'tcx'::"text", 'fit'::"text"]))),
    CONSTRAINT "outdoor_activity_sessions_max_heart_rate_check" CHECK ((("max_heart_rate" >= 25) AND ("max_heart_rate" <= 260))),
    CONSTRAINT "outdoor_activity_sessions_route_visibility_check" CHECK (("route_visibility" = ANY (ARRAY['private'::"text", 'followers'::"text", 'public'::"text"]))),
    CONSTRAINT "outdoor_activity_sessions_source_check" CHECK (("source" = ANY (ARRAY['gps'::"text", 'import_gpx'::"text", 'import_tcx'::"text", 'import_fit'::"text", 'google_fit'::"text", 'health_connect'::"text", 'apple_health'::"text"])))
);


