--
-- Name: partner_meal_nutrition_missing_queue; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."partner_meal_nutrition_missing_queue" WITH ("security_invoker"='true', "security_barrier"='true') AS
 SELECT "id" AS "meal_id",
    "restaurant_id",
    "name" AS "meal_name",
    "approval_status",
    "is_available",
    "nutrient_completeness_score",
    "nutrient_missing_codes",
    "nutrient_invalid_codes",
    "nutrition_version",
    NULL::timestamp with time zone AS "updated_at"
   FROM "public"."meals" "m"
  WHERE ((COALESCE("nutrient_completeness_score", 0) < 100) OR (COALESCE("array_length"("nutrient_invalid_codes", 1), 0) > 0));


ALTER VIEW "public"."partner_meal_nutrition_missing_queue" OWNER TO "postgres";

