--
-- Name: program_exercises; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."program_exercises" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "program_id" "uuid" NOT NULL,
    "exercise_name" "text" NOT NULL,
    "sets" integer DEFAULT 3 NOT NULL,
    "reps" "text" NOT NULL,
    "rest_seconds" integer DEFAULT 60,
    "notes" "text",
    "day_number" integer NOT NULL,
    "order_index" integer DEFAULT 0 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "exercise_catalog_id" "text",
    "progression_rule" "jsonb" DEFAULT '{"enabled": false, "rep_max": 12, "rep_min": 8, "strategy": "double_progression", "rpe_ceiling": 8.5, "rep_increment": 1, "deload_percent": 10, "load_increment_kg": 2.5, "failure_sessions_before_deload": 2}'::"jsonb" NOT NULL,
    "set_type" "text" DEFAULT 'normal'::"text" NOT NULL,
    "superset_group" "text",
    "prescription_unit" "text" DEFAULT 'reps'::"text" NOT NULL,
    "target_min" numeric,
    "target_max" numeric,
    "weight_rounding_kg" numeric DEFAULT 0.5 NOT NULL,
    CONSTRAINT "program_exercises_day_number_check" CHECK (("day_number" > 0)),
    CONSTRAINT "program_exercises_prescription_unit_check" CHECK (("prescription_unit" = ANY (ARRAY['reps'::"text", 'seconds'::"text", 'minutes'::"text", 'meters'::"text", 'kilometers'::"text"]))),
    CONSTRAINT "program_exercises_progression_rule_check" CHECK ((("jsonb_typeof"("progression_rule") = 'object'::"text") AND (COALESCE(("progression_rule" ->> 'strategy'::"text"), 'double_progression'::"text") = ANY (ARRAY['double_progression'::"text", 'linear_load'::"text", 'reps_only'::"text", 'sets_only'::"text", 'rir_based'::"text", 'density'::"text"])) AND (COALESCE((("progression_rule" ->> 'rep_min'::"text"))::integer, 1) > 0) AND (COALESCE((("progression_rule" ->> 'rep_max'::"text"))::integer, 1) >= COALESCE((("progression_rule" ->> 'rep_min'::"text"))::integer, 1)) AND (COALESCE((("progression_rule" ->> 'load_increment_kg'::"text"))::numeric, (0)::numeric) >= (0)::numeric) AND (COALESCE((("progression_rule" ->> 'rep_increment'::"text"))::integer, 1) > 0) AND ((COALESCE((("progression_rule" ->> 'set_increment'::"text"))::integer, 1) >= 1) AND (COALESCE((("progression_rule" ->> 'set_increment'::"text"))::integer, 1) <= 3)) AND ((COALESCE((("progression_rule" ->> 'max_sets'::"text"))::integer, 6) >= 1) AND (COALESCE((("progression_rule" ->> 'max_sets'::"text"))::integer, 6) <= 12)) AND ((COALESCE((("progression_rule" ->> 'target_rir'::"text"))::numeric, (2)::numeric) >= (0)::numeric) AND (COALESCE((("progression_rule" ->> 'target_rir'::"text"))::numeric, (2)::numeric) <= (5)::numeric)) AND ((COALESCE((("progression_rule" ->> 'rest_decrement_seconds'::"text"))::integer, 15) >= 5) AND (COALESCE((("progression_rule" ->> 'rest_decrement_seconds'::"text"))::integer, 15) <= 60)) AND ((COALESCE((("progression_rule" ->> 'min_rest_seconds'::"text"))::integer, 30) >= 0) AND (COALESCE((("progression_rule" ->> 'min_rest_seconds'::"text"))::integer, 30) <= 600)) AND ((COALESCE((("progression_rule" ->> 'rpe_ceiling'::"text"))::numeric, 8.5) >= (6)::numeric) AND (COALESCE((("progression_rule" ->> 'rpe_ceiling'::"text"))::numeric, 8.5) <= (10)::numeric)) AND ((COALESCE((("progression_rule" ->> 'failure_sessions_before_deload'::"text"))::integer, 2) >= 1) AND (COALESCE((("progression_rule" ->> 'failure_sessions_before_deload'::"text"))::integer, 2) <= 6)) AND ((COALESCE((("progression_rule" ->> 'deload_percent'::"text"))::numeric, (10)::numeric) >= (5)::numeric) AND (COALESCE((("progression_rule" ->> 'deload_percent'::"text"))::numeric, (10)::numeric) <= (30)::numeric)))),
    CONSTRAINT "program_exercises_set_type_check" CHECK (("set_type" = ANY (ARRAY['normal'::"text", 'dropset'::"text", 'myo'::"text", 'partial'::"text", 'forced'::"text", 'tut'::"text", 'isometric'::"text", 'jump'::"text"]))),
    CONSTRAINT "program_exercises_sets_check" CHECK (("sets" > 0)),
    CONSTRAINT "program_exercises_superset_group_check" CHECK ((("superset_group" IS NULL) OR ("superset_group" ~ '^[A-Z0-9]{1,4}$'::"text"))),
    CONSTRAINT "program_exercises_target_range_check" CHECK (((("target_min" IS NULL) AND ("target_max" IS NULL)) OR (("target_min" IS NOT NULL) AND ("target_max" IS NOT NULL) AND ("target_min" >= (0)::numeric) AND ("target_max" >= "target_min")))),
    CONSTRAINT "program_exercises_weight_rounding_check" CHECK (("weight_rounding_kg" = ANY (ARRAY[0.25, 0.5, (1)::numeric, 1.25, (2)::numeric, 2.5, (5)::numeric])))
);


