--
-- Name: public_meal_catalog; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."public_meal_catalog" WITH ("security_barrier"='true') AS
 SELECT "m"."id",
    "m"."restaurant_id",
    "r"."name" AS "restaurant_name",
    "m"."name",
    "m"."description",
    "m"."image_url",
    "m"."category",
    "m"."category_id",
    "m"."meal_type",
    "m"."ingredients",
    "m"."calories",
    "m"."protein",
    "m"."protein_g",
    "m"."carbs",
    "m"."carbs_g",
    "m"."fats",
    "m"."fat_g",
    "m"."fiber_g",
    "m"."price",
    "m"."prep_time_minutes",
    "m"."rating",
    "m"."avg_rating",
    "m"."review_count",
    "m"."order_count",
    "m"."is_featured",
    "m"."is_vip_exclusive",
    "m"."supports_high_protein",
    "m"."high_protein_price_adjustment",
    "m"."high_protein_calories_increase",
    "m"."high_protein_protein_increase",
    "m"."supports_large",
    "m"."large_price_adjustment",
    "m"."large_calories_increase",
    "m"."large_protein_increase",
    "m"."primary_language",
    "m"."vendor",
    "m"."featured_priority",
    "m"."approval_status",
    "m"."is_available",
    "m"."deleted_at",
    "m"."created_at",
    COALESCE(( SELECT "jsonb_agg"("jsonb_build_object"('meal_type', "mmo"."meal_type", 'price', "mmo"."price", 'is_available', "mmo"."is_available") ORDER BY ("array_position"(ARRAY['breakfast'::"text", 'lunch'::"text", 'dinner'::"text", 'snack'::"text"], "mmo"."meal_type"))) AS "jsonb_agg"
           FROM "public"."meal_menu_offerings" "mmo"
          WHERE ("mmo"."meal_id" = "m"."id")), '[]'::"jsonb") AS "menu_offerings"
   FROM ("public"."meals" "m"
     JOIN "public"."restaurants" "r" ON (("r"."id" = "m"."restaurant_id")))
  WHERE (("m"."approval_status" = 'approved'::"text") AND (COALESCE("m"."is_available", false) = true) AND ("m"."deleted_at" IS NULL) AND ("r"."approval_status" = 'approved'::"public"."approval_status") AND (COALESCE("r"."is_active", false) = true) AND ("r"."deleted_at" IS NULL));


ALTER VIEW "public"."public_meal_catalog" OWNER TO "postgres";

--
-- Name: VIEW "public_meal_catalog"; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW "public"."public_meal_catalog" IS 'Approved public meal projection. Excludes estimated cost and rejected, unavailable, or deleted rows.';


