--
-- Name: restaurant_capacity_status; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."restaurant_capacity_status" WITH ("security_invoker"='true') AS
 SELECT "id",
    "name",
    "max_meals_per_day",
    "current_day_orders",
    ("max_meals_per_day" - "current_day_orders") AS "remaining_capacity",
        CASE
            WHEN ("current_day_orders" >= "max_meals_per_day") THEN 'AT_CAPACITY'::"text"
            WHEN (("current_day_orders")::numeric >= (("max_meals_per_day")::numeric * 0.9)) THEN 'NEAR_CAPACITY'::"text"
            WHEN (("current_day_orders")::numeric >= (("max_meals_per_day")::numeric * 0.75)) THEN 'HIGH_USAGE'::"text"
            ELSE 'NORMAL'::"text"
        END AS "capacity_status",
    "round"(((("current_day_orders")::numeric / (NULLIF("max_meals_per_day", 0))::numeric) * (100)::numeric), 1) AS "usage_percentage",
    "daily_reset_at"
   FROM "public"."restaurants" "r"
  WHERE ("is_active" = true);


ALTER VIEW "public"."restaurant_capacity_status" OWNER TO "postgres";

--
-- Name: VIEW "restaurant_capacity_status"; Type: COMMENT; Schema: public; Owner: postgres
