--
-- Name: restaurant_details_secure; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."restaurant_details_secure" WITH ("security_invoker"='true') AS
 SELECT "id",
    "restaurant_id",
    "cuisine_type",
    "dietary_tags",
    "alternate_phone",
    "website_url",
    "operating_hours",
    "avg_prep_time_minutes",
    "max_meals_per_day",
        CASE
            WHEN (("auth"."uid"() IN ( SELECT "restaurants"."owner_id"
               FROM "public"."restaurants"
              WHERE ("restaurants"."id" = "restaurant_details"."restaurant_id"))) OR "public"."has_role"("auth"."uid"(), 'admin'::"public"."app_role")) THEN "security"."decrypt_sensitive_data"("bank_account_number_encrypted")
            ELSE NULL::"text"
        END AS "bank_account_number",
        CASE
            WHEN (("auth"."uid"() IN ( SELECT "restaurants"."owner_id"
               FROM "public"."restaurants"
              WHERE ("restaurants"."id" = "restaurant_details"."restaurant_id"))) OR "public"."has_role"("auth"."uid"(), 'admin'::"public"."app_role")) THEN "security"."decrypt_sensitive_data"("bank_iban_encrypted")
            ELSE NULL::"text"
        END AS "bank_iban",
        CASE
            WHEN (("auth"."uid"() IN ( SELECT "restaurants"."owner_id"
               FROM "public"."restaurants"
              WHERE ("restaurants"."id" = "restaurant_details"."restaurant_id"))) OR "public"."has_role"("auth"."uid"(), 'admin'::"public"."app_role")) THEN "security"."decrypt_sensitive_data"("bank_swift_encrypted")
            ELSE NULL::"text"
        END AS "swift_code",
        CASE
            WHEN (("auth"."uid"() IN ( SELECT "restaurants"."owner_id"
               FROM "public"."restaurants"
              WHERE ("restaurants"."id" = "restaurant_details"."restaurant_id"))) OR "public"."has_role"("auth"."uid"(), 'admin'::"public"."app_role")) THEN "security"."decrypt_sensitive_data"("bank_name_encrypted")
            ELSE NULL::"text"
        END AS "bank_name",
    "onboarding_step",
    "onboarding_completed",
    "terms_accepted",
    "terms_accepted_at",
    "created_at",
    "updated_at"
   FROM "public"."restaurant_details";


ALTER VIEW "public"."restaurant_details_secure" OWNER TO "postgres";

