--
-- Name: slow_query_candidates; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."slow_query_candidates" WITH ("security_invoker"='true') AS
 SELECT "schemaname",
    "tablename",
    "attname" AS "column_name",
    "n_distinct",
    "null_frac",
    "correlation"
   FROM "pg_stats"
  WHERE (("schemaname" = 'public'::"name") AND ("n_distinct" < (100)::double precision))
  ORDER BY "null_frac" DESC;


