--
-- Name: translation_statistics; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."translation_statistics" WITH ("security_invoker"='true') AS
 SELECT 'total_meals'::"text" AS "metric",
    ("count"(*))::"text" AS "value"
   FROM "public"."meals"
  WHERE ("meals"."deleted_at" IS NULL)
UNION ALL
 SELECT 'translated_meals'::"text" AS "metric",
    ("count"(DISTINCT "meal_translations"."meal_id"))::"text" AS "value"
   FROM "public"."meal_translations"
  WHERE ("meal_translations"."language_code" = 'ar'::"public"."language_code")
UNION ALL
 SELECT 'pending_review'::"text" AS "metric",
    ("count"(*))::"text" AS "value"
   FROM "public"."meal_translations"
  WHERE (("meal_translations"."language_code" = 'ar'::"public"."language_code") AND ("meal_translations"."review_status" = 'pending'::"text"))
UNION ALL
 SELECT 'approved_translations'::"text" AS "metric",
    ("count"(*))::"text" AS "value"
   FROM "public"."meal_translations"
  WHERE (("meal_translations"."language_code" = 'ar'::"public"."language_code") AND ("meal_translations"."review_status" = 'approved'::"text"))
UNION ALL
 SELECT 'auto_translated_count'::"text" AS "metric",
    ("count"(*))::"text" AS "value"
   FROM "public"."meal_translations"
  WHERE (("meal_translations"."language_code" = 'ar'::"public"."language_code") AND ("meal_translations"."is_auto_translated" = true));


ALTER VIEW "public"."translation_statistics" OWNER TO "postgres";

