--

CREATE TABLE IF NOT EXISTS "public"."user_health_scores" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" NOT NULL,
    "calculated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "score_week_start" "date" NOT NULL,
    "macro_adherence_score" numeric(5,2),
    "meal_consistency_score" numeric(5,2),
    "weight_logging_score" numeric(5,2),
    "protein_accuracy_score" numeric(5,2),
    "overall_score" numeric(5,2) NOT NULL,
    "category" "text" GENERATED ALWAYS AS (
CASE
    WHEN ("overall_score" >= (80)::numeric) THEN 'green'::"text"
    WHEN ("overall_score" >= (60)::numeric) THEN 'orange'::"text"
    ELSE 'red'::"text"
END) STORED,
    "metrics_used" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "user_health_scores_macro_adherence_score_check" CHECK ((("macro_adherence_score" >= (0)::numeric) AND ("macro_adherence_score" <= (100)::numeric))),
    CONSTRAINT "user_health_scores_meal_consistency_score_check" CHECK ((("meal_consistency_score" >= (0)::numeric) AND ("meal_consistency_score" <= (100)::numeric))),
    CONSTRAINT "user_health_scores_overall_score_check" CHECK ((("overall_score" >= (0)::numeric) AND ("overall_score" <= (100)::numeric))),
    CONSTRAINT "user_health_scores_protein_accuracy_score_check" CHECK ((("protein_accuracy_score" >= (0)::numeric) AND ("protein_accuracy_score" <= (100)::numeric))),
    CONSTRAINT "user_health_scores_weight_logging_score_check" CHECK ((("weight_logging_score" >= (0)::numeric) AND ("weight_logging_score" <= (100)::numeric)))
);


ALTER TABLE "public"."user_health_scores" OWNER TO "postgres";

