--
-- Name: user_orders_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."user_orders_view" WITH ("security_invoker"='true') AS
 SELECT "ms"."id",
    "ms"."user_id",
    "ms"."scheduled_date",
    "ms"."meal_type",
    "ms"."is_completed",
    "ms"."created_at" AS "order_created_at",
    "ms"."delivery_type",
    "ms"."delivery_fee",
    "m"."id" AS "meal_id",
    "m"."name" AS "meal_name",
    "m"."description" AS "meal_description",
    "m"."calories",
    "m"."protein_g",
    "m"."carbs_g",
    "m"."fat_g",
    "m"."image_url" AS "meal_image_url",
    "r"."id" AS "restaurant_id",
    "r"."name" AS "restaurant_name",
    "r"."logo_url" AS "restaurant_logo_url",
    "p"."full_name" AS "user_full_name",
    "p"."email" AS "user_email"
   FROM ((("public"."meal_schedules" "ms"
     JOIN "public"."meals" "m" ON (("ms"."meal_id" = "m"."id")))
     JOIN "public"."restaurants" "r" ON (("m"."restaurant_id" = "r"."id")))
     JOIN "public"."profiles" "p" ON (("ms"."user_id" = "p"."user_id")));


ALTER VIEW "public"."user_orders_view" OWNER TO "postgres";

