--
-- Name: webhook_queue_status; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."webhook_queue_status" WITH ("security_invoker"='true') AS
 SELECT "status",
    "event_type",
    "count"(*) AS "count",
    "min"("created_at") AS "oldest",
    "max"("created_at") AS "newest"
   FROM "public"."webhook_delivery_queue"
  WHERE ("created_at" > ("now"() - '24:00:00'::interval))
  GROUP BY "status", "event_type";


