--
-- Name: domain_event_outbox; Type: TABLE; Schema: security; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "security"."domain_event_outbox" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "event_type" "text" NOT NULL,
    "schema_version" integer DEFAULT 1 NOT NULL,
    "aggregate_type" "text" NOT NULL,
    "aggregate_id" "uuid",
    "actor_id" "uuid",
    "audience_user_id" "uuid" NOT NULL,
    "idempotency_key" "text" NOT NULL,
    "correlation_id" "uuid",
    "causation_id" "uuid",
    "payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "privacy_classification" "text" DEFAULT 'standard'::"text" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "attempt_count" integer DEFAULT 0 NOT NULL,
    "max_attempts" integer DEFAULT 5 NOT NULL,
    "next_attempt_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "lease_token" "uuid",
    "lease_expires_at" timestamp with time zone,
    "last_error_code" "text",
    "occurred_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "processed_at" timestamp with time zone,
    CONSTRAINT "domain_event_outbox_aggregate_type_check" CHECK (("aggregate_type" ~ '^[a-z][a-z0-9_]{0,79}$'::"text")),
    CONSTRAINT "domain_event_outbox_attempt_count_check" CHECK ((("attempt_count" >= 0) AND ("attempt_count" <= 20))),
    CONSTRAINT "domain_event_outbox_event_type_check" CHECK (("event_type" ~ '^[a-z][a-z0-9_]*\.[a-z][a-z0-9_]*\.v[1-9][0-9]*$'::"text")),
    CONSTRAINT "domain_event_outbox_idempotency_key_check" CHECK ((("char_length"("idempotency_key") >= 1) AND ("char_length"("idempotency_key") <= 220))),
    CONSTRAINT "domain_event_outbox_max_attempts_check" CHECK ((("max_attempts" >= 1) AND ("max_attempts" <= 20))),
    CONSTRAINT "domain_event_outbox_payload_check" CHECK (("jsonb_typeof"("payload") = 'object'::"text")),
    CONSTRAINT "domain_event_outbox_payload_check1" CHECK (("octet_length"(("payload")::"text") <= 4096)),
    CONSTRAINT "domain_event_outbox_privacy_classification_check" CHECK (("privacy_classification" = ANY (ARRAY['standard'::"text", 'sensitive'::"text", 'restricted'::"text"]))),
    CONSTRAINT "domain_event_outbox_schema_version_check" CHECK ((("schema_version" >= 1) AND ("schema_version" <= 100))),
    CONSTRAINT "domain_event_outbox_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'processing'::"text", 'failed'::"text", 'completed'::"text", 'dead_letter'::"text"])))
);

ALTER TABLE ONLY "security"."domain_event_outbox" FORCE ROW LEVEL SECURITY;


ALTER TABLE "security"."domain_event_outbox" OWNER TO "postgres";

