    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "dedupe_key" "text" NOT NULL,
    "quiet_hours_policy" "text" DEFAULT 'respect'::"text" NOT NULL,
    "deep_link_type" "text",
    "deferred_until" timestamp with time zone,
    "suppressed_at" timestamp with time zone,
    "suppression_reason" "text",
    "attempt_count" integer DEFAULT 0 NOT NULL,
    "last_error_code" "text",
    "retryable" boolean DEFAULT true NOT NULL,
    "provider_message_id" "text",
    "analytics_event" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "locale" "text" DEFAULT 'en'::"text" NOT NULL,
    "rendered_title" "text",
    "rendered_message" "text",
    "delivery_data" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "max_attempts" integer DEFAULT 5 NOT NULL,
    "next_attempt_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "lease_token" "uuid",
    "lease_expires_at" timestamp with time zone,
    "delivered_at" timestamp with time zone,
    "failed_at" timestamp with time zone,
    CONSTRAINT "notification_event_deliveries_attempt_count_check" CHECK ((("attempt_count" >= 0) AND ("attempt_count" <= 20))),
    CONSTRAINT "notification_event_deliveries_channel_check" CHECK (("channel" = ANY (ARRAY['in_app'::"text", 'push'::"text", 'email'::"text", 'whatsapp'::"text"]))),
    CONSTRAINT "notification_event_deliveries_quiet_hours_policy_check" CHECK (("quiet_hours_policy" = ANY (ARRAY['respect'::"text", 'bypass'::"text"]))),
    CONSTRAINT "notification_event_deliveries_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'deferred'::"text", 'suppressed'::"text", 'processing'::"text", 'delivered'::"text", 'failed'::"text", 'dead_letter'::"text"])))
);

