    CONSTRAINT "notification_event_templates_body_en_check" CHECK ((("char_length"("body_en") >= 1) AND ("char_length"("body_en") <= 1000))),
    CONSTRAINT "notification_event_templates_channels_check" CHECK (("channels" <@ ARRAY['in_app'::"text", 'push'::"text"])),
    CONSTRAINT "notification_event_templates_channels_check1" CHECK ((("cardinality"("channels") >= 1) AND ("cardinality"("channels") <= 2))),
    CONSTRAINT "notification_event_templates_quiet_hours_policy_check" CHECK (("quiet_hours_policy" = ANY (ARRAY['respect'::"text", 'bypass'::"text"]))),
    CONSTRAINT "notification_event_templates_title_ar_check" CHECK ((("char_length"("title_ar") >= 1) AND ("char_length"("title_ar") <= 120))),
