--
-- Name: notification_operations_status; Type: VIEW; Schema: security; Owner: postgres
--

CREATE OR REPLACE VIEW "security"."notification_operations_status" AS
 SELECT "template_key",
    "channel",
    "status",
    ("count"(*))::integer AS "delivery_count",
    "min"("created_at") AS "oldest_created_at",
    "max"("updated_at") AS "latest_updated_at",
    "max"("attempt_count") AS "max_attempt_count",
    ("count"(*) FILTER (WHERE ("status" = 'dead_letter'::"text")))::integer AS "dead_letter_count",
    ("count"(*) FILTER (WHERE ("status" = 'suppressed'::"text")))::integer AS "suppressed_count",
    ("count"(*) FILTER (WHERE ("status" = 'deferred'::"text")))::integer AS "deferred_count",
    "min"("deferred_until") FILTER (WHERE ("status" = 'deferred'::"text")) AS "next_deferred_until",
    "array_remove"("array_agg"(DISTINCT "suppression_reason"), NULL::"text") AS "suppression_reasons",
    "array_remove"("array_agg"(DISTINCT "last_error_code"), NULL::"text") AS "error_codes"
   FROM "security"."notification_event_deliveries"
  GROUP BY "template_key", "channel", "status";


ALTER VIEW "security"."notification_operations_status" OWNER TO "postgres";

--
-- Name: VIEW "notification_operations_status"; Type: COMMENT; Schema: security; Owner: postgres
--

COMMENT ON VIEW "security"."notification_operations_status" IS 'Service-role-only notification delivery operations summary without recipient PII.';


--
-- Name: notification_pipeline_status; Type: VIEW; Schema: security; Owner: postgres
--

CREATE OR REPLACE VIEW "security"."notification_pipeline_status" AS
 SELECT 'domain_event'::"text" AS "queue",
    "domain_event_outbox"."event_type" AS "category",
    "domain_event_outbox"."status",
    ("count"(*))::integer AS "item_count",
    "min"("domain_event_outbox"."created_at") AS "oldest_created_at",
    "max"("domain_event_outbox"."attempt_count") AS "max_attempt_count",
    "array_remove"("array_agg"(DISTINCT "domain_event_outbox"."last_error_code"), NULL::"text") AS "error_codes"
   FROM "security"."domain_event_outbox"
  GROUP BY "domain_event_outbox"."event_type", "domain_event_outbox"."status"
UNION ALL
 SELECT 'delivery'::"text" AS "queue",
    "notification_event_deliveries"."template_key" AS "category",
    "notification_event_deliveries"."status",
    ("count"(*))::integer AS "item_count",
    "min"("notification_event_deliveries"."created_at") AS "oldest_created_at",
    "max"("notification_event_deliveries"."attempt_count") AS "max_attempt_count",
    "array_remove"("array_agg"(DISTINCT "notification_event_deliveries"."last_error_code"), NULL::"text") AS "error_codes"
   FROM "security"."notification_event_deliveries"
  GROUP BY "notification_event_deliveries"."template_key", "notification_event_deliveries"."status";


ALTER VIEW "security"."notification_pipeline_status" OWNER TO "postgres";

