-- Name: meal_allergens Authenticated users can delete meal allergens; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Authenticated users can delete meal allergens" ON "public"."meal_allergens" FOR DELETE USING (("public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role") OR (EXISTS ( SELECT 1
   FROM ("public"."meals" "m"
     JOIN "public"."restaurants" "r" ON (("r"."id" = "m"."restaurant_id")))
  WHERE (("m"."id" = "meal_allergens"."meal_id") AND ("r"."owner_id" = ( SELECT "auth"."uid"() AS "uid")))))));


