   FROM ("public"."meals" "m"
     JOIN "public"."restaurants" "r" ON (("r"."id" = "m"."restaurant_id")))
  WHERE (("m"."id" = "meal_allergens"."meal_id") AND ("r"."owner_id" = ( SELECT "auth"."uid"() AS "uid")))))));


