--
-- Name: knowledge_chunks Authenticated users read published knowledge chunks; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Authenticated users read published knowledge chunks" ON "public"."knowledge_chunks" FOR SELECT TO "authenticated" USING ((EXISTS ( SELECT 1
   FROM "public"."knowledge_documents" "document"
  WHERE (("document"."id" = "knowledge_chunks"."document_id") AND ("document"."status" = 'published'::"text") AND ("document"."effective_from" <= CURRENT_DATE) AND (("document"."effective_to" IS NULL) OR ("document"."effective_to" >= CURRENT_DATE))))));


--
-- Name: delivery_jobs Authorized users can update delivery jobs; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Authorized users can update delivery jobs" ON "public"."delivery_jobs" FOR UPDATE TO "authenticated" USING (("public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role") OR "public"."is_active_fleet_operator"(( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
   FROM "public"."drivers" "d"
  WHERE (("d"."user_id" = ( SELECT "auth"."uid"() AS "uid")) AND (("d"."id" = "delivery_jobs"."driver_id") OR ((("delivery_jobs"."status")::"text" = 'pending'::"text") AND ("delivery_jobs"."driver_id" IS NULL)))))) OR (EXISTS ( SELECT 1
   FROM "public"."meal_schedules" "ms"
  WHERE (("ms"."id" = "delivery_jobs"."schedule_id") AND ("ms"."user_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
   FROM "public"."restaurants" "r"
  WHERE (("r"."id" = "delivery_jobs"."restaurant_id") AND "public"."is_restaurant_operator"("r"."id", ( SELECT "auth"."uid"() AS "uid"))))))) WITH CHECK (("public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role") OR "public"."is_active_fleet_operator"(( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
   FROM "public"."drivers" "d"
  WHERE (("d"."user_id" = ( SELECT "auth"."uid"() AS "uid")) AND (("d"."id" = "delivery_jobs"."driver_id") OR ((("delivery_jobs"."status")::"text" = 'pending'::"text") AND ("delivery_jobs"."driver_id" IS NULL)))))) OR (EXISTS ( SELECT 1
   FROM "public"."meal_schedules" "ms"
  WHERE (("ms"."id" = "delivery_jobs"."schedule_id") AND ("ms"."user_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
   FROM "public"."restaurants" "r"
  WHERE (("r"."id" = "delivery_jobs"."restaurant_id") AND "public"."is_restaurant_operator"("r"."id", ( SELECT "auth"."uid"() AS "uid")))))));


--
-- Name: delivery_job_status_history Authorized users can view delivery job history; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Authorized users can view delivery job history" ON "public"."delivery_job_status_history" FOR SELECT TO "authenticated" USING (("public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role") OR "public"."is_active_fleet_operator"(( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
   FROM ("public"."delivery_jobs" "dj"
     JOIN "public"."meal_schedules" "ms" ON (("ms"."id" = "dj"."schedule_id")))
  WHERE (("dj"."id" = "delivery_job_status_history"."delivery_job_id") AND ("ms"."user_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
   FROM ("public"."delivery_jobs" "dj"
     JOIN "public"."drivers" "d" ON (("d"."id" = "dj"."driver_id")))
  WHERE (("dj"."id" = "delivery_job_status_history"."delivery_job_id") AND ("d"."user_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
   FROM ("public"."delivery_jobs" "dj"
     JOIN "public"."restaurants" "r" ON (("r"."id" = "dj"."restaurant_id")))
  WHERE (("dj"."id" = "delivery_job_status_history"."delivery_job_id") AND "public"."is_restaurant_operator"("r"."id", ( SELECT "auth"."uid"() AS "uid")))))));


--
-- Name: delivery_jobs Authorized users can view delivery jobs; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Authorized users can view delivery jobs" ON "public"."delivery_jobs" FOR SELECT TO "authenticated" USING (("public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role") OR "public"."is_active_fleet_operator"(( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
   FROM "public"."drivers" "d"
  WHERE (("d"."user_id" = ( SELECT "auth"."uid"() AS "uid")) AND (("d"."id" = "delivery_jobs"."driver_id") OR ((("delivery_jobs"."status")::"text" = 'pending'::"text") AND ("delivery_jobs"."driver_id" IS NULL) AND ("d"."is_active" = true) AND ("d"."is_online" = true) AND (("d"."approval_status")::"text" = 'approved'::"text")))))) OR (EXISTS ( SELECT 1
   FROM "public"."meal_schedules" "ms"
  WHERE (("ms"."id" = "delivery_jobs"."schedule_id") AND ("ms"."user_id" = ( SELECT "auth"."uid"() AS "uid"))))) OR (EXISTS ( SELECT 1
   FROM "public"."restaurants" "r"
