  WHERE (("kitchen_queue_items"."order_source" = 'order'::"text") AND ("o"."id" = "kitchen_queue_items"."order_id") AND ("r"."owner_id" = "auth"."uid"())))))) WITH CHECK (((EXISTS ( SELECT 1
   FROM ("public"."meal_schedules" "ms"
     JOIN "public"."restaurants" "r" ON (("r"."id" = "ms"."restaurant_id")))
  WHERE (("kitchen_queue_items"."order_source" = 'meal_schedule'::"text") AND ("ms"."id" = "kitchen_queue_items"."order_id") AND ("r"."owner_id" = "auth"."uid"())))) OR (EXISTS ( SELECT 1
   FROM ("public"."orders" "o"
     JOIN "public"."restaurants" "r" ON (("r"."id" = "o"."restaurant_id")))
  WHERE (("kitchen_queue_items"."order_source" = 'order'::"text") AND ("o"."id" = "kitchen_queue_items"."order_id") AND ("r"."owner_id" = "auth"."uid"()))))));


