  WHERE (("ur"."user_id" = "auth"."uid"()) AND ("ur"."role" = ANY (ARRAY['admin'::"public"."app_role", 'staff'::"public"."app_role"]))))) OR (EXISTS ( SELECT 1
   FROM "public"."coach_client_assignments" "cca"
  WHERE (("cca"."coach_id" = "auth"."uid"()) AND ("cca"."client_id" = "notifications"."user_id") AND ("cca"."status" = 'active'::"text")))) OR (EXISTS ( SELECT 1
   FROM (("public"."delivery_jobs" "dj"
     JOIN "public"."drivers" "d" ON (("d"."id" = "dj"."driver_id")))
     JOIN "public"."restaurants" "r" ON (("r"."id" = "dj"."restaurant_id")))
  WHERE (("dj"."id" = (NULLIF(("notifications"."data" ->> 'delivery_job_id'::"text"), ''::"text"))::"uuid") AND ("d"."user_id" = "notifications"."user_id") AND ("r"."owner_id" = "auth"."uid"()))))));


