--

CREATE POLICY "restaurants_aal2_admin_select" ON "public"."restaurants" FOR SELECT TO "authenticated" USING (((COALESCE(("auth"."jwt"() ->> 'aal'::"text"), 'aal1'::"text") = 'aal2'::"text") AND "public"."has_role"(( SELECT "auth"."uid"() AS "uid"), 'admin'::"public"."app_role")));


--
-- Name: restaurants restaurants_operator_select; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "restaurants_operator_select" ON "public"."restaurants" FOR SELECT TO "authenticated" USING ((("owner_id" = ( SELECT "auth"."uid"() AS "uid")) OR (EXISTS ( SELECT 1
   FROM "public"."staff_members" "sm"
  WHERE (("sm"."restaurant_id" = "restaurants"."id") AND ("sm"."user_id" = ( SELECT "auth"."uid"() AS "uid")) AND (COALESCE("sm"."is_active", false) = true))))));


